window.__QUIZ_SUBJECT__=[{"id": "objective>Government>1995>1", "subject": "Government", "year": "1995", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "The primary function of government in a state is to", "images": [], "options": {"A": "Build schools and hospitals", "B": "Provide transport service", "C": "Engage in campaigns and rallies", "D": "Maintain law and order"}, "answer": "D", "explanation": "The primary function of a government in a state is to maintain law and order. This is because the government is responsible for the enforcement of laws and regulations, and ensuring that all citizens abide by these laws. This helps to prevent chaos and disorder, and ensures the smooth running of the state. Building schools and hospitals, providing transport services, and engaging in campaigns and rallies are also functions of the government, but they are not the primary function.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1995>2", "subject": "Government", "year": "1995", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A country is most likely to have a good government only if it has", "images": [], "options": {"A": "A Good constitution but bad operators", "B": "Good operators but bad constitution", "C": "A good constitution and good operators", "D": "A legitimate government"}, "answer": "D", "explanation": "A legitimate government is one duly elected by the people.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>3", "subject": "Government", "year": "1995", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following is a basic principle of democracy? Rule by", "images": [], "options": {"A": "The majority and the right of the minority", "B": "The minority at the expense of the majority", "C": "The wealthy few", "D": "A monarch"}, "answer": "A", "explanation": "A basic principle of democracy is rule by the majority with respect for the rights of the minority. This means that while the majority's decision is followed, the rights and freedoms of the minority are still protected and respected.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1995>4", "subject": "Government", "year": "1995", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Which of the following is legal source of political authority?", "images": [], "options": {"A": "Power from the gun", "B": "Economic power", "C": "Minority power", "D": "Power from the electorate"}, "answer": "D", "explanation": "In a democratic society, the legal source of political authority is power from the electorate. This means that the people, through voting, give politicians the authority to govern. This is different from power from the gun (military power), economic power (wealth), or minority power (rule by a small group), which are not democratic sources of political authority.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>5", "subject": "Government", "year": "1995", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : EXECUTIVE", "question": "Which organ of government is vested with the responsibility of initiating bills and recommending them to the legislature for consideration? The", "images": [], "options": {"A": "Federal House of Representatives", "B": "Executive", "C": "Congress", "D": "Senate"}, "answer": "B", "explanation": "The Executive branch of government is responsible for initiating bills and recommending them to the legislature for consideration. The Executive branch includes the President, Vice President, and other executive officers to implement and enforce laws written by the legislature. The Federal House of Representatives, Congress, and Senate are all part of the legislative branch, not the executive.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1995>6", "subject": "Government", "year": "1995", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "The independence of the Judiciary can  be enhanced in all the following cases except where", "images": [], "options": {"A": "Judges are granted special immunity", "B": "Judges are paid handsome remuneration", "C": "The President is also the Chief Judge", "D": "The salaries of judges are drawn from consolidated fund"}, "answer": "C", "explanation": "The independence of the Judiciary can be compromised if the President is also the Chief Judge. This is because the separation of powers principle, which is fundamental to the operation of a democratic government, requires that the three branches of government - the executive, legislative, and judicial - operate independently of each other. If the President, who is part of the executive branch, is also the Chief Judge, this would violate the separation of powers and could potentially compromise the independence of the judiciary.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>7", "subject": "Government", "year": "1995", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following is a feature of feudalism?", "images": [], "options": {"A": "One-party rule", "B": "Multi-party system", "C": "Millitary rule", "D": "Lord-Serf relationship"}, "answer": "D", "explanation": "Feudalism is a social system that was prevalent in Medieval Europe under which, the nobility held lands from the Crown in exchange for military service, and vassals were in turn tenants of the nobles, while the peasants (villeins or serfs) were obliged to live on their lord's land and give him homage, labor, and a share of the produce, notionally in exchange for military protection. Therefore, the Lord-Serf relationship is a feature of feudalism.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1995>8", "subject": "Government", "year": "1995", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : MONARCHICAL", "question": "Which of the following is the unique feature of Monarchy?", "images": [], "options": {"A": "Members of the executive are popularl elected", "B": "Succession is hereditary", "C": "Separation of powers is absolute", "D": "Its operation is based on collective responsibilty"}, "answer": "B", "explanation": "Monarchy is a form of government in which a single family rules from generation to generation. The power, or sovereignty, is often held by a single person, who is the monarch. A unique feature of monarchy is that the succession is hereditary, meaning that the throne is passed down to the monarch's descendants, usually from parent to child.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>9", "subject": "Government", "year": "1995", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET", "question": "There is no seperation of powers in a Cabinet system because", "images": [], "options": {"A": "Members of the Executive are also memebers of the Judiciary", "B": "The President is also a member of parliament", "C": "The Prime Minister and his cabinet ministers are also members of parliament", "D": "Some elected parliamentarians are also judges"}, "answer": "C", "explanation": "In a Cabinet system of government, there is no complete separation of powers because the Prime Minister and his cabinet ministers are also members of parliament. This means that they are part of both the executive and legislative branches of government. The executive branch is responsible for implementing and enforcing laws, while the legislative branch is responsible for making laws. Therefore, the same individuals being part of both branches blurs the line of separation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>10", "subject": "Government", "year": "1995", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "In democracies, political participation could be restricted on the basis of", "images": [], "options": {"A": "Religion", "B": "Age", "C": "Race", "D": "Sex"}, "answer": "B", "explanation": "In democracies, political participation could be restricted on the basis of age. This is because there are usually minimum age requirements to vote or to run for office. For example, in many countries, you must be at least 18 years old to vote. Restrictions based on religion, race, or sex are generally considered undemocratic and are against the principles of equal rights and non-discrimination.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>11", "subject": "Government", "year": "1995", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Disenfranchisement refers to the", "images": [], "options": {"A": "Qualification of voters in an election", "B": "Disqualification of fraudulent persidential aspirants", "C": "Denial of right to vote in an election", "D": "`Right to vote in all elections"}, "answer": "C", "explanation": "Disenfranchisement refers to the denial of the right to vote in an election. It is a situation where a person or group of people are deprived of their voting rights. This can occur due to various reasons such as legal barriers, systemic barriers, or discrimination.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>12", "subject": "Government", "year": "1995", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "The limitation on the right to life can be found", "images": [], "options": {"A": "Among the people", "B": "In the case of a convicted person", "C": "In the Executive", "D": "In the Government"}, "answer": "B", "explanation": "The limitation on the right to life can be found in the case of a convicted person. This refers to the legal principle that a person's right to life can be limited or taken away by the state if they are convicted of a serious crime, such as murder. This is often the legal justification for capital punishment.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1995>13", "subject": "Government", "year": "1995", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following is not an agent of political socialization?", "images": [], "options": {"A": "Tourism", "B": "Mass media", "C": "Peer group", "D": "University"}, "answer": "A", "explanation": "Political socialization is the process by which individuals learn and frequently internalize a political lens framing their perceptions of how power is arranged and how the world around them is (and should be) organized. Those individuals are influenced by a variety of factors including family, school, peer group, and mass media. Tourism, however, is not typically considered an agent of political socialization.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1995>14", "subject": "Government", "year": "1995", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Political sovereignty belongs to", "images": [], "options": {"A": "The people", "B": "Students", "C": "Soldiers", "D": "The parliament"}, "answer": "A", "explanation": "Political sovereignty refers to the highest level of absolute power through which any independent state is governed. This power belongs to the people in a democratic system. The people exercise their power through voting in elections to choose their representatives in the parliament. Therefore, the correct answer is 'The people'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>15", "subject": "Government", "year": "1995", "type": "Objective", "topic": "CITIZENSHIP : MEANING AND MODE OF ACQUISITION", "question": "An alien who has lived in Nigeria for twenty years may acquire citizenship by", "images": [], "options": {"A": "Nationlization", "B": "Naturalization", "C": "Registration", "D": "Marriage"}, "answer": "B", "explanation": "Naturalization is ​the process of making somebody who was not born in a particular country a citizen of that country.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>16", "subject": "Government", "year": "1995", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : REPUBLICAN", "question": "In a republican parliamentary system of government, the ceremonial Head of State is the", "images": [], "options": {"A": "Chief Justice", "B": "Prime Minister", "C": "President", "D": "Party Leader"}, "answer": "C", "explanation": "In a republican parliamentary system of government, the ceremonial Head of State is the President. A republican parliamentary system is a type of government in which the head of state is an elected or nominated president rather than a monarch, while the legislature (parliament) holds the supreme power. The president in such a system serves largely ceremonial duties, as the real power lies with the parliament.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>17", "subject": "Government", "year": "1995", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following is not a feature of capitalism?", "images": [], "options": {"A": "Free enterprise", "B": "Private ownership of capital", "C": "Minimal government intervention", "D": "Profit maximization"}, "answer": "A", "explanation": "Capitalism is not a free enterprise. This is the most appropriate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>18", "subject": "Government", "year": "1995", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "A representative government can be established through", "images": [], "options": {"A": "A general election", "B": "A military coup", "C": "An imposition", "D": "Espionage"}, "answer": "A", "explanation": "A representative government is a system where citizens elect representatives to make laws on their behalf. This is typically done through a general election where citizens vote for their preferred candidates. A military coup, imposition, and espionage are not democratic means of establishing a representative government.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1995>19", "subject": "Government", "year": "1995", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Delegated legislation is suitable for", "images": [], "options": {"A": "Relieving the parliarment of its work-load", "B": "Enthroning the rule of law", "C": "Ensuring the fusion of powers", "D": "Checking the executive arm of government"}, "answer": "A", "explanation": "Delegated legislation is a type of legislation that is passed on by the Parliament to a person or body under its authority. This is done to relieve the Parliament of its workload as it cannot possibly handle all the details of complex legislation. Therefore, the correct answer is 'Relieving the parliament of its work-load'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>20", "subject": "Government", "year": "1995", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "A necessary companion of the Rule of Law is", "images": [], "options": {"A": "A special military tribunal", "B": "The constant harassment of pressmen", "C": "The supermacy of the ordinary law", "D": "The trial of suspects in camera"}, "answer": "C", "explanation": "The Rule of Law is a principle that suggests that every individual, including the government, is subject to the law and that all are equal before the law. A necessary companion of the Rule of Law is the supremacy of the ordinary law, which means that no individual or government is above the law and everyone is subject to the same laws. Therefore, the correct answer is 'The supremacy of the ordinary law'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>21", "subject": "Government", "year": "1995", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "An appropriation bill is", "images": [], "options": {"A": "State boundary adjustment bill", "B": "A state creation bill", "C": "Private member's bill", "D": "A monetary bill"}, "answer": "D", "explanation": "An appropriation bill is a bill that authorizes the government to withdraw funds for use during the financial year.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>22", "subject": "Government", "year": "1995", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "A coalition government can be described as one which", "images": [], "options": {"A": "Is made up of more than one political party", "B": "Is formed by the political party that won the election", "C": "Can effectively defend the nation", "D": "Operates in a presidential system of government"}, "answer": "A", "explanation": "A coalition government is a form of government in which political parties cooperate, reducing the dominance of any one party within that coalition. The usual reason for this arrangement is that no party on its own can achieve a majority in the election. A coalition government might also be created in a time of national difficulty or crisis. Therefore, it is made up of more than one political party, hence option 1 is correct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>23", "subject": "Government", "year": "1995", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : YORUBA", "question": "One of the modern principles of government found in the traditional political system of Yoruba is that of", "images": [], "options": {"A": "The constitution", "B": "Checks and balances", "C": "Bicameralism", "D": "Multi-partism"}, "answer": "B", "explanation": "The traditional political system of the Yoruba people had a system of checks and balances. This was evident in the way power was distributed among the Oba (King), the council of chiefs, and the various societies and guilds. Each had its own sphere of influence and could check the excesses of the others. This is similar to the modern principle of checks and balances where power is distributed among the three arms of government - the executive, legislature, and judiciary - to prevent the abuse of power.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>24", "subject": "Government", "year": "1995", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : IGBO", "question": "The function of the age-group in the Igbo pre-colonial society was to", "images": [], "options": {"A": "Enforce laws and punish erring members", "B": "Make laws for the people when an Ofo died", "C": "Give judgement on land tenure matters", "D": "Make sure that the religion of the people was observed"}, "answer": "A", "explanation": "In the Igbo pre-colonial society, the age-grade system was a significant institution. One of its primary functions was to enforce laws and punish erring members. The age-grade system was a form of social organization where individuals of the same age range formed a group with specific roles and responsibilities. These responsibilities included maintaining law and order, executing communal projects, and defending the community.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>25", "subject": "Government", "year": "1995", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI~~PRE-COLONIAL POLITICAL SYSTEM : IGBO~~PRE-COLONIAL POLITICAL SYSTEM : YORUBA", "question": "An important feature of the traditional government in West Africa was the Council of", "images": [], "options": {"A": "Farmers", "B": "Family Heads", "C": "Elders", "D": "Ministers"}, "answer": "C", "explanation": "In traditional West African societies, the Council of Elders was a significant feature. The Council of Elders was a group of respected individuals, usually older men, who had a wealth of experience and wisdom. They were responsible for making important decisions for the community, including settling disputes, making laws, and overseeing ceremonies. Therefore, the correct answer is 'Elders'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>26", "subject": "Government", "year": "1995", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "A political party is mainly interested in", "images": [], "options": {"A": "Contesting elections to gain power", "B": "Opposing the governmnet in power", "C": "Educating the public", "D": "Formulating governmnet policies"}, "answer": "A", "explanation": "A political party is a group of people who share similar political views and work together to influence government policy and governance. The primary goal of a political party is to gain power by winning elections. This is because it is only when they are in power that they can implement their policies and ideas. Therefore, the correct answer is 'Contesting elections to gain power'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1995>27", "subject": "Government", "year": "1995", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS", "question": "The most important merit of a multi-system is that it", "images": [], "options": {"A": "Guarantees the viability of many parties", "B": "Disallows smaller political parties from gaining political power", "C": "Reduces oppression within the various parties", "D": "Gives representation to the widest shades of opinion and interest"}, "answer": "D", "explanation": "A multi-party system is a system in which multiple political parties across the political spectrum run for national election, and all have the capacity to gain control of government offices, separately or in coalition. The most important merit of a multi-party system is that it gives representation to the widest shades of opinion and interest. This is because in a multi-party system, different parties can represent different ideologies and interests, thus ensuring that a wide range of views are represented in the political process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>28", "subject": "Government", "year": "1995", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "A pressure group can be defined as a", "images": [], "options": {"A": "Large group interested in seizing polical power", "B": "Group organized around an interest for governmental action", "C": "Small group interested in sharing governmental power", "D": "Sophisticated group interested in balkanization"}, "answer": "B", "explanation": "A pressure group is a group of people who are organized and actively try to influence public policy and especially government legislation about a specific issue or cause. They do not aim to become a government but they are interested in influencing governmental actions. Therefore, a pressure group can be defined as a group organized around an interest for governmental action.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1995>29", "subject": "Government", "year": "1995", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "An election in which people vote for issues of public policy rather than candidates is known as a", "images": [], "options": {"A": "Mini election", "B": "General election", "C": "Bye-election", "D": "Referendum"}, "answer": "D", "explanation": "A referendum is a type of election where people vote on a single political question that has been referred to them for a direct decision. It is a form of direct democracy where citizens are given the power to decide on specific policy issues. The other options refer to different types of elections where candidates are voted for, not policy issues.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>30", "subject": "Government", "year": "1995", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Where no absolute majority is obtained in the first round of elections, the most viable option is the", "images": [], "options": {"A": "Simple majority", "B": "Proportional representation", "C": "Second ballot", "D": "Bye- election"}, "answer": "C", "explanation": "Second ballot refers to an electoral procedure where no candidate emerges as a clear winner in a first ballot, candidates at the bottom of the poll are eliminated and another ballot is held among the remaining candidates. Main objective of the Second Ballot system is to increase the chances of a candidate being elected on an absolute majority of the vote.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1995>31", "subject": "Government", "year": "1995", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : ELECTORAL MANAGEMENT BODY", "question": "Which of the following is a function of Electoral Commisions?", "images": [], "options": {"A": "Arbitrating among political parties", "B": "Arranging and conducting elections", "C": "Organizing political parties", "D": "Supporting political parties"}, "answer": "B", "explanation": "The function of Electoral Commissions is to arrange and conduct elections. They are responsible for ensuring that elections are free, fair, and transparent. They do not arbitrate among political parties, organize political parties, or support political parties. Their role is purely administrative and regulatory.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1995>32", "subject": "Government", "year": "1995", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI", "question": "The indirect Rule system succeeded in Hausa/Fulani society because the", "images": [], "options": {"A": "Society had only one religion", "B": "People recevied quranic education", "C": "People were peaceful", "D": "Existing administration favoured the system"}, "answer": "D", "explanation": "The indirect rule system succeeded in the Hausa/Fulani society because the existing administration favoured the system. The British colonial administration found it easier to govern through the existing traditional structures, which were already accepted and respected by the people. The fact that the society had only one religion, people received Quranic education, or people were peaceful were not the primary reasons for the success of the indirect rule system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>33", "subject": "Government", "year": "1995", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "The policy of Association was adopted by the", "images": [], "options": {"A": "British to replace their policy of Indirect Rule", "B": "French to replace their policy of Assimilation", "C": "British on their arrival in West Africa", "D": "French on their departure from West Africa"}, "answer": "B", "explanation": "The Policy of Association was the second policy of the French Colonial Administration which recognized and preserved the identity, traditions, institutions, religions, customs, and way of life of the people within the French empire. This policy was emphasized by the French between 1920-1945.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>34", "subject": "Government", "year": "1995", "type": "Objective", "topic": "NATIONALISM : NATIONALISM: MEANING, FACTORS AND EFFECTS.", "question": "Nationalism in Africa eventually led to", "images": [], "options": {"A": "A rapid political awareness among the colonialists", "B": "The alignment of the new states", "C": "De-colonization", "D": "The formation of a continental army"}, "answer": "C", "explanation": "Nationalism in Africa eventually led to de-colonization. Nationalism is a political ideology that involves a strong identification of a group of individuals with a nation. In the context of Africa, nationalism was a significant force for the end of colonial rule and the achievement of independence by African nations. It led to the rise of anti-colonial political movements that sought and eventually succeeded in gaining independence for their nations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>35", "subject": "Government", "year": "1995", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "One major achievement of the Richards Constitution of Nigeria was that it", "images": [], "options": {"A": "United the North and South under a single Legislature", "B": "Introduced the elective principle", "C": "Provided for official African majority in the Legislature", "D": "Made more Africans member of the Executive council"}, "answer": "A", "explanation": "Richards constitution of 1946 solved the problem of legislating for the North by proclamation. A central legislature was created in which all the regions were being represented. The constitution also created regional assemblies in the Northern, Western and Eastern regions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>36", "subject": "Government", "year": "1995", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "The 1954 Constitution of Nigeria made the country a true Federation because it provided for", "images": [], "options": {"A": "The abolition of representation of white officials", "B": "The election of all members of parliament", "C": "A division of functions between the centre and the regions", "D": "The post of a Prime Minister at the centre"}, "answer": "C", "explanation": "The 1954 Constitution of Nigeria made the country a true Federation by providing for a division of functions between the centre and the regions. This meant that each region had its own government and was responsible for certain aspects of governance, while the central government was responsible for matters of national importance. This is a key feature of a federal system of government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>37", "subject": "Government", "year": "1995", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : POST- INDEPENDENCE CONSTITUTIONS", "question": "The Chicks Commission in Nigeria was up to look into the issue of", "images": [], "options": {"A": "Revenue allocation", "B": "Minority groups", "C": "State creation", "D": "Constitutional amendment"}, "answer": "A", "explanation": "The Chicks Commission was set up in Nigeria to look into the issue of Revenue allocation. The commission was established in 1953 by the British colonial government to examine and recommend ways of sharing revenue between the regional and central government in Nigeria.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1995>38", "subject": "Government", "year": "1995", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "The decision to separate Lagos from the Western Region and make it a neutral Federal territory was taken at the", "images": [], "options": {"A": "1950 general conference", "B": "1953 constitutional conference", "C": "1954 constitutional conference", "D": "1957 constitutional conference"}, "answer": "B", "explanation": "The conference which sat between July 30 and August 22, 1953, reached the agreement that Lagos should be separated from the Western region and made a neutral federal territory.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1995>39", "subject": "Government", "year": "1995", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "Which of the following was not required of  Presidential candidate for the 1979 election in Nigeria? He must", "images": [], "options": {"A": "Be a Nigerian citizen by birth", "B": "Be an indigene of one of the northern states", "C": "Be sponsored by a registered political party", "D": "Have paid his income tax for three years as and when due"}, "answer": "B", "explanation": "The 1979 constitution of Nigeria did not require a presidential candidate to be an indigene of one of the northern states. The requirements were: he must be a Nigerian citizen by birth, be sponsored by a registered political party, and have paid his income tax for three years as and when due.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>40", "subject": "Government", "year": "1995", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY~~STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL~~STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : CONFEDERAL~~STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET", "question": "Between 1960 and 1980, Nigeria experienced all the following systems of government except", "images": [], "options": {"A": "Unitary", "B": "Federal", "C": "Confederal", "D": "Parliamentary"}, "answer": "C", "explanation": "Between 1960 and 1980, Nigeria experienced Unitary, Federal, and Parliamentary systems of government. However, it did not experience a Confederal system of government. In a confederal system, the constituent states retain a large degree of independence and sovereignty, with the central government only coordinating and not controlling the states.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1995>41", "subject": "Government", "year": "1995", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "The first Head of State and Head of Government in Nigeria was", "images": [], "options": {"A": "Lord Frederich Lugard", "B": "Alhaji Abubakar Tafawa Balewa", "C": "Alhaji Shehu Shagari", "D": "Gen. J.T.U. Aguiyi-Ironsi"}, "answer": "C", "explanation": "Alhaji Shehu Shagari was the first executive president of Nigeria.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>42", "subject": "Government", "year": "1995", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : POST- INDEPENDENCE CONSTITUTIONS", "question": "The functions of the Governor-General in Nigeria after independence did not include", "images": [], "options": {"A": "The dismissal of Ministers", "B": "Ceremonial functions", "C": "The appointment of the Prime Minister", "D": "The granting of pardon"}, "answer": "C", "explanation": "The governor general did not appoint the prime minister.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1995>43", "subject": "Government", "year": "1995", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "Which of the following was the first political party in Nigeria? The", "images": [], "options": {"A": "Action Group (AG)", "B": "Northern People's congress (NPC)", "C": "National Council for Nigeria and the Camerouns (NCNC)", "D": "Nigerian National Democratic Party (NNDP)"}, "answer": "D", "explanation": "The Nigerian National Democratic Party (NNDP) was the first political party in Nigeria. It was formed in 1923 by Herbert Macaulay.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>44", "subject": "Government", "year": "1995", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "Which of the following is not true of a federal system of government?", "images": [], "options": {"A": "There are three legislature lists", "B": "Powers are not constitutionally shared", "C": "There are component units", "D": "The constitution is written and rigid"}, "answer": "B", "explanation": "In a federal system of government, powers are constitutionally shared between the central government and the component units. This is one of the key features of a federal system. Therefore, the statement 'Powers are not constitutionally shared' is not true of a federal system of government.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1995>45", "subject": "Government", "year": "1995", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "The main criticism against pre-independence political parties in Nigeria was that they", "images": [], "options": {"A": "Were not national outlook", "B": "Had no manifestos", "C": "Did not contribute to political development", "D": "Did not educate the electorate"}, "answer": "A", "explanation": "The main criticism against pre-independence political parties in Nigeria was that they were not national in outlook. This means that they were often based on regional or ethnic lines, rather than representing the interests of the entire country. This led to a lack of unity and cohesion in the political landscape, which in turn hindered the development of a strong and stable national identity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>46", "subject": "Government", "year": "1995", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : ACHIEVEMENTS AND FAILURES", "question": "Which of the following did not generate political crises in Nigeria? The", "images": [], "options": {"A": "Motion for self government in 1956 by Enahoro", "B": "Adoption of Abuja as the new Federal Capital", "C": "Head count of 1962", "D": "1964 General Elections"}, "answer": "B", "explanation": "The adoption of Abuja as the new Federal Capital did not generate political crises in Nigeria. The other options, such as the motion for self government in 1956 by Enahoro, the head count of 1962, and the 1964 General Elections, all led to significant political crises due to disagreements and conflicts between different political groups and regions. However, the decision to move the capital from Lagos to Abuja was largely accepted and did not lead to any major political conflicts.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1995>47", "subject": "Government", "year": "1995", "type": "Objective", "topic": "MILITARY RULE : VARIOUS MILITARY REGIMES", "question": "The major policy of General Gowon's administration immediately after the Nigerian civil war was", "images": [], "options": {"A": "Restructuring ,Reoccurrence and Reconciliation", "B": "National Economic Restructuring", "C": "Reconstruction Reconciliation and Rehabilitation", "D": "Structural Adjustment Programme"}, "answer": "C", "explanation": "Gowon subsequently declared his famous \"no victor, no vanquished\" speech, and followed it up with an amnesty for the majority of those who had participated in the Biafran uprising, as well as a program of \"Reconciliation, Reconstruction, and Rehabilitation\"", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1995>48", "subject": "Government", "year": "1995", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : ACHIEVEMENTS AND FAILURES", "question": "Which of the following was not an election issue in Nigeria during the Second Republic ?", "images": [], "options": {"A": "Change of the colour of Naira", "B": "Creation of more local governments", "C": "Provision of free education", "D": "Provision of more houses"}, "answer": "A", "explanation": "During the Second Republic in Nigeria, the change of the colour of Naira was not an election issue. The issues that were prominent during the elections were related to socio-economic and political matters such as creation of more local governments, provision of free education and provision of more houses.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>49", "subject": "Government", "year": "1995", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "Which of the following countries was not involved in the peace-keeping effort in Liberia ?", "images": [], "options": {"A": "Ghana", "B": "Nigeria", "C": "Sierra Leone", "D": "Cameroun"}, "answer": "D", "explanation": "The peacekeeping effort in Liberia was led by the Economic Community of West African States (ECOWAS) under the banner of the ECOWAS Monitoring Group (ECOMOG). The main contributors to this force were Nigeria, Ghana, and Sierra Leone. Cameroun was not involved in the peacekeeping effort in Liberia.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>50", "subject": "Government", "year": "1995", "type": "Objective", "topic": "MILITARY RULE : VARIOUS MILITARY REGIMES", "question": "The first military Head of State in Nigeria was General", "images": [], "options": {"A": "Muhammadu Buhari", "B": "Olusegun Obasanjo", "C": "Aguiyi-lronsi", "D": "Yakubu Gowon"}, "answer": "C", "explanation": "The first military Head of State in Nigeria was Major General Johnson Thomas Umunnakwe Aguiyi-Ironsi. He took over power after the 1966 coup d'etat that overthrew the first republic. The other options listed were also military heads of state but they came into power after Aguiyi-Ironsi.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1995>51", "subject": "Government", "year": "1995", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "Which of the following is a feature of public corporation ? It", "images": [], "options": {"A": "Provides social services and amenities", "B": "Has a Director -General as head of General Administration", "C": "Is set up to make profit", "D": "Has a minister as the administrative head"}, "answer": "A", "explanation": "A public corporation is a company that is owned by the government, and its main purpose is to provide services to the public. It is not primarily set up to make profit, but to provide social services and amenities. Therefore, the correct answer is option 1.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1995>52", "subject": "Government", "year": "1995", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "One of the problem facing local government in Nigeria is the", "images": [], "options": {"A": "Withdrawal of grants by the central governmnent", "B": "Interference from the central government", "C": "Inclusion of traditional rulers in the local government council", "D": "Lack of personnel"}, "answer": "B", "explanation": "Local governments in Nigeria often face interference from the central government. This interference can take many forms, including the central government dictating policies and decisions, or exerting control over local government finances. Therefore, the correct answer is option 2.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>53", "subject": "Government", "year": "1995", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "Local governments are essential because they", "images": [], "options": {"A": "Encouage division in the country", "B": "Check abuse of office by governmnet functionaries", "C": "Implement government policies at the local level", "D": "Make laws for the nation"}, "answer": "C", "explanation": "Local governments are essential because they implement government policies at the local level. They are the closest tier of government to the people and they play a key role in the implementation of government policies at the grassroots level. They do not make laws for the nation, that is the role of the legislative arm of government at the national level. They also do not encourage division in the country or check abuse of office by government functionaries, these are not their primary roles.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>54", "subject": "Government", "year": "1995", "type": "Objective", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "The goal which a state aspires to achieve in its relation with other states may be referred to as", "images": [], "options": {"A": "Diplomatic interest", "B": "National policy", "C": "National interest", "D": "Political independence"}, "answer": "C", "explanation": "National Interests can as defined as the claims, objectives, goals, demands and interests which a nation always tries to preserve, protect, defend and secure in relation with other states.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>55", "subject": "Government", "year": "1995", "type": "Objective", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "Nigeria's foreign policy came into the limelight at independence because", "images": [], "options": {"A": "Nigeria did not know any other country before then", "B": "Only at independence do States proclaim their foreign policy principles", "C": "Her internal policies were harsh", "D": "Nigeria was self-sufficient before independence"}, "answer": "B", "explanation": "At independence, states usually proclaim their foreign policy principles. This is because they are now sovereign and can make decisions that affect their relations with other countries. Foreign policy is a strategy or approach chosen by national governments to achieve their international goals. Nigeria's foreign policy came into the limelight at independence because it was at this point that Nigeria began to interact with other nations as a sovereign state, hence the need to establish its foreign policy principles.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>56", "subject": "Government", "year": "1995", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "Which of the following has the Organization of African Unity (OAU) failed to achieve?", "images": [], "options": {"A": "Setting up an African High Command", "B": "Setting border disputes in Africa", "C": "Giving assistance to liberation movernmnets in African", "D": "Contributing to the economic and social development of member states"}, "answer": "A", "explanation": "The Organization of African Unity (OAU), now the African Union (AU), has failed to achieve the setting up of an African High Command. The African High Command was proposed as a collective security arrangement to provide for the defense of any African state under attack. However, due to various reasons such as national sovereignty concerns and lack of consensus among member states, the idea has not been realized.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1995>57", "subject": "Government", "year": "1995", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "ECOWAS was set up purely for", "images": [], "options": {"A": "Political advantages", "B": "Social adavantages", "C": "Economic adavantages", "D": "Historical advantages"}, "answer": "C", "explanation": "The Economic Community of West African States (ECOWAS) was established to promote economic integration across countries in the West African region. Therefore, it was set up for economic advantages.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>58", "subject": "Government", "year": "1995", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "The resolutions and programmes of the OAU are executed by the", "images": [], "options": {"A": "Secretariat", "B": "Commission of Mediation Councilation and Arbitration", "C": "Head of Government of each member state", "D": "Council of Ministers"}, "answer": "C", "explanation": "They form the executive arm of the organization. This is the accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1995>59", "subject": "Government", "year": "1995", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "All the following organs/agencies of the United Nations Organization have their headquarters situated in New York except the", "images": [], "options": {"A": "United Nations Development Projects (UNDP)", "B": "World Health Organization (WHO)", "C": "International Court of Justice (ICJ)", "D": "United Nations Educational, Seientific and Cutural Organization (UNESCO)"}, "answer": "C", "explanation": "The International Court of Justice (ICJ) is not headquartered in New York, but in The Hague, Netherlands. The ICJ is the principal judicial organ of the United Nations (UN). It settles legal disputes between member states and gives advisory opinions to authorized UN organs and specialized agencies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1995>60", "subject": "Government", "year": "1995", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "One of the objective of the United Nations Organization (UNO) is to", "images": [], "options": {"A": "Develop the African States", "B": "Maintain International peace and security", "C": "Ensure that workers all over the world are paid handsome wages and salaries", "D": "Provide ammunition for any warring states"}, "answer": "B", "explanation": "One of the main objectives of the United Nations Organization (UNO) is to maintain international peace and security. This is stated in the UN Charter, which is the foundational treaty of the United Nations. The UN does this by working to prevent conflict; helping parties in conflict make peace; peacekeeping; and creating the conditions to allow peace to hold and flourish.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1996>1", "subject": "Government", "year": "1996", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "The functions of government include all the following except the", "images": [], "options": {"A": "Maintenance of peace and order", "B": "Maintenance of the country's constitution", "C": "Protection of citizens from malicious attacks", "D": "Provision of free medical services"}, "answer": "D", "explanation": "The functions of government include maintenance of peace and order, maintenance of the country's constitution, and protection of citizens from malicious attacks. However, the provision of free medical services is not a mandatory function of the government. It is a policy decision that varies from one country to another and is not a universally accepted function of government.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1996>2", "subject": "Government", "year": "1996", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Delegated legislature refers to the", "images": [], "options": {"A": "Power of government agencise to make laws", "B": "Laws made by the legislature", "C": "Transfer of law making power to the exective and judiciary arms", "D": "Laws made by government agencies as authorised by the legislature"}, "answer": "D", "explanation": "Delegated Legislation is laws delegated to another person to make it authoritative, enforce and interprete such laws.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>3", "subject": "Government", "year": "1996", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The concept of sovereignty was popularised by", "images": [], "options": {"A": "J.J Rousseau", "B": "Jean Bodin", "C": "C.L Montesquieu", "D": "John Locke"}, "answer": "B", "explanation": "The concept of sovereignty was popularised by Jean Bodin. Sovereignty is the full right and power of a governing body over itself, without any interference from outside sources or bodies. In political theory, sovereignty is a substantive term designating supreme legitimate authority over some polity. Jean Bodin was a French jurist and political philosopher, member of the Parlement of Paris and professor of law in Toulouse. He is best known for his theory of sovereignty.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>4", "subject": "Government", "year": "1996", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A system of government which allowed individual citizens to control the means of production and distribution is called", "images": [], "options": {"A": "Capitalism", "B": "Fascism", "C": "Feudalism", "D": "Communism"}, "answer": "A", "explanation": "Capitalism is an economic system based on the private ownership of the means of production and their operation for profit.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1996>5", "subject": "Government", "year": "1996", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Political authority is the", "images": [], "options": {"A": "Consent and recognition of the legitimacy of the government by the governed", "B": "Power of the governmnet to impose its will on the people", "C": "Ability of the people to reject a bad government", "D": "Power of the government derived from the constitution"}, "answer": "A", "explanation": "Authority is the legitimacy of government rule. This is the most appropriate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>6", "subject": "Government", "year": "1996", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "In which of the following political system is the Rule of Law likely to be most enhanced?", "images": [], "options": {"A": "Military", "B": "Parliamentary", "C": "Fascist", "D": "Monarchical"}, "answer": "B", "explanation": "The Rule of Law is most likely to be enhanced in a Parliamentary system. This is because in a Parliamentary system, the government is accountable to the people and there are checks and balances to ensure that the law is fairly applied and enforced.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1996>7", "subject": "Government", "year": "1996", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "An essential feature of democracy is", "images": [], "options": {"A": "Election by all adults", "B": "Government by few wealthy men", "C": "Participation by everyone in the economic sector", "D": "Majority rule"}, "answer": "D", "explanation": "Democracy respects majority rule. This is the most appropriate answer", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1996>8", "subject": "Government", "year": "1996", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Who is regarded as the father of Communism?", "images": [], "options": {"A": "Karl Marx", "B": "V.I Lenin", "C": "Benito Mussolini", "D": "A.V Dicey"}, "answer": "A", "explanation": "The Father of Communism, Karl Marx, a German philosopher and economist, proposed this new ideology in his Communist Manifesto, which he wrote with Friedrich Engel.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>9", "subject": "Government", "year": "1996", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY", "question": "Which of the following is an important feature of a unitary constitution?", "images": [], "options": {"A": "Revolutionary power", "B": "Concentration of power", "C": "Deconcentration of power", "D": "Enfranchisement of power"}, "answer": "B", "explanation": "A unitary constitution is characterized by the concentration of power in a central authority. In a unitary system, the central government holds most of the power, although it may delegate authority to local governments. The central government has the ability to retract these powers at its discretion. Therefore, the correct answer is 'Concentration of power'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>10", "subject": "Government", "year": "1996", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "A major reason for enshrining fundamental human rights in the constitution is to", "images": [], "options": {"A": "Make the constitution flexible", "B": "Protect the rights of individuals in the society", "C": "Protect the rights of office holders", "D": "Prevent military intervention"}, "answer": "B", "explanation": "Fundamental human rights are enshrined in the constitution to protect the rights of individuals in the society. These rights include the right to life, freedom of speech, freedom of assembly, and others. They are included in the constitution to ensure that every individual, regardless of their status, is treated fairly and equally under the law. Therefore, the correct answer is 'Protect the rights of individuals in the society'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1996>11", "subject": "Government", "year": "1996", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The security and ratification of major executive decisions by the legislature are an application of", "images": [], "options": {"A": "The rule of law", "B": "Checks and balances", "C": "Delegated legislation", "D": "Fusion of powers"}, "answer": "B", "explanation": "Checks and balances refer to the separation of power to avoid one entity or body wielding too much power.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>12", "subject": "Government", "year": "1996", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : CONFEDERAL", "question": "Which of the following is the disadvantages of confederation?", "images": [], "options": {"A": "The central governmnet is too far from the people", "B": "The central authority is vested with too much power", "C": "The primary loyality of the citizens is to the central government", "D": "It encourages secession"}, "answer": "D", "explanation": "One of the disadvantages of a confederation is that it encourages secession. In a confederation, the central authority is weak while the component units are strong. This can lead to a situation where the component units may want to secede from the confederation if their interests are not being met.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1996>13", "subject": "Government", "year": "1996", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET", "question": "A major feature of the parliamentary system of government is that", "images": [], "options": {"A": "Members of the executive are also members of the legfislature", "B": "The head of state is also the head of government", "C": "There is clear-cut separation of powers", "D": "The constitution cannot be amended"}, "answer": "A", "explanation": "In a parliamentary system of government, the executive is derived from the legislature and remains responsible to it. This means that members of the executive are also members of the legislature. This is a key feature of the parliamentary system of government. The head of state is not necessarily the head of government, there is not a clear-cut separation of powers, and the constitution can be amended.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>14", "subject": "Government", "year": "1996", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "A constitution can be best be discribed as", "images": [], "options": {"A": "The complied laws of a state", "B": "A general book of laws", "C": "The fundamental laws to guide the government of a state", "D": "A detailed code of conduct for politicians"}, "answer": "C", "explanation": "A constitution is the rule book for a state. It sets out the fundamental principles by which the state is governed.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1996>15", "subject": "Government", "year": "1996", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The process of distribution of powers among authorities distinct from the central government is known as", "images": [], "options": {"A": "Centralization", "B": "Delegation", "C": "Deconcentration", "D": "Decentralization"}, "answer": "D", "explanation": "Decentralization transfers authority and responsibility of major government functions from central to sub-national governments.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>16", "subject": "Government", "year": "1996", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "Constitutionalism denotes that", "images": [], "options": {"A": "The Constitution is largely made up of conventions", "B": "The provision of the constitution is strictly adhered to", "C": "The constitution is not easy to amend", "D": "There is a constitutional Head of State"}, "answer": "B", "explanation": "Constitutionalism is the philosophy characterized by government authority being constrained by a constitution, supported by the people.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>17", "subject": "Government", "year": "1996", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Franchise means the", "images": [], "options": {"A": "Abilty to conduct elections", "B": "Body of principles governing the conduct of an election", "C": "Right to partcipate in an election", "D": "Right granted to French citizens to vote"}, "answer": "C", "explanation": "Franchise in the context of government and politics refers to the right to vote. It is the privilege or right granted to qualifying citizens to vote in public elections. Therefore, the correct answer is 'Right to participate in an election'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1996>18", "subject": "Government", "year": "1996", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "Question time in the legislature affords members the opportunity to", "images": [], "options": {"A": "Raise important questions outside the agenda", "B": "Challenge court decisions", "C": "Execute government policies", "D": "Ask more questions"}, "answer": "A", "explanation": "Question time in the legislature is a period during a parliamentary sitting when members of the parliament ask questions of government ministers (including the prime minister), which they are obliged to answer. It is an opportunity to hold the government accountable for its actions and policies. Therefore, the correct answer is 'Raise important questions outside the agenda'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>19", "subject": "Government", "year": "1996", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "Public opinion can be best be defined as", "images": [], "options": {"A": "One man's view on public issues", "B": "Sentiments expressed on public policies", "C": "The sum total of popular views on public policies", "D": "The view of the rich expressed on public affairs"}, "answer": "C", "explanation": "Public opinion is the collective opinion on a specific topic or voting intention relevant to society.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>20", "subject": "Government", "year": "1996", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Which of the following best explains the term manifesto? The", "images": [], "options": {"A": "Constitution of the political party", "B": "Authority to form a political party", "C": "Proposed programme of a political party", "D": "Symbol of the ruling political party"}, "answer": "C", "explanation": "A manifesto is a published declaration of the intentions, motives, or views of the issuer, be it an individual, group, political party or government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>21", "subject": "Government", "year": "1996", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Universal adult suffrage is very popular today because it", "images": [], "options": {"A": "Allows the establishment of military regimes", "B": "Allows for equal political representation", "C": "Allows for greater political participation", "D": "Ensures equal performance of all political parties"}, "answer": "C", "explanation": "Universal adult franchise ensures that all adult citizens have the right to vote and elect their representative irrespective of their gender, wealth, caste etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1996>22", "subject": "Government", "year": "1996", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "The purpose of an election is to", "images": [], "options": {"A": "Allow people to participate in choosing their leaders", "B": "Provide social amenities for the electorate", "C": "Declare election results", "D": "Give people political education"}, "answer": "A", "explanation": "The purpose of an election is to allow people to participate in choosing their leaders. Elections are a fundamental aspect of democracy and they provide citizens with the opportunity to express their political preferences by voting for the candidate or party that they believe will best represent their interests.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1996>23", "subject": "Government", "year": "1996", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Which of the following is not a method of election?", "images": [], "options": {"A": "Simple majority", "B": "Proportional representation", "C": "Single-member constituency", "D": "Plurality system"}, "answer": "C", "explanation": "The term 'Single-member constituency' is not a method of election but rather a type of electoral division or constituency. In a single-member constituency, only one representative is elected to a legislature or other public office. The methods of election include Simple majority, Proportional representation, and Plurality system.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1996>24", "subject": "Government", "year": "1996", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "How many Nigerians were elected into Legislative Council when the elective principle was applied in 1923?", "images": [], "options": {"A": "Two", "B": "Six", "C": "Four", "D": "Five"}, "answer": "B", "explanation": "Governor Clifford appointed 13 unofficial members to the Legislative Council, of which seven were Europeans and six Africans.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>25", "subject": "Government", "year": "1996", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "One of the advantages of the simple majority system of voting is that it", "images": [], "options": {"A": "Discourages election malpractices", "B": "Gives an accurate result of an election", "C": "Is very suitable to large countries", "D": "Is simple and cheap to operate"}, "answer": "D", "explanation": "The simple majority system of voting, also known as first-past-the-post, is a system where the candidate with the most votes wins. It doesn't necessarily discourage election malpractices or give an accurate result of an election. It's not particularly suitable for large countries as it can lead to a lack of representation for minority groups. However, it is simple and cheap to operate as it requires less administrative effort compared to other voting systems.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1996>26", "subject": "Government", "year": "1996", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "The geographical units into which a country is divided for the purpose of elections are called", "images": [], "options": {"A": "Constituencies", "B": "Polling areas", "C": "Local government areas", "D": "States"}, "answer": "A", "explanation": "In the context of elections, a country is divided into geographical units known as constituencies. Each constituency elects one representative to the parliament or assembly. Polling areas, local government areas, and states are also divisions within a country, but they are not specifically used for the purpose of elections.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1996>27", "subject": "Government", "year": "1996", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "Local authorities impose rates because", "images": [], "options": {"A": "The Government wants the rich to become richer", "B": "The poor are expected to finance political parties", "C": "Of the need to provide fund for public corporations", "D": "Of the need to provide essential amenities for the citizens"}, "answer": "D", "explanation": "Local authorities impose rates primarily to generate revenue for the provision of essential amenities and services for the citizens. These amenities include public schools, hospitals, roads, parks, waste management, and other public utilities. This is not related to making the rich richer or financing political parties, and while some of the funds may go to public corporations, the primary purpose is to provide for the citizens.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>28", "subject": "Government", "year": "1996", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "Local government is described as grassroots government because", "images": [], "options": {"A": "It is the nearest government to the people", "B": "Its headquarters is located in the villages", "C": "All the leaders are from the villages", "D": "It is the first tier of government"}, "answer": "A", "explanation": "Local government is often referred to as 'grassroots government' because it is the level of government that is closest to the people, both geographically and in terms of direct impact on their daily lives. It is responsible for local affairs and services, and its officials are often more accessible to the public than those at higher levels of government. The location of its headquarters or the origin of its leaders does not define it as a grassroots government, and while it is often the first tier of government, this is not the reason it is referred to as such.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1996>29", "subject": "Government", "year": "1996", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "Which of the following is true of a public corporation? It is", "images": [], "options": {"A": "Set up to make profit for the government", "B": "To provide essential service for the people at a low cost", "C": "Owned by the governor of a state", "D": "Established by a bye-law"}, "answer": "B", "explanation": "A public corporation is a company that is owned by the government, and its main purpose is to provide essential services to the public at a low cost. It is not primarily set up to make profit for the government, but to serve the public interest. Therefore, the correct answer is 'To provide essential service for the people at a low cost'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1996>30", "subject": "Government", "year": "1996", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI", "question": "In the Hausa pre-colonial political system, sovereignty was located in the", "images": [], "options": {"A": "Quadi", "B": "Emir", "C": "Waziri", "D": "Madawaki"}, "answer": "B", "explanation": "In the Hausa pre-colonial political system, sovereignty was located in the Emir. The Emir was the supreme ruler and had the final say in all matters. The Quadi, Waziri, and Madawaki were all important figures in the political system, but they did not hold sovereignty. Therefore, the correct answer is 'Emir'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1996>31", "subject": "Government", "year": "1996", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Which of the following was the most senior official under the British colonial administration? The", "images": [], "options": {"A": "District Officer", "B": "Lieutenant Governor", "C": "President", "D": "Governor"}, "answer": "D", "explanation": "The Governor was the most senior official under the British colonial administration. The Governor was the representative of the British Crown in a colony and had executive, legislative, and judicial powers. The Lieutenant Governor, District Officer, and President were all subordinate to the Governor.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>32", "subject": "Government", "year": "1996", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "A major objection to the Indirect Rule system was", "images": [], "options": {"A": "Economy in administration", "B": "Administration through illitrate heads", "C": "The involvement of many Africans in administration", "D": "The control of territories by the colonial secretary"}, "answer": "B", "explanation": "One of the major objections to the Indirect Rule system was the administration through illiterate heads. Indirect Rule was a system of governance used by the British and French to control parts of their colonial empires, particularly in Africa and Asia, which relied on indigenous chiefs and rulers to govern their people according to local customs and traditions. However, many of these local leaders were illiterate and not well-versed in modern methods of governance, which led to inefficiencies and injustices in the administration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>33", "subject": "Government", "year": "1996", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "The development of nationalist activities was more rapid in British West Africa than in French West Africa because the", "images": [], "options": {"A": "French West Africans were not interested in having self-government", "B": "French administerative policies did not allow for political agitation", "C": "British were no longer interested in governing their acquired territories", "D": "British did not have a standing army in West Afric, unlike their French counterparts"}, "answer": "B", "explanation": "The development of nationalist activities was more rapid in British West Africa than in French West Africa mainly because the French administrative policies were more restrictive and did not allow for political agitation. The French colonial policy was based on the concept of assimilation, where the colonies were considered as an extension of France and were expected to adopt French culture and language. This policy did not encourage the development of local political institutions and thus, hindered the growth of nationalist activities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>34", "subject": "Government", "year": "1996", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "The French policy of assimilation was based on the idea that the African culture was", "images": [], "options": {"A": "Expensive", "B": "Unwritten", "C": "Inferior", "D": "Elaborate"}, "answer": "C", "explanation": "The French policy of assimilation was based on the idea that the African culture was inferior. The policy aimed at making the colonies an extension of France by encouraging the locals to adopt French culture, language, and law. The underlying assumption was that French culture was superior and that the Africans would benefit from adopting it. This is why the policy was seen as a form of cultural imperialism.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>35", "subject": "Government", "year": "1996", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "The general strike of 1954 in Nigeria gave force to the", "images": [], "options": {"A": "Formation of the Commonwealth", "B": "Introduction of the Green Revolution", "C": "Formation of the United Nations Organization (UNO)", "D": "Demands of the nationalist movement"}, "answer": "D", "explanation": "The general strike of 1954 in Nigeria was a significant event in the country's struggle for independence. It was a nationwide strike by Nigerian workers demanding better working conditions and higher wages. This strike gave force to the demands of the nationalist movement, which was pushing for Nigeria's independence from British colonial rule. Therefore, the correct answer is 'Demands of the nationalist movement'. The other options are not related to the general strike of 1954 in Nigeria.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>36", "subject": "Government", "year": "1996", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Which of the following best describes the position of the traditional rulers during the colonial period? They", "images": [], "options": {"A": "Were directly involved in government", "B": "Made laws for the people", "C": "Were part of the executive arm of government", "D": "Served as a link between the people and the government"}, "answer": "D", "explanation": "During the colonial period, traditional rulers in Nigeria served as a link between the people and the government. They were not directly involved in government, did not make laws for the people, and were not part of the executive arm of government. Instead, they served as intermediaries, conveying the wishes and concerns of the people to the colonial government and vice versa. Therefore, the correct answer is 'Served as a link between the people and the government'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>37", "subject": "Government", "year": "1996", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "A major result of the Clifford Constitution of 1922 in Nigeria was the", "images": [], "options": {"A": "Introduction of party policies", "B": "Increase in nationalist activities throughout West Africa", "C": "Establishment of the university of Nigeria, Nsukka", "D": "Adoption of the fedetal system of government"}, "answer": "A", "explanation": "The constitution introduced elective principles. This is the most appropriate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>38", "subject": "Government", "year": "1996", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "The 1954 Lyttleton Constitution of Nigeria created the office of the", "images": [], "options": {"A": "Regional Premier", "B": "Prime Minister", "C": "Speaker of the House", "D": "Governor"}, "answer": "C", "explanation": "It established the offices of the speaker and deputy speaker.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>39", "subject": "Government", "year": "1996", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "To have have an orderly society a state needs", "images": [], "options": {"A": "President", "B": "Chief judge", "C": "Constitution", "D": "Legislature"}, "answer": "C", "explanation": "A constitution sets out how all the elements of government are organised and how power is carved up among different political units.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1996>40", "subject": "Government", "year": "1996", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "Which of the following was a resolution in North Atlantic Charter of 1941 that helped to stimulate nationalist movements in West Africa?", "images": [], "options": {"A": "People all over the world had the right to vote and be voted for", "B": "People all over the world had the right to choose their own from of government", "C": "All colonial territories should be members of the League of Nations", "D": "Newspaper should support the colonial masters"}, "answer": "B", "explanation": "The North Atlantic Charter of 1941, which later led to the formation of the United Nations, had a resolution that people all over the world had the right to choose their own form of government. This principle stimulated nationalist movements in West Africa as it gave them the impetus to fight for self-determination and independence from colonial rule.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1996>41", "subject": "Government", "year": "1996", "type": "Objective", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : ORIGINS, FACTORS AND STRUCTURE", "question": "The first commission set up to work out revenue procedure for Nigeria was the", "images": [], "options": {"A": "Phillipson Commission", "B": "Chick Commission", "C": "Raisman Commission", "D": "Binns Commission"}, "answer": "A", "explanation": "There have been ten Revenue allocation regimes in Nigeria since the first fiscal commission known as the Sir Sydney Phillipson Commission crafted three cardinal principles of derivation, even progress and population for Nigeria in 1946.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1996>42", "subject": "Government", "year": "1996", "type": "Objective", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : FEATURES AND PROBLEMS", "question": "Which of the following is the basic factor in the formation of a federation? The", "images": [], "options": {"A": "Presence of a common enemy", "B": "Desire for union", "C": "Existence of a single large ethnic group", "D": "Presence of an ambitious ruling class"}, "answer": "B", "explanation": "The basic factor in the formation of a federation is the desire for union. A federation is a political entity characterized by a union of partially self-governing provinces, states, or other regions under a central federal government. Therefore, the desire for union is a fundamental factor in its formation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>43", "subject": "Government", "year": "1996", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "The political parties which formed a coalition government at the center after the 1954 general elections in Nigeria were the", "images": [], "options": {"A": "NEPU and AG", "B": "NPC and NCNC", "C": "NPC and NEPU", "D": "AG and NPC"}, "answer": "B", "explanation": "The coalition government formed after the 1954 general elections in Nigeria was between the Northern People's Congress (NPC) and the National Council of Nigeria and the Cameroons (NCNC). The NPC was a major political party in Nigeria during the nation's pre-independence and first republic era, while the NCNC was a Nigerian political party from 1944 to 1966. The coalition was formed to create a balance of power between the northern and southern regions of Nigeria.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>44", "subject": "Government", "year": "1996", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "Which of the following political parties produced four ministers in the National Government of 1957 in Nigeria? The", "images": [], "options": {"A": "AG", "B": "NCNC", "C": "NPC", "D": "NEPU"}, "answer": "C", "explanation": "There were 13 African ministers, of whom six were from the NCNC, four were of the Northern People's Congress (NPC), two belonged to the Action Group, and one was from the Kamerun National Conference (KNC).", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>45", "subject": "Government", "year": "1996", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "The Nigeria attained republican status through the 1963 constitution means that it", "images": [], "options": {"A": "Introduce the executive presidential system of government", "B": "Severed the remaining links with the British monarch", "C": "Created a unitary state", "D": "Introduced a multi-party system"}, "answer": "B", "explanation": "The attainment of republican status through the 1963 constitution means that Nigeria severed the remaining links with the British monarch. Prior to this, Nigeria was a constitutional monarchy with the British monarch as the head of state. The 1963 constitution made Nigeria a republic, with a Nigerian as the head of state.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>46", "subject": "Government", "year": "1996", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "The political party that transformed from a cultural organization known as The Jam''iyyar Mutanen Arewa was the", "images": [], "options": {"A": "NEPU", "B": "NPC", "C": "NCNC", "D": "NNDP"}, "answer": "B", "explanation": "Northern People's Congress (NPC) is a political party in Nigeria. Formed in June 1949, the party held considerable influence in the Northern Region from the 1950s until the military coup of 1966. It was formerly a cultural organization known as Jamiyaar Mutanem Arewa.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>47", "subject": "Government", "year": "1996", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : ACHIEVEMENTS AND FAILURES", "question": "The immediate cause of Kano riot of 1953 was the", "images": [], "options": {"A": "NCNC tour of Northern Nigeria led by Dr. Azikiwe", "B": "Action Group tour of Northern Nigeria led by Chief S.L Akintola", "C": "Mobbing of Northern leaders at Lagos", "D": "Issue of the administrative position of Lagos"}, "answer": "B", "explanation": "The remote cause of the riot was the strained relationship between the Northern and Southern political leaders over the issue of self-government in 1956. The last straw that broke the camel's back was the tour by a delegation of the AG and NCNC led by Chief Samuel Akintola. That tour which was aimed at campaigning for self-government acted as the immediate cause of the Kano riot. It sparked off a chain of disorder that culminated in the riot.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1996>48", "subject": "Government", "year": "1996", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PRESIDENTIAL", "question": "In a presidential system the head of government is called the", "images": [], "options": {"A": "Prime Minister", "B": "Governor-General", "C": "Executive President", "D": "Chancellor"}, "answer": "C", "explanation": "In a presidential system of government, the head of government is called the Executive President. This is because the president is both the head of state and the head of government, combining the roles of the monarch and prime minister in a parliamentary system. The president is responsible for the execution and enforcement of the law, and has the power to veto or sign legislation into law.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1996>49", "subject": "Government", "year": "1996", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "The main cause of the 1962/63 census crisis was that", "images": [], "options": {"A": "There was widepread inflation of the census results in many regions", "B": "Inexperienced officials were used in the enumeration", "C": "The police prevented enumerators from doing their work", "D": "There was no fund to provide enough materials for the head count"}, "answer": "A", "explanation": "The outright refute of the census result by the Eastern and Western regions. The protest and criticism of gross irregularities and inflation of census figures by the census officers.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1996>50", "subject": "Government", "year": "1996", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "In the 1979 Constitution of Nigeria the National Assembly was made up of", "images": [], "options": {"A": "The two House of Assembly", "B": "Both the State and Federal Houses of Assembly", "C": "The House of Chiefs and elected representatives", "D": "Elected and unelected representatives"}, "answer": "A", "explanation": "The constitution created the National Assembly as the highest national law making body of the federation. The National Assembly was made up of two houses namely the House of Senate and the House of Representatives.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>51", "subject": "Government", "year": "1996", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "All the following are reasons for military intervention in politics except", "images": [], "options": {"A": "Corrupt practices by civilian adminstrations", "B": "Tribalism and nepotism", "C": "Regular promotion of military officers", "D": "Ailing economic situations"}, "answer": "C", "explanation": "Military intervention in politics is usually due to reasons such as corrupt practices by civilian administrations, tribalism and nepotism, and ailing economic situations. However, the regular promotion of military officers is an internal military affair and does not directly influence military intervention in politics.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>52", "subject": "Government", "year": "1996", "type": "Objective", "topic": "MILITARY RULE : VARIOUS MILITARY REGIMES", "question": "The second Nigeria military leader to be assassinated in military coup d'etat was", "images": [], "options": {"A": "General Aguiyi Ironsi", "B": "Major General Maman Vatsa", "C": "Col .B.S. Dimka", "D": "General Murtala Mohammed"}, "answer": "D", "explanation": "The second Nigerian military leader to be assassinated in a military coup d'etat was General Murtala Mohammed. He was assassinated on February 13, 1976, in an unsuccessful coup attempt led by Lt. Col Buka Suka Dimka.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1996>53", "subject": "Government", "year": "1996", "type": "Objective", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : FEATURES AND PROBLEMS", "question": "In federal system of government , the component units", "images": [], "options": {"A": "Have equal powers with the central authority", "B": "Derive their powers from the constitution", "C": "Are subordinate to one another", "D": "Maintain separate currencies"}, "answer": "B", "explanation": "In a federal system of government, the powers of the component units are derived from the constitution. This means that the constitution of the country outlines the powers that the federal, state, and local governments have. It is the constitution that determines what each level of government is responsible for and how they can exercise their powers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>54", "subject": "Government", "year": "1996", "type": "Objective", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "The focus of Nigeria's foreign policy is", "images": [], "options": {"A": "That Nigeria cannot join the Non-Aligned Movement", "B": "Nigeria as a frontline country", "C": "That African Liberation Movements should look elsewhere for aids", "D": "Africa as its centre-piece"}, "answer": "D", "explanation": "The focus of Nigeria's foreign policy is Africa as its centre-piece. This means that Nigeria's foreign policy is primarily concerned with the affairs of the African continent. Nigeria has always played a leading role in the affairs of Africa, particularly in the areas of peacekeeping, conflict resolution, and economic development. This is reflected in its foreign policy which places a high priority on Africa.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>55", "subject": "Government", "year": "1996", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "The first executive secretary of the Economic Community of West African States (ECOWAS) was", "images": [], "options": {"A": "Diallo Tell", "B": "Nzo Ekangaki", "C": "Abubakar Ouattara", "D": "Salim A. Salim"}, "answer": "C", "explanation": "Aboubakar Diaby Ouattara (born 25 December 1938) is a diplomat from Côte d'Ivoire. He served as the first Executive Secretary in the Economic Community of West African States (ECOWAS) from its inception in 1977 until 1985.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1996>56", "subject": "Government", "year": "1996", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "The major aim of the Organization of African Unity (OAU) is to", "images": [], "options": {"A": "Introduce a common currency for all African states", "B": "Maintain international friendliness, peace, and cooperation", "C": "Promote international oppression", "D": "Encourage international sporting activities"}, "answer": "B", "explanation": "The major aim of the Organization of African Unity (OAU) is to maintain international friendliness, peace, and cooperation. The OAU was established to promote unity and solidarity among African States; to coordinate and intensify cooperation for development; to safeguard the sovereignty and territorial integrity of Member States and to promote international cooperation within the framework of the United Nations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>57", "subject": "Government", "year": "1996", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "The supreme policy-making organ of the Organization of Africa Unity (OAU) is the", "images": [], "options": {"A": "Council of Ministers", "B": "Assembly of Heads of State and Governments", "C": "General Secretariat", "D": "Defence Commission"}, "answer": "B", "explanation": "The supreme policy-making organ of the Organization of Africa Unity (OAU) is the Assembly of Heads of State and Governments. The Assembly of Heads of State and Governments is the supreme organ of the OAU and it determines the general policy and direction of the OAU.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>58", "subject": "Government", "year": "1996", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "October 24 of each year is universally marked as the United Nations Day because on this day, the", "images": [], "options": {"A": "United Nations Organisation officially came into existence", "B": "United Nations Charter was drawn up", "C": "Two Super Powers signed the United Nations Charter", "D": "Charter on Fundamental Human rights was signed"}, "answer": "B", "explanation": "United Nations Day, on 24 October, marks the anniversary of the entry into force in 1945 of the UN Charter.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1996>59", "subject": "Government", "year": "1996", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The Headquarters of the International Court of Justice is at", "images": [], "options": {"A": "New York", "B": "Geneva", "C": "Paris", "D": "The Hague"}, "answer": "D", "explanation": "The International Court of Justice (ICJ) is the principal judicial organ of the United Nations (UN). It was established in June 1945 by the Charter of the United Nations and began work in April 1946. The seat of the Court is at the Peace Palace in The Hague (Netherlands).", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1996>60", "subject": "Government", "year": "1996", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The most significant achievement of the United Nations Organisation (UNO) since its formation is the", "images": [], "options": {"A": "Prevention of another world War", "B": "Settlement of the Middle East Crisis", "C": "Enlargement of its membership", "D": "Appointment of an African as the head of the International Court of Justice"}, "answer": "A", "explanation": "The prevention of another world war was the major reason for its establishment and it has achieved that so far.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>1", "subject": "Government", "year": "1997", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN INSTITUTION OF THE STATE:", "question": "Government as an institution of the state means the", "images": [], "options": {"A": "Method of organizing parties and preasure group", "B": "Process of decision-making in a society", "C": "Methods of resolution of conflicts among the people", "D": "Structures and systems for decision-making in society"}, "answer": "D", "explanation": "Government as an institution of the state is defined as the machinery that is setup by the state to administer it's functions and duties.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>2", "subject": "Government", "year": "1997", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "In a feudal system, the hierarchy of citizens is the king,", "images": [], "options": {"A": "Nobles and lords", "B": "Queen and lords", "C": "Knights and nobles", "D": "Serfs and knights"}, "answer": "C", "explanation": "After the rank of king, the hierarchy was the nobles, the knights, the clergy (religious people), the tradesmen and the peasants.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1997>3", "subject": "Government", "year": "1997", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The political culture of the country is said to be participatory if individuals are", "images": [], "options": {"A": "Interested in voting and contesting elections", "B": "Not allowed to criticize the government", "C": "Not allowed to join political parties of their choice", "D": "Only allowed to vote but cannot contest for higher offices"}, "answer": "A", "explanation": "A participatory political culture is one in which citizens are actively involved in the political process. This includes activities such as voting and contesting elections. Therefore, the correct answer is 'Interested in voting and contesting elections'. The other options do not reflect a participatory political culture as they limit the involvement of individuals in the political process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>4", "subject": "Government", "year": "1997", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The ability of leaders to make and enforce decisions in a state is called", "images": [], "options": {"A": "Sovereignty", "B": "Political power", "C": "Socialization", "D": "Legitimacy"}, "answer": "B", "explanation": "Political power refers to the ability of leaders to make and enforce decisions in a state. Sovereignty refers to the supreme power or authority in a state, socialization is the process of learning norms, rules, regulations, values and attitudes of society and legitimacy refers to the acceptance and recognition of an authority. Therefore, the correct answer is 'Political power'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>5", "subject": "Government", "year": "1997", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The idea of separation of powers as a political concept was developed by", "images": [], "options": {"A": "Louis Mostesquieu", "B": "A.V Dicey", "C": "Thomas Hobbes", "D": "Karl Marx"}, "answer": "A", "explanation": "The first modern formulation of the doctrine was that of the French political philosopher Montesquieu in De l'esprit des lois (1748; The Spirit of Laws).", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1997>6", "subject": "Government", "year": "1997", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Fascist movement has its origin in", "images": [], "options": {"A": "Germany", "B": "Italy", "C": "Spain", "D": "The defunct Soviet Union"}, "answer": "B", "explanation": "The Fascist movement originated in Italy in the early 20th century. It was led by Benito Mussolini and it emphasized aggressive nationalism, militarism, and the supremacy of the state. It was against communism, socialism, liberal democracy, and individual rights and freedoms. It was later adopted by Germany under Adolf Hitler.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>7", "subject": "Government", "year": "1997", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Which of the following factors enhances the operation of the Rule of Law?", "images": [], "options": {"A": "Well-equipped police force", "B": "Establishment of modern press", "C": "Independent judiciary", "D": "Enlightened citizens"}, "answer": "C", "explanation": "The operation of the Rule of Law is enhanced by an independent judiciary. The Rule of Law is a principle that all people and institutions are subject to and accountable to law that is fairly applied and enforced. An independent judiciary ensures that this principle is upheld as it can make decisions free from influence by the other branches of government or from private or partisan interests. Judges are able to make rulings based on what the law says and not on what they, or anyone else, thinks the law should say.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>8", "subject": "Government", "year": "1997", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "An important reason for granting the Judiciary the power of Judicial Review is to enable it to", "images": [], "options": {"A": "Uphold the surpremacy of the Constitution", "B": "Promote freedom of the press", "C": "Elevate the Judiciary above the other organs", "D": "Demonstrate the independence of the Judiciary"}, "answer": "A", "explanation": "The power of Judicial Review is granted to the Judiciary to enable it to uphold the supremacy of the Constitution. Judicial Review is the power of a court to review the actions of public sector bodies in terms of their legality, or to review the constitutionality of legislation or some types of executive actions. By doing so, it ensures that all laws and actions are in compliance with the constitution, thereby upholding its supremacy.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1997>9", "subject": "Government", "year": "1997", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "The Judiciary are independent when judges are", "images": [], "options": {"A": "Popularly elected into political offices", "B": "Free to join any political party of their choice", "C": "Free from external control and interference", "D": "Empowered to amend the national constitution"}, "answer": "C", "explanation": "The Judiciary is considered independent when it is free from external control and interference. This means that judges can make decisions without fear of reprisal, punishment, or influence from other branches of government or from private or partisan interests. This independence allows them to uphold the rule of law and protect individual rights.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1997>10", "subject": "Government", "year": "1997", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : EXECUTIVE", "question": "Which of the following comprises the President, the Ministers, the Civil Servants and the Police? The", "images": [], "options": {"A": "Armed Forces", "B": "Judiciary", "C": "Legislature", "D": "Executive"}, "answer": "D", "explanation": "The Executive branch of government comprises the President, the Ministers, the Civil Servants and the Police. The Executive is responsible for implementing and enforcing laws written by the legislature. It also manages the day-to-day operations of government.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1997>11", "subject": "Government", "year": "1997", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "A constitution can be defined as", "images": [], "options": {"A": "The rules guiding parliamentary procedures", "B": "The rules guiding the affairs of an institution of society", "C": "The constituent elements of a contractual agreement", "D": "All written laws of a state"}, "answer": "B", "explanation": "A constitution sets out how all the elements of government are organised and how power is carved up among different political units.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1997>12", "subject": "Government", "year": "1997", "type": "Objective", "topic": "CONSTITUTIONS : TYPES AND FEATURES", "question": "The constitution of federal system is usually", "images": [], "options": {"A": "Written and rigid", "B": "Superior in content", "C": "Difficult to understand", "D": "For the use of the federal government only"}, "answer": "A", "explanation": "In a federal system, the constitution is usually written and rigid. This is because it outlines the distribution of powers and functions between the federal (central) and state (provincial) governments. This distribution needs to be clearly defined and not easily changed, hence the constitution is written and rigid. Therefore, the correct answer is 'Written and rigid'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>13", "subject": "Government", "year": "1997", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Constitutionalism emphasizes that those who govern the state should do so according to", "images": [], "options": {"A": "Their whims and caprices", "B": "Laid-down rules of public behaviour", "C": "The direction of judges", "D": "The dictates of their egos"}, "answer": "B", "explanation": "Constitutionalism is a political philosophy based on the idea that government authority is derived from and limited by a body of fundamental law. It emphasizes that those who govern the state should do so according to laid-down rules of public behaviour, not their whims and caprices, the direction of judges, or the dictates of their egos. This ensures that the government operates within the established laws.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>14", "subject": "Government", "year": "1997", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY", "question": "One of features of a unitary state is that", "images": [], "options": {"A": "A two party system is usually entrenched in the constitution", "B": "The constituion is flexible", "C": "Power is shared among all levels of governmnet", "D": "The cilvil service is supreme"}, "answer": "B", "explanation": "A unitary state is a state governed as a single entity in which the central government is ultimately supreme. One of the features of a unitary state is that the constitution is flexible. This means that the constitution can be easily amended or changed by the central government. The other options are not necessarily features of a unitary state. A two-party system is not a requirement, power is not shared among all levels of government (rather, the central government has the ultimate power), and the civil service is not supreme (the central government is).", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>15", "subject": "Government", "year": "1997", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PRESIDENTIAL", "question": "Impeachment as an instrument of check on the Executive is useful mainly in a", "images": [], "options": {"A": "Federal system", "B": "Cabinet system", "C": "Unitary system", "D": "Presidential system"}, "answer": "D", "explanation": "Impeachment is a constitutional process that allows the legislature to remove a sitting executive, such as the president, from office. This process is mainly used in a Presidential system where the president is both the head of state and government. In a Presidential system, the president is not directly accountable to the legislature, hence impeachment serves as a check on the executive's power.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1997>16", "subject": "Government", "year": "1997", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Fundamental human rights are entrenched in the Constitution of a state in order to", "images": [], "options": {"A": "Encourage unlimited freedom", "B": "Guarantee the liberty of citizens", "C": "Restrict the liberty of citizens", "D": "Make the government popular"}, "answer": "B", "explanation": "Fundamental human rights are basic rights and freedoms that belong to every individual, from birth until death. These rights are entrenched in the constitution of a state to guarantee the liberty of citizens. They serve as a protection against the power of the state and prevent the government from having absolute power. They ensure that individuals are protected against any form of abuse or violation from the state or other individuals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>17", "subject": "Government", "year": "1997", "type": "Objective", "topic": "CITIZENSHIP : MEANING AND MODE OF ACQUISITION", "question": "An alien could become a legal member of a state by", "images": [], "options": {"A": "Migration", "B": "Employment", "C": "Naturalization", "D": "Socialization"}, "answer": "C", "explanation": "Naturalization is the process of becoming or making someone a citizen of a country that they were not born in.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>18", "subject": "Government", "year": "1997", "type": "Objective", "topic": "CITIZENSHIP : MEANING AND MODE OF ACQUISITION", "question": "A Nigerian may lose his Citizenship if he", "images": [], "options": {"A": "Is convicted for a criminal offence", "B": "Renounces it in exchange for another", "C": "Loses his international passport", "D": "Is deported from a foreign country"}, "answer": "B", "explanation": "A Nigerian may lose his citizenship if he renounces it in exchange for another. Renunciation is the voluntary act of relinquishing one's citizenship or nationality. It is the opposite of naturalization, whereby a person voluntarily acquires a citizenship, and is one of the many forms of loss of citizenship.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>19", "subject": "Government", "year": "1997", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Two -Party system implies that the only two parties", "images": [], "options": {"A": "Exist in the country", "B": "Are capable of capturing power", "C": "Can form a coalition", "D": "Can register members"}, "answer": "B", "explanation": "A two-party system is a system where two major political parties dominate politics within a government. One of the two parties typically holds a majority in the legislature and is usually referred to as the majority party while the other is the minority party. This implies that these two parties are capable of capturing power.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>20", "subject": "Government", "year": "1997", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "The ultimate aim of political party is", "images": [], "options": {"A": "Influence government policies", "B": "Gain control of government", "C": "Seek to discredit the government", "D": "Provide for the welfare of its members"}, "answer": "B", "explanation": "The ultimate aim of a political party is to gain control of the government. Political parties are organized groups of people with similar ideas or ideologies who seek to influence public policy by getting their candidates elected to public office. Therefore, their ultimate goal is to gain control of the government in order to implement their policies and ideas.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>21", "subject": "Government", "year": "1997", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Political parties mobilize the support of the electorate by", "images": [], "options": {"A": "Promoting violence", "B": "Campaigning", "C": "Rigging elections", "D": "Encouraging coup d'etats"}, "answer": "B", "explanation": "Political parties mobilize the support of the electorate by campaigning. Campaigning involves activities like public speeches, advertising, and other activities designed to influence voters. This is a peaceful and democratic way of mobilizing support, unlike promoting violence, rigging elections, or encouraging coup d'etats, which are undemocratic and illegal.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>22", "subject": "Government", "year": "1997", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS", "question": "Which of the following will produce a weak government?", "images": [], "options": {"A": "Coalition", "B": "Two-Party system", "C": "General elections", "D": "Presidential"}, "answer": "A", "explanation": "A coalition government can often be weak because it is made up of different parties with different ideologies and agendas. This can lead to disagreements and instability, making it difficult for the government to make decisions and implement policies effectively. A two-party system, general elections, and a presidential system do not inherently produce a weak government.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1997>23", "subject": "Government", "year": "1997", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "The main objective of pressure group is to", "images": [], "options": {"A": "Fund election campaigns", "B": "Change the government by violent means", "C": "Influence government policies", "D": "Change the mainfestos of all political parties"}, "answer": "C", "explanation": "Pressure groups are organizations that try to influence public policy or legislation. They operate by lobbying members of the government and, in some cases, the public. They do not seek to directly control or govern. Their main objective is to influence government policies, not to fund election campaigns, change the government by violent means, or change the manifestos of all political parties.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>24", "subject": "Government", "year": "1997", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "Lobbying mainly involves the application of pressure on", "images": [], "options": {"A": "People in commerce through monetary gifts", "B": "Legislators through material gifts", "C": "People in government throught persasive arguments", "D": "Legislator by intimidation and blackmail"}, "answer": "C", "explanation": "\"Lobbying\" means communicating with any official in the legislative or executive branch for the purpose of attempting to influence legislative or administrative action or a ballot issue.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>25", "subject": "Government", "year": "1997", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "Membership of pressure groups is usually limited because they", "images": [], "options": {"A": "Pursue specific and narrow objectives", "B": "Seek unlimited freedom their members", "C": "Promote other people's interests", "D": "Are not patriotic"}, "answer": "A", "explanation": "Pressure groups are usually formed to address specific issues or advocate for specific causes. Therefore, their objectives are often specific and narrow, which may not appeal to everyone, hence limiting their membership. This is why option 1 is correct.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1997>26", "subject": "Government", "year": "1997", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "For an Electoral Commission to conduct a free and fair election, it must be", "images": [], "options": {"A": "Controlled by the government", "B": "Funded by only one of the political parties", "C": "An importial and independent body", "D": "Supervised by a governmnet agency"}, "answer": "C", "explanation": "For an Electoral Commission to conduct a free and fair election, it must be impartial and independent. This means it should not be influenced or controlled by any political party or government. It should be able to make decisions and conduct the election process without any external interference. This ensures that the election process is fair and credible. Therefore, option 3 is the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>27", "subject": "Government", "year": "1997", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "An electoral college refers to", "images": [], "options": {"A": "Training school for electoral officers", "B": "Medium of indirect election", "C": "Means of educating the electorate", "D": "Place where public opinion is formed"}, "answer": "B", "explanation": "An electoral college is a set of electors who are selected to elect a candidate to particular offices.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>28", "subject": "Government", "year": "1997", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "An indirect election takes place when", "images": [], "options": {"A": "Election is conducted for seats in the legislature", "B": "Voting is by proxy", "C": "Election result is decided by the Judiciary", "D": "Elected representatives vote on behalf of the electorate"}, "answer": "D", "explanation": "Indirect election is a process in which voters in an election do not actually choose between candidates for an office, but rather elect persons who will then make the choice. It means that elected representatives vote on behalf of the electorate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>29", "subject": "Government", "year": "1997", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "A bye-election is conducted when", "images": [], "options": {"A": "The Parliament is dissovled", "B": "Some vacant seats exist in Parliament", "C": "A Minister resigns", "D": "The military takes over government"}, "answer": "B", "explanation": "A by-election is an election that is held to choose a new member of parliament when a member has resigned or died.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>30", "subject": "Government", "year": "1997", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Which of the following was a requirement for suffrage under the first elections in Nigeria in 1923?", "images": [], "options": {"A": "A minimum income of ƹ100 per annum", "B": "12-month residence in Europe", "C": "24-month residence in the capital city", "D": "Being a male adult and legally married"}, "answer": "A", "explanation": "The first elections in Nigeria in 1923 required a minimum income of ƹ100 per annum for suffrage. This was a way to limit the voting rights to the wealthy and educated class of the society. Therefore, the correct answer is 'A minimum income of ƹ100 per annum'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1997>31", "subject": "Government", "year": "1997", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "Who among the following is a civil servant in Nigeria?", "images": [], "options": {"A": "The managing director of a bank", "B": "A director in the Ministry of Defence", "C": "A major in the Army", "D": "A Commissioner of Police"}, "answer": "A", "explanation": "The bank is a private sector. This is the most appropriate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>32", "subject": "Government", "year": "1997", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC/CIVIL SERVICE COMMISSION –MEANING AND FUNCTIONS.", "question": "The main duty of the Civil Service Commission under the Nigerian Republican Constitution was", "images": [], "options": {"A": "The retirement and settlement of pension for federal civil servants", "B": "Advising the government on the establishment of new ministries", "C": "The appointment and promotion of judges", "D": "The recruitment, discipline and promotion of civil servants"}, "answer": "D", "explanation": "The Civil Service Commission under the Nigerian Republican Constitution was primarily responsible for the recruitment, discipline, and promotion of civil servants. This means they were in charge of hiring new employees, enforcing discipline, and promoting employees based on performance and qualifications. The other options listed are not the main duties of the Civil Service Commission.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1997>33", "subject": "Government", "year": "1997", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "Neutrality of civil servants implies that they should", "images": [], "options": {"A": "Belong to political parties of their choice", "B": "Be recruited on the basis of merit", "C": "Serve any government loyally", "D": "Be appointed on permanent basis"}, "answer": "C", "explanation": "Neutrality of civil servants implies that they should serve any government loyally. This is because civil servants are expected to be politically neutral and serve the government of the day, irrespective of the political party in power. They are not supposed to show allegiance to any political party but to the state. Hence, their loyalty is to the government and not to any political party.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>34", "subject": "Government", "year": "1997", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "One of the features of Local Government Reforms of 1976 in Nigeria is the", "images": [], "options": {"A": "Reduction of financial aids to local governments", "B": "Establishment of local government police", "C": "Establishment of traditional institutions in each local govements", "D": "Introduction of full-time chairmen and supervisory councillors"}, "answer": "C", "explanation": "Another features of the 1976 local government reform in Nigeria, is that the reform stopped recognizing traditional rulers as members of the local government.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1997>35", "subject": "Government", "year": "1997", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "Government control of public corporations in Nigeria is mainly to", "images": [], "options": {"A": "Ensure public accountability", "B": "Allow freedom of each on the part of the corporations", "C": "Guarantee profit maximization of the corporations", "D": "Protect the appointment of foreigners in the corporations"}, "answer": "A", "explanation": "The main reason for government control of public corporations in Nigeria is to ensure public accountability. Public corporations are created by the government and they operate on public funds. Therefore, it is necessary for the government to control and regulate these corporations to ensure that they are accountable to the public and that the funds are used appropriately.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>36", "subject": "Government", "year": "1997", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : YORUBA", "question": "Who among the following could pass death sentence on an accused person in the pre-colonial Yoruba Kingdom? The", "images": [], "options": {"A": "Paramount Ruler", "B": "Provincial Heads", "C": "Queen Mother", "D": "Cults"}, "answer": "B", "explanation": "The provincial heads can do that. This is the most appropriate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>37", "subject": "Government", "year": "1997", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "The French policy of Assimilation attempted to", "images": [], "options": {"A": "Use chiefs as intermediaries between the government and the citizens", "B": "Africanize the civil service", "C": "Make the Africans think and behave like French citizens", "D": "Allow Africans develop on their own"}, "answer": "C", "explanation": "The French policy of Assimilation was a colonial policy that aimed to transform colonial subjects into French citizens by teaching them the French language, French customs, and French law. The ultimate goal was to make the Africans think and behave like French citizens.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1997>38", "subject": "Government", "year": "1997", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Where was Indirect Rule successfully practised before it was introduced to Africa?", "images": [], "options": {"A": "Latin America", "B": "USA", "C": "Britain", "D": "Japan"}, "answer": "B", "explanation": "It was used in the USA. This is the most appropriate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>39", "subject": "Government", "year": "1997", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Which of the following best describes the administration of a Crown Colony", "images": [], "options": {"A": "Administration of a colony through local chiefs", "B": "Appointment of local chiefs as Governors-General of the colonial territories by the home government", "C": "Oppressive rule of the minority White over the majority Black", "D": "Administration of colonial territories by a Governor on behalf of the British Government"}, "answer": "D", "explanation": "A Crown Colony was a type of colonial administration in the British Empire. It was ruled by a governor appointed by the monarch. The governor was responsible for the administration of the colony on behalf of the British Government. Therefore, the correct answer is 'Administration of colonial territories by a Governor on behalf of the British Government'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>40", "subject": "Government", "year": "1997", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "One of effects of the agitations by the National Congress of British West Africa in the 1920s was the", "images": [], "options": {"A": "Establishment to Town Councils in th Protectorate", "B": "Abolition of racial discrimination in the Civil Service", "C": "Deposition of traditional rulers by Africans", "D": "Election of Africans into the Legislative Councils"}, "answer": "D", "explanation": "The National Congress of British West Africa (NCBWA) was a political pressure group that demanded greater participation of Africans in the colonial government. One of the effects of their agitation was the election of Africans into the Legislative Councils. Therefore, the correct answer is 'Election of Africans into the Legislative Councils'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1997>41", "subject": "Government", "year": "1997", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "Which of the following is a result of nationalist activities in French West Africa?", "images": [], "options": {"A": "Indigenat", "B": "The Loi Cadre", "C": "Negritude", "D": "Direct Rule"}, "answer": "B", "explanation": "The loi cadre, or \"framework law,\" redefined the relationship between France and its sub-Saharan African colonies. Passed in June 1956, this law granted partial autonomy to the territories but left the French government with key powers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>42", "subject": "Government", "year": "1997", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : POST- INDEPENDENCE CONSTITUTIONS", "question": "Regionalism was fully operated in NIgeria by the", "images": [], "options": {"A": "Clifford Constitution", "B": "Macpherson Constitution", "C": "Richard Constitution", "D": "Republican Constitution"}, "answer": "C", "explanation": "The constitution emphasized the regions. This is the most appropriate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1997>43", "subject": "Government", "year": "1997", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "The General Conference of 1950 on Nigeria was held in", "images": [], "options": {"A": "Ibadan", "B": "London", "C": "Enugu", "D": "New York"}, "answer": "A", "explanation": "The General Conference of 1950 on Nigeria was held in Ibadan. This conference was a significant event in Nigeria's journey towards independence. It was held in Ibadan, Nigeria, and it was the first time that Nigerians had a significant say in the drafting of their constitution. The conference led to the creation of the Macpherson Constitution, which was used in Nigeria from 1951 to 1954.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>44", "subject": "Government", "year": "1997", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "One defect of the Macpherson Constitution was that", "images": [], "options": {"A": "Franchise was still limited to Logas and Calabar", "B": "Nigeria were not given representation in the Parliament", "C": "Nigeria ministers were not charged with full ministrial responsibility", "D": "Nigerians were not consulted before introducing the constitution"}, "answer": "C", "explanation": "Ministers did not have full responsibility. In the constitution, Nigeria ministers were not charged with full ministrial responsibility.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1997>45", "subject": "Government", "year": "1997", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "The rationalization of the Civil Service in Nigeria could be traced to the", "images": [], "options": {"A": "Nigerian Council of 1914", "B": "Lyttleton Constitution of 1954", "C": "Richard Constitution of 1946", "D": "General Conference of 1950"}, "answer": "B", "explanation": "The Lyttleton Constitution of 1954 rationalized of the Civil Service in Nigeria.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1997>46", "subject": "Government", "year": "1997", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PRESIDENTIAL", "question": "The 1979 Constitution of Nigeria introduced a system of government similar to that of", "images": [], "options": {"A": "The U.S.A", "B": "Britain", "C": "France", "D": "Australlia"}, "answer": "A", "explanation": "The 1979 Constitution of Nigeria introduced a system of government similar to that of the U.S.A. This system is known as the Presidential system of government. In this system, the President is both the head of state and the head of government, and the executive powers are vested in the President. This is similar to the system of government in the U.S.A.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>47", "subject": "Government", "year": "1997", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Under a federal system of government , a citizen living in any part of the country is expected to obey laws made by the", "images": [], "options": {"A": "Federal Government only", "B": "Federal and Local Governments", "C": "Local Government only", "D": "Federal, State and Local Government"}, "answer": "D", "explanation": "In a federal system of government, power is divided between a central government and individual states or provinces. Therefore, a citizen is expected to obey laws made by the Federal, State, and Local Government. Federal laws apply to the entire country, state laws apply within the state, and local laws apply within a local jurisdiction like a city or county.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1997>48", "subject": "Government", "year": "1997", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The principle for sharing the wealth of the nation among the different levels of government is called", "images": [], "options": {"A": "Delegated legislation", "B": "Revenue allocation", "C": "Bicameralism", "D": "Checks and balances"}, "answer": "B", "explanation": "The principle for sharing the wealth of the nation among the different levels of government is called Revenue allocation. This involves the distribution of revenue, derived from tax sources, among different levels of government i.e., central, state and local governments. Delegated legislation, Bicameralism, and Checks and balances are not related to the sharing of wealth among different levels of government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>49", "subject": "Government", "year": "1997", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "The first political party in Nigeria was formed by", "images": [], "options": {"A": "Chief Obafemi Awolowo", "B": "Dr Nnamdi Azikiwe", "C": "Sir Herbert Macaulay", "D": "Alhaji Aminu Kano"}, "answer": "C", "explanation": "The first political party in Nigeria was the Nigerian National Democratic Party (NNDP) formed by Sir Herbert Macaulay in 1923. Therefore, the correct answer is Sir Herbert Macaulay.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>50", "subject": "Government", "year": "1997", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "Which of the following is a pre-independence political party in Nigeria?", "images": [], "options": {"A": "Nigerian Youth Movenment (NYM)", "B": "Unity Party of Nigeria (UPN)", "C": "Northern Elements Progressive Union (NEPU)", "D": "United Meddle Belt Congress (UMBC)"}, "answer": "A", "explanation": "The Nigerian Youth Movement (NYM) was a pre-independence political party in Nigeria. It was formed in 1934 and was active until 1951. The other options listed are post-independence political parties. Therefore, the correct answer is Nigerian Youth Movement (NYM).", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>51", "subject": "Government", "year": "1997", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "The political parties that formed the Opposition in the House of Representatives during the First Republic in Nigeria were the", "images": [], "options": {"A": "NCNC and UMBC", "B": "AG and UMBC", "C": "NCNC and NEPU", "D": "AG and NCNC"}, "answer": "B", "explanation": "They formed the opposition while NPC and NCNC formed a coalition.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>52", "subject": "Government", "year": "1997", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "Which of the following political parties entered into an accord at the centre after the 1979 General Elections in Nigeria?", "images": [], "options": {"A": "NPN and NPP", "B": "NPP and UPN", "C": "GNPP and NPN", "D": "NPN and UPN"}, "answer": "A", "explanation": "After the 1979 General Elections in Nigeria, the National Party of Nigeria (NPN) and the Nigerian People's Party (NPP) entered into an accord at the centre. The 1979 General Elections marked the beginning of the Second Republic in Nigeria, and the NPN and NPP formed a coalition government at the centre.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>53", "subject": "Government", "year": "1997", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "One of the problems of military administrations in West Africa is that soldiers", "images": [], "options": {"A": "Are representatives of the people", "B": "Lack of discipline", "C": "Are not well organized", "D": "Are not trained for governance"}, "answer": "D", "explanation": "Military personnel are trained for warfare and defense, not for governance. They lack the necessary skills and knowledge to effectively manage a country's economy, social welfare, and political affairs. This often leads to mismanagement, corruption, and violation of human rights.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>54", "subject": "Government", "year": "1997", "type": "Objective", "topic": "MILITARY RULE : VARIOUS MILITARY REGIMES", "question": "Which of the following is not a process in the transition from military to civilian rule?", "images": [], "options": {"A": "Drafting of new constitution", "B": "Appointment of ministers", "C": "Setting up of a constituent assembly", "D": "Arrangement for and conduct of elections"}, "answer": "B", "explanation": "The transition from military to civilian rule involves several processes, including the drafting of a new constitution, setting up of a constituent assembly, and arrangement for and conduct of elections. However, the appointment of ministers is not a process in the transition. It is a step that is taken after the transition has been completed and a civilian government has been established.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>55", "subject": "Government", "year": "1997", "type": "Objective", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "Nigeria relation with other countries are determined largely by the", "images": [], "options": {"A": "National interest", "B": "Political culture", "C": "Traditional rulers", "D": "Opinions of exporters"}, "answer": "A", "explanation": "The national interest is a sovereign state's goals and ambitions (economic, military, cultural, or otherwise), taken to be the aim of government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>56", "subject": "Government", "year": "1997", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "Nigeria belongs to all the following international organization except the", "images": [], "options": {"A": "Organiztion of African Unity (OAU)", "B": "United Nation Organization (UNO)", "C": "North Atlantic Treaty Organization (NATO)", "D": "Organization of Petroleum Exporting Countries (OPEC)"}, "answer": "C", "explanation": "Nigeria is a member of the Organization of African Unity (OAU), United Nation Organization (UNO), and Organization of Petroleum Exporting Countries (OPEC). However, Nigeria is not a member of the North Atlantic Treaty Organization (NATO). NATO is a military alliance of countries from North America and Europe. Nigeria, being an African country, does not belong to this organization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>57", "subject": "Government", "year": "1997", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "Which of the following Heads of State initiated the formation of ECOWAS?", "images": [], "options": {"A": "Yakubu Gowon and Gnasingbe Eyadema", "B": "Dauda Jawara and Abdoul Diouf", "C": "Sekou Toure and Joseph Momoh", "D": "Thomas Sankara and Samuel Doe"}, "answer": "A", "explanation": "The Economic Community of West African States (ECOWAS) was initiated by the Heads of State of Nigeria and Togo, Yakubu Gowon and Gnasingbe Eyadema respectively. ECOWAS is a regional political and economic union of fifteen countries located in West Africa. It was established to promote economic integration across the region.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1997>58", "subject": "Government", "year": "1997", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "An international organization which has former British colonies as its member is the", "images": [], "options": {"A": "Organization of African Unity (OAU)", "B": "Economic Community west African States (ECOWAS)", "C": "United Nations Organization (UNO)", "D": "Commonwealth of Nations"}, "answer": "D", "explanation": "The Commonwealth of Nations, generally known simply as the Commonwealth, is a political association of 54 member states, nearly all of which are former territories of the British Empire. The chief institutions of the organisation are the Commonwealth Secretariat, which focuses on intergovernmental aspects, and the Commonwealth Foundation, which focuses on non-governmental relations amongst member states.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>59", "subject": "Government", "year": "1997", "type": "Objective", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "An international organization which has mainly economic matters as its objectives is the", "images": [], "options": {"A": "Commonwealth of Nations", "B": "League of Nations", "C": "United Nations Organization", "D": "Organization of Petroleum Exporting Countries"}, "answer": "D", "explanation": "The Organization of Petroleum Exporting Countries (OPEC) is an international organization that primarily deals with economic matters, specifically the regulation of oil prices and production levels. The other options, such as the Commonwealth of Nations, League of Nations, and United Nations Organization, are more focused on political, social, and humanitarian issues, not primarily economic matters.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1997>60", "subject": "Government", "year": "1997", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "Which of the following countries is a permanent member of the Security Council?", "images": [], "options": {"A": "India", "B": "Canada", "C": "China", "D": "Korea"}, "answer": "C", "explanation": "China, France, Russian Federation, the United Kingdom, and the United States are the fiver permanent members of the UN security council.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>1", "subject": "Government", "year": "1998", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Liberal democracy thrives best in a", "images": [], "options": {"A": "Fascist system", "B": "Multi-party system", "C": "Feudal system", "D": "One - party system"}, "answer": "B", "explanation": "In liberal democracy, an elected government cannot discriminate against specific individuals or groups when it administers justice, protects basic rights such as freedom of assembly and free speech, provides for collective security, or distributes economic and social benefits.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>2", "subject": "Government", "year": "1998", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Feudalism is a system of government where", "images": [], "options": {"A": "A few people monopolize the ownership of land", "B": "Factors of production are controlled by the capitalists", "C": "Communal ownership of property is prevalent", "D": "State ownership of capital is prevalent"}, "answer": "A", "explanation": "Feudalism was a system in which people were given land and protection by people of higher rank, and worked and fought for them in return.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>3", "subject": "Government", "year": "1998", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following is a feature of communism?", "images": [], "options": {"A": "Common ownership of the means of production", "B": "Dictatorship of the bourgeosis", "C": "Class struggle", "D": "Individual ownership of property"}, "answer": "A", "explanation": "Communism is an ideology or system based on the idea that the property of a community should be owned collectively and shared among everyone.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>4", "subject": "Government", "year": "1998", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET", "question": "The principle that any government that loses the support of the legislature resigns is practised in a", "images": [], "options": {"A": "Unitary system", "B": "Monarchical system", "C": "Cabinet system", "D": "Federal system"}, "answer": "C", "explanation": "The principle that any government that loses the support of the legislature resigns is practiced in a Cabinet system. This is because in a Cabinet system, the executive is accountable to the legislature, and if the legislature withdraws its support, the executive (government) must resign. Hence, the correct answer is 'Cabinet system'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1998>5", "subject": "Government", "year": "1998", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The purpose of Montesquieu's argument for the separation of powers was to", "images": [], "options": {"A": "Prevent tyranny by the government", "B": "Promote the efficiency of government", "C": "Ensure equality of all before the law", "D": "Promote unity in the machinery of govement"}, "answer": "A", "explanation": "Such a separation, it has been argued, limits the possibility of arbitrary excesses by government, since the sanction of all three branches is required for the making, executing, and administering of laws.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1998>6", "subject": "Government", "year": "1998", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "A system where at least two levels of government derive their powers from the constitution is called", "images": [], "options": {"A": "Unitary", "B": "Cabinet", "C": "Federal", "D": "Presidential"}, "answer": "C", "explanation": "Federalism is a system of government in which the same territory is controlled by two levels of government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>7", "subject": "Government", "year": "1998", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "Which of the following countries has an unwritten constitution?", "images": [], "options": {"A": "Ghana", "B": "Nigeria", "C": "Canada", "D": "Britain"}, "answer": "D", "explanation": "Britain is the country that has an unwritten constitution among the options provided. An unwritten constitution is one where no single document or written law encompasses the fundamental principles concerning state organization and the basic rights and duties of citizens. Instead, it is based on a combination of statutes, legal conventions, treaties, and other sources. Britain's constitution is considered 'unwritten' as it's formed from various sources including statute law, case law, and conventions.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1998>8", "subject": "Government", "year": "1998", "type": "Objective", "topic": "CONSTITUTIONS : TYPES AND FEATURES", "question": "A constitution that requires a complex procedure for the amendment of its provision is described as", "images": [], "options": {"A": "Unwritten", "B": "Flexible", "C": "Classified", "D": "Rigid"}, "answer": "D", "explanation": "A constitution that requires a complex procedure for the amendment of its provision is described as Rigid. A rigid constitution is one that requires a special procedure for its amendment, usually involving a higher degree of consensus or a supermajority. This is to ensure that changes to the constitution reflect a broad consensus in society, and are not made hastily or without due consideration.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1998>9", "subject": "Government", "year": "1998", "type": "Objective", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : FEATURES AND PROBLEMS", "question": "One of the reasons why states form a federation is to", "images": [], "options": {"A": "Make the government of a small nation easy", "B": "Keep the residual powers", "C": "Cater for local differences", "D": "Be able take quick decisions"}, "answer": "C", "explanation": "States form a federation to cater for local differences. In a federation, power is divided between the central government and the constituent states or provinces. This allows for local differences to be catered for at the state or provincial level, while the central government handles matters of national importance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>10", "subject": "Government", "year": "1998", "type": "Objective", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : ORIGINS, FACTORS AND STRUCTURE", "question": "Concurrent list in a federal constitution contains issues within the legislative powers of the", "images": [], "options": {"A": "Federal and local councils", "B": "Army and local government", "C": "Police and the legislature", "D": "Federal government and state government"}, "answer": "D", "explanation": "The concurrent list in a federal constitution contains issues within the legislative powers of both the federal government and the state government. This means that both levels of government have the authority to make laws on these issues. The other options are incorrect because they do not accurately represent the entities that share legislative powers in a federation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>11", "subject": "Government", "year": "1998", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "In the legislature, a private member's bill is", "images": [], "options": {"A": "Introduced by a member of Parliament", "B": "Related to matters of local interest", "C": "Related to matters of sanitary nature", "D": "Introduced by the Executive"}, "answer": "A", "explanation": "A private member's bill is a bill (proposed law) introduced into a legislature by a legislator who is not acting on behalf of the executive branch.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>12", "subject": "Government", "year": "1998", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "The legislature of a federal system of government is usually", "images": [], "options": {"A": "Unicameral", "B": "Multi-cameral", "C": "Bicameral", "D": "Rigid"}, "answer": "C", "explanation": "In a federal system of government, the legislature is usually bicameral. This means it has two chambers or houses. This is to ensure a balance of power and representation between the different states or regions that make up the federation. Therefore, the correct answer is 'Bicameral'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>13", "subject": "Government", "year": "1998", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The communist ideology was propounded by", "images": [], "options": {"A": "Charles De Gaulle", "B": "Karl Marx", "C": "John Locke", "D": "Williams Du Bois"}, "answer": "B", "explanation": "The Father of Communism, Karl Marx, a German philosopher and economist, proposed this new ideology in his Communist Manifesto, which he wrote with Friedrich Engels in 1848.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1998>14", "subject": "Government", "year": "1998", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : EXECUTIVE", "question": "Collective responsibility implies that every member of cabinet", "images": [], "options": {"A": "Is responsible to the Head of State", "B": "Obeys the Prime Minister without questions", "C": "May support or oppose the decision made by the cabinet", "D": "Take the credit or blame for the decisions made by the cabinet"}, "answer": "D", "explanation": "Collective responsibility implies that every member of the cabinet takes the credit or blame for the decisions made by the cabinet. This is a constitutional convention in governments using the Westminster System that members of the cabinet must publicly support all governmental decisions made in Cabinet, even if they do not privately agree with them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>15", "subject": "Government", "year": "1998", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY", "question": "A state is said to be unitary if it", "images": [], "options": {"A": "Has a rigid constitution", "B": "Is organized under a single government", "C": "Is headed by a Prime Minister", "D": "Is under military rule"}, "answer": "B", "explanation": "A unitary state is a state governed as a single entity in which the central government is ultimately supreme. The central government may create (or abolish) administrative divisions (sub-national units). Such units exercise only the powers that the central government chooses to delegate. This means that a state is unitary if it is organized under a single government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>16", "subject": "Government", "year": "1998", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET", "question": "In parliamentary system of government a vote of no confidence means expression of disapproval of", "images": [], "options": {"A": "Government 's general policies", "B": "The activities of the court of law", "C": "The opposition's methods of campaign", "D": "The activities of trade unions"}, "answer": "A", "explanation": "In a parliamentary system of government, a vote of no confidence is primarily targeted at the government and its policies. It is a statement or vote which states that a person(s) in a position of responsibility (government, managerial, etc.) is no longer deemed fit to hold that position, perhaps because they are inadequate in some respect, are failing to carry out obligations, or are making decisions that other members feel are detrimental. Therefore, a vote of no confidence means expression of disapproval of the government's general policies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>17", "subject": "Government", "year": "1998", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "A government shared by two authorities is called", "images": [], "options": {"A": "Diarchy", "B": "Theocracy", "C": "Gerontocracy", "D": "Aristocracy"}, "answer": "A", "explanation": "Diarchy, from the Greek δι- \"twice\" and αρχια, \"rule\", is a form of government in which two individuals, the diarchs, are the heads of state.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>18", "subject": "Government", "year": "1998", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "A singled-member constituency is one in which", "images": [], "options": {"A": "Two or more representatives are elected from one constituency", "B": "Only one candidate can contest election", "C": "Only one representative is elected from each constituency", "D": "Opposition candidates are not alloews to contest elections"}, "answer": "C", "explanation": "A single-member constituency is one in which only one representative is elected from each constituency. This is a type of electoral district that returns one officeholder to a body with multiple members such as a legislature. This is in contrast to multi-member constituencies, which elect more than one member to represent them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>19", "subject": "Government", "year": "1998", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PRESIDENTIAL", "question": "Presidential system of government allows the", "images": [], "options": {"A": "President to be a member of the legislature", "B": "President to elect ministers from outside the Legislature", "C": "Judiciary to be a part of the Executive", "D": "President to dismiss members of the Legislature"}, "answer": "B", "explanation": "In a presidential system of government, the president is both the head of state and head of government. The president is not a member of the legislature, but he/she has the power to choose his/her cabinet members, who are often referred to as ministers, from outside the legislature. This is to ensure the separation of powers, a fundamental principle in a presidential system of government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>20", "subject": "Government", "year": "1998", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : EXECUTIVE", "question": "The Executive arm of government refers to a body which", "images": [], "options": {"A": "Supervises councillors", "B": "Makes laws", "C": "Administers the law", "D": "Supervises elections"}, "answer": "C", "explanation": "The executive arm of government is responsible for implementing, administering, and enforcing the law. This includes carrying out the day-to-day administration of the state, executing the laws made by the legislature, maintaining order, and providing public services. The executive does not make laws (that's the role of the legislature) or supervise elections (that's usually the role of an independent electoral commission).", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1998>21", "subject": "Government", "year": "1998", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS", "question": "One major disadvantage of a two-party system is that", "images": [], "options": {"A": "Choice of political associations is limited", "B": "Choice of party candidates is without limit", "C": "Political education is for party members only", "D": "Party leaders are allowed to contest elections"}, "answer": "A", "explanation": "A two-party system is a form of party system where two major political parties dominate the political landscape. In such a system, the choice of political associations is limited because only two parties have a realistic opportunity to compete for and win elections. This limits the diversity of views that can be represented in the political system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>22", "subject": "Government", "year": "1998", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : EXECUTIVE", "question": "Which of the following methods can be used by the Legislature to check the Executive in a presidential system?", "images": [], "options": {"A": "Dissolution", "B": "Delegated Legislation", "C": "Court Injunction", "D": "Impeachment"}, "answer": "D", "explanation": "In a presidential system, the legislature can check the executive through impeachment. Impeachment is a process in which an official is accused of unlawful activity, the outcome of which, depending on the country, may include the removal of that official from office as well as criminal or civil punishment. Dissolution, Delegated Legislation, and Court Injunction are not methods used by the Legislature to check the Executive in a presidential system.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1998>23", "subject": "Government", "year": "1998", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Indirect election refers to an election that", "images": [], "options": {"A": "Is conducted through an electoral college", "B": "Allows voters to vote for themselves", "C": "Is solely organized by the citizens", "D": "Allows voter to cast their votes openly"}, "answer": "A", "explanation": "Indirect election refers to a system where citizens vote for representatives who then vote on the policies or individuals in question. This is typically done through an electoral college, which is a body of people representing the states of the US, who formally cast votes for the election of the president and vice president.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>24", "subject": "Government", "year": "1998", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "Universal adult suffrage means that only", "images": [], "options": {"A": "The wealthy class is allowed to contest elections", "B": "The educated class is allowed to vote", "C": "Eligible adults are allowed to vote and be voted for", "D": "Women are allowed to vote and be voted for"}, "answer": "C", "explanation": "Universal adult suffrage refers to the right of all adult citizens to vote in political elections, regardless of their wealth, education, gender, or social status. Therefore, it means that all eligible adults are allowed to vote and be voted for.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1998>25", "subject": "Government", "year": "1998", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : TYPES, MERITS AND DEMERITS", "question": "The system of election whereby each political party is given a percentage of seats that is equal to the percentage of popular votes cast in its favour is known as", "images": [], "options": {"A": "Absolute plurality", "B": "Proportional representation", "C": "Simple majority", "D": "Simple plurality"}, "answer": "B", "explanation": "Proportional representation (PR) refers to a type of electoral system under which subgroups of an electorate are reflected proportionately in the elected body.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>26", "subject": "Government", "year": "1998", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "Constitutional government means a government", "images": [], "options": {"A": "Run by constitutional lawyers", "B": "Without a constitution", "C": "That applies arbitrary rules", "D": "Subject to constitutional provisions"}, "answer": "D", "explanation": "A constitutional government is a government that is subject to constitutional provisions. This means that the government's powers are limited by a constitution, which is a set of fundamental principles or established precedents according to which a state or other organization is governed. The constitution defines the structure, functions, powers, and limits of the government and the rights of the citizens. Therefore, a constitutional government is not run by constitutional lawyers, it is not without a constitution, and it does not apply arbitrary rules.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>27", "subject": "Government", "year": "1998", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "A pressure group is a body of people organized for the purpose of", "images": [], "options": {"A": "Defending the nation", "B": "Exercising political power", "C": "Exercising influence on government", "D": "Collecting money for charitable concerns"}, "answer": "C", "explanation": "A pressure group is an organization that tries to influence public policy or legislation. They operate by exerting influence on government, not by directly exercising political power. Therefore, the correct answer is 'Exercising influence on government'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>28", "subject": "Government", "year": "1998", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "Public opinion is defined as the", "images": [], "options": {"A": "Opinion tonpolitical leaders and public officials", "B": "Expressed views of the active and conscious citizens", "C": "Published views of the ruling party", "D": "Opinion of the entire citizenry"}, "answer": "B", "explanation": "Public opinion is the collective opinion of the people of a society or state on an issue or problem. This concept came about through the process of urbanization and other political and social forces. It is not necessarily the opinion of the entire citizenry but the expressed views of the active and conscious citizens. Therefore, the correct answer is 'Expressed views of the active and conscious citizens'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>29", "subject": "Government", "year": "1998", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "One of the reasons for the establishment of a public corporation is to", "images": [], "options": {"A": "Undertake projects that require huge sums of money", "B": "Make profit for the government", "C": "Provide funds for the maintenance of political associations", "D": "Compete with local governments in the provision of social services"}, "answer": "A", "explanation": "Public corporations are established by the government to undertake projects that require huge capital outlay which is beyond the reach of private individuals or companies. These projects are usually of national importance and are aimed at providing essential services to the public. The government, through public corporations, can mobilize the necessary resources to undertake such projects.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1998>30", "subject": "Government", "year": "1998", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "The policy-making powers in a public corporation are vested in the", "images": [], "options": {"A": "Managing Director", "B": "Board of Directors", "C": "Chairman of Public Service Commission", "D": "Trade Unions"}, "answer": "B", "explanation": "In a public corporation, the policy-making powers are vested in the Board of Directors. The Board of Directors is responsible for setting the strategic direction of the corporation and making key decisions that affect the operation of the corporation. The Managing Director, Chairman of Public Service Commission, and Trade Unions do not have the authority to make policies for the corporation. They can contribute to policy-making through their roles, but the final decision rests with the Board of Directors.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1998>31", "subject": "Government", "year": "1998", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "Local governments can raise funds through", "images": [], "options": {"A": "Exercise duties", "B": "Import duties", "C": "Property rates", "D": "Income taxes"}, "answer": "C", "explanation": "Local governments have the authority to raise funds through property rates. Property rates are taxes that property owners pay based on the value of their property. The local government uses these funds to provide local services. Exercise duties, import duties, and income taxes are typically collected by the federal or state government, not the local government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>32", "subject": "Government", "year": "1998", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "The 1976 local government reforms in Nigeria ensure that local governments", "images": [], "options": {"A": "Are of the same size", "B": "Operate the same annual budgets", "C": "Are now independent of the federal government", "D": "Have the same functions and compositions"}, "answer": "C", "explanation": "It made them the third tier of government. This is the most accurate answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>33", "subject": "Government", "year": "1998", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "For purposes of local government elections, local government areas are generally divided into", "images": [], "options": {"A": "Constituencies", "B": "Zones", "C": "Regions", "D": "Wards"}, "answer": "D", "explanation": "For purposes of local government elections, local government areas are generally divided into Wards. A ward is a local authority area, typically used for electoral purposes. Wards are usually named after neighbourhoods, landmarks, geographical features and in some cases historical figures of significance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1998>34", "subject": "Government", "year": "1998", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "Neutrality of civil servants means that they", "images": [], "options": {"A": "Are free to do whatever they like", "B": "Should not take part in politics", "C": "Can be seen but must not be heard", "D": "Cannot be tried in court for misbehaviour"}, "answer": "B", "explanation": "Neutrality of civil servants means that they should not take part in politics. Civil servants are expected to be politically neutral in their job to ensure that the public service serves the government of the day in a politically impartial manner. This is to maintain public confidence in the civil service.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>35", "subject": "Government", "year": "1998", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY", "question": "The Unification Decree that turned Nigeria to a Unitary State was promulgated during the regime of General", "images": [], "options": {"A": "Muhammadu Buhari", "B": "Aguiyi Ironsi", "C": "Olusegun Obasnajo", "D": "Murtala Mohammed"}, "answer": "B", "explanation": "The Unification Decree that turned Nigeria to a Unitary State was promulgated during the regime of General Aguiyi Ironsi. The decree was known as Decree No. 34 of 1966 and it abolished the federal structure of the country and replaced it with a unitary system.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1998>36", "subject": "Government", "year": "1998", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI", "question": "The emirate system in the Hausa/Fulani traditional administration was", "images": [], "options": {"A": "Hierarchical", "B": "Unilateral", "C": "Democratic", "D": "Expensive"}, "answer": "A", "explanation": "The emirate system in the Hausa/Fulani traditional administration was hierarchical. This system was characterized by a well-defined administrative structure with the Emir at the top, followed by a hierarchy of officials, each with his own specific administrative responsibilities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>37", "subject": "Government", "year": "1998", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : IGBO", "question": "In the Igbo traditional political system, the Okpara was the", "images": [], "options": {"A": "Administrative head of his kindred", "B": "Priest", "C": "King", "D": "Commander-in chief of the army"}, "answer": "A", "explanation": "In the Igbo traditional political system, the Okpara was the administrative head of his kindred. The Okpara was responsible for the welfare of the kindred, and he was the one who represented the kindred in the village meetings. He was not a priest, king, or commander-in-chief of the army.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>38", "subject": "Government", "year": "1998", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "Nationalist movements started late in French West Africa because", "images": [], "options": {"A": "Africans were allowed to enlist in the army", "B": "Africans felt they were free", "C": "Africans wanted to maintain trade relations with France", "D": "France suppressed political associations and parties."}, "answer": "D", "explanation": "Nationalist movements started late in French West Africa because France suppressed political associations and parties. This suppression made it difficult for nationalist movements to gain momentum. The French colonial government was known for its policy of assimilation, which aimed to make Africans French citizens but also suppressed their political rights and freedoms. This is not related to Africans being allowed to enlist in the army, feeling free, or wanting to maintain trade relations with France.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1998>39", "subject": "Government", "year": "1998", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : YORUBA", "question": "An Oba in the traditional Yoruba political system was", "images": [], "options": {"A": "The executive head of his people", "B": "Ceremonial monarch only", "C": "War general only", "D": "The spokesman of his people"}, "answer": "B", "explanation": "He was checked by the Oyomesi. This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>40", "subject": "Government", "year": "1998", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : POST- INDEPENDENCE CONSTITUTIONS", "question": "Universal adult suffrage was first adopted throughout Nigeria under the constitution of", "images": [], "options": {"A": "1922", "B": "1979", "C": "1958", "D": "1960"}, "answer": "B", "explanation": "Only after the military coups of 1966-1978 was true universal suffrage granted under the 1979 Constitution of Nigeria.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1998>41", "subject": "Government", "year": "1998", "type": "Objective", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : FEATURES AND PROBLEMS", "question": "A recurrent problem of Nigerian federalism is", "images": [], "options": {"A": "National awareness", "B": "National unity", "C": "Assimilation", "D": "Dual citizenship"}, "answer": "B", "explanation": "The recurrent problem of Nigerian federalism is National unity. Federalism is a system of government in which powers are divided between a central authority and constituent political units. In Nigeria, the challenge has always been how to maintain unity in the midst of diverse ethnic, religious, and regional differences.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>42", "subject": "Government", "year": "1998", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : POST- INDEPENDENCE CONSTITUTIONS", "question": "One of the main features of the Republican Constitution adopted by Nigeria in 1963 was that the", "images": [], "options": {"A": "Office of the Governor-General was retained", "B": "Prime Minister became the Head of State", "C": "President became the Head of State", "D": "President was responsible to the Queen of England"}, "answer": "C", "explanation": "One of the main features of the Republican Constitution adopted by Nigeria in 1963 was that the President became the Head of State. This marked a shift from the previous system where the Queen of England was the symbolic Head of State and the Governor-General was her representative in Nigeria. The change to a republic meant that Nigeria was now fully independent and no longer owed any allegiance to the British monarchy.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1998>43", "subject": "Government", "year": "1998", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "In the 1922 Clifford Constitution of Nigeria", "images": [], "options": {"A": "All the members of the Executive Council were British", "B": "None of the members of the Executive Council were British", "C": "All the members of the Executive Council were Nigerians", "D": "All the members of the Executive Council were popularly elected"}, "answer": "A", "explanation": "The 1922 Clifford Constitution of Nigeria was a British colonial constitution. At that time, Nigeria was under British rule, and the Executive Council was made up of British officials. Therefore, all the members of the Executive Council were British.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1998>44", "subject": "Government", "year": "1998", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "Who among `the following nationalists founded the first political party in Nigeria?", "images": [], "options": {"A": "Nnamdi Azikiwe", "B": "Obafemi Awolowo", "C": "Samuel Akinsanya", "D": "Herbert Macaulay"}, "answer": "D", "explanation": "Herbert Macaulay is considered the founder of Nigerian nationalism and was one of the first Nigerian nationalists. He founded the Nigerian National Democratic Party (NNDP), the first political party in Nigeria, in 1923.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>45", "subject": "Government", "year": "1998", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : ACHIEVEMENTS AND FAILURES", "question": "A major problem of political parties in Nigeria during the First Republic was that all", "images": [], "options": {"A": "Were financially handicapped", "B": "Had poor leadership", "C": "Were tribally based", "D": "Failed to contest elections"}, "answer": "C", "explanation": "During the First Republic in Nigeria, political parties were largely tribally based. This was a major problem as it led to regionalism and tribalism, which hindered national unity and development. The parties were not financially handicapped as they had support from their regional governments. They did not have poor leadership, rather they had strong leaders who were, however, more focused on regional interests. They also did not fail to contest elections, in fact, they actively participated in the elections.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>46", "subject": "Government", "year": "1998", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "Which of the following political parties immediately succeeded the Nigerian Youth Movement?", "images": [], "options": {"A": "National Council of Nigeria and the Camerouns (NCNC)", "B": "Northern People's congress (NPC)", "C": "Nigerian National Democratic Party (NNDP)", "D": "Action Group (AG)"}, "answer": "A", "explanation": "Following fallouts in NYM, NCNC came aboard. This is the most accurate answer", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>47", "subject": "Government", "year": "1998", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "After the 1959 Elections in Nigeria, a coalition government was formed at the Centre by the", "images": [], "options": {"A": "Northern People's Congress and Northern Elememts Progressive Union", "B": "Northern people's Congress and National Council of Nigeria Citizens", "C": "Action Group and Northern Elements Progressive Union", "D": "National Council of Nigerian Citizens and Nothern Elements Progressive Union"}, "answer": "B", "explanation": "AG and UMBC formed the opposition. This is the most accurate answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>48", "subject": "Government", "year": "1998", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PRESIDENTIAL", "question": "The Kaduna State's Executive / Legislative Crisis of 1981 resulted in", "images": [], "options": {"A": "A declarationn of a state of emergency in the North", "B": "The impeachment and removal of the Governor of the State", "C": "The appointment of a presidential liaison officer to the State", "D": "Delayed election in the State"}, "answer": "B", "explanation": "The Kaduna State's Executive / Legislative Crisis of 1981 resulted in the impeachment and removal of the Governor of the State. This was due to a power tussle between the executive and legislative arms of government in the state, which led to a constitutional crisis. The crisis was resolved by the impeachment and removal of the governor by the state's House of Assembly.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1998>49", "subject": "Government", "year": "1998", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : ACHIEVEMENTS AND FAILURES", "question": "The dominant actors in the Action Group crisis of 1962 were", "images": [], "options": {"A": "Dauda Adegbenro and Adesoji Aderemi", "B": "Obafemi Awolowo and Ladoke Akintola", "C": "Anthony Enahoro and Bode Thomas", "D": "Adetokunbo Ademola and Fani Kayode"}, "answer": "B", "explanation": "The Action Group crisis of 1962 was a political crisis that occurred in Nigeria, and the dominant actors were Obafemi Awolowo and Ladoke Akintola. The crisis began when a faction of the Action Group party, led by Ladoke Akintola, disagreed with the party's leader, Obafemi Awolowo, over policy issues. This led to a split in the party, causing a political crisis in the Western Region of Nigeria.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1998>50", "subject": "Government", "year": "1998", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "Who founded the Unity Party of Nigeria in the Second Republic?", "images": [], "options": {"A": "Dr Nnamdi Azikiwe", "B": "Chief Michael Ajasin", "C": "Chief Obafemi Awolowo", "D": "Alhaji Shehu Shagari"}, "answer": "C", "explanation": "The Unity Party of Nigeria (UPN) was a Nigerian political party that was dominant in western Nigeria during the second republic (1978-1983). The party revolved around the political leadership of Obafemi Awolowo, a sometimes polemical politician but effective administrator.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>51", "subject": "Government", "year": "1998", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "The political party that controlled the Federal Government during the Second Republic in Nigeria was the", "images": [], "options": {"A": "Nigerian Advance Party (NAP)", "B": "Unity Party of Nigeria (UPN)", "C": "National Party of Nigeria (NPN)", "D": "Nigerian People's Party (NPP)"}, "answer": "C", "explanation": "The National Party of Nigeria (NPN) was the dominant political party in Nigeria during the Second Republic (1979–1983).", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>52", "subject": "Government", "year": "1998", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "The 1953 motion for self-government now in Nigeria was moved by", "images": [], "options": {"A": "Alhaji Tafawa Balawa", "B": "Alhaji Ahmadu Bello", "C": "Chief Anthony Enahoro", "D": "Mallam Aminu Kano"}, "answer": "C", "explanation": "The 1953 motion for self-government in Nigeria was moved by Chief Anthony Enahoro. He was a member of the Action Group party and he moved the motion in the House of Representatives in 1953. The motion was for Nigeria to gain independence from British colonial rule in 1956. However, the motion was not successful at the time due to opposition from the Northern representatives who felt that the North was not ready for independence.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>53", "subject": "Government", "year": "1998", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI", "question": "One of the major functions of the emir in the Hausa-Fulani traditional political system was to", "images": [], "options": {"A": "Organize the people for communal worship only", "B": "Interpret all laws", "C": "Influence elections in his emirate", "D": "Levy collect and spend taxes"}, "answer": "D", "explanation": "In the Hausa-Fulani traditional political system, the Emir was the administrative and spiritual leader of his emirate. One of his major functions was to levy, collect and spend taxes. The taxes were used for the administration of the emirate and for providing security and other social services. The Emir did not organize the people for communal worship only, interpret all laws, or influence elections in his emirate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>54", "subject": "Government", "year": "1998", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The traditional system of government in pre-colonial Nigeria was based largely on", "images": [], "options": {"A": "Socialism", "B": "Fascism", "C": "Communalism", "D": "Capitalism"}, "answer": "C", "explanation": "The traditional system of government in pre-colonial Nigeria was based largely on communalism. Communalism is a system of government in which virtually all members of a community participate in decision making and in which there is common ownership of property. It is not based on socialism, fascism, or capitalism.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>55", "subject": "Government", "year": "1998", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "Which of the following bodies may regarded as a regional organization?", "images": [], "options": {"A": "OAU", "B": "UNO", "C": "Commonwealth", "D": "ECOWAS"}, "answer": "D", "explanation": "A regional organization is an international organization that involves countries from a specific region. The Economic Community of West African States (ECOWAS) is a regional political and economic union of fifteen countries located in West Africa. Therefore, ECOWAS can be regarded as a regional organization.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1998>56", "subject": "Government", "year": "1998", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The non-permanent members of the Security Council of the United Nations Organization are appointed for a period of", "images": [], "options": {"A": "One year", "B": "Two years", "C": "Three years", "D": "Four years"}, "answer": "B", "explanation": "The non-permanent members of the Security Council of the United Nations Organization are elected for a term of two years. The United Nations Security Council is one of the six main organs of the UN, charged with ensuring international peace and security, accepting new members to the United Nations and approving any changes to its charter.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>57", "subject": "Government", "year": "1998", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The most representative organ of the United Nations Organization is the", "images": [], "options": {"A": "Security Council", "B": "Economic and Social Council", "C": "General Assembly", "D": "Trusteeship"}, "answer": "C", "explanation": "The General Assembly is the most representative organ of the United Nations Organization because it is the only one in which all 193 member countries have equal representation: one nation, one vote. The General Assembly meets once a year in a regular session and in special or emergency sessions when needed. During these sessions, the entire international community comes together to discuss and work on a wide array of international issues covered by the UN Charter.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>58", "subject": "Government", "year": "1998", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The veto power in the United Nations Organization (UNO) is exercised by", "images": [], "options": {"A": "All members of the Security Council", "B": "The permanent members of the Security Council", "C": "Members of the International Court of Justice", "D": "All members of the General Assembly"}, "answer": "B", "explanation": "The veto power in the United Nations Organization (UNO) is exercised by the five permanent members of the Security Council. These members are the United States, the United Kingdom, France, Russia, and China. The 'veto power' refers to the power of these permanent members to block any resolution in the Security Council, even if it has received the required number of votes. This power is not held by any other members of the UN.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>59", "subject": "Government", "year": "1998", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The international Court of Justice has it headquarters in", "images": [], "options": {"A": "The Hague", "B": "Paris", "C": "London", "D": "New York"}, "answer": "A", "explanation": "The International Court of Justice (ICJ) is the principal judicial organ of the United Nations (UN). It was established in June 1945 by the Charter of the United Nations and began work in April 1946. The seat of the Court is at the Peace Palace in The Hague (Netherlands).", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1998>60", "subject": "Government", "year": "1998", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "The commission or Mediation, Conciliation and Arbitration is an organ of the", "images": [], "options": {"A": "ECOWAS", "B": "OAU", "C": "Commonwealth", "D": "UNESCO"}, "answer": "B", "explanation": "The Commission of Mediation, Conciliation and Arbitration is an organ of the Organization of African Unity (OAU), now known as the African Union (AU). It was established to peacefully resolve disputes among member states.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1999>1", "subject": "Government", "year": "1999", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Political power is concerned with the", "images": [], "options": {"A": "Allocation of resources and enforcement of decisions", "B": "Use of force to ensure compliance", "C": "Process of winning wars by the military", "D": "Formation of pressure groups"}, "answer": "B", "explanation": "The political power definition in government is the ability of an individual or a group of people to influence the thoughts, actions, and mindset of people in a nation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>2", "subject": "Government", "year": "1999", "type": "Objective", "topic": "CONSTITUTIONS : FUNCTIONS", "question": "The essence of the constitution is to", "images": [], "options": {"A": "Safeguard the rights and freedom of the citizens", "B": "Ensure tyranny and oppression of the masses", "C": "Encourage military intervention in politics", "D": "Suppress the views of the minority groups"}, "answer": "A", "explanation": "The essence of a constitution is to safeguard the rights and freedom of the citizens. A constitution is a set of fundamental principles or established precedents according to which a state or other organization is governed. These rules together make up, i.e. constitute, what the entity is. It is the highest law of the land and it is designed to protect the rights and freedoms of the citizens, not to suppress them or encourage military intervention.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>3", "subject": "Government", "year": "1999", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "In democracy, political sovereignty resides with the", "images": [], "options": {"A": "Judiciary", "B": "Legislature", "C": "Electorate", "D": "President"}, "answer": "C", "explanation": "In a democracy, political sovereignty resides with the electorate. This is because in a democratic system, the power to choose leaders and make decisions lies with the people, who exercise this power through voting. The electorate refers to all the people in a country or area who are entitled to vote in an election.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>4", "subject": "Government", "year": "1999", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The highest stage of socialism is", "images": [], "options": {"A": "Racism", "B": "Fascism", "C": "Communism", "D": "Nazism"}, "answer": "C", "explanation": "Communism is an ideology or system based on the idea that the property of a community should be owned collectively and shared among everyone.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1999>5", "subject": "Government", "year": "1999", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Feudalism is a practice in which", "images": [], "options": {"A": "The citizens have no political and social rights", "B": "Hereditary landlords ruled peasants", "C": "Political leadership is based on force", "D": "The social structure is stratified"}, "answer": "B", "explanation": "Feudalism is a historical system of power dispersed and balanced between the king and his nobles. In this system, hereditary landlords ruled over the peasants who lived on their lands, and these peasants would in turn provide services to the landlord. The services often included labor and soldiers for the landlord's military campaigns.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1999>6", "subject": "Government", "year": "1999", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The rule of the privileged nobility is referred to as", "images": [], "options": {"A": "Plutocracy", "B": "Monarchy", "C": "Aristocracy", "D": "Autocracy"}, "answer": "C", "explanation": "Aristocracy is a form of government that places strength in the hands of a small, privileged ruling class, the aristocrats.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1999>7", "subject": "Government", "year": "1999", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "The rights to freedom of speech means that people are free to", "images": [], "options": {"A": "Express anything they like about government", "B": "Disobey the government of the day", "C": "Express opinion within the limits of the law", "D": "Participate in government"}, "answer": "C", "explanation": "The right to freedom of speech allows individuals to express their opinions, ideas, and beliefs. However, this freedom is not absolute and is subject to certain limitations to prevent harm to others, such as defamation, incitement to violence, or hate speech. Therefore, people are free to express their opinion within the limits of the law.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>8", "subject": "Government", "year": "1999", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "A federal constitution is usually", "images": [], "options": {"A": "Flexible", "B": "Unwritten", "C": "Written and flexible", "D": "Written and rigid"}, "answer": "D", "explanation": "A federal constitution is a system of government in which power is divided between a central authority and constituent political units. It is usually written and rigid. 'Written' means that the laws, rights, and obligations are documented in a single text. 'Rigid' means that the process of amending or changing the constitution is difficult and involves more than a simple majority. This is to ensure stability and protect the rights of the minority from the whims of the majority.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>9", "subject": "Government", "year": "1999", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "The end of each session of the legislature is called", "images": [], "options": {"A": "Dissolution", "B": "Suspension", "C": "Closure", "D": "Prorogation"}, "answer": "D", "explanation": "Prorogation in the Westminster system of government is the action of proroguing, or interrupting, a parliament, or the discontinuance of meetings for a given period of time, without a dissolution of parliament.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>10", "subject": "Government", "year": "1999", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET", "question": "The political effect of the removal of the Prime Minister under a parliamentary system of government is", "images": [], "options": {"A": "A general election", "B": "The suspension of the ministers", "C": "The suspension of the constitution", "D": "The dissolution of the courts of law"}, "answer": "A", "explanation": "The political effect of the removal of the Prime Minister under a parliamentary system of government is a general election. In a parliamentary system, the Prime Minister is the head of government and his/her removal usually triggers a general election to choose a new leader. The other options do not accurately describe the political effects of the Prime Minister's removal.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1999>11", "subject": "Government", "year": "1999", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET", "question": "The Chief Executive in a parliamentary system of government is known as the", "images": [], "options": {"A": "President", "B": "Speaker", "C": "Prime Minister", "D": "Governor-General"}, "answer": "C", "explanation": "In a parliamentary system of government, the Chief Executive is known as the Prime Minister. The Prime Minister is the head of government in a parliamentary system. The Prime Minister leads the executive branch of government, commands the majority in the parliament and is the leader of the cabinet.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1999>12", "subject": "Government", "year": "1999", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Which of the following is basic feature of the rule of law?", "images": [], "options": {"A": "Equality before the law", "B": "Secret trial of offenders", "C": "Exective control of the Judiciary", "D": "Unlimited powers for the police"}, "answer": "A", "explanation": "A basic feature of the rule of law is 'Equality before the law'. This means that all individuals, regardless of their status, are subject to the same laws of the land. The rule of law is a principle that ensures that all individuals, institutions, and entities are accountable to laws that are publicly promulgated, equally enforced, and independently adjudicated.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>13", "subject": "Government", "year": "1999", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "Which of the following is usually expected to be entrenched in a constitution?", "images": [], "options": {"A": "Ownership of landed property", "B": "Fundamental human rights", "C": "Electoral rules and regulations", "D": "Registration of political parties"}, "answer": "B", "explanation": "A constitution is a set of fundamental principles or established precedents according to which a state or other organization is governed. These rules together make up, i.e. constitute, what the entity is. Fundamental human rights are usually entrenched in a constitution to protect the citizens from any form of violation or abuse. These rights are considered basic to the existence and well-being of every individual in the society, hence they are constitutionally provided for and protected.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>14", "subject": "Government", "year": "1999", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "One of the advantages of delegated legislation is that it", "images": [], "options": {"A": "Lessens the work of parliament", "B": "Lessens the work of legal draftsmen", "C": "Reduces the power of the local authority", "D": "Makes parliament more popular with the pople"}, "answer": "A", "explanation": "Delegated legislation is a kind of secondary legislation where the legislative power is transferred to an individual or body under powers given to them by an Act of Parliament. One of the advantages of delegated legislation is that it lessens the work of parliament. This is because it allows the time of Parliament to be freed up as Parliament simply does not have the time to debate and consider every small detail. Therefore, Parliament can focus on more important matters and allow others to decide on the less important details.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>15", "subject": "Government", "year": "1999", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Elections are held for the purpose of", "images": [], "options": {"A": "Strengtnening the powers of the political leaders", "B": "Ensuring a peaceful change of government", "C": "Creating more political parties", "D": "Uniting the people of a country"}, "answer": "B", "explanation": "Elections are held for the purpose of ensuring a peaceful change of government. This is because elections provide a democratic way for citizens to choose their leaders. It allows for a peaceful transition of power from one leader or party to another, thereby preventing potential conflicts or violence that could arise from power struggles.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1999>16", "subject": "Government", "year": "1999", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "A multi-member constituency is one in which", "images": [], "options": {"A": "Two or more parties are allowed to contest elections", "B": "Franchise is restricted", "C": "The electorate is entitled to vote only once", "D": "Two or more representatives are elected from one constituency"}, "answer": "D", "explanation": "A multi-member constituency is one in which two or more representatives are elected from one constituency. This is a type of electoral system where more than one legislative seat is contested in each electoral district. It contrasts with single-member constituencies, where only one candidate is elected per electoral district.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>17", "subject": "Government", "year": "1999", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : EXECUTIVE", "question": "In a democracy, which of the following can exert appreciable control on the activities of the Executive?", "images": [], "options": {"A": "Military", "B": "Legislature", "C": "Traditional Rulers", "D": "Police"}, "answer": "B", "explanation": "In a democracy, the Legislature can exert appreciable control on the activities of the Executive. This is because in a democratic system of government, the principle of separation of powers is practiced. This principle ensures that the three arms of government (Executive, Legislature, and Judiciary) are independent and can check the activities of each other. The Legislature, in particular, has the power to make laws and scrutinize the activities of the Executive.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>18", "subject": "Government", "year": "1999", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Universal Adult Suffrage is an dispensable factor in the practice of", "images": [], "options": {"A": "Constitutionalism", "B": "Socialism", "C": "Democracy", "D": "Oligarchy"}, "answer": "C", "explanation": "Universal Adult Suffrage is an indispensable factor in the practice of Democracy. Universal Adult Suffrage refers to the right of all adult citizens to vote in an election, regardless of their gender, race, or social status. This is a fundamental principle in a democratic system of government where the power of governance is derived from the people. The people express their will and choose their leaders through voting, hence the importance of Universal Adult Suffrage.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>19", "subject": "Government", "year": "1999", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "In federations, concurrent list of powers is usually given to the", "images": [], "options": {"A": "Federal government", "B": "Regional units", "C": "Central authority and regional units", "D": "Regional units and local authorities"}, "answer": "C", "explanation": "In federations, the concurrent list of powers is usually given to both the central authority and regional units. This means that both levels of government have the authority to make laws on matters that fall within the concurrent list. The idea behind this is to ensure a balance of power and prevent any one level of government from becoming too powerful.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1999>20", "subject": "Government", "year": "1999", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "In the Organizational structure of a mass political party, the policy making body is the", "images": [], "options": {"A": "Secretary General of the party", "B": "National Executive Committee", "C": "National Chairman", "D": "Parliamentary Committee of the party"}, "answer": "B", "explanation": "In the organizational structure of a mass political party, the policy making body is usually the National Executive Committee. This committee is typically responsible for making major decisions and setting the overall direction of the party. The Secretary General, National Chairman, and Parliamentary Committee of the party all play important roles within the party, but they do not typically have the same level of decision-making authority as the National Executive Committee.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1999>21", "subject": "Government", "year": "1999", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "Judicial review means the process by which", "images": [], "options": {"A": "Judges review past court decisions and judgements", "B": "The court determine the constitutionality of the actions of rulers", "C": "Judiccial precedents are implemented", "D": "The court settles disputes between citizens and government"}, "answer": "B", "explanation": "Judicial review is a process under which executive or legislative actions are subject to review by the judiciary. A court with judicial review power may invalidate government laws, decisions, actions if they are found to be unconstitutional. Therefore, the correct answer is 'The court determines the constitutionality of the actions of rulers'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>22", "subject": "Government", "year": "1999", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Which of the following controls government expenditure ?", "images": [], "options": {"A": "The Courts", "B": "The Police", "C": "The Treasury", "D": "The Public"}, "answer": "C", "explanation": "Government expenditure is controlled by the Treasury. The Treasury is the government department responsible for managing the country's public finances, including revenues and expenditures. Therefore, the correct answer is 'The Treasury'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>23", "subject": "Government", "year": "1999", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "One -party system of government may lead to", "images": [], "options": {"A": "Stateless society", "B": "Autocracy", "C": "Liberal democracy", "D": "Oligarchy"}, "answer": "B", "explanation": "Autocracy is a system of government in which absolute power over a state is concentrated in the hands of one person.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>24", "subject": "Government", "year": "1999", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "A cardinal feature of a rigid constitution is that it", "images": [], "options": {"A": "Can only be amended by the Judiciary", "B": "Requires the votes of the electorate for its amendment", "C": "Requires 2/3 majority for its amendment", "D": "Requires of special procedure for its amendment"}, "answer": "D", "explanation": "A cardinal feature of a rigid constitution is that it requires a special procedure for its amendment. A rigid constitution is one that requires a special procedure that is more difficult than the ordinary legislative process. This is to ensure that changes are not made lightly and that they reflect a broad consensus in society.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1999>25", "subject": "Government", "year": "1999", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "The life of the legislature comes to an end during", "images": [], "options": {"A": "Prorogation", "B": "Adjournment", "C": "Dissolution", "D": "The end of a session"}, "answer": "C", "explanation": "Dissolution of a legislative assembly (or parliament) is the mandatory simultaneous resignation of all of its members, in anticipation that a successive legislative assembly will reconvene later with possibly different members. In a democracy, the new assembly is chosen by a general election.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>26", "subject": "Government", "year": "1999", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A feature of democratic government is that it is", "images": [], "options": {"A": "Authoriatarian and totalitarian", "B": "Brutal and repressive", "C": "Firm and disciplined", "D": "Representative and accountable"}, "answer": "D", "explanation": "A feature of democratic government is that it is representative and accountable. Authoritarian and totalitarian governments are characterized by a lack of political pluralism and are often characterized by absolute power centralized in a leader or a small group. Brutal and repressive governments use force and intimidation to control the population. Firm and disciplined can describe any type of government, not just democratic ones. Representative and accountable governments, on the other hand, are characterized by elected officials representing the people and being accountable to them.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1999>27", "subject": "Government", "year": "1999", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "According to Marxism, those who own and control productive resources in a capitalist state are", "images": [], "options": {"A": "Unionist", "B": "Workers", "C": "Exploiters", "D": "Managers"}, "answer": "C", "explanation": "According to Marxism, those who own and control productive resources in a capitalist state are referred to as the bourgeoisie or the capitalist class. They are often seen as exploiters because they profit from the labor of the working class (proletariat). Therefore, the term 'Exploiters' is the most appropriate choice among the given options.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>28", "subject": "Government", "year": "1999", "type": "Objective", "topic": "CITIZENSHIP : MEANING AND MODE OF ACQUISITION", "question": "A foreigner can become a citizen of another state by", "images": [], "options": {"A": "Immigration", "B": "Naturalization", "C": "Nationalization", "D": "Indigenization"}, "answer": "B", "explanation": "Naturalization (or naturalisation) is the legal act or process by which a non-citizen of a country may acquire citizenship or nationality of that country.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>29", "subject": "Government", "year": "1999", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "Local government laws are known as", "images": [], "options": {"A": "Decrees", "B": "Acts", "C": "Bye-laws", "D": "Orders"}, "answer": "C", "explanation": "Local government laws are known as Bye-laws. Bye-laws are laws that are passed by local government or corporations and apply only within their specific areas or to their specific functions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1999>30", "subject": "Government", "year": "1999", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET", "question": "The passing of a vote of no confidence is a method of removing the Executive in a", "images": [], "options": {"A": "Parliamentary system of government", "B": "Military system government", "C": "Presidential system of government", "D": "Confederal system of government"}, "answer": "A", "explanation": "The passing of a vote of no confidence is a method of removing the Executive in a Parliamentary system of government. In a parliamentary system, the executive is accountable to the legislature, and the legislature can express its lack of support for the executive by passing a vote of no confidence, which usually leads to the resignation of the executive or a call for new elections.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1999>31", "subject": "Government", "year": "1999", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "The major function of an electoral commission is to", "images": [], "options": {"A": "Appoint members of the judiciary", "B": "Appoint the staff of local government", "C": "Announce the dissolution of the assembly", "D": "Make arrangements for the conduct of elections"}, "answer": "D", "explanation": "The major function of an electoral commission is to make arrangements for the conduct of elections. An electoral commission is an independent body, typically established by the constitution or legislation, whose duty is to supervise the conduct of elections. This includes tasks such as voter registration, ballot design and distribution, supervision of polling, vote counting, and declaration of results.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1999>32", "subject": "Government", "year": "1999", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Free and fair election can exist where there is", "images": [], "options": {"A": "Double voting", "B": "Secret balloting", "C": "Referendum", "D": "Plebiscite"}, "answer": "B", "explanation": "Free and fair elections can exist where there is secret balloting. Secret balloting is a voting method in which a voter's choices in an election or a referendum are anonymous. This is intended to ensure the voter records a sincere choice by forestalling attempts to influence the voter by intimidation or bribery. The system is one means of achieving the goal of political privacy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>33", "subject": "Government", "year": "1999", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "An election, held to resolve important political question facing a country is called", "images": [], "options": {"A": "Referendum", "B": "Bye-election", "C": "General election", "D": "Primary election"}, "answer": "A", "explanation": "A referendum is a direct and universal vote in which an entire electorate is invited to vote on a particular proposal or important political question. This may result in the adoption of a new policy or specific law. In contrast, a bye-election is held to fill a political office that has become vacant between regularly scheduled elections. General elections are held to elect a representative or representatives, while primary elections are used by political parties to select candidates for a subsequent election.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>34", "subject": "Government", "year": "1999", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "Public opinion enables the government to", "images": [], "options": {"A": "Find out what the people think about its activities", "B": "Organize political conferences and solidarity rallies", "C": "Punish political opponents", "D": "Employ more workers"}, "answer": "A", "explanation": "Public opinion is a collective expression of the general population's thoughts on a particular political issue or government activity. It enables the government to understand what the people think about its activities, which can guide policy-making and decision-making processes. The other options do not accurately describe the role of public opinion in government.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1999>35", "subject": "Government", "year": "1999", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "The main objective of pressure groups is to", "images": [], "options": {"A": "Influence the public", "B": "Influence government decisions", "C": "Organize strikes and demonstrations", "D": "Criticize the government"}, "answer": "B", "explanation": "Pressure groups are organized groups of people who share common interests or issues and seek to influence public policy and decision making. They do this by lobbying government officials, participating in public debates, and using various forms of advocacy to influence public opinion and government decisions. Therefore, the main objective of pressure groups is to influence government decisions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>1999>36", "subject": "Government", "year": "1999", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "A major weakness of one-party system is that it", "images": [], "options": {"A": "Does not aggregate public opinion", "B": "Negates the principle of one man one vote", "C": "Ensures freedom of political choice", "D": "Encourages dictatorship"}, "answer": "D", "explanation": "A one-party system is a type of state in which one political party has the right to form the government, usually based on the existing constitution. All other parties are either outlawed or allowed to take only a limited and controlled participation in elections. Such a system is often criticized for leading to dictatorship, as it lacks political competition and checks and balances that are seen in a multi-party system. Therefore, a major weakness of one-party system is that it encourages dictatorship.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>37", "subject": "Government", "year": "1999", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "One of the important of political parties is", "images": [], "options": {"A": "Educating the electorate through rallies and campaigns", "B": "Organizing international conference", "C": "Advising on the appointment of judges", "D": "Hiring personnel for political leader"}, "answer": "A", "explanation": "Political parties play a crucial role in educating the electorate about their policies, manifestos, and candidates through rallies and campaigns. This helps voters make informed decisions during elections. Organizing international conferences, advising on the appointment of judges, and hiring personnel for political leaders are not primary functions of political parties.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>38", "subject": "Government", "year": "1999", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : IGBO", "question": "The traditional political rule in pre-colonial British West Africa was characterized by", "images": [], "options": {"A": "Anarchy", "B": "Separation of powers", "C": "Tyrannical rule", "D": "Rule by consent"}, "answer": "D", "explanation": "The traditional political rule in pre-colonial British West Africa was characterized by rule by consent. This means that the leaders ruled with the consent and approval of the people. Anarchy, separation of powers, and tyrannical rule do not accurately describe the political system during this period.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1999>39", "subject": "Government", "year": "1999", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "To implement Indirect Rule in Eastern Nigeria, the British appointed", "images": [], "options": {"A": "Village heads", "B": "Warrant chiefs", "C": "Ozo title holders", "D": "Aba women as head"}, "answer": "B", "explanation": "The warrant chief system emanated as a matter of necessity from the lack of preexisting chieftaincy traditions in some parts of Africa. There were parts of British colonial territories, such as the Igbo region of eastern Nigeria, which had no tradition of chieftaincy intuitions.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1999>40", "subject": "Government", "year": "1999", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "The colonial governor whose constitution introduced elective principle into the Nigerian politics was", "images": [], "options": {"A": "Arthur Richards", "B": "Frederick Lugard", "C": "Hugh Clifford", "D": "John Macpherson"}, "answer": "C", "explanation": "The colonial governor whose constitution introduced elective principle into the Nigerian politics was Hugh Clifford. The Clifford Constitution of 1922 was the first to introduce the elective principle, albeit limited, into the legislative council. The constitution provided for the election of four members to the legislative council from Lagos and Calabar.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1999>41", "subject": "Government", "year": "1999", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PRESIDENTIAL", "question": "The system of government recommended by the 1979 Constitution of Nigeria was the", "images": [], "options": {"A": "Feudal system", "B": "Unitary system", "C": "Parliamentary system", "D": "Presidential system"}, "answer": "D", "explanation": "The 1979 Constitution of Nigeria recommended the Presidential system of government. In a Presidential system, the president is both the head of state and the head of government, and has a fixed term of office. The president is also the chief executive officer, responsible for the execution of laws and policies, and is not directly responsible to the legislature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>42", "subject": "Government", "year": "1999", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : ACHIEVEMENTS AND FAILURES", "question": "The first president of the Nigerian republic was", "images": [], "options": {"A": "Obafemi Awolowo", "B": "Nnamdi Azikiwe", "C": "Ahmadu Bello", "D": "Emeka Anyaoku"}, "answer": "B", "explanation": "The first president of the Nigerian republic was Nnamdi Azikiwe. He served as the first President of Nigeria from 1963 to 1966. He is considered a key figure in the history of Nigeria, advocating for a united and independent nation during his time in politics.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>43", "subject": "Government", "year": "1999", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "Which of the following ideological groups was in existence before the formation of the Organization of African Unity (OAU)?", "images": [], "options": {"A": "Cassablanca, Lagos, and Monrovia group", "B": "Brazzaviile, Lome, and Accra group", "C": "Cassablanca, Brazzaviile, Conakry group", "D": "Cassablanca, Brazzaviile, Monrovia group"}, "answer": "D", "explanation": "The Casablanca Group emerged in 1961, comprising seven countries: Algeria, Egypt, Ghana, Guinea, Libya, Mali and Morocco. The Monrovia Group comprised the twelve countries of the Brazzaville Group as well as Ethiopia, Liberia, Nigeria, Sierra Leone, Somalia, Togo, Tunisia and Congo (Kinshasa).", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1999>44", "subject": "Government", "year": "1999", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "The best way to keep military out of politics in developing countries is to", "images": [], "options": {"A": "Pay soldiers better salaries", "B": "Imprison coup plotters", "C": "Outlaw coup planning", "D": "Ensure good governance"}, "answer": "D", "explanation": "The best way to keep the military out of politics in developing countries is to ensure good governance. Good governance includes aspects like transparency, accountability, rule of law, and participation. When these aspects are upheld, the need for military intervention in politics is reduced. Paying soldiers better salaries, imprisoning coup plotters, or outlawing coup planning may not necessarily prevent military intervention in politics if the underlying issues of poor governance are not addressed.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1999>45", "subject": "Government", "year": "1999", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "The greatest achievement of nationalist movements in West Africa was the", "images": [], "options": {"A": "Interference in the affairs of member nations", "B": "Formation of democratic governments in the sub-region", "C": "Attainment of independence by member states", "D": "Formation of a regional peace keeping force"}, "answer": "C", "explanation": "The greatest achievement of nationalist movements in West Africa was the attainment of independence by member states. Nationalist movements in West Africa were primarily focused on achieving independence from colonial rule. They sought to end foreign domination and establish self-rule. This was achieved when countries like Nigeria, Ghana, Sierra Leone, and others gained independence in the late 1950s and early 1960s.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>46", "subject": "Government", "year": "1999", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "Which of the following links the Commonwealth countries together?", "images": [], "options": {"A": "Currency", "B": "Electoral system", "C": "The political system", "D": "The English language"}, "answer": "D", "explanation": "The English language is the primary link between Commonwealth countries. The Commonwealth is a political association of 54 member states, nearly all of which are former territories of the British Empire. The English language, being the official language of the British Empire, was adopted by these countries and has remained a common medium of communication among them. Although they also share other aspects like similar political systems and legal structures, these are not as universal as the English language.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>47", "subject": "Government", "year": "1999", "type": "Objective", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "The implementation of Nigerian foreign policy during the first republic (1960-1966) was basically", "images": [], "options": {"A": "Pro-Western", "B": "Pro-Eastern", "C": "African-centered", "D": "Pro-Asian"}, "answer": "A", "explanation": "This is because the country is newly independent and affiliated to the British.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>1999>48", "subject": "Government", "year": "1999", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "The first West African to become the Secretary General of the Commonwealth is", "images": [], "options": {"A": "Emeka Anyaoku", "B": "Agboola Gambari", "C": "Arnold Smith", "D": "Shridath Ramphal"}, "answer": "A", "explanation": "The first West African to become the Secretary General of the Commonwealth is Emeka Anyaoku. He served as the third Secretary-General of the Commonwealth of Nations from 1990 to 2000. The Commonwealth is a political association of 54 member states, nearly all of which are former territories of the British Empire.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>49", "subject": "Government", "year": "1999", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The organ of the United Nations responsible for negotiating agreements with the specialized agencies is the", "images": [], "options": {"A": "General Assembly", "B": "Security Council", "C": "Economic and Social Council", "D": "Trusteeship Council"}, "answer": "C", "explanation": "The Economic and Social Council (ECOSOC) is the organ of the United Nations responsible for coordinating the economic, social, and related work of 15 UN specialized agencies, their functional commissions and five regional commissions. ECOSOC serves as the central forum for discussing international economic and social issues, and for formulating policy recommendations addressed to member states and the United Nations system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>1999>50", "subject": "Government", "year": "1999", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "Which of the following is the most powerful organ of the United Nations?", "images": [], "options": {"A": "Trusteeship Council", "B": "Security Council", "C": "Council of Ministers", "D": "Secretariat"}, "answer": "B", "explanation": "The Security Council is the most powerful organ of the United Nations. It has primary responsibility, under the UN Charter, for the maintenance of international peace and security. A change to the UN Charter can only be made by a two-thirds vote of the General Assembly and ratification by two-thirds of the Member States, including all five permanent members of the Security Council, which are China, France, Russia, the United Kingdom, and the United States.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2000>1", "subject": "Government", "year": "2000", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN INSTITUTION OF THE STATE:", "question": "Government  as an institution of a state can best be defined as a body that?", "images": [], "options": {"A": "Recruits and trains political leaders", "B": "Settles disputes and interpretes laws for the state", "C": "Legislates,executes and interprete laws for the state", "D": "Conducts elections for the state"}, "answer": "C", "explanation": "The government acts as an agency or machinery by which the state maintain its existence and carries out its function. The government legislates, executes and interprets laws for the state.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2000>2", "subject": "Government", "year": "2000", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Political authority  is the?", "images": [], "options": {"A": "Legitimate right to exercise political power", "B": "Ability to control political campaigns", "C": "Right to participate in political campaigns", "D": "Right to form political parties"}, "answer": "A", "explanation": "Politics is the set of activities that are associated with the governance of a country, state or area. While political authority is the power held by a political entity to require action and claim obedience to its rules. It is the legitimate right to exercise political powers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2000>3", "subject": "Government", "year": "2000", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The rule of law  refers to the principle of?", "images": [], "options": {"A": "Legality and impartiality", "B": "The supreme power of rulers", "C": "The immunity of judges from legal actions", "D": "The orderly execution of government policies"}, "answer": "A", "explanation": "Rule of law is the absolute supremacy of the law over everybody both the rulers and the ruled. It is the principle of legality and partiality.  Rule of law in simple language shows that nobody is above the law, whether they are wealthy and powerful people or they are the poor and common people.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2000>4", "subject": "Government", "year": "2000", "type": "Objective", "topic": "CITIZENSHIP : MEANS OF SAFEGUARDING RIGHTS OF CITIZENS.", "question": "Freedom of speech  is a fundamental human right employed by citizens but it may be limited if", "images": [], "options": {"A": "Loyalty is not shown to the ruling party", "B": "It exposes the wrong-doings of the government", "C": "It endangers the security of the state", "D": "It is used to cause embarrassment to the judiciary"}, "answer": "C", "explanation": "The security of the state or a nation is very important and if it is threatened by an individual's speech, in such case freedom of speech may be limited or infringed upon.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2000>5", "subject": "Government", "year": "2000", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "Which of the following is an obligation of a citizen?", "images": [], "options": {"A": "Attending political rallies", "B": "Taking part in independence day celebration", "C": "Contesting elections", "D": "Paying respect to the national flag"}, "answer": "D", "explanation": "Of the options listed the only obligation is paying respect to the national flag, which is a sign of patriotism.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2000>6", "subject": "Government", "year": "2000", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The extent to which the citizens regard the institutions,officials and activities of government as right and acceptable is known as?", "images": [], "options": {"A": "Power", "B": "Legitimacy", "C": "Influence", "D": "Authority"}, "answer": "B", "explanation": "Legitimacy is the extent to which citizens regard the institutions, officials, and activities of the government as right and acceptable.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2000>7", "subject": "Government", "year": "2000", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Diplomatic immunity is a limitation to?", "images": [], "options": {"A": "The theory of separation of powers", "B": "Principles of checks and balances", "C": "Parliamentary supremacy", "D": "The rule of law"}, "answer": "D", "explanation": "The rule of law in simple terms state that NOBODY is above the law, but one of its limitation is DIPLOMATIC IMMUNITY.  Diplomatic immunity is the privilege of exemption from certain LAWS and taxes granted to diplomats by the state in which they are working. It is a principle of international law that limits the degree to which foreign government and government international organization officials and employees are subjected to police officers and judges in their country of assignment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2000>8", "subject": "Government", "year": "2000", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "A federal state is always expensive to run because?", "images": [], "options": {"A": "Every parliamentarian wants to be rich", "B": "Government departments are duplicated", "C": "Judges are highly paid from the consolidated fund", "D": "Maintenance of the army involves high expenditure"}, "answer": "B", "explanation": "Federalism/federal system of government leads to unnecessary duplication of organs and levels of government. This makes the running of government very expensive.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2000>9", "subject": "Government", "year": "2000", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS", "question": "In which of the following party systems are all shades of opinions and interests adequately represented?", "images": [], "options": {"A": "Zero-party", "B": "One-party", "C": "Two-party", "D": "Multi-party"}, "answer": "D", "explanation": "Multiparty system is the system where more than two parties are constitutionally recognized and allowed to operate and compete for gaining political power. In this system all shades of opinion and interests are adequately represented because of the number of parties participating.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2000>10", "subject": "Government", "year": "2000", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : EXECUTIVE", "question": "Veto power in a presidential system lies with the?", "images": [], "options": {"A": "Attorney General", "B": "Chief of Army Staff", "C": "Executive President", "D": "Prime Minister"}, "answer": "C", "explanation": "Veto power is the power or right invested in one branch of a government to cancel or postpone the decisions, enactments etc of another branch, especially the right of a president, governor, or other chief executive to reject bills passed by legislature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2000>11", "subject": "Government", "year": "2000", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following is the lowest class of people in the hierarchy of a feudal system?", "images": [], "options": {"A": "Nobles", "B": "Serfs", "C": "Lords", "D": "Manor"}, "answer": "B", "explanation": "The classes of feudal system from top to bottom include:  1. Monarch  2. Lords (nobles)  3. Knights  4. Peasants/ serfs", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2000>12", "subject": "Government", "year": "2000", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Mussolini's fascism and Hitler's nazism are good examples of?", "images": [], "options": {"A": "Arnachy", "B": "Feudalism", "C": "Totalitarianism", "D": "Oligarchy"}, "answer": "C", "explanation": "Totalitarianism refers to a political system in which all authority is in the hands of the state. In this form of government the ruler is an absolute dictator (not restricted by a constitution or laws or opposition etc)  Examples: Mussolin's fascism, Hitter's nazism, China under Mao zedong, and North Korea under kim's dynasty.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2000>13", "subject": "Government", "year": "2000", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "Which of the following is supreme in a federal system?", "images": [], "options": {"A": "Judiciary", "B": "Legislature", "C": "Constitution", "D": "Executive"}, "answer": "C", "explanation": "A constitution is a supreme law of a country. It contains the fundamental rules that constitute the country and its institutions.  Constitutions defines the power of the entities and the limits of that power.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2000>14", "subject": "Government", "year": "2000", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "An order directing a detainee to be brought before the court is called?", "images": [], "options": {"A": "Habeas corpus", "B": "An appearance", "C": "An injunction", "D": "A referendum"}, "answer": "A", "explanation": "Habeas corpus is a legal term that refers to an order issued by a court to a person who is detaining another, commanding him to bring the detainee before the court. The purpose of this writ is to prevent unlawful detention or imprisonment. The term 'habeas corpus' is Latin for 'you shall have the body', indicating that the person detained must be physically brought before the court.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2000>15", "subject": "Government", "year": "2000", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Which of the following is a feature of an elite party?", "images": [], "options": {"A": "Members are recruited from the working class", "B": "The leadership is composed of aristocrats and wealthy merchants", "C": "It usually consists of existing associations, clubs and trade unions", "D": "Its leadership has certain techniques which attract supporters"}, "answer": "B", "explanation": "An elite party is a political party that is dominated by members of the social elite, such as aristocrats and wealthy merchants. This is because the elite party is often associated with the interests of the upper class, and its leadership is usually composed of individuals from these social strata.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2000>16", "subject": "Government", "year": "2000", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "An undesirable feature of capitalism is?", "images": [], "options": {"A": "Exploitation", "B": "Market economy", "C": "Profit motive", "D": "Free competition"}, "answer": "A", "explanation": "Capitalism is an economic and political system in which a country's trade and industry are controlled by private owners for profit, rather than by the state. Because it is profit oriented it leads to exploitation of its members.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2000>17", "subject": "Government", "year": "2000", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "The system of voting on behalf of another person is known as?", "images": [], "options": {"A": "Voting by lot", "B": "Casting votes", "C": "Voting by proxy", "D": "Preference voting"}, "answer": "C", "explanation": "The system of voting on behalf of another person is known as 'Voting by proxy'. Proxy voting is a form of voting whereby a member of a decision-making body may delegate his or her voting power to a representative, to enable a vote in absence. The representative may be another member of the same body, or external.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2000>18", "subject": "Government", "year": "2000", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Authoritarianism is least inherent in?", "images": [], "options": {"A": "Feudalism", "B": "Fascism", "C": "Democracy", "D": "Monarchy"}, "answer": "C", "explanation": "Democracy does not support authoritarianism, it supports power to the people and not to a sole entity/ an individual.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2000>19", "subject": "Government", "year": "2000", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET~~STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PRESIDENTIAL", "question": "In which of the following systems of government are ceremonial and executive powers usually fused?", "images": [], "options": {"A": "Parliamentary", "B": "Presidential", "C": "Collegial", "D": "Confederal"}, "answer": "B", "explanation": "In a Presidential system of government, the ceremonial and executive powers are usually fused. This is because the President, who is the head of state, also performs the roles of the head of government. This means that the President not only performs ceremonial duties such as representing the country in foreign affairs and being a symbol of national unity, but also executes laws, appoints officials, and generally runs the government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2000>20", "subject": "Government", "year": "2000", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "The  programme of a political party is known as its?", "images": [], "options": {"A": "Constitution", "B": "Document", "C": "Manifesto", "D": "Propaganda"}, "answer": "C", "explanation": "Manifesto is a public declaration of principles, policies or intentions especially that of a political party. i.e The programme of a political party is called a MANIFESTO.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2000>21", "subject": "Government", "year": "2000", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "Which of the following is a source of a country's constitution?", "images": [], "options": {"A": "Mandamus", "B": "Judicial precedents", "C": "Injunctions", "D": "Political decisions"}, "answer": "B", "explanation": "Judicial precedent is the source of law where past decisions create law for judges to refer back to for guidance in future cases.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2000>22", "subject": "Government", "year": "2000", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The acquisition of political power through hereditary means is a feature of?", "images": [], "options": {"A": "Communalism", "B": "Capitalism", "C": "Oligarchy", "D": "Monarchy"}, "answer": "D", "explanation": "The acquisition of political power through hereditary means is a feature of Monarchy. In a monarchy, the position of the head of state is passed down through family lines, typically from parent to child. This is different from other forms of government where leaders are elected or appointed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2000>23", "subject": "Government", "year": "2000", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "Which of the following factors limits the expression of public opinion?", "images": [], "options": {"A": "The type of government in a state", "B": "The establishment of private media organizations", "C": "The high literacy rate of the citizens", "D": "Religious belief of the citizenry"}, "answer": "A", "explanation": "The type of government in a state can limit the expression of public opinion, there is freedom to express opinion publicly in democracy as compared to totalitarian system of government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2000>24", "subject": "Government", "year": "2000", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "If the federal government and the unit governments are to preserve their autonomy, the?", "images": [], "options": {"A": "Federal government must be supreme", "B": "Unit government must be supreme", "C": "Judiciary must be supreme", "D": "Constitution must be supreme"}, "answer": "D", "explanation": "The constitution is supreme law, it defines the power of an entity, also their function, and the limit to their power.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2000>25", "subject": "Government", "year": "2000", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : CONFEDERAL", "question": "Which of the following best describes the relationship between the central and the component governments in a confederation?", "images": [], "options": {"A": "The central government collects revenue for component governments", "B": "The central and component governments have equal powers", "C": "The central governments legislates for the component governments", "D": "The central government is weaker than the component governments"}, "answer": "D", "explanation": "The central government is weaker than the component government.  Central government represents the whole country (it is broad and weaker) while component government units of government variously called regions, local authorities, states, provinces and cantons- which are constitutionally recognised and largely autonomous. They are more concentrated and stronger.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2000>26", "subject": "Government", "year": "2000", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "The administrative head of a public corporation in Nigeria is the?", "images": [], "options": {"A": "Managing director", "B": "Secretary", "C": "Board of Directors", "D": "Chairman"}, "answer": "A", "explanation": "The administrative head of a public corporation in Nigeria is the Managing Director. The Managing Director is responsible for the day-to-day management of the corporation. The Board of Directors oversees the Managing Director, but they are not involved in the daily operations of the corporation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2000>27", "subject": "Government", "year": "2000", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC/CIVIL SERVICE COMMISSION –MEANING AND FUNCTIONS.", "question": "The appointment, promotion and discipline of civil sevants are the responsibility of the?", "images": [], "options": {"A": "Civil Service Union", "B": "Judicial Service Commission", "C": "Civil Service Commission", "D": "Electoral Commission"}, "answer": "C", "explanation": "The Civil Service Commission is responsible for the appointment, promotion, and discipline of civil servants. The Civil Service Commission is a government agency that is responsible for ensuring that the civil service system is managed in a fair and efficient manner. It is responsible for hiring and promoting civil servants based on their skills and qualifications, rather than political affiliations or personal connections.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2000>28", "subject": "Government", "year": "2000", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "Red tapism  in the civil service refers to?", "images": [], "options": {"A": "The use of red tapes on legal documents", "B": "Slowness of action", "C": "The co-operation between civil servants and politicians", "D": "The politicisation of the civil service"}, "answer": "B", "explanation": "Red tapism refers to excessive regulation or rigid conformity to formal rules that is considered redundant(excessive) or bureaucratic and hinders/ prevents action or decision-making.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2000>29", "subject": "Government", "year": "2000", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "The grant of the right to vote is called?", "images": [], "options": {"A": "Enfranchisement", "B": "Disqualification", "C": "Prohibition", "D": "Participation"}, "answer": "A", "explanation": "The grant of the right to vote is called Enfranchisement. Enfranchisement is the process of giving voting rights to citizens. It is the opposite of disenfranchisement, which is the removal of those rights. The term is often used in the context of the extension of voting rights to groups previously denied them.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2000>30", "subject": "Government", "year": "2000", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The system which allows private individuals and companies to own and control the means of production is known as?", "images": [], "options": {"A": "Socialism", "B": "Fascism", "C": "Capitalism", "D": "Communism"}, "answer": "C", "explanation": "Capitalism allows private individuals or companies to own and control means of production in order to make profit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2000>31", "subject": "Government", "year": "2000", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Which of the following factors may work against a representative system of government?", "images": [], "options": {"A": "High literacy of the electorate", "B": "The introduction of universal adult suffrage", "C": "Independent electoral  commission", "D": "Rigging of elections"}, "answer": "D", "explanation": "Representative government is an electoral system where citizens vote to elect people to represent their interests and concerns.  Rigging of election works against this. Rigging is manipulation of votes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2000>32", "subject": "Government", "year": "2000", "type": "Objective", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : FEATURES AND PROBLEMS", "question": "The powers allocated to the central government in a federation are contained in the?", "images": [], "options": {"A": "Central legislative list", "B": "Exclusive legislative list", "C": "Residual legislative list", "D": "Concurrent legislative list"}, "answer": "B", "explanation": "The executive legislative list contains the power allocated to the central government in a federation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2000>33", "subject": "Government", "year": "2000", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "The Nigerian federal legislature is called the?", "images": [], "options": {"A": "Senate", "B": "Congress", "C": "National Assembly", "D": "House of Representatives"}, "answer": "C", "explanation": "The Nigerian federal legislature is called the National Assembly. The National Assembly is a bicameral legislature that consists of the Senate (upper house) and the House of Representatives (lower house). Therefore, while the Senate and the House of Representatives are parts of the National Assembly, they are not the correct answer to the question as a whole.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2000>34", "subject": "Government", "year": "2000", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Delegated legislation has the advantage of?", "images": [], "options": {"A": "Enlightening the public about law making procedure", "B": "Saving parliamentary time", "C": "Reducing the expenses of the legislature", "D": "Preventing the executive from becoming too powerful"}, "answer": "B", "explanation": "Advantages of delegated legislature include:  -Saves time for the parliaments  -Enables flexibility  -Allows for quick action in national emergency e.t.c", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2000>35", "subject": "Government", "year": "2000", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "Nigeria's first constitution was the?", "images": [], "options": {"A": "Lyttleton Constitution", "B": "Clifford Constitution", "C": "Macpherson Constitution", "D": "Independence Constitution"}, "answer": "B", "explanation": "Nigeria's first constitution was the Clifford Constitution. The Clifford Constitution was enacted in 1922 by Governor Hugh Clifford. It was the first constitution of Nigeria and it established the Nigerian Legislative Council.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2000>36", "subject": "Government", "year": "2000", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "The Nigerian Macpherson Constitution of 1951 was significant for?", "images": [], "options": {"A": "The introduction of electoral college", "B": "Providing for the office of the prime minister", "C": "The creation of states", "D": "Establishing the Supreme Court"}, "answer": "A", "explanation": "The Nigerian Macpherson Constitution of 1951 was significant for the introduction of the electoral college. The electoral college system was introduced to elect members of the House of Representatives. This was a significant step towards self-governance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2000>37", "subject": "Government", "year": "2000", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "The concept of regionalism in Nigeria was first introduced by the?", "images": [], "options": {"A": "Independence Constitution", "B": "Macpherson Constitution", "C": "Richard's Constitution", "D": "Lyttleton Constitution"}, "answer": "C", "explanation": "The concept of regionalism in Nigeria was first introduced by the Richard's Constitution. The Richard's Constitution of 1946 introduced regionalism as a way of accommodating the country's diversity. It divided the country into three regions: North, West, and East.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2000>38", "subject": "Government", "year": "2000", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "Immediately after the Nigerian Civil War, Gowon's regime embarked on?", "images": [], "options": {"A": "Rejuvenation,resettlement and reconstruction", "B": "Reconciliation,rehabilitation and reconstruction", "C": "Rebuilding,rejuvenation and rehabilitation", "D": "Rehabilitation,renaissance and repression"}, "answer": "B", "explanation": "Immediately after civil war, Gowon's regime embarked on reconciliation (bringing everyone back to good terms with one another), rejuvenation (repairing) and rehabilitation (recovery)", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2000>39", "subject": "Government", "year": "2000", "type": "Objective", "topic": "MILITARY RULE : VARIOUS MILITARY REGIMES", "question": "Which of the following military regimes in Nigeria played a prominent role in the liberation of colonized African states?", "images": [], "options": {"A": "Aguiyi Ironsi", "B": "Murtala/Obasanjo", "C": "Muhammadu Buhari", "D": "Ibrahim Babangida"}, "answer": "B", "explanation": "General Muritala Muhammed and Olusegun Obasanjo(FMR. president) both played a role in liberation of colonized African states during their military regime.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2000>40", "subject": "Government", "year": "2000", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Traditional rulers appointed by the British to implement indirect rule in Eastern Nigeria were called?", "images": [], "options": {"A": "Palace chiefs", "B": "Village chiefs", "C": "Warrant chiefs", "D": "Crown chiefs"}, "answer": "C", "explanation": "Warrant chiefs are traditional or indigenous rulers appointed by the British to implement indirect rule in Eastern Nigeria.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2000>41", "subject": "Government", "year": "2000", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "The bill introduced by a member of the legislature is known as?", "images": [], "options": {"A": "A private member's bill", "B": "An executive bill", "C": "A state bill", "D": "A political party's bill"}, "answer": "A", "explanation": "A bill introduced by a member of the legislature who is not a part of the executive (government) is known as a private member's bill. This is different from an executive bill, which is introduced by a member of the executive or government. A state bill and a political party's bill are not standard terms used in legislative procedures.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2000>42", "subject": "Government", "year": "2000", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "In the federation of Nigeria, states are equally represented in the?", "images": [], "options": {"A": "Senate", "B": "House of Representative", "C": "Judiciary", "D": "National Population Commission"}, "answer": "A", "explanation": "In Nigeria, each state is represented equally in the senate (as in the U.S) However, unlike in the United states where each senator is elected by his/her entire state electorate, Nigerian senators are elected from district within their state.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2000>43", "subject": "Government", "year": "2000", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : IGBO", "question": "In pre-colonial Igboland, administrative meetings were presided over by the?", "images": [], "options": {"A": "Mazi", "B": "Ogbuefi", "C": "Ozo title holder", "D": "Okpara"}, "answer": "C", "explanation": "Ozo title holder is believed to be an 'Nze' implying living spirit and ancestor. He becomes the moral conscience of the community and is seen to be a fair adjudicator in cases of dispute within the community.In cases of dispute within the community.  In precolonial Igboland, He presides over administrative meetings.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2000>44", "subject": "Government", "year": "2000", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI~~PRE-COLONIAL POLITICAL SYSTEM : YORUBA~~PRE-COLONIAL POLITICAL SYSTEM : IGBO", "question": "Checks and balances  was a feature of pre-colonial political administration of the?", "images": [], "options": {"A": "Hausa", "B": "Yoruba", "C": "Igbo", "D": "Fulani"}, "answer": "B", "explanation": "The yoruba political structure in pre-colonial times was structured in layers of traditional rulers and almost every layer of authority served as a check on the other.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2000>45", "subject": "Government", "year": "2000", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI~~PRE-COLONIAL POLITICAL SYSTEM : YORUBA~~PRE-COLONIAL POLITICAL SYSTEM : IGBO", "question": "Which of the following groups had the best egalitarian traditional political system?", "images": [], "options": {"A": "Hausa/Fulani", "B": "Yoruba", "C": "Igbo", "D": "Edo"}, "answer": "C", "explanation": "The igbo administrative system was decentralized and characterized by the principle of acephalous(absence of a centralized government). It was therefore a chiefless society which was segmentary and egalitarian in nature.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2000>46", "subject": "Government", "year": "2000", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI", "question": "In the pre-colonial Hausa/Fulani system, the appointment of an Emir in the Caliphate was approved by the?", "images": [], "options": {"A": "Sardauna of Sokoto and the Alkali", "B": "Galadima and the Waiziri", "C": "Shehu of Borno and the Galadima", "D": "Sultan of Sokoto and the Emir of Gwandu"}, "answer": "D", "explanation": "Usman dan folio led the fulani jihad and took over the political leadership of Hausa and established the sokoto caliphate. He appointed emirs to rule the caliphate. He appointed emirs to rule the caliphate and the emirs owe alligiance to Dan fodio and his two representatives at Gwandu and Sokoto.  Hence, Sultan of sokoto and Emir of Gwandu approves the Emir in the caliphate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2000>47", "subject": "Government", "year": "2000", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "The french policy of Assimilation in West Africa was a form of?", "images": [], "options": {"A": "Indirect rule", "B": "Direct rule", "C": "Democratic", "D": "Monarchy"}, "answer": "B", "explanation": "The French policy of Assimilation in West Africa was a form of Direct rule. This policy was a system of governance used by the French in their colonies, where the colonies were administered directly by the French government. The colonies were considered as an extension of France and were expected to adopt French customs and culture.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2000>48", "subject": "Government", "year": "2000", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "One of the problems facing the Economic Community of West African States (ECOWAS) is that?", "images": [], "options": {"A": "Member states do not attend meetings regularly", "B": "Member states do not have a common currency", "C": "Some member states want to contribute larger funds to the community", "D": "It is a rival to the Organisation of African Unity"}, "answer": "B", "explanation": "Problems of Ecowas include language barrier. Ideological differences. No common currency. Political Instability etc", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2000>49", "subject": "Government", "year": "2000", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The world organization which existed before the United Nations Organisation was the?", "images": [], "options": {"A": "League of Nations", "B": "European Economics Community", "C": "Organization of African Unity", "D": "Commonwealth of Nations"}, "answer": "A", "explanation": "League of nations was the forerunner of United Nations meant to promote international cooperation and to achieve peace and security.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2000>50", "subject": "Government", "year": "2000", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "Which of the following bodies is the most representative organ of the United Nations Organization (UNO)?", "images": [], "options": {"A": "The Economic and Social Council", "B": "The Trusteeship Council", "C": "The Security Council", "D": "The General Assembly"}, "answer": "D", "explanation": "The General Assembly is the main deliberative policy making and representative organ of the UN. It is the only UN body with universal representation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2001>1", "subject": "Government", "year": "2001", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION", "question": "The first agent of political socialization is the?", "images": [], "options": {"A": "School", "B": "Mass media", "C": "Community", "D": "Family"}, "answer": "D", "explanation": "The formation of political values occurs through political socialization and begins in childhood while the first agent of political socialization is the family.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2001>2", "subject": "Government", "year": "2001", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES", "question": "Baron Montesquieu was noted for the theory of ?", "images": [], "options": {"A": "The rule of law", "B": "Delegated Legislation", "C": "Separation of powers", "D": "Equality before the law"}, "answer": "C", "explanation": "Baron Montesquieu is most noted for his theory of separation of powers. In his book 'The Spirit of the Laws', he proposed that the best way to secure liberty and prevent a government from becoming corrupted was to divide the responsibilities of governing among different bodies. This concept has been widely adopted in the constitution of many democratic countries to prevent the abuse of power.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2001>3", "subject": "Government", "year": "2001", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY", "question": "Political sovereignty in the state resides with the?", "images": [], "options": {"A": "Executive", "B": "People", "C": "National Assembly", "D": "International community"}, "answer": "B", "explanation": "Political sovereignty rests in that class of people under whose the mass of the people is or the people are.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2001>4", "subject": "Government", "year": "2001", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY", "question": "A political system in which there is only one source of authority in a state is?", "images": [], "options": {"A": "Confederal", "B": "Parliamentary", "C": "Presidential", "D": "Unitary"}, "answer": "D", "explanation": "Unitary system of government is one in which there is a single central government that does not share power with anybody.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2001>5", "subject": "Government", "year": "2001", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : MONARCHICAL", "question": "Which of the following best describes an absolute monarch? He", "images": [], "options": {"A": "Wields the supreme power in a state", "B": "Is elected by an electoral college", "C": "Is elected by the electorate", "D": "Has a fixed tenure of office"}, "answer": "A", "explanation": "An absolute monarch is a ruler who has supreme authority and where that authority is not restricted by any written laws, legislature, or customs. These are often hereditary monarchies. In contrast, in constitutional monarchies, the head of state's authority derives from or is legally bound or restricted by a constitution or legislature.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2001>6", "subject": "Government", "year": "2001", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The modern idea of democracy includes all the following except?", "images": [], "options": {"A": "Unlimited freedom", "B": "Universal suffrage", "C": "Periodic electrons", "D": "Equality before the law"}, "answer": "A", "explanation": "Universal suffrage (the right of almost all adults to vote in political elections).  Periodic elections and equality before the law are all part of the modern ideas of democracy except unlimited freedom.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2001>7", "subject": "Government", "year": "2001", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Which of the following is a method of acquiring political power in democracy?", "images": [], "options": {"A": "Heredity", "B": "Election", "C": "Imposition", "D": "Selection"}, "answer": "B", "explanation": "In a democracy, political power is typically acquired through elections. This is because democracy is a system of government where citizens exercise power by voting. In a direct democracy, the citizens as a whole form a governing body and vote directly on each issue. In a representative democracy, the citizens elect representatives from among themselves. The other options such as heredity, imposition, and selection are not methods of acquiring political power in a democracy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2001>8", "subject": "Government", "year": "2001", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "One of the arguments against delegated legislation is that it?", "images": [], "options": {"A": "Encroaches on the functions of the judiciary", "B": "Is against the principles of separation of powers", "C": "Promotes limited government", "D": "Wastes the time of the legislature"}, "answer": "B", "explanation": "Delegated legislation is making laws outside the legislature and hence is against the principle of separation of power.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2001>9", "subject": "Government", "year": "2001", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "A practice by which semi autonomous units are given part of governmental powers and functions is known as?", "images": [], "options": {"A": "Deconcentration", "B": "Distribution", "C": "Devolution", "D": "Decongestion"}, "answer": "C", "explanation": "Devolution involves giving of governmental powers and functions to semi-autonomous units. It is the transfer of power to a lower level especially by central government to local or regional administration.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2001>10", "subject": "Government", "year": "2001", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "A disadvantage of centralized administration is that?", "images": [], "options": {"A": "Wide powers are allocated to subnational bodies", "B": "The influence of the central administration is easily felt by local people", "C": "Local people are not easily exploited by the subnational agents", "D": "Subnational bodies are denied initiative in decision making"}, "answer": "D", "explanation": "In centralized administration decision are made from the top(central government) and subnational (local or regional) bodies are denied initiative in decision making.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2001>11", "subject": "Government", "year": "2001", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "Judicial independence  means that the courts are independent of the?", "images": [], "options": {"A": "Civil Service and the Bar", "B": "Executive and the Legislature", "C": "Legislature and the Ministry of Justice", "D": "Executive and the Military"}, "answer": "B", "explanation": "Judicial independence refers to the concept that the judiciary should be independent from the other branches of government, that is, the executive and the legislature. This is a key principle in the separation of powers, where the powers of the state are divided into distinct branches to prevent any one branch from gaining absolute power.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2001>12", "subject": "Government", "year": "2001", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "A citizen expresses loyalty to his nation by ?", "images": [], "options": {"A": "Participating in sports", "B": "Supporting political parties", "C": "Singing the national anthem when required", "D": "Lobbying for ministerial appointment"}, "answer": "C", "explanation": "A citizen expresses loyalty to his nation in various ways, one of which is by respecting and adhering to national symbols and rituals. Singing the national anthem when required is a demonstration of respect and loyalty to the nation. It is a symbolic act that shows allegiance and patriotism.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2001>13", "subject": "Government", "year": "2001", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "A citizen can participate in the politics of his country by?", "images": [], "options": {"A": "Acquiring university education", "B": "Attending international meetings", "C": "Contesting for an elective post", "D": "Being a good sportsman"}, "answer": "C", "explanation": "A citizen can participate in the politics of his country by contesting for an elective post. This allows the citizen to be directly involved in the decision-making process and to represent the interests of other citizens. The other options do not necessarily involve political participation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2001>14", "subject": "Government", "year": "2001", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "The office of the ombudsman is created to act as?", "images": [], "options": {"A": "Spy for government", "B": "An agency to redress mal-administration", "C": "Regulator of government activities", "D": "Sole administrator of public corporations"}, "answer": "B", "explanation": "An Ombudsman is that official appointed to investigate individuals complaint against a company or organization especially a public authority.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2001>15", "subject": "Government", "year": "2001", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "A constitution that has special rule for its amendment is said to be?", "images": [], "options": {"A": "Written", "B": "Federal", "C": "Confederal", "D": "Rigid"}, "answer": "D", "explanation": "A constitution that has special rules for its amendment is said to be rigid. A rigid constitution is one where the procedures for amendment are more difficult. It requires special procedures to be amended, which often involve a higher level of agreement or broader consensus than ordinary laws.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2001>16", "subject": "Government", "year": "2001", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "Which of the following statements best describes an unwritten constitution?", "images": [], "options": {"A": "A legislature is always unicameral", "B": "The source of the constitution is supreme court verdicts", "C": "There are no limitations on the powers of government", "D": "The body of rules and laws cannot all be found in a single document"}, "answer": "D", "explanation": "An unwritten constitution is a constitution not embodied in a single document but based chiefly on custom and precedent as expressed in statues and judicial decision.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2001>17", "subject": "Government", "year": "2001", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "The process by which people vote to elect their representatives is called?", "images": [], "options": {"A": "Electoral system", "B": "Plebiscite", "C": "Electoral college", "D": "Franchise"}, "answer": "A", "explanation": "The process by which people vote to elect their representatives is called the Electoral system. An electoral system is a set of rules that determine how elections and referendums are conducted and how their results are determined. It includes the process of voting, the method of counting votes, and the way in which votes translate into the final result.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2001>18", "subject": "Government", "year": "2001", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "Apart from making laws,the legislature has the important function of?", "images": [], "options": {"A": "Implementing executive decisions", "B": "Advising the judiciary", "C": "Appointing the civil servants", "D": "Checking the executive powers"}, "answer": "D", "explanation": "Apart from making laws, the legislature has the important function of checking the executive powers. This is known as the oversight function of the legislature. It involves monitoring and supervision of the executive branch by the legislature to ensure that the executive complies with the law and implements policies efficiently. It is a key aspect of the system of checks and balances in a democratic government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2001>19", "subject": "Government", "year": "2001", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "Which of the following is a demerit of bicameral legislature?", "images": [], "options": {"A": "The scope for political participation is limited", "B": "Passing of bills into acts is delayed", "C": "No safeguard for the minority groups", "D": "There is tendency for despotic rule"}, "answer": "B", "explanation": "A bicameral legislature is a legislative body that is divided into two separate assemblies, chambers, or houses, known as a bicameral system. One of the demerits of a bicameral legislature is that the process of passing bills into acts is often delayed due to the need for approval from both houses. This can slow down the legislative process and delay the implementation of important policies.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2001>20", "subject": "Government", "year": "2001", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "One form of delegated legislation is?", "images": [], "options": {"A": "Case laws", "B": "Statutory instruments", "C": "Conventions", "D": "Man-made laws"}, "answer": "B", "explanation": "Statutory instruments are a form of legislation which allows provisions of an act of parliament to be subsequently brought into force or altered without parliament having to pass a new act. They are also called secondary delegated or subordinate legislation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2001>21", "subject": "Government", "year": "2001", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY", "question": "A system in which one level of government exercises an overwhelming authority over others can best be described as?", "images": [], "options": {"A": "Confederal", "B": "Parliamentary", "C": "Unitary", "D": "Presidential"}, "answer": "C", "explanation": "In a unitary system, all powers are held by a single, central agency. The central government creates local units of government for its own convenience and needs. Those local governments have only those powers that the central government chooses to give them. This is the most common form of government in the world.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2001>22", "subject": "Government", "year": "2001", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "A major  weakness of a one-party system is that it?", "images": [], "options": {"A": "Encourages the emergence of dictators", "B": "Ensures freedom of political choice", "C": "Negates the principle of one man one vote", "D": "Requires a bicameral legislature"}, "answer": "A", "explanation": "A one-party system is a type of state in which one political party has the right to form the government, usually based on the existing constitution. All other parties are either outlawed or allowed to take only a limited and controlled participation in elections. A major weakness of this system is that it encourages the emergence of dictators. This is because there is no competition or checks and balances to prevent one person or party from gaining absolute power.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2001>23", "subject": "Government", "year": "2001", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "A multi-party system, the opposition party is as important as the ruling party because it", "images": [], "options": {"A": "Has equal number of supporters as the ruling party", "B": "Is as strong as the ruling party", "C": "May force the government to resign", "D": "Is the alternative government"}, "answer": "D", "explanation": "In a multi-party system, the opposition party is as important as the ruling party because it serves as an alternative government. This means that if the ruling party fails to govern effectively, the opposition party can take over. This ensures that the ruling party is kept in check and that it governs in the best interest of the people.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2001>24", "subject": "Government", "year": "2001", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Under a two-party system, the opposition party is as important as the ruling party because it", "images": [], "options": {"A": "Has equal number of supporters as the ruling party", "B": "Is as strong as the ruling party", "C": "May force the government to resign", "D": "Is the alternative government"}, "answer": "D", "explanation": "Under a two-party system, the opposition party is as important as the ruling party because it serves as an alternative government. Similar to the first question, the opposition party serves as a check and balance to the ruling party and can take over if the ruling party fails to govern effectively.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2001>25", "subject": "Government", "year": "2001", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "The dissolution of parliament is usually followed by a?", "images": [], "options": {"A": "General election", "B": "Referendum", "C": "Plebiscite", "D": "Resolutions"}, "answer": "A", "explanation": "Each parliament last for a stipulated period of time after which it will be dissolved followed by the general election.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2001>26", "subject": "Government", "year": "2001", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "A major function of public corporation is to", "images": [], "options": {"A": "Construct roads and bridges", "B": "Compete with private companies", "C": "Provide certain essential services for all", "D": "Collect revenue for government"}, "answer": "C", "explanation": "A major function of public corporations is to provide certain essential services for all. Public corporations are government-owned entities that are created to provide services that are considered essential for the public. These services can include utilities like water and electricity, transportation, healthcare, and more. They are not primarily focused on competing with private companies or constructing roads and bridges, although they may do these things as part of their operations. Collecting revenue for the government is also not their primary function, although they may generate revenue through the services they provide.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2001>27", "subject": "Government", "year": "2001", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Carpet- crossing is a characteristic of", "images": [], "options": {"A": "Monarchical system", "B": "Cabinet system", "C": "Presidential system", "D": "Unitary system"}, "answer": "B", "explanation": "cabinet/parliamentary system of government allows for carpet crossing (politician changing their party allegiance)", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2001>28", "subject": "Government", "year": "2001", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "A minister controls public corporations by", "images": [], "options": {"A": "Auditing the accounts of the corporations himself", "B": "Giving general policy directives", "C": "Criticising the corporations through the mass media", "D": "Undertaking day-to-day administration of the corporations"}, "answer": "B", "explanation": "A minister controls public corporations by giving general policy directives. This means that the minister sets the overall direction and goals for the corporation, but does not get involved in the day-to-day operations. This is different from auditing the accounts, criticizing the corporations through the media, or undertaking day-to-day administration, which are not typical roles of a minister.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2001>29", "subject": "Government", "year": "2001", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "When there is a second chamber in a federal state it", "images": [], "options": {"A": "Makes up for the imbalance in the representation in the lower house", "B": "Ensures that the judiciary is independent of the executive", "C": "Reduces the power of the electorate", "D": "Alone makes laws for the country"}, "answer": "A", "explanation": "The second chamber in a federal state makes up for the imbalance in the representation in the lower house.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2001>30", "subject": "Government", "year": "2001", "type": "Objective", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : FEATURES AND PROBLEMS", "question": "Countries adopt federal system of government because of", "images": [], "options": {"A": "Uneven development", "B": "Adoption of a state religion", "C": "The fear of domination of minorities", "D": "The availability of limited resources"}, "answer": "C", "explanation": "Countries often adopt a federal system of government to prevent the domination of minorities. In a federal system, power is divided between a central government and individual states or provinces. This allows for a degree of self-governance at the local level, which can help to protect the rights and interests of minority groups. It also helps to maintain a balance of power and prevent any one group from dominating the others.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2001>31", "subject": "Government", "year": "2001", "type": "Objective", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : FEATURES AND PROBLEMS", "question": "The three main contesting issues about revenue allocation in Nigeria are", "images": [], "options": {"A": "Oil,cocoa and groundnut", "B": "Oil,minority and majority", "C": "Ethnicity,corruption and nepotism", "D": "Derivation,population and even developments"}, "answer": "D", "explanation": "The three main contesting issues about revenue allocation in Nigeria are Derivation, population and even developments. Derivation refers to the principle that revenue should be allocated based on the source of the revenue. Population refers to the principle that revenue should be allocated based on the population of each state. Even development refers to the principle that revenue should be allocated in a way that promotes even development across all states.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2001>32", "subject": "Government", "year": "2001", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "In Nigeria, the concurrent list of powers belongs to the", "images": [], "options": {"A": "Local authorities only", "B": "Executives, the judiciary and the legislature", "C": "Federal and state governments", "D": "State and local governments"}, "answer": "C", "explanation": "Concurrent(simultaneous) list of powers belong to both the federal and state government i.e they both are invested with power.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2001>33", "subject": "Government", "year": "2001", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "Rule by decrees is associated with?", "images": [], "options": {"A": "Military governments", "B": "Totalitarian governments", "C": "Democratic system", "D": "Delegated legislation"}, "answer": "A", "explanation": "Rule by decree is a style of governance allowing quick, unchallenged creation of law by a single person or group, and is used primarily by dictators, absolute monarchs, and military governments. Therefore, it is associated with military governments.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2001>34", "subject": "Government", "year": "2001", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "Which of the following Nigeria Constitutions brought the Northern Provinces into the Legislative Council?", "images": [], "options": {"A": "The 1979 Constitution", "B": "The Richards Constitution", "C": "The Clifford Constitution", "D": "The Lyttleton Constitution"}, "answer": "B", "explanation": "The Richards Constitution of 1946 is the constitution that brought the Northern Provinces into the Legislative Council in Nigeria. This constitution introduced a system of representative government, which meant that Nigerians were given the right to elect their representatives to the Legislative Council.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2001>35", "subject": "Government", "year": "2001", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "Under the Independent Constitution of Nigeria, the final Court of Appeal was the", "images": [], "options": {"A": "West African Court of Appeal", "B": "Sharia Court of Nigeria", "C": "Privy Council", "D": "Supreme Military Council"}, "answer": "C", "explanation": "Privy council in Britain was the final court of appeal under the independence constitution of Nigeria.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2001>36", "subject": "Government", "year": "2001", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : ACHIEVEMENTS AND FAILURES", "question": "The Nigerian Youth Movement (NYM) collapsed because of", "images": [], "options": {"A": "Leadership struggle", "B": "The ban on the press of the government", "C": "High handedness by the leadership", "D": "Corruption and nepotism"}, "answer": "A", "explanation": "The Nigerian Youth Movement (NYM) collapsed because of leadership struggle. The NYM was a Nigerian nationalist organization that emerged in 1934 in Lagos, and was composed mainly of students, teachers, and other intellectuals. It was initially called the Lagos Youth Movement, but changed its name to the Nigerian Youth Movement in 1936. The NYM was formed to promote national consciousness and forge a path towards Nigeria's independence. However, it was plagued by regional and ethnic tensions, and these internal conflicts led to a leadership struggle that eventually caused the collapse of the movement.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2001>37", "subject": "Government", "year": "2001", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "A major reason why the warrant chiefs were rejected in Eastern Nigeria was that", "images": [], "options": {"A": "The chiefs were illiterates", "B": "They were not indigenes", "C": "They usurped the positions of the nationalists", "D": "The system was not customary"}, "answer": "D", "explanation": "Warrant chiefs were installed as a means of indirect rule by the British, however this was rejected in Eastern Nigerian because it was not part of their custom.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2001>38", "subject": "Government", "year": "2001", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "After the annexation in 1861, Lagos became a?", "images": [], "options": {"A": "Trust territory", "B": "Crown colony", "C": "Protectorate", "D": "Consular territory"}, "answer": "B", "explanation": "After the annexation in 1861, Lagos became a Crown Colony. A Crown Colony is a type of colonial administration of the English and later British Empire, which were directly controlled by the Crown. Lagos was under the direct control of the British government through a governor. The other options are incorrect because Lagos was not a trust territory, protectorate or a consular territory after the annexation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2001>39", "subject": "Government", "year": "2001", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI", "question": "In the Hausa/Fulani traditional political administration the Madawaki was the?", "images": [], "options": {"A": "Chief judge", "B": "Chief tax collector", "C": "Head of fishermen", "D": "Commander of the calvary"}, "answer": "D", "explanation": "In Hausa/Fulani traditional political administration, the Madawaki was the commander of the calvary.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2001>40", "subject": "Government", "year": "2001", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "The chairman of the Unity Party of Nigeria (UPN) during the Second Republic in Nigeria was", "images": [], "options": {"A": "Aminu Kano", "B": "Joseph Wayas", "C": "Ume Ezeoke", "D": "Obafemi Awolowo"}, "answer": "D", "explanation": "The chairman of the Unity Party of Nigeria (UPN) during the Second Republic in Nigeria was Obafemi Awolowo. The Unity Party of Nigeria was a political party in Nigeria during the Second Republic (1978-1983). It was one of the major political parties along with the National Party of Nigeria (NPN), the Nigeria People's Party (NPP), and others. Obafemi Awolowo was a Nigerian nationalist and statesman who played a key role in Nigeria's independence movement, the First and Second Republics and the Civil War.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2001>41", "subject": "Government", "year": "2001", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : YORUBA", "question": "Among the Yoruba, the presentation of parrot egg to the Oba indicates?", "images": [], "options": {"A": "Outright rejection by his subjects", "B": "Acceptance of royal order", "C": "Obeisance and homage to the king", "D": "Prayer for long life for the king"}, "answer": "A", "explanation": "Among the yoruba's the presentation of parrot egg to the Oba(king) is a message of outright rejection by his subject.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2001>42", "subject": "Government", "year": "2001", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "One important effect of the 1922 Constitution of Nigeria was the?", "images": [], "options": {"A": "Formation of political parties", "B": "Establishment of a University in West Africa", "C": "Fusion of both the legislative and executive powers", "D": "Establishment of a military government"}, "answer": "A", "explanation": "The 1922 Constitution of Nigeria led to the formation of political parties. This constitution introduced elective principles and paved the way for the emergence of political parties in Nigeria.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2001>43", "subject": "Government", "year": "2001", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : ACHIEVEMENTS AND FAILURES", "question": "During the 1964 federal elections in Nigeria, there was a total boycott of voting in?", "images": [], "options": {"A": "Lagos", "B": "The Northern Region", "C": "The Eastern Region", "D": "The Mid-Western Region"}, "answer": "C", "explanation": "During the 1964 federal elections in Nigeria, there was a total boycott of voting in the Eastern Region. The Eastern Region was dominated by the Igbo ethnic group, and the political party in power there, the National Council of Nigeria and the Cameroons (NCNC), boycotted the elections due to perceived irregularities and intimidation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2001>44", "subject": "Government", "year": "2001", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : IGBO", "question": "In pre-colonial West Africa, no centralized political administration existed among the?", "images": [], "options": {"A": "Hausa", "B": "Igbo", "C": "Yoruba", "D": "Kanuri"}, "answer": "B", "explanation": "In pre-colonial West Africa, no centralized political administration existed among the Igbo. The Igbo people, primarily located in southeastern Nigeria, traditionally lived in autonomous local communities, unlike the Hausa, Yoruba, and Kanuri peoples, who had established centralized city-states or kingdoms.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2001>45", "subject": "Government", "year": "2001", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "Under the Nigerian Constitution of 1979, representation in the lower House was based on?", "images": [], "options": {"A": "Equality of states", "B": "The geographical size of each state", "C": "The population of each state", "D": "The number of Local Governments in each state"}, "answer": "C", "explanation": "Under 1979 constitution of Nigeria, representation in the lower house was based on the population of each state.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2001>46", "subject": "Government", "year": "2001", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : ACHIEVEMENTS AND FAILURES", "question": "Who among the following was dismissed from the Action Group at the Jos Congress of February, 1962?", "images": [], "options": {"A": "Anthony Enahoro", "B": "Ladoke Akintola", "C": "Dauda Adegbenro", "D": "Adesoji Aderemi"}, "answer": "B", "explanation": "Ladoke Akintola was dismissed from action group (A.G) at the Jos congress of february, 1962 due to the rift between him and Obafemi Awolowo", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2001>47", "subject": "Government", "year": "2001", "type": "Objective", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "If the receiving state does not approve a diplomat on account of his past activities, he is considered?", "images": [], "options": {"A": "A doyen of diplomatic corps", "B": "An extra-ordinary ambassador", "C": "An ambassador plenipotentiary", "D": "A 'persona-non-grata'"}, "answer": "D", "explanation": "A persona non grata is a foreign person whose entering or remaining in a particular country is prohibited by that country's government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2001>48", "subject": "Government", "year": "2001", "type": "Objective", "topic": "FOREIGN POLICIES : ADVANTAGES AND DISADVANTAGES", "question": "Nigeria's idea of Africa as the centre-piece of her foreign policy includes all the following except?", "images": [], "options": {"A": "Support for Apartheid policy in South Africa", "B": "Promotion of African unity", "C": "Creation of more Nigerian missions in Africa", "D": "Settling of disputes in Africa"}, "answer": "A", "explanation": "Nigeria's idea of Africa as the centre-piece of her foreign policy includes promotion of African unity, creation of more Nigerian missions in Africa, and settling of disputes in Africa. However, it does not include support for Apartheid policy in South Africa. Apartheid was a system of institutionalized racial segregation that existed in South Africa and Southwest Africa (now Namibia) from 1948 until the early 1990s. Nigeria was one of the foremost supporters of anti-apartheid movements, including the African National Congress; the Nigerian government issued more than $5 million to these movements between 1960 and 1995.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2001>49", "subject": "Government", "year": "2001", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "The organ of the organisation of Africa Unity (OAU) responsible for the appointment of the Secretary-General is the?", "images": [], "options": {"A": "Appointment Commission", "B": "Liberation committee", "C": "Assembly of Heads of State and Governments", "D": "Economic and Social Commission"}, "answer": "C", "explanation": "Assembly of heads of states and governments is responsible for the appointment of the Secretary General.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2001>50", "subject": "Government", "year": "2001", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "Which of the following is an organ of the United Nations Organization (UNO)?", "images": [], "options": {"A": "Assembly of Heads of state", "B": "International Labour Organization", "C": "Council of Ministers", "D": "The Security Council"}, "answer": "D", "explanation": "The United Nations has  six principal organs:  -The General Assembly  -The Security Council  -Economic and Social Council   -Trusteeship Council  -The international Court of Justice.  -The Secretariat.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2002>1", "subject": "Government", "year": "2002", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A classless society is the ultimate goal of?", "images": [], "options": {"A": "Socialism", "B": "Totalitarianism", "C": "Capitalism", "D": "Federalism"}, "answer": "A", "explanation": "Socialism is an economic system in which everyone in society equally owns the factors of production.  This system produces a classless society.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2002>2", "subject": "Government", "year": "2002", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Fascism  as a system of government originated in?", "images": [], "options": {"A": "Italy", "B": "Germany", "C": "France", "D": "Britain"}, "answer": "A", "explanation": "Fascism as a system of government originated in Italy. Fascism is a form of far-right, authoritarian ultranationalism characterized by dictatorial power, forcible suppression of opposition, and strong regimentation of society and of the economy which came to prominence in early 20th-century Europe. The first fascist movements emerged in Italy during World War I, before spreading to other European countries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>3", "subject": "Government", "year": "2002", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A country is said to be democratic if?", "images": [], "options": {"A": "Gerrymandering exists", "B": "There are free and fair elections", "C": "Citizens are disenfranchised", "D": "The press is owned by the government"}, "answer": "B", "explanation": "A country is said to be democratic if there are free and fair elections. This is because democracy is a system of government where citizens exercise power by voting. In a democratic country, all eligible citizens have equal access to participate in political life which means they have a right to vote in elections freely and fairly. None of the other options represent the core principles of democracy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>4", "subject": "Government", "year": "2002", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Constitutionalism  is synonymous with?", "images": [], "options": {"A": "Separation of powers", "B": "Supremacy of the law", "C": "Delegated legislation", "D": "Checks and balances"}, "answer": "B", "explanation": "The constitution exemplifies the \"supremacy of the law\" or the supreme law of the land. It is the basic principle and laws of a nation, state, or social group that determine the powers and duties of the government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>5", "subject": "Government", "year": "2002", "type": "Objective", "topic": "CITIZENSHIP : MEANING AND MODE OF ACQUISITION", "question": "Citizenship can be acquired by?", "images": [], "options": {"A": "Nationalism", "B": "Naturalization", "C": "Indigenization", "D": "Collectivism"}, "answer": "B", "explanation": "Citizenship can be acquired by naturalization. Naturalization is a legal process through which a non-citizen in a country may acquire citizenship or nationality of that country. It may be done by a statute, without any effort on the part of the individual, or it may involve an application and approval by legal authorities. The rules of naturalization vary from country to country and typically include a minimum legal residency requirement.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2002>6", "subject": "Government", "year": "2002", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "A citizen's right to expression can be limited if he?", "images": [], "options": {"A": "Pays taxes when due", "B": "Serves as a witness in court", "C": "Commits slander, libel or sedition", "D": "Fails to vote during elections"}, "answer": "C", "explanation": "When a Citizen promote falsehood via slander (spoken words), libel (written words) or sedition (incite people via falsehood)", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>7", "subject": "Government", "year": "2002", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "An organization whose ultimate aim is to gain the control of government and implement its programmes is known as a?", "images": [], "options": {"A": "Pressure group", "B": "Political group", "C": "Trade union", "D": "Professional association"}, "answer": "B", "explanation": "A political group is an organization whose ultimate aim is to gain control of government and implement its programmes. This is because political groups, also known as political parties, are organized groups of people who have the same ideology, or who otherwise have the same political positions, and field candidates for elections, in an attempt to get them elected and thereby implement the party's agenda. A pressure group, trade union, and professional association do not have the ultimate aim of gaining control of government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>8", "subject": "Government", "year": "2002", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Franchise can best be described as the political right to?", "images": [], "options": {"A": "Vote during elections", "B": "Contest elections", "C": "Belong to political parties", "D": "Vote and be voted for"}, "answer": "D", "explanation": "Franchise can best be described as the political right to vote and be voted for. This is because franchise refers to the right to vote. In many democracies, where the term is still used, franchise describes not only the right to vote but also the practical question of whether citizens are registered to vote in elections. Being able to vote, or being able to be voted for, are both part of the concept of franchise.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2002>9", "subject": "Government", "year": "2002", "type": "Objective", "topic": "CITIZENSHIP : MEANS OF SAFEGUARDING RIGHTS OF CITIZENS.", "question": "Which of the following protect the rights of the individual in a State?", "images": [], "options": {"A": "The police and the soldiers", "B": "The executive and the legislature", "C": "The police and the courts", "D": "The lawmakers and lawyers"}, "answer": "C", "explanation": "The police and the court s are law enforcers and make sure individuals are not denied their rights i.e they protect rights", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>10", "subject": "Government", "year": "2002", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "A representative government is one in which?", "images": [], "options": {"A": "The executive controls the judiciary", "B": "Half of the parliament is popularly elected", "C": "Traditional rulers form majority in parliament", "D": "The ultimate power resides with the people"}, "answer": "D", "explanation": "In representative government, the ultimate power resides in the people because they can vote in or \"vote out\" a leader. They are the ones who choose those in government", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2002>11", "subject": "Government", "year": "2002", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : CONFEDERAL", "question": "Autonomy of constituent units is an important feature of?", "images": [], "options": {"A": "Confederal government", "B": "Presidential government", "C": "Unitary government", "D": "Parliamentary government"}, "answer": "A", "explanation": "Confederation is the type of government in which sovereign states together as  autonomous bodies to form a loose political union, in which the central government is subordinate to the component (those state that makes up the confederation) government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>12", "subject": "Government", "year": "2002", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Another name for the simple majority system of voting is the?", "images": [], "options": {"A": "First-part-the post system", "B": "Proportional representation", "C": "Absolute majority", "D": "Second ballot system"}, "answer": "A", "explanation": "In a  first-past-the-post ( FPTP  or  FPP ; sometimes formally called  single-member plurality voting  or  SMP )  electoral system , voters cast their vote for a candidate of their choice, and the candidate who receives the most votes wins, even if they received less than half of the votes. First-past-the-post voting is a plurality voting   method.FPTP is a common electoral system,especially in systems that use  single-member electoral divisions .", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>13", "subject": "Government", "year": "2002", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Under delegated legislation, the institution empowered to make laws is the?", "images": [], "options": {"A": "Press", "B": "Pressure groups", "C": "Executive", "D": "Political parties"}, "answer": "C", "explanation": "Delegated legislation refers to laws made by an individual or body under powers given to them by an Act of Parliament. The institution empowered to make laws under delegated legislation is the Executive. The Executive is the branch of government responsible for the implementation of laws and policies, and it includes institutions like the presidency, the cabinet, and the civil service.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2002>14", "subject": "Government", "year": "2002", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : EXECUTIVE", "question": "Which of the following formulates and implements government policy?", "images": [], "options": {"A": "Judiciary", "B": "Labour", "C": "Executive", "D": "Police"}, "answer": "C", "explanation": "The Executive is the branch of government that formulates and implements government policy. It is responsible for the daily administration of the state and has the authority and responsibility for the administration of government policies, the administration of the bureaucracy, the execution of laws, and the provision of public services.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2002>15", "subject": "Government", "year": "2002", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PRESIDENTIAL", "question": "One of the main principles of the presidential system is the?", "images": [], "options": {"A": "Parliamentary supremacy", "B": "Separation of powers", "C": "Creation of local governments", "D": "Collective responsibility"}, "answer": "B", "explanation": "The main principle of the presidential system is the separation of powers. This principle is based on the idea that the powers of a government should be split between two or more strongly independent entities to prevent any one entity from gaining absolute power. This separation is typically between the executive, legislative, and judicial branches of government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>16", "subject": "Government", "year": "2002", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "One of the functions of political parties is to?", "images": [], "options": {"A": "Make laws", "B": "Declare a state of emergency", "C": "Interpret the constitution", "D": "Aggregate interest"}, "answer": "D", "explanation": "One of the functions of political parties is to aggregate interest. This means that political parties bring together diverse interests and opinions of the people, and present them in a manner that influences government policies and decisions. They do this by representing the views of their members and supporters, and by influencing the direction of government policies through their participation in the legislative process.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2002>17", "subject": "Government", "year": "2002", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The principle of checks and balances modifies the theory of?", "images": [], "options": {"A": "Delegation legislation", "B": "Supremacy of the law", "C": "Separation of power", "D": "Rule of law"}, "answer": "C", "explanation": "The theory of separation of power  modifies  the principle of checks and balance.  Because separation of powers, create different levels of power, making it easy to check excesses.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>18", "subject": "Government", "year": "2002", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "Pressure groups use all the following techniques to achieve their objectives except?", "images": [], "options": {"A": "Lobbying", "B": "Demonstrating", "C": "Coup de tat", "D": "Strikes"}, "answer": "C", "explanation": "Pressure groups use:  -Lobbying  -Strikes and boycotts.  -Publicity campaigns  -Mass media  -Letters and petitions   -Electoral politics   -Demonstrations  -Courts  They do not employ Coup de tat", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>19", "subject": "Government", "year": "2002", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Which of the following is not a purpose of elections?", "images": [], "options": {"A": "Political recruitment", "B": "Rigging", "C": "Exercise of franchise", "D": "Legitimacy"}, "answer": "B", "explanation": "The purpose of elections is to allow citizens to choose their representatives in a democratic manner. It involves political recruitment, exercise of franchise, and conferring legitimacy to the elected officials. Rigging, which involves fraudulent manipulation of election results, is not a purpose of elections but a malpractice.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2002>20", "subject": "Government", "year": "2002", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PRESIDENTIAL", "question": "Impeachment and veto powers are features of the?", "images": [], "options": {"A": "Parliamentary system", "B": "Unitary system", "C": "Theocratic system", "D": "Presidential system"}, "answer": "D", "explanation": "Impeachment and veto powers are features of the Presidential system. Impeachment is a process that allows legislative bodies to bring charges against a government official for misconduct. Veto power is the power of a president or governor to reject a bill proposed by a legislature by refusing to sign it into law. Neither of these features are characteristic of a parliamentary, unitary, or theocratic system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>21", "subject": "Government", "year": "2002", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : CONFEDERAL", "question": "A system of government where the component units are stronger than the central authority is known as?", "images": [], "options": {"A": "Federalism", "B": "Confederation", "C": "Fascism", "D": "Feudalism"}, "answer": "B", "explanation": "A system of government where the component units are stronger than the central authority is known as a Confederation. In a confederation, the central government is weaker than the sub-units, and it has only as much power as the sub-units are willing to grant. This is different from a federal system where the central government and the sub-units share powers, and neither is completely autonomous.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>22", "subject": "Government", "year": "2002", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : REPUBLICAN", "question": "A government headed by a person elected for a fixed period of time is referred to as?", "images": [], "options": {"A": "Monarchical", "B": "Socialist", "C": "Republican", "D": "Military"}, "answer": "C", "explanation": "A republic is a state in which the supreme power is held by the people and their elected representative and which has an elected representative and which has an elected or nominated president rather than a monarch.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2002>23", "subject": "Government", "year": "2002", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "The referring of a political question to the electorate for a decision is known as?", "images": [], "options": {"A": "Referendum", "B": "Election", "C": "Mass media", "D": "Public opinion"}, "answer": "A", "explanation": "A referendum is a vote in which all the people in a country or an area are asked to give their opinion about or decide an important political or social question.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>24", "subject": "Government", "year": "2002", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following allows the concentration of wealth in private hands?", "images": [], "options": {"A": "Fascism", "B": "Capitalism", "C": "Feudalism", "D": "Socialism"}, "answer": "B", "explanation": "Capitalism is an economic system where private entities own the factors of production. The four factors are entrepreneurship, capital goods, natural resources, and labor. The owners of capital goods, natural resources, and entrepreneurship exercise control through companies. Individuals own their labor. The only role of government is to enforce the rules of the market by ensuring everyone plays fair and doesn't cheat. Capitalism requires a free market economy to succeed. It distributes goods and services according to the laws of supply and demand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>25", "subject": "Government", "year": "2002", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "A constitutional function of local governments is the?", "images": [], "options": {"A": "Provision of security guards for streets", "B": "Provision of market stalls and motor parks", "C": "Control of prison services", "D": "Collection of duties on goods"}, "answer": "B", "explanation": "Local government makes provision for communal basic resources, or infrastructure and basic resources for the community E.g Motor park and market stalls building e.t.c", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2002>26", "subject": "Government", "year": "2002", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "Local governments can raise funds through?", "images": [], "options": {"A": "Import duties", "B": "Company duties", "C": "Excise duties", "D": "Rates"}, "answer": "D", "explanation": "Local governments can raise funds through rates. Rates are a type of tax that property owners pay based on the value of their property. This is a common source of revenue for local governments, which they use to fund services and infrastructure in the local area. The other options listed - import duties, company duties, and excise duties - are not typically sources of revenue for local governments. These are usually collected by state or federal governments.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2002>27", "subject": "Government", "year": "2002", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY", "question": "In unitary states, local authorities derive their powers from the", "images": [], "options": {"A": "Judiciary", "B": "Electorate", "C": "Elected councillors", "D": "Legislature"}, "answer": "D", "explanation": "In a unitary state, local authorities derive their powers from the Legislature. A unitary state is a state governed as a single entity in which the central government is ultimately supreme. The central government may create (or abolish) administrative divisions (sub-national units). Such units exercise only the powers that the central government chooses to delegate. Therefore, the correct answer is 'Legislature'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>28", "subject": "Government", "year": "2002", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "The  anonymity  of a civil servant means that the", "images": [], "options": {"A": "Receives neither praise nor blame publicity", "B": "Is above the law of the land", "C": "Should not take part in union activities", "D": "Should not be disciplined because of his expertise"}, "answer": "A", "explanation": "Anonymity- means to remain unknown or in obscurity, hidden from view. The Anonymity of a civil servant therefore means he receives neither blame nor praise publicly.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2002>29", "subject": "Government", "year": "2002", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "Public corporations are established mainly to?", "images": [], "options": {"A": "Cater for the welfare of its officials.", "B": "Provide essential services and amenities", "C": "Co-ordinate activities of the ministries", "D": "Advise the government on commerce"}, "answer": "B", "explanation": "Public corporation are established mainly to provide essential services and amenities to the general public", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>30", "subject": "Government", "year": "2002", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "Under military governments, local authorities issue bye-laws, while State governments issue", "images": [], "options": {"A": "Edicts", "B": "Decrees", "C": "Warrants", "D": "Orders"}, "answer": "A", "explanation": "Under military governments, local authorities issue bye-laws, while State governments issue Edicts. An edict is an official order or proclamation issued by a person in authority, in this case, the state government under a military regime. Decrees, warrants, and orders are also forms of official orders, but they are not typically issued by state governments under military rule.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>31", "subject": "Government", "year": "2002", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "Traditional practices which can be sanctioned by public opinion when they are broken are called?", "images": [], "options": {"A": "Decrees", "B": "Local laws", "C": "Customs", "D": "Edicts"}, "answer": "C", "explanation": "Traditional practices that can be sanctioned by public opinion when they are broken are called customs. Customs are practices or behaviors that are traditional in a particular society or group. They are generally accepted and followed by the members of that society or group. When these customs are broken, it is often the public opinion that sanctions or condemns the act.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>32", "subject": "Government", "year": "2002", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "One major characteristics of capitalism is that it results in?", "images": [], "options": {"A": "Unjust and unequitable distribution of societal resources", "B": "Full employment for youths.", "C": "Organization of production to meet the needs of the poor", "D": "Job security for casual workers"}, "answer": "A", "explanation": "One major characteristic of capitalism is that it often results in unjust and unequitable distribution of societal resources. Capitalism is an economic system where private entities own the factors of production. The four factors are entrepreneurship, capital goods, natural resources, and labor. The owners of these resources compete in the marketplace to create goods and services that are profitable. However, this often leads to a concentration of wealth in the hands of a few, leading to an unequal distribution of resources.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2002>33", "subject": "Government", "year": "2002", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "After which of the following stages will a bill be said to have reached the report stage in Parliament?", "images": [], "options": {"A": "Committee stage", "B": "First reading", "C": "Second reading", "D": "Third reading"}, "answer": "A", "explanation": "Process of passing a bill;  -First reading   -Second reading  -Committee stage   -Report stage   -Third reading  -Assent", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>34", "subject": "Government", "year": "2002", "type": "Objective", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "What is detente  in international relations?", "images": [], "options": {"A": "Detention of war prisoners", "B": "Posting of ambassadors", "C": "Military alliance between nations", "D": "Peace agreement between nations"}, "answer": "D", "explanation": "Detente is a peace agreement, the easing of hostility or tension or strained relations especially between countries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>35", "subject": "Government", "year": "2002", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "The Aba women riots of 1929 in Nigeria was caused by the?", "images": [], "options": {"A": "Fear of domination by warrant chiefs", "B": "Absence of a well organised system of taxation", "C": "Fear of women being taxed", "D": "Existence of a centralized authority"}, "answer": "C", "explanation": "The Aba women riot of 1929 was touched off by the rumour of imposition of direct taxation on the women", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2002>36", "subject": "Government", "year": "2002", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "Which of the following pairs of countries have unwritten constitution?", "images": [], "options": {"A": "Ghana and Germany", "B": "Nigeria and America", "C": "Britain and Isreal", "D": "Nigeria and Ghana"}, "answer": "C", "explanation": "An unwritten constitution is one that is not codified in a single document but consists of several different sources that may be written or unwritten. Britain and Israel are examples of countries with unwritten constitutions. Britain's constitution is derived from a number of sources including statutes, conventions, and works of authority. Israel, on the other hand, has a series of Basic Laws but no formal constitution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>37", "subject": "Government", "year": "2002", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "The 1885 Berlin Conference was conveyed to?", "images": [], "options": {"A": "Encourage slave trade in Africa", "B": "Organize warfare against Africa", "C": "Seek a way of developing Africa", "D": "Partition Africa among European powers"}, "answer": "D", "explanation": "The 1885 Berlin conference marked the climax of the European  competition for African territories .Africa was partitioned/ divided among European powers.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2002>38", "subject": "Government", "year": "2002", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "Which of the following defines the  Loi Cadre  in French West Africa?", "images": [], "options": {"A": "Outline laws for administrative and political reforms", "B": "A military cadet used to enforce laws", "C": "A new law to punish offenders without trials", "D": "The centre for political awareness in West Africa"}, "answer": "A", "explanation": "Loi cadre or \"framework law\" was passed by the French parliament to give a measure of self government to African territories. It outlined laws to African territories. It attained outlined laws for administrative and political reforms.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2002>39", "subject": "Government", "year": "2002", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "The method used by the French to slow down the development of nationalist activities West African territories was?", "images": [], "options": {"A": "Free press", "B": "The indigenat", "C": "Free education", "D": "Certification"}, "answer": "B", "explanation": "The French slow down nationalist indigenization is the act of making something more native:transformation of some services, idea, e.t.c to suit local culture by involving more indigens.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>40", "subject": "Government", "year": "2002", "type": "Objective", "topic": "NATIONALISM : NATIONALISM: MEANING, FACTORS AND EFFECTS.", "question": "The ultimate goal of the nationalists in Africa was to?", "images": [], "options": {"A": "Recover the resources exploited by the colonialists", "B": "Improve the status of the traditional rulers", "C": "Stop export trade", "D": "Obtain political independence"}, "answer": "D", "explanation": "Nationalism is an ideology and movement that promotes the interests of a particular nation(as in a group of people) especially with the aim of gaining and maintaining the nation's sovereignty (self-governance) over its homeland.Hence the reason why Nationalist struggle to gain independence from the grip of colonialism.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>41", "subject": "Government", "year": "2002", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "With which of the following did the French attempt to change African culture?", "images": [], "options": {"A": "Socialization", "B": "Association", "C": "Assimilation", "D": "Indirect rule"}, "answer": "C", "explanation": "The French employed assimilation i.e educating non-french natives in the language and culture of the french, hence making African imbibe their (french) culture.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>42", "subject": "Government", "year": "2002", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Indirect rule failed in some areas of West Africa because of the?", "images": [], "options": {"A": "Creation of the institution of warrant chiefs", "B": "Introduction of kingmakers", "C": "Non-inclusion of chiefs in administration", "D": "Exploitation of resources in some communities"}, "answer": "A", "explanation": "-Decentralized nature of the government.  -Introduction of warrant chiefs   -Opposition by educated elites   These are some of the reasons indirect rule failed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>43", "subject": "Government", "year": "2002", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI~~PRE-COLONIAL POLITICAL SYSTEM : IGBO~~PRE-COLONIAL POLITICAL SYSTEM : YORUBA", "question": "In the pre-colonial period,traditional rulers in most parts of West Africa ware appointed by the?", "images": [], "options": {"A": "Oracle priest", "B": "Ogboni", "C": "Kingmakers", "D": "Age-grade"}, "answer": "C", "explanation": "In the pre-colonial period, traditional rulers in most parts of West Africa were appointed by the kingmakers. Kingmakers were a group of influential people in the kingdom who had the power to choose or elect the king. They were usually elders or chiefs who had a deep understanding of the traditions and customs of the kingdom. The oracle priest, Ogboni, and age-grade were not universally involved in the appointment of traditional rulers across West Africa.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>44", "subject": "Government", "year": "2002", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "Which of the following countries was a former French territory in West Africa?", "images": [], "options": {"A": "The Gambia", "B": "Ghana", "C": "Liberia", "D": "Senegal"}, "answer": "D", "explanation": "Former french territories of West Africa include:Senegal,French,Guinea,the ivory coast,and the French Sudan, to which Dahomey was added in 1899.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2002>45", "subject": "Government", "year": "2002", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "Which of the following is not a member of the Organization of Africa Unity (OAU)?", "images": [], "options": {"A": "South Africa", "B": "Comoro Island", "C": "Lesotho", "D": "Angola"}, "answer": "D", "explanation": "Angola is not a member.   The OAU now known as the AU(African Union) has 55 members currently and Angola is not one of them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>46", "subject": "Government", "year": "2002", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "An organ of the United Nations Organization (UNO) whose decision is binding on all members is the?", "images": [], "options": {"A": "Security Council", "B": "Economic and Social Council", "C": "Trusteeship Council", "D": "International court of justice"}, "answer": "D", "explanation": "International Court of Justice(ICJ), sometimes cakked World Court, is one of the six principal organs of the United Nation (UN). AND IT'S DECISION IS BINDING ON ALL MEMBERS.  The main organs of the UN are the General Assembly, the security Council,the Economic and Social Council,the Trusteeship Council, the International Court of Justice, and the UN Secretariat.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>47", "subject": "Government", "year": "2002", "type": "Objective", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "The foreign policy of West African states is mainly determined by?", "images": [], "options": {"A": "Expansionist interest", "B": "Constitutional provisions", "C": "National interest", "D": "International organizations"}, "answer": "C", "explanation": "The foreign policy of any country, including West African states, is primarily determined by its national interest. National interest refers to a country's goals and ambitions whether economic, military, or cultural. It is the driving force behind a country's foreign policy, influencing its interactions and relationships with other countries and international organizations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2002>48", "subject": "Government", "year": "2002", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : REPUBLICAN", "question": "The Queen of England ceased to be the Head of State of Nigeria on 1st October,", "images": [], "options": {"A": "1960", "B": "1963", "C": "1965", "D": "1979"}, "answer": "B", "explanation": "The Queen of England ceased to be the head of state of Nigeria at the adoption of the Republican Constitution in October 1963.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2002>49", "subject": "Government", "year": "2002", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "A union government was advocated for Africa by the?", "images": [], "options": {"A": "Cassablanca group", "B": "Monrovia group", "C": "The Brazzaville group", "D": "Malagsy group"}, "answer": "A", "explanation": "Cassablanca group first advocated for a union government in Africa.   The group composed of seven states led by radical,left-wing leaders-Algeria,Egypt,Ghana,Tanzania,Guinea,Libya,Mali and Morocco. The conflict and eventual compromise between the Casablanca Group and the Monrovia Group led to the establishment of the organisation of Africa Unity.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2002>50", "subject": "Government", "year": "2002", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "Food and Agricultural Organization(FAO) is one of the specialized agencies of the?", "images": [], "options": {"A": "Organization of African Unity (OAU)", "B": "Economic Community of West African States (ECOWAS)", "C": "Organization of Petroleum Exporting Countries (OPEC)", "D": "United Nations Organization (UNO)"}, "answer": "D", "explanation": "The Food and Agriculture Organisation (FAO) is a specialised agency of the United Nations Organization (UNO).", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2003>1", "subject": "Government", "year": "2003", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN INSTITUTION OF THE STATE:", "question": "Government as an institution of the state refers to the", "images": [], "options": {"A": "police and armed forces", "B": "judiciary, the president and his minister", "C": "legislature, the executive and the judiciary", "D": "economic and political institutions"}, "answer": "C", "explanation": "Government as an institution of a state comprises of the three arms of government which include legislature, executive and judiciary.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2003>2", "subject": "Government", "year": "2003", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Authority means", "images": [], "options": {"A": "an automatic right to be obeyed", "B": "legitimate right to be obeyed", "C": "a civic right to obey others", "D": "a civic right to be obeyed"}, "answer": "B", "explanation": "Authority means the legitimate right to be obeyed. It is right to control others and compel/obey without the use of sanction or force.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>3", "subject": "Government", "year": "2003", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "Zionism resulted in the establishment of the state of", "images": [], "options": {"A": "Iraq", "B": "Jordan", "C": "Israel", "D": "Lebanon"}, "answer": "C", "explanation": "Zionism is a nationalist movement that advocates for the re-establishment of a Jewish homeland in the territory defined as the historic Land of Israel. This movement resulted in the establishment of the state of Israel in 1948.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2003>4", "subject": "Government", "year": "2003", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "As a political ideology, capitalism seeks to", "images": [], "options": {"A": "encourage collective ownership of property", "B": "stimulate individual enterprise", "C": "eliminate social and economic inequalities", "D": "make the rich, richer and the poor"}, "answer": "B", "explanation": "Capitalism is a political ideology that allow private ownership of resources in a state where government participation is minimal.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>5", "subject": "Government", "year": "2003", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The purpose of Montesquieu's theory of separation of powers is to", "images": [], "options": {"A": "prevent tyranny by the government", "B": "uphold the supremacy of parliament", "C": "ensure equality before the law", "D": "guarantee free and fair elections"}, "answer": "A", "explanation": "Separation of power prevent tyranny by the government. It is the division of political power and functions among the three arms of government i.e legislature, executive and judiciary.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>6", "subject": "Government", "year": "2003", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The concept of sovereignty was first introduced into political terminology in 1576 by", "images": [], "options": {"A": "Winston Churchill", "B": "Jean Bodin", "C": "Karl Marx", "D": "Abraham Lincoln"}, "answer": "B", "explanation": "The concept of sovereignty was first introduced into political terminology in 1576 by Jean Bodin. Sovereignty is the full right and power of a governing body over itself, without any interference from outside sources or bodies. In political theory, sovereignty is a substantive term designating supreme legitimate authority over some polity. Jean Bodin was a French jurist and political philosopher, member of the Parlement of Paris and professor of law in Toulouse. He is best known for his theory of sovereignty.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>7", "subject": "Government", "year": "2003", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Power is different from authority because power lacks", "images": [], "options": {"A": "ability", "B": "sovereignty", "C": "probity", "D": "legitimacy"}, "answer": "D", "explanation": "Power is the ability to control other and compel to obey with the use of sanction while Authority is legitimacy right to control other and compel to obey. Power lack legitimacy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>8", "subject": "Government", "year": "2003", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Oligarchy implies rulership by", "images": [], "options": {"A": "an absolute monarch", "B": "a few powerful individuals", "C": "a military government", "D": "a charismatic leader"}, "answer": "B", "explanation": "Oligarch is a form of government that places political power in the hands of a few people. It implies rulership by a few powerful individuals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>9", "subject": "Government", "year": "2003", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A fascist regime is both", "images": [], "options": {"A": "fair and legitimate", "B": "responsive and responsible", "C": "authoritarian and totalitarian", "D": "democratic and constitutional"}, "answer": "C", "explanation": "Fascist regime is both authoritarian and totalitarian. It is a form of government headed by a dictator, in which government has a total control overall activities in the state.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2003>10", "subject": "Government", "year": "2003", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Freedom to act as one pleases but within the law is described as", "images": [], "options": {"A": "democracy", "B": "separation of powers", "C": "human right", "D": "civic responsibility"}, "answer": "C", "explanation": "Human right is the freedom to act as one pleases but within the law. It is inalienable rights and priviledge enjoyed by the citizens of a given state, which are usually stated in the constitution of the country.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>11", "subject": "Government", "year": "2003", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "A written constitution should have", "images": [], "options": {"A": "an easy process of amendment", "B": "the principle of judicial interpretation", "C": "a hereditary process of succession", "D": "a propertied franchise"}, "answer": "B", "explanation": "Written constitution should have the principle of Judicial interpretation. A written constitution is a document establishing the selection of rules embodied in a document in which fundamental principles concerning the organisation of a political system, powers of its various agencies are written down and codified.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>12", "subject": "Government", "year": "2003", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Checks and balances violate the principle of", "images": [], "options": {"A": "rule of law", "B": "devolution", "C": "decentralization", "D": "separation of powers"}, "answer": "D", "explanation": "Check and balances violate the principle of separation of powers.  Check and balances emphasizes the power of any of the organs checking the activities of the others.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2003>13", "subject": "Government", "year": "2003", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : MONARCHICAL", "question": "In a constitutional monarchy, the Head of State performs mainly", "images": [], "options": {"A": "executive functions", "B": "judicial functions", "C": "administrative functions", "D": "ceremonial functions"}, "answer": "D", "explanation": "In a constitutional monarchy, the Head of State mainly performs ceremonial functions. A constitutional monarchy is a form of government in which a monarch acts as head of state within the parameters of a written or unwritten constitution. The monarch's role is largely ceremonial and symbolic, while the real political power is exercised by other political leaders, such as the prime minister or the parliament.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>14", "subject": "Government", "year": "2003", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET", "question": "If a member of the legislature is appointed a Minister, he forfeits his seat in the legislature. This is a feature of the", "images": [], "options": {"A": "presidential system of government", "B": "parliamentary system of government", "C": "communist system of government", "D": "feudal system of government"}, "answer": "A", "explanation": "If a member of the legislative is appointed a minister, he forfeits his seat in the legislature. This is a feature of the presidential system of government.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2003>15", "subject": "Government", "year": "2003", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PRESIDENTIAL", "question": "Which of the following statements about the presidential system is false?", "images": [], "options": {"A": "The constitution is supreme", "B": "Existence of official opposition", "C": "The president is popularly elected", "D": "Ministers are not members of parliament"}, "answer": "B", "explanation": "In a presidential system of government, there is no official opposition. The concept of an official opposition is more common in parliamentary systems where the largest party or coalition not in government is known as the official opposition.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2003>16", "subject": "Government", "year": "2003", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY", "question": "In a unitary system of government, power is derived from", "images": [], "options": {"A": "the judiciary", "B": "the executive", "C": "the constitution", "D": "source of authority"}, "answer": "C", "explanation": "In a unitary system of government, power is derived from the constitution. The constitution is the supreme law of the land and it outlines how power is distributed and exercised within the state. It is from the constitution that the executive, judiciary, and legislature derive their powers and functions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>17", "subject": "Government", "year": "2003", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "Citizens who are legally qualified to vote form", "images": [], "options": {"A": "a constituency", "B": "the executive council", "C": "the House of Assembly", "D": "the electorate"}, "answer": "D", "explanation": "Citizens who are legally qualified to vote form the electorate. The electorate is a term that refers to all the people in a country or area who are entitled to vote in an election. It does not refer to a constituency, the executive council, or the House of Assembly.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>18", "subject": "Government", "year": "2003", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Which of the following is an indirect form of election?", "images": [], "options": {"A": "Electoral college", "B": "General election", "C": "Referendum", "D": "Bye-election"}, "answer": "A", "explanation": "An indirect form of election is the Electoral college. In this system, voters cast ballots for a slate of electors who then cast votes for candidates on behalf of the electorate. General elections, referendums, and bye-elections are all direct forms of elections where citizens vote directly for the candidate or issue at hand.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>19", "subject": "Government", "year": "2003", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Franchise owes its evolution to the", "images": [], "options": {"A": "development of representative government", "B": "establishment of state enterprise", "C": "development of the cabinet", "D": "establishment of electoral commission"}, "answer": "A", "explanation": "Franchise owes it evolution to the development of representative government. Franchise may be defined as the political rights of qualified adult citizens of a given country, to vote and to be voted for, in any political election.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2003>20", "subject": "Government", "year": "2003", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "One of the main functions of an election is", "images": [], "options": {"A": "co-ordination of electoral activities", "B": "making of rules for governance", "C": "legitimization of the government", "D": "creating an avenue for politicians to make money"}, "answer": "C", "explanation": "One of the main functions of an election is the legitimization of the government. Elections provide a platform for citizens to express their will and choose their representatives in the government. This process gives the elected government legitimacy, as it is seen as a reflection of the people's will. This is a fundamental principle in democratic societies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>21", "subject": "Government", "year": "2003", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Which of the following factors limits universal adult suffrage?", "images": [], "options": {"A": "wealth", "B": "age", "C": "education", "D": "heredity"}, "answer": "B", "explanation": "Universal adult suffrage refers to the right of citizens in a given state who are of voting age to vote. The main factor that limits this is age. Citizens must reach a certain age, usually 18 years, to be eligible to vote. Wealth, education, and heredity do not limit universal adult suffrage as voting rights are not dependent on these factors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>22", "subject": "Government", "year": "2003", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "The manifesto of a political party is a document which outlines", "images": [], "options": {"A": "a country's political party development", "B": "a party's programme", "C": "the national ideology", "D": "the interest of party members"}, "answer": "B", "explanation": "The manifesto of a political party is a document that outlines the party's programme. It contains the party's policies, goals, and plans that it intends to implement if it gains power. It does not outline a country's political party development, the national ideology, or the interest of party members.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>23", "subject": "Government", "year": "2003", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS", "question": "A system in which two or more political parties form the government is called", "images": [], "options": {"A": "a coalition", "B": "an association", "C": "a decentralization", "D": "a centralization"}, "answer": "A", "explanation": "Collation government is a system where two or more political parties form the government of a country.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2003>24", "subject": "Government", "year": "2003", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "Red tapism can be explained as", "images": [], "options": {"A": "the decentralized way of taking decisions", "B": "a flexible way by which government decisions are taken", "C": "the rigid dependence on routine by civil servants", "D": "management by objectives"}, "answer": "C", "explanation": "Red tapism refers to the excessive bureaucracy or adherence to rules and formalities, especially in public business. It is often associated with long complex procedures and rules that are seen as unnecessary and hinder decision-making. The term 'red tape' originates from the red tape used to bind legal and official documents in the past.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2003>25", "subject": "Government", "year": "2003", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "A major objectives of a pressure groups is to", "images": [], "options": {"A": "influence policies of government", "B": "contest elections", "C": "control the machinery of government", "D": "provide political education"}, "answer": "A", "explanation": "A major objective of a pressure groups is to influence policies of governments pressure groups is defined as organised groups, which influence government decisions socially or economically, without necessarily entering into election activities for the control of government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>26", "subject": "Government", "year": "2003", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : MASS MEDIA", "question": "Which of the following agents of public opinion is the most widespread?", "images": [], "options": {"A": "Mass media", "B": "The schools", "C": "The interest groups", "D": "Political parties"}, "answer": "A", "explanation": "Mass media is agent of public opinion that is most widespread. The opinion of the people can be expressed through mass media such as television, radio, newspaper e.t.c.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2003>27", "subject": "Government", "year": "2003", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "A statutory corporation is under the supervision of", "images": [], "options": {"A": "the Chief Justice", "B": "commissioner of Police", "C": "a minister", "D": "a local government chairman"}, "answer": "C", "explanation": "The statutory corporation is under the supervision of minister, it is controlled by board of directors which is appointed by government, owned by government and established by the Act of Parliament.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>28", "subject": "Government", "year": "2003", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "One of the functions of local government is to", "images": [], "options": {"A": "collect company tax", "B": "make bye-laws", "C": "defend the nation", "D": "mint currency"}, "answer": "B", "explanation": "One of the functions of local government is to make bye-laws. Bye-laws are local laws made by a local council that apply only within a specific geographical area. These laws are made to control the activities of people in these areas and to manage local resources.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2003>29", "subject": "Government", "year": "2003", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "The law-making body in Nigeria is called the", "images": [], "options": {"A": "Congress", "B": "Presidium", "C": "National Assembly", "D": "Parliament"}, "answer": "C", "explanation": "The law-making body in Nigeria is called the National Assembly. The National Assembly is the bicameral legislature of the Federal Republic of Nigeria, consisting of two chambers: the House of Representatives and the Senate.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2003>30", "subject": "Government", "year": "2003", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "The independence of the judiciary is meant to", "images": [], "options": {"A": "protect the rights of the judges", "B": "safeguard the liberties of individuals", "C": "enable judges enact laws at will", "D": "allow judges to participate in partisan politics"}, "answer": "B", "explanation": "The independence of the Judiciary arm of government is meant to safeguard the liberties of individuals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>31", "subject": "Government", "year": "2003", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "An institution which seeks to redress people's grievances against abuse of administrative power is the", "images": [], "options": {"A": "Ombudsman", "B": "Judiciary", "C": "Directorate of Public Prosecution", "D": "Judicial Service Commission"}, "answer": "A", "explanation": "Ombudsman is an institution which seeks to redress people's grievances against abuse of administrative power.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>32", "subject": "Government", "year": "2003", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "Which of the following was not a feature of assimilation policy?", "images": [], "options": {"A": "Forced labour", "B": "Compulsory military service", "C": "Indigenate", "D": "Use of traditional rulers"}, "answer": "D", "explanation": "Assimilation policy does not make use of traditional rulers. It ws the official colonial policy of the french Administration in West Africa. It was a direct rule where french impose their culture on the African culture.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2003>33", "subject": "Government", "year": "2003", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Two-party system of government enables the electorate to", "images": [], "options": {"A": "participate in government", "B": "choose freely between alternatives", "C": "mobilize favourable opinion for government", "D": "sympathise with government"}, "answer": "B", "explanation": "A two-party system is a form of party system where two major political parties dominate voting in nearly all elections, at every level. As a result, all, or nearly all, elected offices end up being held by candidates endorsed by one of the two major parties. This system enables the electorate to choose freely between alternatives.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>34", "subject": "Government", "year": "2003", "type": "Objective", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : FEATURES AND PROBLEMS", "question": "Nigeria was a Federal state under the constitution of 1954 because the constitution provided for", "images": [], "options": {"A": "equal representation between the North and South", "B": "a division of functions between the centre and the component states", "C": "direct election of members of parliament", "D": "the post of a prime minister"}, "answer": "B", "explanation": "Nigeria was a federal state under the constitution of 1954 because the constitution provided for a division of functions between the centre and the component states.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2003>35", "subject": "Government", "year": "2003", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "All the following were the demands made by the National Congress of British West Africa from the colonial government except the", "images": [], "options": {"A": "establishment of a legislative council in each of the British colonial territories", "B": "appointment of an African as a governor in each of the British colonial territories", "C": "establishment of a West African House of Assembly", "D": "establishment of a West African University"}, "answer": "B", "explanation": "Appointment of an African as a governor in each of the british colonial territories is not of the demands made by the National Congrss of British West Africa (NCBWA).", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2003>36", "subject": "Government", "year": "2003", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : ELECTORAL MANAGEMENT BODY", "question": "The responsibilities of dividing a country into constituencies and accepting the nomination of candidates for elections are shouldered by the", "images": [], "options": {"A": "Ombudsman", "B": "President", "C": "Electoral Commission", "D": "Census Board"}, "answer": "C", "explanation": "Electoral Commission is responsible for division of country into constituencies and accept the nomination of candidates for elections.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>37", "subject": "Government", "year": "2003", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "The two main policies introduced by the French in West Africa were", "images": [], "options": {"A": "indirect rule and direct rule", "B": "indirect rule and assimilation", "C": "direct rule and indigenat", "D": "assimilation and association"}, "answer": "D", "explanation": "The french colonial ruler introduced two major policies which are policy of assimilation and policy of association.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>38", "subject": "Government", "year": "2003", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : POST- INDEPENDENCE CONSTITUTIONS", "question": "The Loi cadre was passed in", "images": [], "options": {"A": "1959", "B": "1956", "C": "1955", "D": "1954"}, "answer": "B", "explanation": "The Loi Cadre (Framework Law) was passed in 1956. This was a significant law in the decolonization process in French West Africa. It allowed for universal suffrage and gave the African colonies a greater voice in their own governance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>39", "subject": "Government", "year": "2003", "type": "Objective", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "A benefit which a country seeks to achieve in her relations with other nations is called", "images": [], "options": {"A": "national interest", "B": "commercial interest", "C": "international diplomacy", "D": "foreign policy objective"}, "answer": "A", "explanation": "National Interest is a benefit which a country seeks to achieve in her relations with other nations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>40", "subject": "Government", "year": "2003", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The international organization formed after the Second World War to guarantee international peace and security is called the", "images": [], "options": {"A": "Non-Aligned Movement", "B": "United Nations Organization", "C": "League of Nations", "D": "Cassablanca Group"}, "answer": "B", "explanation": "United Nations Organisation (UNO) is an International organisation formed after the second world war to guarantee international peace and security.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2003>41", "subject": "Government", "year": "2003", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Under the British colonial administration, the Executive Council was purely", "images": [], "options": {"A": "judicial body", "B": "an advisory body", "C": "charged with making laws", "D": "a tax collecting agency"}, "answer": "B", "explanation": "The Executive Council under the British colonial administration was an advisory body. It was a group of high-ranking officials and advisors who provided counsel to the Governor. They did not have the power to make laws or collect taxes, and they were not a judicial body.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>42", "subject": "Government", "year": "2003", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "The policy which sought to turn Africans into Frenchmen and rule them through institutions similar to those in France was", "images": [], "options": {"A": "assimilation", "B": "association", "C": "Loi-cadre", "D": "Africanization"}, "answer": "A", "explanation": "Policy of Assimilation is the policy which sought to turn Africans into frenchmen and rule them through institution similar to those in france. It was a direct rule on Africans by the french colonial master.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>43", "subject": "Government", "year": "2003", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "Many African leaders adopted the single-party system of government after independence in order to promote", "images": [], "options": {"A": "fundamental human rights", "B": "constitutional government", "C": "national unity", "D": "competitive politics"}, "answer": "C", "explanation": "National unity was introduced by African leader by adopting the single-party system of government after independence.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2003>44", "subject": "Government", "year": "2003", "type": "Objective", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "The principle of non-alignment means that a country", "images": [], "options": {"A": "is neutral in international trade", "B": "does not belong to any world organization", "C": "does not belong to any of the power blocs", "D": "has no diplomatic mission abroad"}, "answer": "C", "explanation": "The principle of non-alignment means that a country does not belong to any of the power blocs. Non-alignment is a foreign policy strategy where a country does not align itself with or against any major power bloc or alliance. It was a significant policy for many countries during the Cold War, where the world was divided into two major power blocs: the capitalist bloc led by the United States and the communist bloc led by the Soviet Union.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>45", "subject": "Government", "year": "2003", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "The annual budget of the Organization of African Unity (OAU) is approved by the", "images": [], "options": {"A": "Security Council", "B": "Council of Ministers", "C": "Economic and Social Council", "D": "Commission of Mediation and Arbitration"}, "answer": "B", "explanation": "The annual budget of the organisation of African unity (OAU) is approved by the council of ministers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>46", "subject": "Government", "year": "2003", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The World Health Organization (WHO) is an agency of the", "images": [], "options": {"A": "Organization of African Unity (OAU)", "B": "Economic Community of West African States (ECOWAS)", "C": "Commonwealth of Nations", "D": "United Nations Organization"}, "answer": "D", "explanation": "The World Health Organization (WHO) is an agency of the United Nations Organization. The WHO is a specialized agency of the United Nations responsible for international public health. It was established on 7 April 1948, and is headquartered in Geneva, Switzerland. The WHO is a member of the United Nations Development Group.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2003>47", "subject": "Government", "year": "2003", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "The term ECOMOG means", "images": [], "options": {"A": "Economic Community of West African Group", "B": "Economic Community Monetary Group", "C": "ECOWAS Monitoring Group", "D": "ECOWAS Movement Group"}, "answer": "C", "explanation": "The ter ECOMOG meand ECOWAS Monitoring Group. One of the achievement of ECOWAS was the formation ECOMOG to ensure peacekeeping force and also to restore democracy in both Liberia and Sierra leone.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2003>48", "subject": "Government", "year": "2003", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The Headquarters of the United Nations Organization is located at", "images": [], "options": {"A": "New York", "B": "Addis Ababa", "C": "Vienna", "D": "London"}, "answer": "A", "explanation": "The headquarters of the United Nations Organization is located in New York, United States. The United Nations (UN) is an international organization founded in 1945. It is composed of 193 member states and its main headquarters is in Manhattan, New York City.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2003>49", "subject": "Government", "year": "2003", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "The highest organ of the Organization of African Unity (OAU) is the", "images": [], "options": {"A": "Trusteeship Council", "B": "Secretariat", "C": "Assembly of Heads of State", "D": "Council of Ministers"}, "answer": "C", "explanation": "The highest organ of the Organization of African Unity (OAU), now known as the African Union (AU), is the Assembly of Heads of State. This assembly is composed of leaders from all member countries and is responsible for determining the organization's policies and objectives. The Trusteeship Council, Secretariat, and Council of Ministers are also important parts of the organization, but they do not hold as much power as the Assembly of Heads of State.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2003>50", "subject": "Government", "year": "2003", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "It is most unlikely for member nations of the Economic Community of West African States (ECOWAS) to", "images": [], "options": {"A": "fuse into one political entity", "B": "establish a common customs tariff", "C": "have joint development of transport and communications", "D": "abolish obstacles to free movement of citizens"}, "answer": "A", "explanation": "The Economic Community of West African States (ECOWAS) is a regional group of fifteen West African countries. While it aims to promote economic integration across the region, it is most unlikely for member nations to fuse into one political entity. This is because each member nation has its own unique political system, culture, and history. The other options such as establishing a common customs tariff, having joint development of transport and communications, and abolishing obstacles to free movement of citizens are more aligned with the goals of ECOWAS.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>1", "subject": "Government", "year": "2004", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "Constitutional government is run", "images": [], "options": {"A": "by lawyers", "B": "by the politicians", "C": "by applying arbitrary rules", "D": "according to the laws of the land"}, "answer": "D", "explanation": "Constitutional government is run according to the laws of the land or to the stipulated rules, regulations or convention of the state.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2004>2", "subject": "Government", "year": "2004", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A society without constituted authority is called a", "images": [], "options": {"A": "feudal state", "B": "stateless society", "C": "government in exile", "D": "backward society"}, "answer": "B", "explanation": "A society without constituted authority is regarded as stateless society. It is a society without government and constitution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>3", "subject": "Government", "year": "2004", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Direct democracy implies that the governance of a state involves", "images": [], "options": {"A": "all the citizens of the state", "B": "only male citizens", "C": "adult female citizens", "D": "citizens' representatives"}, "answer": "A", "explanation": "Direct democracy is a form of government where decisions are made directly by the citizens rather than their representatives. This means that all the citizens of the state are involved in the governance, making option 1 the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>4", "subject": "Government", "year": "2004", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The theory of Socialism was popularised by", "images": [], "options": {"A": "A. V. Dicey", "B": "Karl Marx", "C": "Baron de Montesquieu", "D": "Aristotle"}, "answer": "B", "explanation": "The theory of Socialism was popularised by Karl Marx. Socialism is a political, social, and economic philosophy encompassing a range of economic and social systems characterised by social ownership of the means of production. It was Karl Marx who popularised this theory, making option 2 the correct answer.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2004>5", "subject": "Government", "year": "2004", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Nobles who form government are called", "images": [], "options": {"A": "theocrats", "B": "aristocrats", "C": "plutocrats", "D": "autocrats"}, "answer": "B", "explanation": "Aristocracy is defined as a form of government in which the best or noble citizens rule. In most cases, people of noble birth or wealth usually rule.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>6", "subject": "Government", "year": "2004", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Political socialization is associated with", "images": [], "options": {"A": "free choice of party programmes", "B": "military takeover of civilian government", "C": "the transmission of political values, attitudes and opinions", "D": "political programmes of transition to civil rule"}, "answer": "C", "explanation": "Political socialization is associated with the transmission of political values, attitudes and opinions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>7", "subject": "Government", "year": "2004", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "In a fascist regime, the Head of State is", "images": [], "options": {"A": "the royal father", "B": "the prime minister", "C": "the elected monarch", "D": "supreme and above the law"}, "answer": "D", "explanation": "In fascist regime, the head of state is supreme and above the law. It is a form of dictatorship government.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2004>8", "subject": "Government", "year": "2004", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following best describes totalitarianism?", "images": [], "options": {"A": "Extreme decentralization", "B": "Excessive centralization of power", "C": "Devolution of power", "D": "Delegation of power"}, "answer": "B", "explanation": "Totalitarianism is defined as a form of government in which the state has absolute control of everything. It is the excessive centralization of power.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2004>9", "subject": "Government", "year": "2004", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Rule by divine right is a feature of", "images": [], "options": {"A": "the republican system", "B": "the feudal system", "C": "absolute monarchy", "D": "democracy"}, "answer": "C", "explanation": "The rule by divine right is a feature of absolute monarchy. Absolute monarchy occurs when there is established constitutional authority to check the king's power. The king rule as the Head of government and Head of State.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>10", "subject": "Government", "year": "2004", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A system in which people contribute for the welfare of their community can be described as", "images": [], "options": {"A": "Communalism", "B": "Socialism", "C": "Communism", "D": "Capitalism"}, "answer": "A", "explanation": "Communalism is a system in which people contribute for welfare of their community. It is a political, social and economic arrangement in which landed property and other natural resources are collectively owned, managed and co-operatively harnessed by the community for the common good of everybody.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>11", "subject": "Government", "year": "2004", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following best describes feudalism?", "images": [], "options": {"A": "A few people monopolise the ownership of land", "B": "Mas ownership of property is prevalent", "C": "State ownership of capital is prevalent", "D": "Workers administer the society"}, "answer": "A", "explanation": "Feudalism occurs when a few people monopolise the ownership of land. It can be defined as the identification of landed property with sovereignty.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>12", "subject": "Government", "year": "2004", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A system of government which is based on the public ownership of means of production and distribution is called", "images": [], "options": {"A": "welfarism", "B": "socialism", "C": "feudalism", "D": "authoritarianism"}, "answer": "B", "explanation": "Socialism is a system of government which is based on the public ownership of means of production and distribution. It is a system of government whereby the means of production and distribution is owned and controlled by the state.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>13", "subject": "Government", "year": "2004", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The principle of 'Separation of Powers' is less applicable in a", "images": [], "options": {"A": "parliamentary system of government", "B": "unitary system of government", "C": "confederal system of government", "D": "federal system of government"}, "answer": "A", "explanation": "The principle of separation of powers is less applicable in a parliamentary system of good because there is fusion of power.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2004>14", "subject": "Government", "year": "2004", "type": "Objective", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : FEATURES AND PROBLEMS", "question": "In a classical federal state, residual powers are vested in the", "images": [], "options": {"A": "federal and state governments", "B": "federal governments", "C": "federal and local governments", "D": "state governments"}, "answer": "D", "explanation": "In a classical federal state, residual powers are vested in the state governments. Residual powers refer to those powers which are not enumerated or listed in the constitution. In a federal system, the constitution divides powers between the central government and the state governments. However, any powers not specifically listed in the constitution are typically considered to be 'residual powers', and these are usually left to the state governments to exercise.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2004>15", "subject": "Government", "year": "2004", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET", "question": "Which of the following systems of government has bicephalous executive?", "images": [], "options": {"A": "Parliamentary", "B": "Monarchical", "C": "Unitary", "D": "Totalitarian"}, "answer": "A", "explanation": "A bicephalous executive refers to a system of government where the executive power is divided between two individuals, typically a ceremonial head of state and a head of government. This is characteristic of a Parliamentary system of government. In such a system, the head of state (often a monarch or president) and the head of government (usually a prime minister) share executive powers. The head of state's role is largely ceremonial, while the head of government is responsible for running the country's day-to-day operations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>16", "subject": "Government", "year": "2004", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PRESIDENTIAL", "question": "In the presidential system of government, the president is responsible to the", "images": [], "options": {"A": "legislature", "B": "judiciary", "C": "electorate", "D": "military"}, "answer": "C", "explanation": "In a presidential system of government, the president is elected by the electorate and is directly responsible to them. The president is the head of state and head of government, and is separate from the legislature. This means that the president cannot be removed by the legislature and is only accountable to the electorate that elected him or her. This is in contrast to a parliamentary system, where the head of government is accountable to the legislature.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2004>17", "subject": "Government", "year": "2004", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Which of the following is not a reason for delegated legislation?", "images": [], "options": {"A": "Technicalities of modern legislation", "B": "The need for flexibility", "C": "To reduce the powers of the legislature", "D": "To ensure speedy legislation"}, "answer": "C", "explanation": "Delegated legislation is a type of legislation that is passed on by the Parliament to a person or an entity, which is not the Parliament itself. The reasons for delegated legislation include the technicalities of modern legislation, the need for flexibility, and to ensure speedy legislation. However, it is not used to reduce the powers of the legislature. In fact, the legislature retains ultimate control over delegated legislation as it can repeal the enabling Act that gives the power to make such legislation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>18", "subject": "Government", "year": "2004", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET", "question": "In which of the following systems of government is the principle of collective responsibility best upheld?", "images": [], "options": {"A": "Presidential", "B": "Cabinet", "C": "Military", "D": "Traditional"}, "answer": "B", "explanation": "Cabinet or parliamentary system of government involve collectively responsibility. It implies that the numbers of executive are collectively responsible for any decision taken by them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>19", "subject": "Government", "year": "2004", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : CONFEDERAL", "question": "Primary loyalty of a citizen in a confederal state goes to the", "images": [], "options": {"A": "government at the centre", "B": "confederating units", "C": "the sovereign state", "D": "assembly at the centre"}, "answer": "B", "explanation": "In a confederal state, the primary loyalty of a citizen goes to the confederating units. This is because in a confederation, the constituent units retain their sovereignty and delegate only a few powers to the central government. Therefore, the citizens' primary loyalty is to their respective constituent units, not the central government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>20", "subject": "Government", "year": "2004", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The theory of the separation of powers was propounded by", "images": [], "options": {"A": "John Locke", "B": "Adam Smith", "C": "Karl Marx", "D": "Harold Wilson"}, "answer": "A", "explanation": "Separation of power was propounded by John locke and baron de montesquie in his book the spirit of laws.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2004>21", "subject": "Government", "year": "2004", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN INSTITUTION OF THE STATE:", "question": "The institution through which governments discharge responsibilities is known as", "images": [], "options": {"A": "organs of government", "B": "pressure groups", "C": "political parties", "D": "national assembly"}, "answer": "A", "explanation": "The institution through which governments discharge responsibilities is the organs of government which are the legislature, executive and judiciary.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2004>22", "subject": "Government", "year": "2004", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : EXECUTIVE", "question": "The primary function of the executive is to", "images": [], "options": {"A": "interpret laws", "B": "punish law breakers", "C": "make laws", "D": "implement government policies"}, "answer": "D", "explanation": "The primary function of the executive is to implement government policies. The executive branch of government is responsible for enforcing laws and administering the daily functions of the state. This includes implementing and enforcing the policies and laws passed by the legislative branch.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2004>23", "subject": "Government", "year": "2004", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "Independence of the judiciary connotes that", "images": [], "options": {"A": "judges must be allowed to participate in politics", "B": "court judges are free to administer oaths of office", "C": "judiciary must not be involved in law-making", "D": "judges must be free from any influence"}, "answer": "D", "explanation": "Independence of the judiciary means that the judiciary should be free from any influence, whether it be from the executive, legislative, or any other source. This is to ensure that judges can make fair and unbiased decisions based on the law and not on any external pressures or influences.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>24", "subject": "Government", "year": "2004", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "The term Unicameralism means", "images": [], "options": {"A": "legislative assemblies", "B": "parliamentary elections", "C": "one-chamber parliament", "D": "complete absence of parliament"}, "answer": "C", "explanation": "Unicameralism means one-chamber parliament. It is the existence of one legislative chamber in a country.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>25", "subject": "Government", "year": "2004", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY", "question": "Which of the following countries is operating a Unitary Constitution?", "images": [], "options": {"A": "Nigeria", "B": "Canada", "C": "Britain", "D": "America"}, "answer": "C", "explanation": "A unitary constitution is a type of government where power is concentrated in the central government, and the sub-national units only exercise the powers that the central government chooses to delegate. Britain operates a unitary constitution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>26", "subject": "Government", "year": "2004", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "The philosophy and fundamental laws of a country are contained in her", "images": [], "options": {"A": "manifesto", "B": "decrees", "C": "edicts", "D": "constitution"}, "answer": "D", "explanation": "The philosophy and fundamental laws of a country are contained in her constitution. A constitution is a set of fundamental principles or established precedents according to which a state or other organization is governed. These rules together make up, i.e. constitute, what the entity is.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2004>27", "subject": "Government", "year": "2004", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC/CIVIL SERVICE COMMISSION –MEANING AND FUNCTIONS.", "question": "Public Complaints Commission in West African countries can be called", "images": [], "options": {"A": "Civil Service Commission", "B": "Ombudsman", "C": "Local Authority Commission", "D": "Ministry of Establishment"}, "answer": "B", "explanation": "The Public Complaints Commission, also known as the Ombudsman, is the institution established by the government to address complaints from aggrieved persons treated unjustly within the public service. The Ombudsman is a mediator between the public and the government's administrative authorities. It is not the Civil Service Commission, Local Authority Commission, or Ministry of Establishment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>28", "subject": "Government", "year": "2004", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Habeas Corpus implies", "images": [], "options": {"A": "unlawful detention", "B": "discrimination in public service", "C": "indiscriminate party formation", "D": "right to vote"}, "answer": "A", "explanation": "Habeas Corpus is a legal term that comes from a Latin phrase that means 'you shall have the body'. It is a recourse in law through which a person can report an unlawful detention or imprisonment to a court and request that the court order the custodian of the person, usually a prison official, to bring the prisoner to court, to determine whether the detention is lawful. It does not imply discrimination in public service, indiscriminate party formation, or the right to vote.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>29", "subject": "Government", "year": "2004", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "In order to preserve the liberties of individuals in a country, which of the following systems is encouraged?", "images": [], "options": {"A": "Feudalism", "B": "Communism", "C": "Multi-party system", "D": "One-party system"}, "answer": "C", "explanation": "Multi-party system preserve the liberties of individuals in a country. Multi-party system occurs when the constitution allow for two or more political parties in a country.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2004>30", "subject": "Government", "year": "2004", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Political parties contest elections in order to", "images": [], "options": {"A": "formulate policies", "B": "influence public opinion", "C": "control political power", "D": "prevent coups d'etat"}, "answer": "C", "explanation": "Political parties contest elections primarily to control political power. By winning elections, they gain the ability to implement their policies and influence the direction of the government. While political parties do formulate policies and influence public opinion, these activities are means to the end of gaining political power. Preventing coups d'etat is not a primary reason for political parties to contest elections.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>31", "subject": "Government", "year": "2004", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "One-party system is favourably disposed to", "images": [], "options": {"A": "national cohesion", "B": "sectarian demands", "C": "rule of law", "D": "religious tolerance"}, "answer": "A", "explanation": "A one-party system is a type of state in which one political party has the right to form the government, usually based on the existing constitution. All other parties are either outlawed or allowed to take only a limited and controlled participation in elections. It is a system that promotes national cohesion because it eliminates the division and competition that comes with multi-party systems.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>32", "subject": "Government", "year": "2004", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "Which of the following pressure groups does Cotton Producers' Union represent?", "images": [], "options": {"A": "Labour", "B": "Economic", "C": "Social", "D": "Political"}, "answer": "B", "explanation": "Economic pressure groups are mostly manufacturers, association like chamber of commerce, cocoa farmers union, cotton producers union etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2004>33", "subject": "Government", "year": "2004", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "Promotional pressure groups usually cater for the interest of", "images": [], "options": {"A": "all workers", "B": "the general public", "C": "non-members only", "D": "all professional bodies"}, "answer": "D", "explanation": "Promotional pressure groups are a type of pressure group that seeks to promote a particular cause, and they usually cater for the interest of all professional bodies. They are not necessarily concerned with the interests of all workers, the general public, or non-members only. They focus on specific issues and try to influence public policy in areas such as the environment, human rights, and social justice.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>34", "subject": "Government", "year": "2004", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "The earliest agent in the formation of public opinion is the", "images": [], "options": {"A": "family", "B": "hospital", "C": "political party", "D": "university"}, "answer": "A", "explanation": "The family is the earliest agent in the formation of public opinion. From a young age, individuals are influenced by the beliefs and values of their family members. This early influence can shape an individual's views and opinions on a variety of topics. Hospitals, political parties, and universities also play a role in forming public opinion, but they come into play later in an individual's life.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2004>35", "subject": "Government", "year": "2004", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "The plurality system of voting could be described as", "images": [], "options": {"A": "complex majority", "B": "two-third majority", "C": "simple majority", "D": "absolute majority"}, "answer": "C", "explanation": "The plurality system of voting, also known as 'first past the post', is a system where the candidate with the most votes (not necessarily a majority) wins. This is also known as a simple majority system. The other options do not accurately describe the plurality system of voting.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>36", "subject": "Government", "year": "2004", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : ELECTORAL MANAGEMENT BODY", "question": "Which of the following is the duty of an Electoral Commission?", "images": [], "options": {"A": "Adjudicating election petitions", "B": "Nominating party candidates", "C": "Campaigning for candidates", "D": "Provision of voters' register"}, "answer": "D", "explanation": "The duty of an Electoral Commission is to manage the electoral process, which includes the provision of voters' register. Adjudicating election petitions is usually the responsibility of the judiciary, not the Electoral Commission. Nominating party candidates and campaigning for candidates are roles of political parties, not the Electoral Commission.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2004>37", "subject": "Government", "year": "2004", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC/CIVIL SERVICE COMMISSION –MEANING AND FUNCTIONS.", "question": "Civil servants are recruited, controlled, promoted and disciplined by the", "images": [], "options": {"A": "teaching service commission", "B": "public complaints commission", "C": "public service commission", "D": "code of conduct bureau"}, "answer": "C", "explanation": "Civil servants are recruited, controlled, promoted, and disciplined by the Public Service Commission. The Public Service Commission is a government agency responsible for the appointment, promotion, transfer, and disciplinary control of civil servants.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>38", "subject": "Government", "year": "2004", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "Red-tapism refers to", "images": [], "options": {"A": "excessive use of formalities in administration", "B": "cutting of the tape during official ceremonies", "C": "measurement with tape rule in government land survey", "D": "use of red carpet for important dignitaries"}, "answer": "A", "explanation": "Red-tapism refers to the excessive use of formalities in administration. It is a term that describes a process that is overly bureaucratic and hinders or prevents action or decision-making. It involves dealing with excessive regulation or rigid conformity to formal rules that is perceived to be unnecessary or bureaucratic.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>39", "subject": "Government", "year": "2004", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "One of the reasons for the establishment of local government authorities is to", "images": [], "options": {"A": "give more powers to the traditional rulers", "B": "bring government nearer to the people", "C": "win support of local chiefs", "D": "prevent political interference by aliens"}, "answer": "B", "explanation": "Local government authorities are established to bring government nearer to the people. This is because they are the level of government that is closest to the people and they are responsible for the administration of areas within their jurisdiction. They provide a way for the government to interact directly with the citizens and address their specific needs and concerns.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2004>40", "subject": "Government", "year": "2004", "type": "Objective", "topic": "CITIZENSHIP : MEANING AND MODE OF ACQUISITION", "question": "Which of the following groups was provided for under the French West African Dual Citizenship?", "images": [], "options": {"A": "Men and women", "B": "Muslims and Christians", "C": "Soldiers and civilians", "D": "Citizens and the subjects"}, "answer": "D", "explanation": "Under the French West African Dual Citizenship, provision was made for citizens and subjects. This was a colonial policy that distinguished between the French citizens (who were the colonial masters) and the subjects (who were the colonized people). The citizens had full rights and privileges of French citizenship while the subjects were governed by the French colonial laws.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2004>41", "subject": "Government", "year": "2004", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "A major feature of the constitutions in British West African colonies in the 1920s was the", "images": [], "options": {"A": "abolition of local government", "B": "introduction of the elective principle", "C": "introduction of council of elders", "D": "introduction of Universal Adult Suffrage"}, "answer": "B", "explanation": "A major feature of the constitutions in British West African colonies in the 1920s was the Introduction of the elective principle.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>42", "subject": "Government", "year": "2004", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "The system of administration adopted by the British in the crown colonies in West Africa was", "images": [], "options": {"A": "direct rule", "B": "democratic", "C": "assimilation", "D": "association"}, "answer": "A", "explanation": "The system of administration adopted by the british the crown colonies in West Africa was direct rule.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>43", "subject": "Government", "year": "2004", "type": "Objective", "topic": "NATIONALISM : NATIONALISM: MEANING, FACTORS AND EFFECTS.", "question": "The development of nationalist movement was late in French West Africa because of the", "images": [], "options": {"A": "Second World War", "B": "indirect rule system", "C": "assimilation policy", "D": "obnoxious land laws"}, "answer": "C", "explanation": "The development of nationalist movement was late in french West Africa because of the policy of assimmilation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2004>44", "subject": "Government", "year": "2004", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "Which of the following factors necessitates the adoption of federalism in a state?", "images": [], "options": {"A": "Fear of one ethnic group dominating the others", "B": "Adoption of a Written Constitution", "C": "Availability of natural resources", "D": "Encouragement of secession"}, "answer": "A", "explanation": "The adoption of federalism in a state is often necessitated by the fear of one ethnic group dominating the others. Federalism is a system of government where powers are divided between a central authority and constituent political units (like states or provinces). This system is often adopted in multi-ethnic countries to ensure that no single ethnic group can dominate the others at the national level. It helps to maintain balance and prevent ethnic conflicts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>45", "subject": "Government", "year": "2004", "type": "Objective", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "The foreign policy of a country is influenced by all the following factors except the", "images": [], "options": {"A": "size of the country", "B": "leadership style", "C": "educational system", "D": "economic system"}, "answer": "C", "explanation": "The foreign policy of a country is influenced by factors such as the size of the country, the leadership style, and the economic system. These factors can affect a country's relations with other countries, its ability to negotiate and enforce treaties, and its ability to protect its national interests. However, the educational system of a country does not directly influence its foreign policy. While education can play a role in shaping the values and perspectives of a country's citizens, it is not a direct factor in determining a country's foreign policy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>46", "subject": "Government", "year": "2004", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "The organs of government which are normally fused in a military regime are the", "images": [], "options": {"A": "civil service and the judiciary", "B": "legislature and the executive", "C": "executive and the civil service", "D": "judiciary and the legislature"}, "answer": "B", "explanation": "In a military regime, the organs of government that are usually fused are the legislature and the executive. This is because in such regimes, the military often takes over the roles of both making and implementing laws, effectively combining the functions of the legislative and executive branches. The judiciary and civil service, on the other hand, often remain separate entities, even under military rule.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>47", "subject": "Government", "year": "2004", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "The first West African to become the Secretary-General of the Commonwealth is", "images": [], "options": {"A": "Ibrahim Gambari", "B": "Abbas Bundu", "C": "Emeka Anyaoku", "D": "Diallo Telli"}, "answer": "C", "explanation": "Emeka Anyaoku from Nigeria was the first West African to become the Secretary-General of the Commonwealth. He served from 1990 to 2000.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2004>48", "subject": "Government", "year": "2004", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "The primary objective of the Economic Community of West African States (ECOWAS) is to", "images": [], "options": {"A": "prevent crimes in West Africa", "B": "promote the socio-economic development of member states", "C": "control pollution and environmental degradation", "D": "promote universal human rights"}, "answer": "B", "explanation": "The primary objective of the Economic Community of West African States (ECOWAS) is to promote the socio-economic development of member states. ECOWAS was established to foster interstate economic and political cooperation. Development is seen not only in terms of economic growth, but also as a means of enhancing the economic and social well-being of the people in the member states.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2004>49", "subject": "Government", "year": "2004", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "The administrative headquarters of the Economic Community of West Africa States (ECOWAS) is in", "images": [], "options": {"A": "Banjul", "B": "Accra", "C": "Bamako", "D": "Abuja"}, "answer": "D", "explanation": "The administrative headquarters of the Economic Community of West African States (ECOWAS) is in Abuja, Nigeria. ECOWAS is a regional political and economic union of fifteen countries located in West Africa. The union was established on 28 May 1975, with the signing of the Treaty of Lagos, with its stated mission to promote economic integration across the region.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2004>50", "subject": "Government", "year": "2004", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The major aim of the United Nations Organisation (UNO) is to", "images": [], "options": {"A": "maintain international peace and security", "B": "co-ordinate and supervise the activities of specialized agencies", "C": "promote sports among all nations", "D": "stabilize the price of oil in the world market"}, "answer": "A", "explanation": "The major aim of the United Nations Organization (UNO) is to maintain international peace and security. The United Nations (UN) is an international organization founded in 1945. It is currently made up of 193 Member States. The mission and work of the United Nations are guided by the purposes and principles contained in its founding Charter. The Charter of the United Nations established six main organs of the United Nations, including the Security Council. It is the Security Council that has the primary responsibility for the maintenance of international peace and security.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2005>1", "subject": "Government", "year": "2005", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A government is said to be legitimate if it", "images": [], "options": {"A": "has the people's mandate to rule", "B": "is not oppressive", "C": "provides social services for the people", "D": "accepts people's criticisms"}, "answer": "A", "explanation": "A government is said to legitimate if it has the people's mandate to rule. Legitimate government is the one that occur in a democratic settings.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>2", "subject": "Government", "year": "2005", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "All types of government perform all the following functions except", "images": [], "options": {"A": "providing welfare and developmental facilities", "B": "maintaining law and order", "C": "encouraging the struggle for power", "D": "encouraging trade with other states"}, "answer": "C", "explanation": "All types of government perform functions such as providing welfare and developmental facilities, maintaining law and order, and encouraging trade with other states. However, encouraging the struggle for power is not a function of government. In fact, governments often work to prevent power struggles in order to maintain stability and order. Therefore, the correct answer is option 3.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>3", "subject": "Government", "year": "2005", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "In the study of government, public administration covers the", "images": [], "options": {"A": "army, prison officers and the police force", "B": "civil service, public corporations and the local governments", "C": "ministries of education, health and agriculture", "D": "schools, hospitals nd health centres"}, "answer": "B", "explanation": "Public administration is a field of study and practice that involves the management of government and its programs, policies, and functions. It covers the civil service, public corporations, and local governments. The civil service refers to the body of government officials who are employed in civil occupations that are neither political nor judicial. Public corporations are government-owned entities that operate in the commercial sector, and local governments are administrative bodies that govern smaller geopolitical areas within a nation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>4", "subject": "Government", "year": "2005", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Sovereignty ultimately resides in", "images": [], "options": {"A": "the people within a political society", "B": "a country's chief executive", "C": "the judges of the Supreme Court", "D": "traditional rulers"}, "answer": "A", "explanation": "Sovereignty ultimately resides in the people within a political society. Sovereignty is the supreme power and authority of a state over and above everybody in the state without any interference by other states.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>5", "subject": "Government", "year": "2005", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Classical democracy implies government", "images": [], "options": {"A": "through representatives", "B": "by all citizens", "C": "through electoral college", "D": "by martial laws"}, "answer": "A", "explanation": "Classic democracy implies government through representatives. It is when the citizens of a country choose their representative through elections.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>6", "subject": "Government", "year": "2005", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following is not a feature of a democratic system of government?", "images": [], "options": {"A": "Limited franchise", "B": "Official opposition", "C": "Periodic elections", "D": "Rule of law"}, "answer": "A", "explanation": "Limited franchise is not a feature of a democratic system of government. It allows for every eligible citizens to vote and to be voted.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>7", "subject": "Government", "year": "2005", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following political concepts is associated with land ownership?", "images": [], "options": {"A": "Racism", "B": "Feudalism", "C": "Nazism", "D": "Socialism"}, "answer": "B", "explanation": "Feudalism can be defined as the identification of landed property with sovereignty. It is a political concepts that is associated with land ownership.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>8", "subject": "Government", "year": "2005", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Fascism was a type of dictatorial government established in", "images": [], "options": {"A": "Germany", "B": "Russia", "C": "Israel", "D": "Italy"}, "answer": "D", "explanation": "Fascism was a type of dictatorial government established in Italy. It was a political ideology that arose in early 20th-century Europe, led by Benito Mussolini in Italy. Fascism is characterized by dictatorial power, forcible suppression of opposition, and strong regimentation of society and of the economy. It does not apply to Germany, Russia, or Israel in this context.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2005>9", "subject": "Government", "year": "2005", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Who among the following is associated with the concept of the rule of law?", "images": [], "options": {"A": "Jean Bodin", "B": "A. V. Dicey", "C": "Jeremy Bentham", "D": "Barom de Montesquieu"}, "answer": "B", "explanation": "The concept of the rule of law is associated with A. V. Dicey. The rule of law is a legal principle that law should govern a nation, and that all are subject to it, including those in power. A. V. Dicey, a British jurist and constitutional theorist, is widely credited for popularizing this concept.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2005>10", "subject": "Government", "year": "2005", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Which of the following is a means of limiting the rule of law?", "images": [], "options": {"A": "Supremacy of the law", "B": "Equality before the law", "C": "Immunity granted to diplomats", "D": "Strike action by workers"}, "answer": "C", "explanation": "Immunity granted to diplomats is a means of limiting the rule of law. Diplomatic immunity is a form of legal immunity that ensures diplomats are given safe passage and are considered not susceptible to lawsuit or prosecution under the host country's laws. This can be seen as a limitation to the rule of law as it exempts certain individuals from the jurisdiction of local laws.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>11", "subject": "Government", "year": "2005", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS A PROCESS OR ART OR GOVERNING", "question": "The lack of interest in politics by many citizens in a country is called", "images": [], "options": {"A": "civil agitation", "B": "mass apathy", "C": "mass protest", "D": "political unrest"}, "answer": "B", "explanation": "Political/mass apathy is the lack of interest in politics by the citizens of a country. It is the political.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>12", "subject": "Government", "year": "2005", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The Industrial Revolution in Europe resulted in", "images": [], "options": {"A": "socialism", "B": "communalism", "C": "aristocracy", "D": "capitalism"}, "answer": "D", "explanation": "The Industrial Revolution in Europe led to the rise of 'capitalism'. Capitalism is an economic system where private individuals or businesses, rather than the state, control trade and industry. The Industrial Revolution saw a shift from agrarian and handicraft economy to one dominated by industry and machine manufacturing, and this process was driven by capitalist enterprises. Socialism, communalism, and aristocracy are different types of social or economic systems, but they were not the primary result of the Industrial Revolution.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2005>13", "subject": "Government", "year": "2005", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "An agreed set of rules prescribing the governance of a country can be called the", "images": [], "options": {"A": "constitution", "B": "charter", "C": "manifesto", "D": "hansard"}, "answer": "A", "explanation": "Constitution is an agreed set of rules prescribing the governance of a country. It is a document that stipulate the rules, regulations and the conventions of a government.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2005>14", "subject": "Government", "year": "2005", "type": "Objective", "topic": "CONSTITUTIONS : TYPES AND FEATURES", "question": "A constitution is said to be rigid if it", "images": [], "options": {"A": "can be amended by the president only", "B": "is difficult to amend", "C": "is unwritten", "D": "is decreed by soldiers"}, "answer": "B", "explanation": "A constitution is said to be rigid if it is difficult to amend. This means that the procedures for changing or amending the constitution are complex and often require supermajorities in a legislature or a referendum. This is done to ensure that changes to the constitution reflect a broad consensus and are not made lightly or for partisan purposes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>15", "subject": "Government", "year": "2005", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY", "question": "A unitary system of government is most suitable for a", "images": [], "options": {"A": "highly religious country", "B": "country with a lot of mineral deposits", "C": "small homogeneous country", "D": "highly populated country"}, "answer": "C", "explanation": "Unitary system of government is suitable for a small homogenous country or country with a small land area or mass.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>16", "subject": "Government", "year": "2005", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET", "question": "The principle of collective responsibility is central to the", "images": [], "options": {"A": "presidential system", "B": "federal system", "C": "unitary system", "D": "parliamentary system"}, "answer": "D", "explanation": "The principle of collective responsibility is central to the parliamentary system. This principle implies that all members of the government must publicly support all governmental decisions made in Cabinet, even if they do not privately agree with them. This support includes voting for the government in the legislature. If a member of the government cannot support a policy, they are expected to resign. This principle is meant to ensure unity and consensus in government decisions and actions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>17", "subject": "Government", "year": "2005", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET", "question": "In a parliamentary system of government, the head of government is usually", "images": [], "options": {"A": "selected by the Council of State", "B": "elected by the Supreme Court", "C": "the Majority Leader in the Legislature", "D": "the Head of State"}, "answer": "C", "explanation": "In a parliamentary system of government, the head of state is usually the majority leader in the legislature.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>18", "subject": "Government", "year": "2005", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : CONFEDERAL", "question": "The practice of two or more sovereign states uniting for security and external affairs is called", "images": [], "options": {"A": "totalitarianism", "B": "confederalism", "C": "republicanism", "D": "sectionalism"}, "answer": "B", "explanation": "Confederalism is a practice where two or more sovereignty states uniting for security and external affairs.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2005>19", "subject": "Government", "year": "2005", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "A unicameral legislature has", "images": [], "options": {"A": "two houses", "B": "one house", "C": "three houses", "D": "one head of state"}, "answer": "B", "explanation": "A unicameral legislature is a type of legislature which consists of one house or assembly. The term 'unicameral' is derived from Latin where 'uni' means 'one' and 'cameral' means 'chamber'. Therefore, a unicameral legislature has one house.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2005>20", "subject": "Government", "year": "2005", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "One of the functions of a Party Whip in the Legislature is to", "images": [], "options": {"A": "punish erring members of the party in the House", "B": "ensure that members are present during important sessions", "C": "ensure that the House is properly dissolved", "D": "lead the minority party in the House debate"}, "answer": "B", "explanation": "A Party Whip in the Legislature is a member of a political party whose task is to ensure party discipline in a legislature. This means that Whips ensure the attendance of the members of the party during important sessions, they ensure that the members vote according to the party line, and they communicate the party message to the members. Therefore, one of the functions of a Party Whip in the Legislature is to ensure that members are present during important sessions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>21", "subject": "Government", "year": "2005", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "The judiciary is an organ of government which", "images": [], "options": {"A": "rules the country according to laws", "B": "makes laws for the country", "C": "gives legal backing to government's budget", "D": "settles disputes in accordance with the laws of the land"}, "answer": "D", "explanation": "The judiciary organ of government settles disputes in accordance with the laws of the land. It interpretes laws in the country.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2005>22", "subject": "Government", "year": "2005", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "To promote justice in a state, judges must", "images": [], "options": {"A": "belong to the ruling party", "B": "punish people who oppose them", "C": "enjoy security of tenure of office", "D": "not socialise with the people"}, "answer": "C", "explanation": "For judges to promote justice in a state, they must enjoy security of tenure of office. This means that they cannot be removed from their position without a valid reason, such as misconduct or incapacity. This security of tenure ensures that judges can make decisions without fear of reprisal or political interference, thereby promoting justice and the rule of law. It does not matter whether they belong to the ruling party, punish people who oppose them, or socialise with the people.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>23", "subject": "Government", "year": "2005", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN INSTITUTION OF THE STATE:", "question": "People pay taxes in order to", "images": [], "options": {"A": "generate revenue for government", "B": "obtain a tax clearance certificate", "C": "avoid being prosecuted in the courts", "D": "save towards the future"}, "answer": "A", "explanation": "Taxes are primarily paid to generate revenue for the government. This revenue is then used to fund public goods and services, such as infrastructure, education, and healthcare. A tax clearance certificate is a document that proves that an individual or company has paid all their taxes, but it is not the reason why people pay taxes. Avoiding prosecution and saving towards the future are also not primary reasons for paying taxes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2005>24", "subject": "Government", "year": "2005", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "All the following are essential functions of political parties except to", "images": [], "options": {"A": "aggregate interests of members of the public", "B": "serve as link between the government and the people", "C": "seek political power lawfully", "D": "seek political power for the military"}, "answer": "D", "explanation": "Political parties do not seek political power for the military. The primary functions of political parties include aggregating the interests of members of the public, serving as a link between the government and the people, and seeking political power lawfully. The military is a separate entity from political parties and is not involved in the political process in a democratic system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>25", "subject": "Government", "year": "2005", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS", "question": "A multi-party system often leads to", "images": [], "options": {"A": "unitary government", "B": "dictatorial government", "C": "coalition government", "D": "parliamentary government"}, "answer": "C", "explanation": "Multi-party system often leads to coalition government. Two or more parties form the government of a state.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2005>26", "subject": "Government", "year": "2005", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "The right of the citizens to vote and be voted for in an election is called", "images": [], "options": {"A": "indirect election", "B": "nomination", "C": "general election", "D": "franchise"}, "answer": "D", "explanation": "The right of the citizens to vote and be voted for in an election is called franchise. This is a fundamental democratic right that allows citizens to participate in the political process. It is also known as suffrage.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2005>27", "subject": "Government", "year": "2005", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "One major advantage of the secret ballot system of election is that, it", "images": [], "options": {"A": "helps to elect the best candidate", "B": "removes the fears of threat and victimization", "C": "enables the best party to win", "D": "ensures the efficiency of the electoral commission"}, "answer": "B", "explanation": "The secret ballot system of election is a voting method in which a voter's choices in an election or a referendum are anonymous. This is intended to ensure the voter records a sincere choice by forestalling attempts to influence the voter by intimidation or bribery. The key benefit is that it 'removes the fears of threat and victimization' as voters can vote without fear of repercussions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>28", "subject": "Government", "year": "2005", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "An election held to determine an important constitutional issue is called a", "images": [], "options": {"A": "direct election", "B": "counter election", "C": "general election", "D": "referendum"}, "answer": "D", "explanation": "A referendum is a direct and universal vote in which an entire electorate is invited to vote on a particular proposal and can have nationwide or local forms. This may result in the adoption of a new policy or specific law. In some countries, it is synonymous with a plebiscite or a vote on a ballot question. Therefore, an election held to determine an important constitutional issue is called a 'referendum'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>29", "subject": "Government", "year": "2005", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "A free and fair election requires all the following except", "images": [], "options": {"A": "political parties", "B": "a long campaign period", "C": "gerrymandered constituencies", "D": "registration of all qualified voters"}, "answer": "C", "explanation": "A free and fair election does not require gerrymandered constituencies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>30", "subject": "Government", "year": "2005", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "An electoral college is a", "images": [], "options": {"A": "form of indirect election", "B": "school for electoral officers", "C": "college which trains party leaders", "D": "policy to dissolve constituencies"}, "answer": "A", "explanation": "An electoral college is a form of indirect election. In this system, voters do not vote for a candidate directly. Instead, they vote for electors, who then vote for the candidate. This system is used in some countries, including the United States, for the election of the president. The other options do not accurately describe what an electoral college is.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2005>31", "subject": "Government", "year": "2005", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "The main objective of a pressure group is to", "images": [], "options": {"A": "change the government", "B": "fund election campaigns", "C": "form the government", "D": "influence government policies"}, "answer": "D", "explanation": "A pressure group is a group of people who are organized actively for promoting and defending their common interest. They are also known as interest groups or lobby groups and they try to influence the government to make policies or legislation that favor their interests. So, the main objective of a pressure group is to influence government policies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>32", "subject": "Government", "year": "2005", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "Public opinion can be expressed through", "images": [], "options": {"A": "census", "B": "general strike", "C": "socialisation", "D": "compromise"}, "answer": "B", "explanation": "Public opinion is the collective opinion of the people of a society or state on an issue or problem. This concept came about through the process of urbanization and other political and social forces. It can be expressed through various mediums, one of which is a general strike. A general strike is a protest movement involving a large number of workers from different industries and sectors, which can effectively express public opinion by disrupting normal societal functioning.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>33", "subject": "Government", "year": "2005", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "A local government administration promotes", "images": [], "options": {"A": "consensus politics", "B": "responsible government", "C": "democracy at the grassroots", "D": "responsive government"}, "answer": "C", "explanation": "Local government administration promote government at the grassroot i.e bring people close to government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>34", "subject": "Government", "year": "2005", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "All the following are features of the civil service except", "images": [], "options": {"A": "anonymity", "B": "political neutrality and impartiality", "C": "security of tenure and permanence", "D": "political maturity and participation"}, "answer": "D", "explanation": "Political maturity and participation is not a feature of civil service. Civil servant do not participate in politics.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2005>35", "subject": "Government", "year": "2005", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "Public corporations are set up by", "images": [], "options": {"A": "the Boards of Directors", "B": "the Minister", "C": "workers in the corporation", "D": "an act of parliament"}, "answer": "D", "explanation": "Public corporation is set up by the Act of Parliament, owned by government and control by the board of directors appointed by government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>36", "subject": "Government", "year": "2005", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "The first Colonial Consul sent to administer the West Coast of Africa by Britain, was", "images": [], "options": {"A": "John Beecroft", "B": "Walter Egerton", "C": "George Goldie", "D": "Donald Cameron"}, "answer": "A", "explanation": "The first Colonial Consul sent to administer the West Coast of Africa by Britain was John Beecroft. He was appointed as the British consul for the Bights of Benin and Biafra (a region covering modern-day Nigeria and Cameroon) in 1849, making him the first British colonial consul in West Africa.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>37", "subject": "Government", "year": "2005", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "The executive head who was responsible for British colonial territories in West Africa was the", "images": [], "options": {"A": "Lord Chancellor", "B": "heir to the British throne", "C": "warrant chief", "D": "Secretary of State"}, "answer": "D", "explanation": "The executive head who was responsible for British Colonial territories in West Africa was Secretary of state.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>38", "subject": "Government", "year": "2005", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "The indirect rule policy did not succeed in some parts of West Africa because", "images": [], "options": {"A": "it was not well understood", "B": "only few British officers were posted to those areas", "C": "the powers of traditional rulers were not centralised", "D": "the elite were participatory to the policy"}, "answer": "C", "explanation": "Indirect rule policy did not succeed in some parts of West Africa because of the powers of traditional rulers.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2005>39", "subject": "Government", "year": "2005", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "The policy of indigenat was practised in the colonies controlled by", "images": [], "options": {"A": "Belgium", "B": "Portugal", "C": "Britain", "D": "France"}, "answer": "D", "explanation": "The policy of indigenat was practiced in the colonies controlled by France. The Indigenat was a set of laws creating, in practice, an inferior legal status for natives of French Colonies from 1887 until 1944-1947.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>40", "subject": "Government", "year": "2005", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "The French policy of Assimilation implied that", "images": [], "options": {"A": "the French transferred powers to Africans", "B": "traditional rulers were recognised", "C": "African countries were granted independence", "D": "Africans were modelled after the French"}, "answer": "D", "explanation": "The French policy of Assimilation implied that Africans were modelled after the French. The policy of Assimilation was a French colonial policy whose main goal was to assimilate colonial subjects into French culture and society. This policy, in theory, aimed to turn the natives of the colonies into Frenchmen by educating them in the French language and culture.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2005>41", "subject": "Government", "year": "2005", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "The West African Students Union (WASU) was formed in 1925 in", "images": [], "options": {"A": "Dakar", "B": "London", "C": "Washington", "D": "New York"}, "answer": "B", "explanation": "The West African Students Union (WASU) was formed in 1925 in London. WASU was a student-led political organization that was founded to promote the interests of African students in Britain, to fight against colonialism, and to promote the cause of African unity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>42", "subject": "Government", "year": "2005", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "One of the achievements of the National Congress of British West Africa (NCBWA) was the", "images": [], "options": {"A": "introduction of railway transportation", "B": "appointment of a federal president", "C": "improvement of living standard", "D": "introduction of the elective principle"}, "answer": "D", "explanation": "The achievement of the National Congress of British West Africa (NCBWA) was the introduction of the elective principle.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>43", "subject": "Government", "year": "2005", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "The main cause of military intervention in government in West Africa was", "images": [], "options": {"A": "that soldiers wanted to form their own political parties", "B": "the breakdown of democratic institutions", "C": "the need to grant the request of the colonial government", "D": "the soldiers wanted to take part in democracy"}, "answer": "B", "explanation": "The main cause of military intervention in government. In West Africa was the breakdown of democratic institutions.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2005>44", "subject": "Government", "year": "2005", "type": "Objective", "topic": "MILITARY RULE : VARIOUS MILITARY REGIMES", "question": "Military governments are likely to be", "images": [], "options": {"A": "democratic", "B": "civilized", "C": "dictatorial", "D": "accountable"}, "answer": "C", "explanation": "Military governments are likely to be dictatorial. This is because they are typically characterized by a single leader or group of leaders with absolute power, and they often suppress political opposition. This is in contrast to democratic governments, which are characterized by the rule of law, free and fair elections, and the protection of human rights.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2005>45", "subject": "Government", "year": "2005", "type": "Objective", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : ORIGINS, FACTORS AND STRUCTURE", "question": "Which of the following West African countries operated a federal constitution at independence?", "images": [], "options": {"A": "Ghana", "B": "Nigeria", "C": "The Gambia", "D": "Sierra Leone"}, "answer": "B", "explanation": "Nigeria operated a federal constitution at independence. A federal constitution is a system of government where power is divided between a central government and individual states or provinces. In this system, both the central government and the individual states have powers to make laws and both are sovereign in their sphere of authority. Nigeria, at independence, adopted this system of government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>46", "subject": "Government", "year": "2005", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "The Economic Community of West African States (ECOWAS) was formed to", "images": [], "options": {"A": "increase the population of West Africa", "B": "stop trading activities with the advanced countries", "C": "encourage aliens to migrate", "D": "promote economic relations in West Africa"}, "answer": "D", "explanation": "The Economic Community of West African States (ECOWAS) was formed to promote economic relations in West Africa. ECOWAS is a regional group of fifteen West African countries, established on 28 May 1975. Its mission is to promote economic integration in all fields of economic activity, particularly industry, transport, telecommunications, energy, agriculture, natural resources, commerce, monetary and financial issues, social and cultural matters.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2005>47", "subject": "Government", "year": "2005", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "Which of the following is associated with the Economic Community of West African States (ECOWAS)?", "images": [], "options": {"A": "Peace-keeping", "B": "Road rehabilitation", "C": "Importation of cars", "D": "Military rule"}, "answer": "A", "explanation": "The Economic Community of West African States (ECOWAS) is a regional political and economic union of fifteen countries located in West Africa. One of its main functions is peacekeeping. ECOWAS has intervened in crises in Liberia, Sierra Leone, Cote d'Ivoire, and Guinea-Bissau, among others. Peacekeeping involves the deployment of military personnel and, in some cases, civilian police officers and civilian personnel to conflict areas to help maintain or restore international peace and security.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2005>48", "subject": "Government", "year": "2005", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "One of the main objectives of the African Union (AU) is to", "images": [], "options": {"A": "hold elections in member states", "B": "distribute military equipment to its members", "C": "encourage co-operation among member states", "D": "establish courts in member states"}, "answer": "C", "explanation": "The African Union (AU) is a continental body consisting of the 55 member states that make up the countries of the African Continent. One of its main objectives is to encourage cooperation among member states. This is aimed at achieving greater unity and solidarity between the African countries and the peoples of Africa, defend the sovereignty, territorial integrity and independence of its Member States and accelerate the political and socio-economic integration of the continent.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2005>49", "subject": "Government", "year": "2005", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "A person representing his country in a fellow Commonwealth country is called", "images": [], "options": {"A": "a knight", "B": "a representative", "C": "a high commissioner", "D": "an attache"}, "answer": "C", "explanation": "A person representing his country in a fellow Commonwealth country is called a High Commissioner. The Commonwealth is a political association of 54 member states, nearly all of which are former territories of the British Empire. The chief institutions of the organisation are the Commonwealth Secretariat, which focuses on intergovernmental aspects, and the Commonwealth Foundation, which focuses on non-governmental relations between member states.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2005>50", "subject": "Government", "year": "2005", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The most important achievement of the United Nations Organization (UNO) is the", "images": [], "options": {"A": "election of a Secretary General from Africa", "B": "prevention of another world war", "C": "increase in its membership", "D": "settlement of cases of election rigging"}, "answer": "B", "explanation": "The most important achievement of United Nations Organisation (UNO) is the prevention of another world war.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>1", "subject": "Government", "year": "2006", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS A PROCESS OR ART OR GOVERNING", "question": "Government as an act of governing refers to the process of", "images": [], "options": {"A": "ruling people in the society", "B": "establishing political parties", "C": "providing free education", "D": "acquiring social skills"}, "answer": "A", "explanation": "\"Ruling people in the society\" is the answer.    Government as an act of governing refers to a body vested with the power and authority for maintaining security, peace and stability by making and enforcing conventional and fundamental laws in a given state or society.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2006>2", "subject": "Government", "year": "2006", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "An essential feature of a state is?", "images": [], "options": {"A": "availability of mineral resources", "B": "developed infrastructure", "C": "an organized system of law", "D": "developed markets"}, "answer": "C", "explanation": "\"An organized system of law\" is the answer.    Other features of a state include:    Population  Territory  Government  Sovereignty  Recognition  Permanence", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>3", "subject": "Government", "year": "2006", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The modern idea of democracy includes all the following except", "images": [], "options": {"A": "unlimited freedom", "B": "civil liberty", "C": "periodic change", "D": "equality before  the law"}, "answer": "A", "explanation": "\"Unlimited freedom\" is the answer because it is not one of the modern ideas of democracy    The advantages of  modern ideas of democracy include:    It promotes political participation  Legitimacy  Choice of political leadership  Political stability  Encouragement of constitutionalism  Decision making process", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>4", "subject": "Government", "year": "2006", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The political system which allows equal access to the means of production,  distribution and exchange is called", "images": [], "options": {"A": "Totalitarianism", "B": "Capitalism", "C": "Socialism", "D": "Feudalism"}, "answer": "C", "explanation": "\"Socialism\" Is the correct answer    Socialism may be defined as a political cum economic system in which all or part of the means of production and distribution are controlled by the state. In this political system, all the non-human materials of production and distribution are controlled and operated by the government on behalf of the citizens.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2006>5", "subject": "Government", "year": "2006", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The components of sovereignty are", "images": [], "options": {"A": "influence and political authority", "B": "political structure and political socialization", "C": "legal and political independence", "D": "political and economic development"}, "answer": "C", "explanation": "\"Legal and political independence\"  is the correct answer.    The known components of sovereignty are   - Legal independence  - Political independence  The current notion of state sovereignty contains four aspects consisting of territory, population, authority and recognition.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2006>6", "subject": "Government", "year": "2006", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The modern concept of the rule of law was introduced by", "images": [], "options": {"A": "K.C. Wheare", "B": "A.V. Dicey", "C": "Otto Von Bismarck", "D": "Justice Holmes"}, "answer": "B", "explanation": "The modern concept of the rule of law was introduced by; A.V Dicey, a professor of English law who developed and popularized the phrase \" Rule of Law\" in his book titled \" Introduction To The Law of The Constitution\" published in 1885.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>7", "subject": "Government", "year": "2006", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Which of the following principles negates the concept of the rule of law?", "images": [], "options": {"A": "Supremacy of law", "B": "Prevention of arbitrariness in authority", "C": "Equality before the law", "D": "Exercise of absolute power by the law"}, "answer": "D", "explanation": "Exercise of absolute power by the president negates the concept of the law, therefore it is the correct answer.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2006>8", "subject": "Government", "year": "2006", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Another name for Totalitarianism is", "images": [], "options": {"A": "Socialism", "B": "Capitalism", "C": "Communism", "D": "Authoritarianism"}, "answer": "D", "explanation": "Totalitarianism is a political system where the state holds total authority over the society and seeks to control all aspects of public and private life wherever possible. It is also known as Authoritarianism. Socialism, Capitalism, and Communism are economic systems, not political systems like Totalitarianism.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>9", "subject": "Government", "year": "2006", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The concept of separation of powers was popularized by", "images": [], "options": {"A": "Nicholo Machiavelli", "B": "A.V.Dicey", "C": "Baron de Montesquei", "D": "Harold Laski"}, "answer": "C", "explanation": "It was a French political thinker and  jurist Baron De Montesquieu who developed and popularized the principle of  \"Seperation  of Powers\" in his book titled \" Espirit Des Lois\" which means the 'spirit of laws' published in 1748.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>10", "subject": "Government", "year": "2006", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Which of the following does not have the power of delegated legislation?", "images": [], "options": {"A": "A minister", "B": "Market men and women association", "C": "State Government", "D": "Registered Professional Bodies"}, "answer": "B", "explanation": "Market men and women association does not have the power of delegated legislation, therefore it is the correct answer. All other options have the power of delegated legislation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2006>11", "subject": "Government", "year": "2006", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The concept of decentralization includes all the following elements except", "images": [], "options": {"A": "deconcentration", "B": "devolution", "C": "delimitation", "D": "delegation"}, "answer": "C", "explanation": "\" Delimitation\"  is the answer    The forms of decentralization include :  Devolution  Deconcentration  Delegation", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>12", "subject": "Government", "year": "2006", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "All the following are sources of constitutions except", "images": [], "options": {"A": "act of Parliament", "B": "devolution of power", "C": "conventions", "D": "customs"}, "answer": "B", "explanation": "\"Devolution of power\" is the answer    Sources of constitution include:    Past experience  Historical documents  Acts of parliament or statutes  Decrees  Intellectual works   Customs and Norms  Judicial Precedents  Conventions  Constitutional conferences  International laws", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>13", "subject": "Government", "year": "2006", "type": "Objective", "topic": "CONSTITUTIONS : TYPES AND FEATURES", "question": "A constitution is said to be flexible when the provisions are", "images": [], "options": {"A": "known by the rulers", "B": "scattered in several books", "C": "mainly in one document", "D": "easy to amend"}, "answer": "D", "explanation": "A flexible constitution can be defined as that constitution which can be amended and changed easily without stringent and cumbersome procedures.Flexible constitution can be amended with the same procedure used in making ordinary laws.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>14", "subject": "Government", "year": "2006", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : EXECUTIVE", "question": "The power to pardon any citizen charged with any criminal offence lies with the", "images": [], "options": {"A": "legislature", "B": "executive", "C": "human rights organization", "D": "judiciary"}, "answer": "B", "explanation": "The three arms of government include: The Legislature, The Executive and The Judiciary. Executive is the organ of government responsible for the implementation, execution or enforcement of laws, policies and directives made and given by the legislative arm of government. The executive therefore see to it that laws made in a country are obeyed.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2006>15", "subject": "Government", "year": "2006", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS A PROCESS OR ART OR GOVERNING", "question": "The police performs all the following except", "images": [], "options": {"A": "public execution of law breakers", "B": "controlling and directing traffic", "C": "protection of life and property", "D": "enforcement of law and order"}, "answer": "A", "explanation": "\" Public execution of law breakers\" is the answer    Some of the functions of public force include:    To protect life and property of the citizens of a country.  The police force maintains law and order in a country.  The police force regulates and control the movement of motor vehicles.  Prosecution of minor offences.  The police force helps in quelling disturbances and riots.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>16", "subject": "Government", "year": "2006", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "The number of chambers is a bicameral legislature is", "images": [], "options": {"A": "four", "B": "three", "C": "two", "D": "one"}, "answer": "C", "explanation": "A bicameral legislature is a particular body of government that consists of two legislative houses or chambers. In other words, bicameral means 'two-chambered'. The term is derived from the Latin 'bi-' meaning two, and 'camera' meaning chamber. Therefore, the correct answer is two.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2006>17", "subject": "Government", "year": "2006", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "In the legislature, a  filibuster  is one who", "images": [], "options": {"A": "is in charge of party discipline", "B": "presents party bills during the parliamentary sessions", "C": "does not take part in law making", "D": "prevents the passage of a bill by making long speeches"}, "answer": "D", "explanation": "A filibuster is a political procedure where one or more members of parliament or congress debate over a proposed piece of legislation so as to delay or entirely prevent a decision being made on the proposal. It is a form of obstruction in a legislature or other decision-making body. Hence, a filibuster is one who prevents the passage of a bill by making long speeches.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>18", "subject": "Government", "year": "2006", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "The verdicts of judges which are binding in lower courts are called", "images": [], "options": {"A": "orders", "B": "precedents", "C": "council", "D": "oats"}, "answer": "B", "explanation": "In law, a precedent or authority is a legal case that establishes a principle or rule. This principle or rule is then used by the court or other judicial bodies use when deciding later cases with similar issues or facts. The use of precedent provides predictability, stability, fairness, and efficiency in the law. The Latin term 'stare decisis' is the doctrine of legal precedent. Hence, the verdicts of judges which are binding in lower courts are called precedents.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>19", "subject": "Government", "year": "2006", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "The judicial organ of the government is the body which", "images": [], "options": {"A": "initiates bills", "B": "interprete the law", "C": "makes law", "D": "maintains law and order"}, "answer": "B", "explanation": "The Judiciary is the third organ of government responsible for the interpretation and of the laws when they are broken or violated.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2006>20", "subject": "Government", "year": "2006", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "The system of government in which authority is shared between the centre and the component units is called", "images": [], "options": {"A": "unitary system of government", "B": "feudal system of government", "C": "federal system of government", "D": "monarchical system of government"}, "answer": "C", "explanation": "The system of government in which authority is shared between the centre and the component units is called federal system of government. Federal system of government is defined as the one in which government power that exists in one country is shared between  a central government that represents the whole country, government of component regions or states, so that each government of a component region states, so that each government is legally and constitutionally independent and autonomous.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2006>21", "subject": "Government", "year": "2006", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "A constitutionally created account into which all revenues are paid is called", "images": [], "options": {"A": "provident fund", "B": "social security fund", "C": "public accounts fund", "D": "consolidated fund"}, "answer": "D", "explanation": "A constitutionally created account into which all revenues are paid is called a Consolidated Fund. This is a term used in many countries with a parliamentary system to describe the main bank account of the government. It is into this account that all receipts are paid and from which all expenditures under the authority of the parliament are made.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>22", "subject": "Government", "year": "2006", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET", "question": "In a cabinet system of government, the ministers are collectively responsible to the", "images": [], "options": {"A": "president", "B": "parliament", "C": "electorate", "D": "judiciary"}, "answer": "B", "explanation": "In a cabinet system of government, the ministers are collectively responsible to the Parliament. This is a fundamental principle of the Westminster system of parliamentary democracy. The Cabinet, being composed of members of Parliament, is directly accountable to the Parliament. They must maintain the confidence of the majority of members in the House of Representatives, and are subject to questioning and challenge on the floor of the House.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>23", "subject": "Government", "year": "2006", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Official opposition is a feature of", "images": [], "options": {"A": "Parliamentary system", "B": "Totalitarian system", "C": "Nazism", "D": "Fascism   Fascism"}, "answer": "A", "explanation": "One of the features of the Parliamentary/Cabinet system of government is that there is an official opposition party in the parliament.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>24", "subject": "Government", "year": "2006", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : MONARCHICAL", "question": "In a Monarchy, the Head of State is usually", "images": [], "options": {"A": "a military ruler", "B": "the chief justice", "C": "the speaker of the legislature", "D": "a hereditary ruler"}, "answer": "D", "explanation": "Monarchy may be defined as a form of government under the of a king, queen or Emperor known as the monarch. Therefore a hereditary ruler is usually the head of state in a monarchy.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2006>25", "subject": "Government", "year": "2006", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "Which of the following is not a duty of a citizen?", "images": [], "options": {"A": "Obedience of the laws", "B": "Payment of taxes", "C": "Service to the nation", "D": "Giving alms to the poor"}, "answer": "D", "explanation": "The duties of a citizen generally include obedience of the laws, payment of taxes, and service to the nation. Giving alms to the poor, while it can be seen as a moral duty or a religious obligation, is not a civic duty enforced by the government. Therefore, it is not a duty of a citizen in the context of this question.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2006>26", "subject": "Government", "year": "2006", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Free and fair election is necessary for democracy to thrive because it", "images": [], "options": {"A": "makes an unpopular candidate emerge as winner", "B": "helps the people to exercise their popular sovereignty", "C": "makes a popular party to loose the election", "D": "prevents smooth change of government"}, "answer": "B", "explanation": "Free and fair elections are a cornerstone of democracy because they allow the people to exercise their popular sovereignty. Popular sovereignty is a concept that the power of a state and its government is created and sustained by the consent of its people, through their elected representatives. In other words, the people have the power to choose their leaders. This is why free and fair elections are necessary for democracy to thrive.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>27", "subject": "Government", "year": "2006", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : TYPES, MERITS AND DEMERITS", "question": "A system in which a candidate with the highest number of votes is declared winner in an election is called", "images": [], "options": {"A": "First-pass-the-post", "B": "block voting", "C": "second balloting", "D": "proportional representation"}, "answer": "A", "explanation": "A first-pass-the -post is a system in which a candidate with the highest number of votes is declared winner in an election.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>28", "subject": "Government", "year": "2006", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "Pressure groups are also known as", "images": [], "options": {"A": "social clubs", "B": "cultural organization", "C": "interest groups", "D": "secular groups"}, "answer": "C", "explanation": "Pressure groups are also known as 'interest groups'. These are groups that try to influence public policy in the interest of a particular cause. They do this by lobbying government officials, mobilizing public opinion, and sometimes through direct action. They are different from political parties in that they do not seek to gain political power themselves, but rather to influence those who do.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2006>29", "subject": "Government", "year": "2006", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "Public opinion is the view held by the majority", "images": [], "options": {"A": "minority", "B": "civil servants", "C": "majority", "D": "politicians"}, "answer": "C", "explanation": "Public opinion is the view held by the majority. Public opinion may be defined as the collective beliefs, judgements or views held by majority of citizens of a country about public polity or action of the government.  Majority of the people will hold the opinion that the government of the day is doing well when government provides the basic, social and economic needs of the people.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2006>30", "subject": "Government", "year": "2006", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "A manifesto refers to", "images": [], "options": {"A": "the register of party members", "B": "rejected ballot papers", "C": "valid ballot papers", "D": "proposed programme of a party"}, "answer": "D", "explanation": "A manifesto is a public declaration of the intentions, motives, or views of an individual, group, political party or government. In the context of a political party, it refers to the proposed programme of the party. Therefore, the correct answer is 'proposed programme of a party'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2006>31", "subject": "Government", "year": "2006", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "One demerit of a one party system is that it encourages", "images": [], "options": {"A": "red-tapism", "B": "dictatorship", "C": "democracy", "D": "development"}, "answer": "B", "explanation": "The demerits of one party system are:  It is undemocratic  It leads to dictatorship  It abridges human rights  Encourages oppression  Leads to coup", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>32", "subject": "Government", "year": "2006", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "The functions of political parties includes the following except", "images": [], "options": {"A": "being brokers of ideas", "B": "influencing policies in the government", "C": "educate the electorate by clarifying issues", "D": "disseminating information to members"}, "answer": "B", "explanation": "Functions of political parties include:  It helps to select and appoint leaders and personnel for government.  They are brokers of ideas.  Educate the electorate by clarifying issues.  Disseminating information to members.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>33", "subject": "Government", "year": "2006", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "Anonymity of civil servants means that they", "images": [], "options": {"A": "should be seen and heard", "B": "should engage in partisan politics", "C": "should work hard for their superiors", "D": "do not take praise or blames for their performance"}, "answer": "D", "explanation": "Anonymity of civil servants means that they do not take praise or blames for their performance. This is because civil servants are expected to provide non-partisan service to the government of the day, irrespective of which political party is in power. They are not the public face of the decisions they help to implement, hence they do not take the praise or blame for their performance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>34", "subject": "Government", "year": "2006", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "One of the objectives of public corporations is to", "images": [], "options": {"A": "enhance public awareness", "B": "narrow the gap between the rich and the poor", "C": "encourage individual participation", "D": "maximize profit"}, "answer": "B", "explanation": "One of the objectives of public corporations is to narrow the gap between the rich and the poor. Public corporations are government-owned agencies or organizations that operate in the commercial sector. They are established with the aim of providing essential services to the public at affordable rates, thereby helping to reduce income inequality.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>35", "subject": "Government", "year": "2006", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "Public corporation are financed", "images": [], "options": {"A": "by tax payers", "B": "with private funds", "C": "with entrepreneurial funds", "D": "by political parties"}, "answer": "A", "explanation": "Public corporations can be defined as a business organization established, owned , managed and financed with tax payers' taxes by the government of a country with the main motive of not making profit but to render essential services to members of the public.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>36", "subject": "Government", "year": "2006", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "Which of the following is an advantage of local government in West Africa? Acting as", "images": [], "options": {"A": "Agents of money-based policies", "B": "electoral commission", "C": "training grounds for political leaders", "D": "agents for pressure  groups"}, "answer": "C", "explanation": "Local governments in West Africa, like in many other parts of the world, serve as training grounds for political leaders. This is because local government provides an opportunity for individuals to gain political experience, understand the workings of government and serve their community, which can prepare them for higher political positions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>37", "subject": "Government", "year": "2006", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI~~PRE-COLONIAL POLITICAL SYSTEM : YORUBA~~PRE-COLONIAL POLITICAL SYSTEM : IGBO", "question": "Some Pre-Colonial West African governments were democratic because of the existence of", "images": [], "options": {"A": "powerful traditional rulers", "B": "age grades", "C": "religious institutions", "D": "checks and balances"}, "answer": "D", "explanation": "Pre-colonial West-African governments were democratic because of the existence of checks and balances.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2006>38", "subject": "Government", "year": "2006", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "In the pre-colonial West-Africa, the kingdoms of the Asante, Wolof and the Hausa were examples of a", "images": [], "options": {"A": "state", "B": "union", "C": "country", "D": "nation"}, "answer": "A", "explanation": "In the pre-colonial West-Africa, the kingdoms of the Asante, Wolof and the Hausa were examples of a state. A state is a political entity represented by a centralized government that has sovereignty over a geographic area. These kingdoms had their own centralized governments and controlled specific geographic areas, thus they can be classified as states.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>39", "subject": "Government", "year": "2006", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Which of the following countries popularized the use of the indirect rule by the British?", "images": [], "options": {"A": "Nigeria", "B": "Ghana", "C": "Sierra  Leone", "D": "The Gambia"}, "answer": "A", "explanation": "The indirect rule system was popularized in Nigeria by the British. This system of governance was introduced by Lord Lugard, the then High Commissioner of the Protectorate of Northern Nigeria. The system involved ruling through traditional rulers and existing political structures, which was less expensive and easier for the British to manage.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>40", "subject": "Government", "year": "2006", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Indirect Rule was successful in some part of West Africa because", "images": [], "options": {"A": "the British tyrannized the people", "B": "it suited the existing traditional political structure", "C": "British officials learnt the local languages", "D": "the residents were good administrators"}, "answer": "B", "explanation": "Indirect Rule was successful in some parts of West Africa because it suited the existing traditional political structure. The British used the existing traditional rulers and institutions to administer their colonies. This made it easier for them to control and manage their colonies as they did not have to establish a new administrative system. The traditional rulers were made to understand that they were not sovereign rulers but were under the British Crown.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>41", "subject": "Government", "year": "2006", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "The National Congres of British West Africa (NCBWA) was founded in 1919 by", "images": [], "options": {"A": "Kobina Sekyi", "B": "J.B. Danquah", "C": "Mensah Sarbah", "D": "J.E. Casely"}, "answer": "D", "explanation": "NCBWA was founded in 1919 by J.E Casely Hayford. This is the most accurate answer", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2006>42", "subject": "Government", "year": "2006", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Elective principles was introduced in the British Colonies after", "images": [], "options": {"A": "series of negotiations by the chief", "B": "consultations with the age grades", "C": "a series of agitations by educated elites", "D": "the Queen's desire to come to the colonies"}, "answer": "C", "explanation": "Elective principle was introduced in the British colonies after a series of agitations by educated elites.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>43", "subject": "Government", "year": "2006", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "An important innovation of the constitution of British West African colonies in the 1920s was the", "images": [], "options": {"A": "introduction of elective principle", "B": "appointment of Africans to the executive principle", "C": "restriction of governors' veto powers", "D": "opening of regional assemblies"}, "answer": "A", "explanation": "The constitution of British West African colonies in the 1920s introduced the elective principle. This was a significant innovation as it marked the beginning of democratic governance in the colonies. The elective principle is a democratic concept that allows citizens to choose their representatives in government through elections.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>44", "subject": "Government", "year": "2006", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "National Congress of Bristish West Africa (NCBWA) failed to achieve its aim initially because", "images": [], "options": {"A": "the chiefs and Governors opposed those aims", "B": "African workers opposed those aims", "C": "African employed Europeans to write those aims", "D": "the congress failed to bring foreigners into its fold"}, "answer": "A", "explanation": "The National Congress of British West Africa (NCBWA) initially failed to achieve its aims because the chiefs and Governors opposed those aims. The NCBWA was a political pressure group that sought to bring about changes in the political and social life of West Africans. However, their aims were met with resistance from the traditional rulers (chiefs) and the colonial governors who were not ready to relinquish their powers.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2006>45", "subject": "Government", "year": "2006", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "A coup d'etat is regarded as", "images": [], "options": {"A": "A source of political legitimacy", "B": "A manipulation of the constitution", "C": "A constitutional way of changing the government", "D": "An unconstitutional way of changing the government"}, "answer": "D", "explanation": "A coup d'etat refers to an unconstitutional way of changing the government usually by military force.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2006>46", "subject": "Government", "year": "2006", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "The military intervened in West African politics mainly because", "images": [], "options": {"A": "politicians play the game accordingly", "B": "law and order are maintained", "C": "they are better rulers", "D": "of election malpractice"}, "answer": "D", "explanation": "The military has often intervened in West African politics due to perceived corruption and malpractice in the electoral process. They often justify their actions as necessary to restore order and integrity to the political system, although this is not always the result.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>47", "subject": "Government", "year": "2006", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The United Nations Organization (UNO) was founded in 1945 as a successor to the", "images": [], "options": {"A": "Warsaw pact", "B": "World Trade Organization", "C": "North Atlantic Treaty Organizations", "D": "League Of Nations"}, "answer": "D", "explanation": "The United Nations Organization (UNO) was founded in 1945 as a successor to the League of Nations. The League of Nations was an intergovernmental organization founded as a result of the Paris Peace Conference that ended the First World War. It was the first international organization whose principal mission was to maintain world peace. However, after failing to prevent the Second World War, it was dissolved and replaced by the United Nations.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2006>48", "subject": "Government", "year": "2006", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The Secretary - General of the United Nations Organization (UNO) is appointed for a period of", "images": [], "options": {"A": "three years", "B": "five years", "C": "seven years", "D": "nine years"}, "answer": "B", "explanation": "The Secretary-General of the United Nations Organization (UNO) is appointed for a period of five years. The Secretary-General is the chief administrative officer of the United Nations and is appointed by the General Assembly upon the recommendation of the Security Council. The term of office is renewable.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2006>49", "subject": "Government", "year": "2006", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "The official language of the Commonwealth is", "images": [], "options": {"A": "French", "B": "Spanish", "C": "Dutch", "D": "English"}, "answer": "D", "explanation": "The Commonwealth is a political association of 54 member states, nearly all of which are former territories of the British Empire. The head of the Commonwealth is Queen Elizabeth II. Therefore, the official language is English.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2006>50", "subject": "Government", "year": "2006", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "Which of the following blocs existed in Africa, prior to the formation of the Organization of  African Unity (OAU) ? The", "images": [], "options": {"A": "Monronvia, Accra and Cassablanca group", "B": "Brazzaville, Lome and Monrovia group", "C": "Cassablanca, Brazaville and Monrovia group", "D": "Algeria, Monrovia and Cassablanca group"}, "answer": "C", "explanation": "\" Cassablanca, Brassaville and Monrovia group\" is the answer.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2007>1", "subject": "Government", "year": "2007", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS A PROCESS OR ART OR GOVERNING", "question": "Which of the following is related to government as a process of governing?", "images": [], "options": {"A": "Implementation and adjudication of laws", "B": "The role of pressure groups within the state", "C": "Disagreement between state and local government", "D": "Abrogation of fundamental human rights."}, "answer": "A", "explanation": "Government as a process of governing involves the implementation and adjudication of laws. This is because the government is responsible for making laws and ensuring that these laws are followed. Adjudication refers to the legal process by which a judge reviews evidence and argumentation to come to a decision. In this context, it means the government's role in enforcing laws and making judgments when these laws are broken.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>2", "subject": "Government", "year": "2007", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "Which of the following is not an aim for the existence of a state?", "images": [], "options": {"A": "Promotion of economic independence", "B": "Provision of welfare services", "C": "Maintenance of external relations", "D": "Promotion of a common lingua franca"}, "answer": "D", "explanation": "Promotion of common lingua franca is not an aim for the existence of a state, therefore it is the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>3", "subject": "Government", "year": "2007", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Right to rule based on norms, customs and convention of the people is referred to as", "images": [], "options": {"A": "Legal authority", "B": "charismatic authority", "C": "rational authority", "D": "traditional authority"}, "answer": "D", "explanation": "\"Traditional authority \" is the answer    Traditional authority is the source of of authority derived from hereditary families based on the existing customs and traditions. It is the right to rule based on norms, custom and convention of the people.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2007>4", "subject": "Government", "year": "2007", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : REPUBLICAN", "question": "Which of the following is not a legitimate government?", "images": [], "options": {"A": "Democratic government", "B": "Republican government", "C": "Military government", "D": "Monarchical government"}, "answer": "C", "explanation": "A military government is not considered a legitimate government. Legitimate governments are those that are elected by the people and are recognized by the constitution of the country. A military government is usually established through a coup d'etat and is not elected by the people, hence it is not considered legitimate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>5", "subject": "Government", "year": "2007", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The scholar who defined sovereignty as an  absolute power vested in one authority  was", "images": [], "options": {"A": "A.V. Dicey", "B": "Jean Bodin", "C": "John Austin", "D": "B. Montesquieu"}, "answer": "B", "explanation": "Jean Bodin is the scholar who defined sovereignty as an absolute power vested in one authority. Sovereignty refers to the full right and power of a governing body over itself, without any interference from outside sources or bodies. In political theory, sovereignty is a substantive term designating supreme legitimate authority over some polity. In this context, 'absolute power' refers to the complete power to govern without interference or limitation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2007>6", "subject": "Government", "year": "2007", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Political sovereignty belongs to the", "images": [], "options": {"A": "press", "B": "people", "C": "legislature", "D": "executive"}, "answer": "B", "explanation": "Political sovereignty belongs to the people. In a democratic system, sovereignty is vested in the people who elect their representatives to exercise power on their behalf. The concept of political sovereignty is closely related to the concept of popular sovereignty, which is the principle that the authority of a state and its government are created and sustained by the consent of its people, through their elected representatives.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>7", "subject": "Government", "year": "2007", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Direct democracy emanated from the", "images": [], "options": {"A": "Greeks", "B": "Romans", "C": "Germans", "D": "Americans"}, "answer": "A", "explanation": "Direct democracy, also known as pure democracy, is a form of democracy where the people decide on policy initiatives directly. This system originated from the ancient Greeks, specifically in the city-state of Athens around the 5th century BC. Therefore, the correct answer is Greeks.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>8", "subject": "Government", "year": "2007", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Production of goods and services are controlled by the state in", "images": [], "options": {"A": "capitalism", "B": "mixed economy", "C": "socialism", "D": "communalism"}, "answer": "C", "explanation": "Socialism may be defined as a political cum economic system in which all or a large part of the means of production are collectively owned and controlled by the state.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2007>9", "subject": "Government", "year": "2007", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The two major factors that contributed to the development of capitalism were", "images": [], "options": {"A": "emergence of the Protest Reformation and paper money", "B": "The emergence of Adolf Hilter and the first World War", "C": "the theory of individual rights and  the Industrial Revolution in Britain", "D": "the First World War and the Atlantic Charter of 19411"}, "answer": "C", "explanation": "The theory of individual rights and the industrial revolution in Britain contribute to the development of capitalism", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2007>10", "subject": "Government", "year": "2007", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following is a feature of capitalism?", "images": [], "options": {"A": "Removal of social inequalities", "B": "Equitable re-distribution of properties", "C": "Maximization of properties", "D": "Protection of workers"}, "answer": "C", "explanation": "Features of capitalism include:    Labour is regarded as a marketable commodity  There are many producers as well as buyers  Profit motive is the guiding principle.  It has highly developed occupational specialization", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>11", "subject": "Government", "year": "2007", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "In a capitalist state, a society is polarized into the", "images": [], "options": {"A": "Christian and the Muslims", "B": "government and the workers", "C": "bourgeoisie and the proletariat", "D": "diligent people and the lazy people"}, "answer": "C", "explanation": "In a capitalist state, society is often polarized into the bourgeoisie and the proletariat. The bourgeoisie are the owners of the means of production (capital, land, factories, etc.) and the proletariat are the workers who sell their labor for wages. This is a fundamental concept in Marxist theory, which argues that this class division leads to social inequality and conflict.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>12", "subject": "Government", "year": "2007", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The system of government to which political leadership is based on the land ownership is", "images": [], "options": {"A": "communism", "B": "feudalism", "C": "capitalism", "D": "socialism"}, "answer": "B", "explanation": "Feudalism is a primitive system of government and economic system based mainly on hierarchical order of ownership of land.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>13", "subject": "Government", "year": "2007", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The highest stage of socialism is", "images": [], "options": {"A": "fascism", "B": "communalism", "C": "communism", "D": "feudalism"}, "answer": "C", "explanation": "The highest stage of socialism is communism. Socialism is a transitional stage between capitalism and communism. In socialism, the means of production are owned and controlled by the state. However, in communism, the means of production are owned by the community. The state withers away and a classless and stateless society is established.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2007>14", "subject": "Government", "year": "2007", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Communism was popularized by", "images": [], "options": {"A": "Karl Marx and Fredrick Engels", "B": "Max Weber and Aristotle", "C": "Plato and Socrates", "D": "Harold Laski and Jean Bodin"}, "answer": "A", "explanation": "Communism was popularized by Karl Max and Lenin. But since Lenin wasn't given in your option you can make the of the option that has Karl Max in it. It is a theory or system of social organization in which all property is owned by the community and each person contributes and receives according to their ability and needs.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2007>15", "subject": "Government", "year": "2007", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A classless society is obtained in", "images": [], "options": {"A": "Communism", "B": "Capitalism", "C": "feudalism", "D": "plutocracy"}, "answer": "A", "explanation": "A classless society is a key principle of Communism. In a communist society, there is no division of society into classes. The idea is that wealth and power are shared equally among the people, with no one having more than anyone else. This is in contrast to Capitalism, Feudalism, and Plutocracy, where there are distinct classes based on wealth and power.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>16", "subject": "Government", "year": "2007", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The fascist state in Europe was", "images": [], "options": {"A": "Italy", "B": "Germany", "C": "Japan", "D": "Britain"}, "answer": "A", "explanation": "Fascism is a form of far-right, authoritarian government that originated in Italy in the early 20th century, under Benito Mussolini. It was characterized by dictatorial power, forcible suppression of opposition, and strong regimentation of society and of the economy. Although there were fascist movements in other countries, including Germany and Japan, the term 'fascist state' is most closely associated with Italy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>17", "subject": "Government", "year": "2007", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Communalism ensures that everybody within the society is provided", "images": [], "options": {"A": "a means of transportation", "B": "with a chieftaincy title", "C": "with a formal education", "D": "a land to farm"}, "answer": "D", "explanation": "Communalism ensures that everybody within the society is provided with a land to farm. Communalism refers to a system of collective ownership of property and co-operation among members of a community in the execution of development projects. Properties like land are owned collectively and shared on equal basis.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2007>18", "subject": "Government", "year": "2007", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The political way of life which is developed by the society is referred to as", "images": [], "options": {"A": "communalism", "B": "political culture", "C": "agency of socialization", "D": "political socialization"}, "answer": "B", "explanation": "Political culture refers to the attitudes, beliefs, values, and symbols that influence and shape political behavior within a society. It is the product of both the collective history of a political system and the life histories of the members of the system and thus it is rooted both in public events and private experience. Therefore, the political way of life which is developed by the society is referred to as political culture.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>19", "subject": "Government", "year": "2007", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A political aware and active society is said to have a", "images": [], "options": {"A": "subjective political culture", "B": "participatory political culture", "C": "parochial political culture", "D": "evaluation political culture"}, "answer": "B", "explanation": "A politically aware and active society is said to have a participatory political culture. This is because in a participatory political culture, citizens are highly involved in the political process, they are aware of their rights and responsibilities, and they actively participate in political activities such as voting, campaigning, and public debates. This contrasts with a subjective political culture where citizens are less involved and a parochial political culture where citizens have little awareness or interest in politics. An evaluation political culture does not exist in the context of political science.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2007>20", "subject": "Government", "year": "2007", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Fundamental human rights can be defined as", "images": [], "options": {"A": "freedoms enshrined in the constitution", "B": "the provision of the constitution of the ruling political party", "C": "the provision of the local government constitution", "D": "regulation about workers welfare"}, "answer": "A", "explanation": "Freedoms enshrined in the constitution is the answer because it best describes fundamental human rights.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>21", "subject": "Government", "year": "2007", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "A system of government that is made up of elected people is referred to as", "images": [], "options": {"A": "representative government", "B": "socialist government", "C": "capitalist government", "D": "feudalist government"}, "answer": "A", "explanation": "A representative government is a system where citizens elect representatives to make decisions and pass laws on behalf of all the people instead of allowing people to vote directly on laws. It is a democratic form of government. The other options do not accurately describe a system of government made up of elected people.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2007>22", "subject": "Government", "year": "2007", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Which of the following is a means of establishing representative government?", "images": [], "options": {"A": "The existence of functional political parties", "B": "The existence of para - military groups", "C": "Operation of checks and balances", "D": "The operating of the Rule of Law"}, "answer": "A", "explanation": "The existence of functional political parties because it a means of establishing representative government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>23", "subject": "Government", "year": "2007", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Devolution of power is associated with a", "images": [], "options": {"A": "decentralized political system", "B": "feudal political system", "C": "totalitarian political system", "D": "centralized political system"}, "answer": "A", "explanation": "Devolution of power is a form of decentralization where powers are transferred from a central government to subnational levels, such as regional, local, and state governments. Therefore, it is associated with a decentralized political system. A decentralized political system is one where decision-making powers are distributed or delegated away from a central authority to regional and local authorities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>24", "subject": "Government", "year": "2007", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Which of the following is a benefit of  the principle of checks and balances? it", "images": [], "options": {"A": "enables the executive to exercise absolute power", "B": "encourages loyalty of the judiciary to the executive", "C": "rules out disagreement among the organs of government", "D": "prevents domination of government by one organ of government by another"}, "answer": "D", "explanation": "Prevents domination of government by one organ of government by another is the answer because it is a benefit of the principles of checks and balances.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>25", "subject": "Government", "year": "2007", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY", "question": "The degree of centralization is high in a", "images": [], "options": {"A": "unitary system of government", "B": "federal system of government", "C": "representative government", "D": "unrepresentative government"}, "answer": "A", "explanation": "Unitary system of government is the answer because the degree of centralization is high in a unitary system of government.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2007>26", "subject": "Government", "year": "2007", "type": "Objective", "topic": "CONSTITUTIONS : TYPES AND FEATURES", "question": "A constitution that requires special procedures to amend is referred to as", "images": [], "options": {"A": "flexible", "B": "federal", "C": "rigid", "D": "unwritten"}, "answer": "C", "explanation": "A rigid constitution is one that requires special procedures to amend or change. This is often done to protect the constitution from frequent changes and to ensure that any changes made are carefully considered. This is in contrast to a flexible constitution, which can be easily changed without any special procedures.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>27", "subject": "Government", "year": "2007", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "A type of government which allows co-ordinate units make laws is", "images": [], "options": {"A": "federal", "B": "monarchical", "C": "unitary", "D": "presidential"}, "answer": "A", "explanation": "A federal government is a system that divides up power between a strong national government and smaller local governments. In this system, the co-ordinate units (states or provinces) have the power to make their own laws in certain areas, while the national government retains the power to make laws on broader issues.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>28", "subject": "Government", "year": "2007", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY", "question": "One feature of a unitary state is", "images": [], "options": {"A": "The large size of the country", "B": "high level of economic development", "C": "absence of constitutional development of power to the units", "D": "presence of heterogeneous groups"}, "answer": "C", "explanation": "A unitary state is a state governed as a single entity in which the central government is ultimately supreme. The central government may create (or abolish) administrative divisions (sub-national units). Such units exercise only the powers that the central government chooses to delegate. Therefore, the absence of constitutional delegation of power to the units is a feature of a unitary state.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>29", "subject": "Government", "year": "2007", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET", "question": "A characteristic of the parliamentary system is that", "images": [], "options": {"A": "separation of power is not strictly observed", "B": "the prime minister combines the executive and the ceremonial functions", "C": "the president can dismiss any minister without much hinderance", "D": "the ministers are responsible individually to the president"}, "answer": "A", "explanation": "'Separation of power is not strictly observed' is the answer because it is one of the  parliamentary systems. In parliamentary system, members of the executive come from the parliament.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>30", "subject": "Government", "year": "2007", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : CONFEDERAL", "question": "In a confederation, each of the component state is", "images": [], "options": {"A": "militarily weak", "B": "underpopulated", "C": "virtually sovereign", "D": "underdeveloped"}, "answer": "C", "explanation": "In a confederation, each of the component states is virtually sovereign. This means that each state has the power to govern itself without interference from the central government. This is one of the key characteristics of a confederation, which is a union of states in which each state retains its sovereignty, freedom, and independence.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>31", "subject": "Government", "year": "2007", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : CONFEDERAL", "question": "Which of the following countries had practiced confederal system of government?", "images": [], "options": {"A": "Senegal and the Gambia", "B": "Mali and Senegal", "C": "Ghana and Sierra leone", "D": "Nigeria and Niger"}, "answer": "A", "explanation": "Senegal and The Gambia had practiced a confederal system of government. This was known as the Senegambia Confederation which existed between 1982 and 1989. A confederal system of government is a system where the constituent states retain considerable independence, with the central government exercising only limited powers.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2007>32", "subject": "Government", "year": "2007", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "The type of government where the central authority is superior to the component authority is a", "images": [], "options": {"A": "parliamentary system of government", "B": "representative system of government", "C": "confederal system of government", "D": "federal system of government"}, "answer": "D", "explanation": "Federal system of government is the answer because it is the type of government where the central authority is superior to the component authorities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>33", "subject": "Government", "year": "2007", "type": "Objective", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : FEATURES AND PROBLEMS", "question": "The Exclusive list in a federal state includes", "images": [], "options": {"A": "education", "B": "market", "C": "defence", "D": "transportation"}, "answer": "C", "explanation": "In a federal state, the Exclusive list includes matters over which only the federal government has jurisdiction. These matters typically include defense, foreign affairs, and monetary policy. Therefore, 'defence' is the correct answer. Education and transportation can be under concurrent list where both federal and state government can make laws, while market is typically under the jurisdiction of the local government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>34", "subject": "Government", "year": "2007", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "The primary function of the judiciary is to", "images": [], "options": {"A": "make laws", "B": "enforce laws", "C": "interpret laws", "D": "maintain law and order"}, "answer": "C", "explanation": "The primary function of the judiciary is to interpret laws. This means that the judiciary explains the meaning of laws and applies them to individual cases. They do not make laws (that's the role of the legislative branch) or enforce laws (that's the role of the executive branch). Maintaining law and order is a general function of the government, not specifically the judiciary.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2007>35", "subject": "Government", "year": "2007", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "Obedience to the law of the state is a part of one's", "images": [], "options": {"A": "duties", "B": "rights", "C": "privileges", "D": "requirements"}, "answer": "A", "explanation": "Obedience to the law of the state is a part of one's duties. This is because as citizens, we have a responsibility to follow the laws set by the state. This helps to maintain order and ensure the smooth functioning of society. The other options, rights, privileges, and requirements, do not accurately describe the concept of obedience to the law.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2007>36", "subject": "Government", "year": "2007", "type": "Objective", "topic": "CITIZENSHIP : MEANS OF SAFEGUARDING RIGHTS OF CITIZENS.", "question": "Establishment of an independent judiciary is a way of safe-guarding citizens", "images": [], "options": {"A": "rights", "B": "obligations", "C": "privileges", "D": "education"}, "answer": "A", "explanation": "\"Rights\" is the answer because establishment of an independent judiciary is a way of safeguarding it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>37", "subject": "Government", "year": "2007", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "An organized group that seeks the control of power in a state is", "images": [], "options": {"A": "pressure group", "B": "political party", "C": "social group", "D": "co-operative society"}, "answer": "B", "explanation": "Political party is the answer because it is an organized group that seek the control of power in a state.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>38", "subject": "Government", "year": "2007", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A one-party system is common to", "images": [], "options": {"A": "democratic government", "B": "totalitarian government", "C": "representative government", "D": "monarchical government"}, "answer": "B", "explanation": "A one-party system is a type of state in which one political party has the right to form the government, usually based on the existing constitution. This is common to totalitarian governments where only one political party is legally allowed to hold power. Democratic, representative, and monarchical governments can have multiple political parties.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2007>39", "subject": "Government", "year": "2007", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS", "question": "A government that is constituted by several parties after a general election is referred to as", "images": [], "options": {"A": "elite government", "B": "fascist government", "C": "illegitimate government", "D": "national government"}, "answer": "D", "explanation": "\" National government\" is the answer. This is a reflection of democracy.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2007>40", "subject": "Government", "year": "2007", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Disenfranchisement means", "images": [], "options": {"A": "right to vote", "B": "right to form government", "C": "to be disqualified from voting", "D": "disallowing free and fair election"}, "answer": "C", "explanation": "Disenfranchisement refers to the removal or suspension of voting rights. It is a legal mechanism used to prevent a person or group of people from voting. Therefore, the correct answer is 'to be disqualified from voting'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2007>41", "subject": "Government", "year": "2007", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : ELECTORAL MANAGEMENT BODY", "question": "Which of the following is a major feature of an Electoral Commission?", "images": [], "options": {"A": "Support for the ruling party", "B": "Control by government", "C": "Privately funded", "D": "Political neutrality"}, "answer": "D", "explanation": "Features of an electoral commission are:    It is a body with the responsibility of organizing and conducting free and fair elections in a country.  It is a politically neutral and a non partisan organization.  It has branches in different parts of the country  It is the final arbiter in an election", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>42", "subject": "Government", "year": "2007", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "A popular British Colonial System of administration in the protectorates in West Africa was", "images": [], "options": {"A": "Assimilation", "B": "Direct rule", "C": "Association", "D": "Indirect rule"}, "answer": "D", "explanation": "Indirect rule is the answer because it is the British colonial system of administration in the Protectorates in West Africa.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2007>43", "subject": "Government", "year": "2007", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "The introduction of elective principle in colonial West Africa allowed", "images": [], "options": {"A": "Africans to be elected into the Legislative Councils", "B": "the Executive Councils to be dominated by Africans", "C": "an African to become a Governor - General", "D": "the removal of Governor-General's veto powers"}, "answer": "A", "explanation": "The introduction of elective principle in colonial West Africa allowed Africans to be elected into the Legislative Councils. The elective principle was a system that allowed Africans to participate in the governance of their colonies by electing representatives into the Legislative Councils. However, it did not allow for the Executive Councils to be dominated by Africans, an African to become a Governor - General, or the removal of Governor-General's veto powers.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2007>44", "subject": "Government", "year": "2007", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "The political parties that were established in West Africa between 1945 and 1965 fought for", "images": [], "options": {"A": "national conference", "B": "political independence", "C": "supremacy among themselves", "D": "regional integration"}, "answer": "B", "explanation": "Political parties established in West Africa between 1945-1965 did fight for it. Some of them include National Council of Nigeria and the Cameroons/National Council of Nigerian Citizens (NCNC), Nigerian National Democratic Party (NNDP) and Action Group (AG).", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>45", "subject": "Government", "year": "2007", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "The first military coup d'etat in West Africa was staged in", "images": [], "options": {"A": "Niger", "B": "Guinea", "C": "Togo", "D": "Ghana"}, "answer": "C", "explanation": "Togo was the first country in West Africa to experience a military coup when on 13 January 1963 Togolese soldiers, recently demobilised from the French colonial armies and facing unemployment as a result of refusal of their applications to join 'the miniscule Togolese army, staged an armed coup that led to the ouster and death of Sylvanus Olympio, the Togolese President.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2007>46", "subject": "Government", "year": "2007", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "One of the defects of military government is", "images": [], "options": {"A": "freedom of expression", "B": "registration of political parties", "C": "abuse of Human Rights", "D": "promotion of few military officers"}, "answer": "C", "explanation": "One of the defects of military government is the abuse of Human Rights. Military governments are known for their authoritarian rule, where the rights and freedoms of citizens are often suppressed. Human rights include the right to life and liberty, freedom from slavery and torture, freedom of opinion and expression, the right to work and education, and many more. These are often violated in military regimes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>47", "subject": "Government", "year": "2007", "type": "Objective", "topic": "FOREIGN POLICIES : ADVANTAGES AND DISADVANTAGES", "question": "The major defect of foreign policy in West Africa is", "images": [], "options": {"A": "public opinion and pressure groups", "B": "military power", "C": "good economy", "D": "poor leadership"}, "answer": "D", "explanation": "The major defect of foreign policy in West Africa is poor leadership. This is because leadership plays a crucial role in formulating and implementing foreign policy. Poor leadership often results in inconsistent and ineffective foreign policies. Public opinion and pressure groups, military power, and good economy are not defects but rather factors that can influence foreign policy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2007>48", "subject": "Government", "year": "2007", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "The Council of Ministers of the Organization of African Unity (OAU) is made up of", "images": [], "options": {"A": "Justice Minister", "B": "Foreign Affairs Minister", "C": "Education Minister", "D": "Defence Minister"}, "answer": "B", "explanation": "The Council of Ministers of the Organization of African Unity (OAU), now the African Union (AU), is made up of Foreign Affairs Ministers. The Council of Ministers is responsible for coordinating and implementing the decisions of the Assembly of Heads of State and Government, the supreme organ of the OAU/AU. The Council is composed of ministers of foreign affairs or such other ministers or authorities as are designated by the governments of member states. Therefore, the correct answer is the Foreign Affairs Minister.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2007>49", "subject": "Government", "year": "2007", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "The head of the Commonwealth of Nations is", "images": [], "options": {"A": "Queen Elizabeth II", "B": "Don Mckinnon", "C": "Tony Blair", "D": "Margaret Thartcher"}, "answer": "A", "explanation": "\" Queen Elizabeth\" is the answer.   The Commonwealth of Nations (formerly the British Commonwealth), also known as simply The Commonwealth, is an intergovernmental organisation of 52 member states that are mostly former territories of the British Empire.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2007>50", "subject": "Government", "year": "2007", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "The main focus of the Ecowas Monitoring Group (ECOMOG) is the", "images": [], "options": {"A": "Maintenance of peace in troubled spots of West Africa", "B": "Installation of unpopular government in West Africa", "C": "Protection of oil pipe-lines along the coast of West Africa", "D": "Promotion of Military rule"}, "answer": "A", "explanation": "\" The maintenance of peace in troubled spots of West Africa\" is the answer. This is because it is the main focus of ECOMOG. The Economic Community of West African States Monitoring Group (ECOMOG) was a West African multilateral armed force established by the Economic Community of West African States (ECOWAS). ECOMOG was a formal arrangement for separate armies to work together.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2008>1", "subject": "Government", "year": "2008", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN ACADEMIC FIELD OF STUDY – REASONS FOR STUDYING GOVERNMENT.", "question": "Government as an academic field of study refers to", "images": [], "options": {"A": "president and his ministers", "B": "study of political institutions and processes", "C": "working of the organs of government", "D": "membership of international organizations"}, "answer": "B", "explanation": "Government as an academic field of study refers to the study of political institutions and processes. It involves the analysis of political behavior, the theories and practices of governance, and the research of political phenomena. It does not only refer to the president and his ministers, the working of the organs of government, or the membership of international organizations, but it encompasses all these aspects and more.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2008>2", "subject": "Government", "year": "2008", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "A state performs the following functions except", "images": [], "options": {"A": "promoting welfare of the citizens", "B": "encouraging the struggle for power", "C": "providing social services", "D": "encouraging trade with other states"}, "answer": "B", "explanation": "The functions of a state do not include encouraging the struggle for power. The state is responsible for promoting the welfare of its citizens, providing social services, and encouraging trade with other states. The struggle for power can lead to instability and conflict, which are not conducive to the welfare of the citizens or the state as a whole.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>3", "subject": "Government", "year": "2008", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Power can be defined as the ability to", "images": [], "options": {"A": "compel or influence obedience", "B": "encourage self help projects", "C": "delegate judicial functions", "D": "oppose government policies"}, "answer": "A", "explanation": "Power in the context of governance and politics is often defined as the ability to influence or compel obedience. This is because those in power have the capacity to enforce their will or influence the actions, beliefs, or conduct of others. The other options do not accurately define power.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>4", "subject": "Government", "year": "2008", "type": "Objective", "topic": "CITIZENSHIP : MEANING AND MODE OF ACQUISITION", "question": "Which of the following groups has compulsory membership?", "images": [], "options": {"A": "community", "B": "state", "C": "society", "D": "club"}, "answer": "B", "explanation": "A state is a political entity with compulsory membership. This is because once you are born in a certain geographical area defined as a state, you automatically become a member of that state. The other options like community, society, and club do not have compulsory membership as one can choose to join or leave them.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2008>5", "subject": "Government", "year": "2008", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A government which has the ability to compel its citizens to obedience is said to be", "images": [], "options": {"A": "authority", "B": "coercion", "C": "power", "D": "legitimacy"}, "answer": "C", "explanation": "This is the answer because it has the ability to compel its citizens.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2008>6", "subject": "Government", "year": "2008", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A government's supreme power to demand obedience from its citizens demonstrates the notion of", "images": [], "options": {"A": "rule of law", "B": "parliamentary supremacy", "C": "sovereignty", "D": "separation of powers"}, "answer": "C", "explanation": "Sovereignty is the answer because it is the government's supreme power to demand obedience from its citizen demonstrates it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>7", "subject": "Government", "year": "2008", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Nazism  is a political ideology which emphasizes", "images": [], "options": {"A": "supremacy of  race", "B": "collective racial consciousness", "C": "communal racial consciousness", "D": "equality of all races"}, "answer": "A", "explanation": "Nazism, also known as National Socialism, is a political ideology that emerged in Germany in the early 20th century, led by Adolf Hitler. It emphasizes the supremacy of the Aryan race and the need for racial purity. Therefore, the correct answer is 'supremacy of race'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2008>8", "subject": "Government", "year": "2008", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY", "question": "In unitary state, sovereignty resides in the", "images": [], "options": {"A": "political parties", "B": "provincial government", "C": "central government", "D": "pressure group"}, "answer": "C", "explanation": "In a unitary state, all power is held by a single, central authority. It is the opposite of a federation, where governmental powers and responsibilities are divided. In a unitary state, the central government holds all the power and it may choose to delegate powers to local governments. Therefore, the correct answer is 'central government'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>9", "subject": "Government", "year": "2008", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Which of the following facilitates the working of a democratic government?", "images": [], "options": {"A": "Dormant press", "B": "Partial Judiciary", "C": "Vigilante group", "D": "political parties"}, "answer": "D", "explanation": "Political parties facilitate the working of a democratic government. They do this by organizing and mobilizing citizens around particular issues, providing a platform for political debate, and through their role in the formation of government. A dormant press, partial judiciary, and vigilante groups do not facilitate the working of a democratic government. A dormant press does not actively check the government, a partial judiciary does not uphold the rule of law, and vigilante groups often operate outside of the law.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2008>10", "subject": "Government", "year": "2008", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Which of the following negates the principle of the rule of law?", "images": [], "options": {"A": "Independence of the Judiciary", "B": "Trial by Jury", "C": "Immunity of some citizens", "D": "Trial in open courts"}, "answer": "C", "explanation": "The principle of the rule of law states that all individuals, including government officials, are subject to the law and equal before it. Immunity of some citizens negates this principle because it creates a situation where some individuals are above the law. Independence of the Judiciary, Trial by Jury, and Trial in open courts are all principles that uphold the rule of law.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>11", "subject": "Government", "year": "2008", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The principle of rule of law can be defined as", "images": [], "options": {"A": "supremacy of the national assembly", "B": "subordination of the legislature to the judiciary", "C": "supremacy of the law over all the people in the state", "D": "supreme authority of traditional rulers"}, "answer": "C", "explanation": "The principle of rule of law can be defined as the supremacy of the law over all the people in the state. This means that everyone, regardless of their status or position, is subject to the law and can be held accountable for their actions under the law. This principle is fundamental to any democratic society as it ensures equality, fairness, and justice.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>12", "subject": "Government", "year": "2008", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Which of the following is not a delegated legislation?", "images": [], "options": {"A": "Statutory instruments", "B": "Bye laws", "C": "Orders - in - Council", "D": "Public opinion"}, "answer": "D", "explanation": "Delegated legislation refers to laws or regulations that are made by an individual or body under powers given to them by an Act of Parliament. Statutory instruments, Bye laws, and Orders-in-Council are all examples of delegated legislation. Public opinion, however, is not a form of delegated legislation. It is a collective view or belief of the population of a state, and it does not have the force of law.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>13", "subject": "Government", "year": "2008", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Abuse of power by extra - legislative bodies set up by the legislature is checked through", "images": [], "options": {"A": "recall", "B": "general election", "C": "parliamentary control", "D": "impeachment"}, "answer": "C", "explanation": "The abuse of power by extra-legislative bodies set up by the legislature is checked through parliamentary control. Parliamentary control refers to the mechanisms, procedures and methods used by the parliament to control and supervise the executive and administrative actions of the government. This includes questioning ministers, debating on policies and passing of resolutions.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2008>14", "subject": "Government", "year": "2008", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The primary purpose of political participation is to seek", "images": [], "options": {"A": "for bold political offices", "B": "membership of  a pressure group", "C": "for judicial appointment", "D": "military training for politicians"}, "answer": "A", "explanation": "The primary purpose of political participation is to seek for bold political office as people who participate in politics aim at going into politics.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>15", "subject": "Government", "year": "2008", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "A constitution whose provisions are printed and contained in one document is a", "images": [], "options": {"A": "flexible constitution", "B": "written constitution", "C": "confederal constitution", "D": "unitary constitution"}, "answer": "B", "explanation": "A constitution whose provisions are printed and contained in one document is referred to as a written constitution. This is because all the laws, rules, and regulations are documented in a single document that can be referred to when needed.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2008>16", "subject": "Government", "year": "2008", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "A provision of a constitution is said to be entrenched when", "images": [], "options": {"A": "it is changed when the need arises", "B": "courts are not allowed to change it", "C": "it can be changed in the same way as ordinary law", "D": "a referendum is required for its amendment"}, "answer": "D", "explanation": "A provision of a constitution is said to be entrenched when a referendum is required for its amendment. This means that the provision is so important that it cannot be changed without the consent of a majority of the people. A referendum is a general vote by the electorate on a single political question which has been referred to them for a direct decision.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>17", "subject": "Government", "year": "2008", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "A constitutional amendment that is cumbersome is usually described as", "images": [], "options": {"A": "flexible", "B": "rigid", "C": "unitary", "D": "subtle"}, "answer": "B", "explanation": "Rigid constitution is that constitution which cannot be amended or changed so easily because of its stringent and cumbersome procedure of amendment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>18", "subject": "Government", "year": "2008", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET", "question": "The head of government in a parliamentary system of government is the", "images": [], "options": {"A": "President", "B": "Governor", "C": "Prime Minister", "D": "Chancellor"}, "answer": "C", "explanation": "Parliamentary system of government is one in which the head of state is different from head of government and where there is no strict separation of powers between the executive and the legislature. The head of government of a parliamentary system is the Prime Minister.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2008>19", "subject": "Government", "year": "2008", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "An advantage of the federal system of government is that it", "images": [], "options": {"A": "promotes even economic development", "B": "facilitates quick secession", "C": "is less expensive to operate", "D": "encourages unity in diversity"}, "answer": "D", "explanation": "A merit of federal  system is that it encourages of unity in diversity. It is expensive to operate, it does not facilitate quick succession and it does not promote even economic development.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>20", "subject": "Government", "year": "2008", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PRESIDENTIAL", "question": "The executive and ceremonial powers are exercised by the head of state in a", "images": [], "options": {"A": "unitary system", "B": "federal system", "C": "presidential system", "D": "confederal system"}, "answer": "C", "explanation": "Executive and Ceremonial powers are exercised by the head of state in a presidential system of government. Unitary, Federal and confederal do not occur in this scenario.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>21", "subject": "Government", "year": "2008", "type": "Objective", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : FEATURES AND PROBLEMS", "question": "Residual powers in a federation are exercised by the", "images": [], "options": {"A": "federal government", "B": "federal and state government", "C": "state government", "D": "federal and local government"}, "answer": "D", "explanation": "Presidential powers are usually exercised by the local government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>22", "subject": "Government", "year": "2008", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "When two or more parties join to form a government, we have a", "images": [], "options": {"A": "mixed government", "B": "united government", "C": "plural government", "D": "coalition government"}, "answer": "D", "explanation": "Coalition government is a system where two or more parties join to form a government. Mixed, United and Plural government are not fit for this purpose.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>23", "subject": "Government", "year": "2008", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "The leader of the opposition in a parliament belongs to the", "images": [], "options": {"A": "ruling party", "B": "majority party in the parliament", "C": "minority party in the parliament", "D": "electorate"}, "answer": "C", "explanation": "Minority party in the parliament is the leader of the opposition in a parliament.  The electorates are the citizens in a country.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>24", "subject": "Government", "year": "2008", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "Which of the following protects the liberty of individuals in the state?", "images": [], "options": {"A": "executive", "B": "legislature", "C": "judiciary", "D": "cabinet"}, "answer": "C", "explanation": "The judiciary is the branch of government that interprets the law and administers justice. It is responsible for protecting the liberty of individuals in the state. It does this by ensuring that laws are applied fairly and that individuals' rights are not violated. The judiciary acts as a check on the powers of the executive and legislative branches of government, preventing them from acting in a way that infringes on individual liberties.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2008>25", "subject": "Government", "year": "2008", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "The main obligation of a citizen is", "images": [], "options": {"A": "to register for election", "B": "allegiance to the state", "C": "to serve in the army", "D": "the right to life"}, "answer": "B", "explanation": "The main obligation of a citizen is to pledge allegiance to the state  -Right to life is a right of the citizens  -Registration of election is not a main obligation  - It is not compulsory to serve in the army.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2008>26", "subject": "Government", "year": "2008", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "A group that presents candidates for election is a", "images": [], "options": {"A": "political party", "B": "pressure group", "C": "vigilante group", "D": "co-operative group"}, "answer": "A", "explanation": "Political party is a group that presents candidates for elections.  - Pressure groups are associations that come together for a specific course  - Vigilante group are night guards  - Cooperative society is a voluntary organization.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2008>27", "subject": "Government", "year": "2008", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Which of these following is a type of political party?", "images": [], "options": {"A": "Anomic party", "B": "Mass party", "C": "Conglomerate party", "D": "Dynamic party"}, "answer": "B", "explanation": "Mass party is a type of political party that draws its members from all sections of the society and have wide membership and any individual wishing to join is allowed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>28", "subject": "Government", "year": "2008", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Which of the following is not a function of political parties?", "images": [], "options": {"A": "Presenting candidates for election", "B": "Uniting diverse views of different interest group", "C": "Forming government after election", "D": "Bringing the country's economic and social conditions under control"}, "answer": "D", "explanation": "Its function is not to bring the country's economic and social conditions under control as they do not have the power to do so.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>29", "subject": "Government", "year": "2008", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS", "question": "A state with more than one dominant political party of nearly equal strength is operating", "images": [], "options": {"A": "a mass party", "B": "a multi-party system", "C": "an elitist party", "D": "a charismatic party"}, "answer": "B", "explanation": "A multi-party system is a state with more than  one dominant political party of nearly equal strength.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>30", "subject": "Government", "year": "2008", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS", "question": "One - party system is a feature of", "images": [], "options": {"A": "democratic states", "B": "military regimes", "C": "republican states", "D": "communist state"}, "answer": "D", "explanation": "One-party system is an attribute of the communist state. The other options do not relate to one-party system.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2008>31", "subject": "Government", "year": "2008", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "A person who exercises franchise performs", "images": [], "options": {"A": "an executive function", "B": "a legal function", "C": "a civic duty", "D": "an  administrative duty"}, "answer": "C", "explanation": "Franchise refers to the right to vote in public elections. Therefore, a person who exercises franchise is performing a civic duty. A civic duty is a responsibility expected of citizens in a society. Voting in elections is one such responsibility, as it contributes to the democratic process.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2008>32", "subject": "Government", "year": "2008", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Which of the following does not relate to elections?", "images": [], "options": {"A": "Dividing the country into constituencies", "B": "Registering voters", "C": "Printing voter's card", "D": "Impeachment of the president"}, "answer": "D", "explanation": "Impeachment of president is not related to elections as 2/3 of the House can decide on the termination of the president's termination of appointments. Other options relate to election.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>33", "subject": "Government", "year": "2008", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "An organized group which influences government decisions is a", "images": [], "options": {"A": "political party", "B": "co-operative society", "C": "vigilante group", "D": "pressure group"}, "answer": "D", "explanation": "A pressure group is an organized group that seeks to influence government decisions without seeking to control government itself. They do this through lobbying, public campaigning, and other forms of advocacy. This is different from a political party which seeks to control government by winning elections, a co-operative society which is a voluntary association of individuals for their mutual, social, economic, and cultural benefit, and a vigilante group which is a self-appointed group of citizens who undertake law enforcement in their community without legal authority.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2008>34", "subject": "Government", "year": "2008", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "When  a pressure group is made up of people of the same profession, it is called", "images": [], "options": {"A": "a promotional group", "B": "an interest group", "C": "an occupational group", "D": "a religious group"}, "answer": "C", "explanation": "Occupational group relates to pressure groups made up of people with the same profession. Promotional group promotes the interest of the group. Interest and religious group relate to the churches.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2008>35", "subject": "Government", "year": "2008", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "Anonymity in the civil service means that an officer", "images": [], "options": {"A": "should work without complaint", "B": "should not be heard or seen", "C": "does not take praise or blame for his performance", "D": "remains in office indefinitely"}, "answer": "C", "explanation": "The convention of ministerial responsibility requires that ministers, not civil servants, accept responsibility to Parliament for their actions and those of their civil servants. This is guided by the Anonymity principle.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>36", "subject": "Government", "year": "2008", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "The main purpose of setting up public cooperation is to", "images": [], "options": {"A": "make profit for the government", "B": "create employment for all people in the state", "C": "improve production of national craft", "D": "provide essential services to the people at the minimal cost"}, "answer": "D", "explanation": "The other options are not associated to public corporation because they are set up mainly for the above reasons.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>37", "subject": "Government", "year": "2008", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "The British Minister responsible for the administration of British territories in the Crown Colony system was the", "images": [], "options": {"A": "Colonial Secretary", "B": "Secretary of State for the Colonies", "C": "Secretary of Treasury", "D": "Secretary of Native Affairs"}, "answer": "B", "explanation": "Secretary of State for the Colonies is the British minister responsible for the administration of British territories in the crown colony system.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2008>38", "subject": "Government", "year": "2008", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "The policy of Association was introduced in the French Colonies by", "images": [], "options": {"A": "Jacque Chirac", "B": "Charles De Gaulle", "C": "Francois Mitterand", "D": "Nicholas Sarkozy"}, "answer": "B", "explanation": "Charles De Gaulle proposed the policy of assimilation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2008>39", "subject": "Government", "year": "2008", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "The headquarter of the French Colonial government in West Africa was", "images": [], "options": {"A": "Dakar", "B": "Abidjan", "C": "Cotonou", "D": "Niamey"}, "answer": "A", "explanation": "The headquarters of the French Colonial government in West Africa was in Dakar, Senegal. Dakar was the capital of French West Africa from 1902 to 1959. French West Africa was a federation of eight French colonial territories in Africa: Mauritania, Senegal, French Sudan (now Mali), French Guinea, Ivory Coast, Upper Volta (now Burkina Faso), Dahomey (now Benin) and Niger.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>40", "subject": "Government", "year": "2008", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "Which of the following was a nationalist organization?", "images": [], "options": {"A": "People's Redemption Organization", "B": "National Congress of British West Africa", "C": "West African People's League", "D": "National Council of African people"}, "answer": "B", "explanation": "The National Congress of British West Africa (NCBWA) was formed in Accra, Gold Coast (now Ghana) in 1920 by the educated elites from English-speaking West African colonies led by Mr. Joseph Casely Ephraim Hayford of Ghana and Dr. Akinwande Savage of Nigeria.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>41", "subject": "Government", "year": "2008", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "Colonial constitutions were always", "images": [], "options": {"A": "confederal", "B": "federal", "C": "written", "D": "flexible"}, "answer": "D", "explanation": "Colonial constituencies were always flexible i.e they could easily be amended.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>42", "subject": "Government", "year": "2008", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "The highest court of appeal under the independence constitution of the West African states was the", "images": [], "options": {"A": "District Tribunal", "B": "Country Court", "C": "Judicial Committee of Privy Council", "D": "Magistrate Court"}, "answer": "C", "explanation": "The highest court of appeal under the independence constitution of the West African states was the Judicial Committee of Privy Council. The Judicial Committee of the Privy Council is the highest court of appeal for several independent Commonwealth countries, the UK overseas territories, and the British Crown dependencies. It has jurisdiction over civil and criminal appeals from the courts of those territories.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2008>43", "subject": "Government", "year": "2008", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "The official members in the Legislative Councils of the British Colonial Government were", "images": [], "options": {"A": "all Africans", "B": "all white", "C": "minority white", "D": "Majority Africans"}, "answer": "B", "explanation": "They were all whites since it was under the British Colonial Government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>44", "subject": "Government", "year": "2008", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "The pre-independence political parties in British West Africa were largely concerned about", "images": [], "options": {"A": "settling themselves with political offices", "B": "prolonged colonialism in Africa", "C": "adoption of fascism", "D": "political emancipation of affairs"}, "answer": "D", "explanation": "The pre-independence political parties in British West Africa were largely concerned about political emancipation of affairs. They were focused on gaining independence from colonial rule and establishing self-governance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>45", "subject": "Government", "year": "2008", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "Military government rule by", "images": [], "options": {"A": "laws", "B": "proclamations", "C": "decrees", "D": "bye laws"}, "answer": "C", "explanation": "Military governments typically rule by decrees. A decree is an official order issued by a legal authority, in this case, the military government. It has the force of law and is often used in situations where the normal legislative process is bypassed, such as during a military regime.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2008>46", "subject": "Government", "year": "2008", "type": "Objective", "topic": "FOREIGN POLICIES : ADVANTAGES AND DISADVANTAGES", "question": "Which of the following is an advantage a country derives from international relations", "images": [], "options": {"A": "Peaceful settlement of conflicts with nations", "B": "Helping their citizens to sort citizenship of other countries", "C": "Allowing the government to annex more territories", "D": "Increase in population growth"}, "answer": "A", "explanation": "One of the advantages a country derives from international relations is the peaceful settlement of conflicts with other nations. International relations involve diplomatic engagement and negotiation, which can lead to peaceful resolutions of disputes and conflicts. This helps to maintain peace and stability, which is beneficial for the country's development and prosperity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>47", "subject": "Government", "year": "2008", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "Which of the following countries is a member of the Economic Community of West African states (ECOWAS)?", "images": [], "options": {"A": "Cong D.R", "B": "Libya", "C": "Kenya", "D": "Burkina Faso"}, "answer": "D", "explanation": "\"Burkina-Faso'\" is the answer. The Economic Community of West African States (ECOWAS) is a regional group of fifteen West African countries. Founded on 28 May 1975, with the signing of the Treaty of Lagos, its mission is to promote economic integration across the region.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2008>48", "subject": "Government", "year": "2008", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "Which of the following countries was a member of the Monrovia group?", "images": [], "options": {"A": "Chad", "B": "Niger", "C": "Cameroon", "D": "Sierra Leone"}, "answer": "D", "explanation": "The Monrovia Group was a group of African states which were in favor of a gradual approach to African unity and were opposed to the immediate political federation advocated by the Casablanca Group. Sierra Leone was a member of the Monrovia Group. Chad, Niger, and Cameroon were not members of this group.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>49", "subject": "Government", "year": "2008", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "Which of the organs of the United Nations Organizations (UNO) is responsible for appointing staff of the organization?", "images": [], "options": {"A": "Security", "B": "International court of Justice", "C": "The Secretariat", "D": "The Economic and Social Council"}, "answer": "C", "explanation": "The Secretariat is one of the six main organs of the United Nations, led by the Secretary-General. It is responsible for providing studies, information, and facilities needed by United Nations bodies for their meetings. It also carries out tasks as directed by the UN Security Council, the UN General Assembly, the UN Economic and Social Council, and other UN bodies. The Secretariat consists of departments and offices with a total staff, drawn from most of the member states, of about 44,000 international civil servants worldwide. Therefore, it is responsible for appointing staff of the organization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2008>50", "subject": "Government", "year": "2008", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The Organ of the UNO responsible for the affairs of the mandated territories was the", "images": [], "options": {"A": "International Court of Justice", "B": "Trusteeship Council", "C": "Economic and Social Council", "D": "General Assembly"}, "answer": "B", "explanation": "Trusteeship Council is the organ of the UNO responsible for the affairs of the mandated territories.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2009>1", "subject": "Government", "year": "2009", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS A PROCESS OR ART OR GOVERNING", "question": "Government as a process or art of governing means", "images": [], "options": {"A": "voting at general elections", "B": "orders of the judiciary and police", "C": "activities of political parties and pressure groups", "D": "activities of making and enforcing laws of the state"}, "answer": "D", "explanation": "Government as an act of governing implies a body vested with the power and authority for maintaining security, peace and stability by making and enforcing conventional and fundamental laws in a given state/society.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2009>2", "subject": "Government", "year": "2009", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : POLITICAL PARTICIPATION", "question": "Government can be made responsible and accountable to its citizen through the following methods except", "images": [], "options": {"A": "periodic change of government", "B": "demonstration", "C": "political education", "D": "public opinion"}, "answer": "B", "explanation": "Demonstration is not a method because it is a tool used by trade union against employers or government for better welfare. Other options are methods to make government responsible and accountable.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>3", "subject": "Government", "year": "2009", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Power can be described as", "images": [], "options": {"A": "ability of the legislature to delegate its rights of law making to another body", "B": "ability of the executive to encourage pressure groups to go on strike", "C": "capacity of the government to encourage communities to embark on self help projects", "D": "capacity to compel or influence others to act in a certain way"}, "answer": "D", "explanation": "Power is the ability to exert influence and to compel obedience. Hence, it is the capacity to compel or influence others to act in a certain way. The other options do not give a definition of power in the right sense.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>4", "subject": "Government", "year": "2009", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Nazism was practiced  in", "images": [], "options": {"A": "Britain under Churchill", "B": "the United States under Woodrow Wilson", "C": "Germany under Adolf Hitler", "D": "Spain under General Francoi."}, "answer": "C", "explanation": "Nazism is a brand of totalitarianism practiced in Germany under Adolf Hitler between 1933 and 1945. It is a political idealogy.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2009>5", "subject": "Government", "year": "2009", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Fascism can best be described as", "images": [], "options": {"A": "government of a state controlled by a multi-party", "B": "system of government controlled by the armed forces", "C": "existence of a single party dictatorship with a life president", "D": "existence of an elected president for a fixed term"}, "answer": "C", "explanation": "Fascism is a philosophy, principle and organization of the aggressive nationalist and anti-communist dictatorship.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2009>6", "subject": "Government", "year": "2009", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Totalitarianism implies the control of government by", "images": [], "options": {"A": "coalition parties", "B": "parties in succession", "C": "a few elite", "D": "a dictator"}, "answer": "D", "explanation": "Totalitarianism implies the control of government by a Dictator ( Adolf Hitler as the case of Germany).", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>7", "subject": "Government", "year": "2009", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following countries practised totalitarian system of government before the second war?", "images": [], "options": {"A": "Britain and France", "B": "Germany and Italy", "C": "The United States and Canada", "D": "Turkey and India"}, "answer": "B", "explanation": "Totalitarianism is a political system in which the state holds total authority over the society and seeks to control all aspects of public and private life. Before the Second World War, Germany under Adolf Hitler and Italy under Benito Mussolini practiced totalitarianism. They controlled all aspects of life, including politics, the economy, society, and culture, and did not tolerate any form of opposition.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2009>8", "subject": "Government", "year": "2009", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The subordinate class of people in the social hierarchy of feudal system is the", "images": [], "options": {"A": "lords", "B": "vassals", "C": "nobles", "D": "armed forces"}, "answer": "B", "explanation": "In the feudal system, vassals were the subordinate class of people. The feudal system was a social and economic system in the Middle Ages in Europe, where the nobility held lands from the Crown in exchange for military service, and vassals were tenants of the nobles. The vassals were obliged to serve the lords in war, in the court, and in other ways. They were not free and were bound to their lords by a strong sense of loyalty and duty.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>9", "subject": "Government", "year": "2009", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A common language is one of the attributes of a", "images": [], "options": {"A": "government", "B": "society", "C": "nation", "D": "state"}, "answer": "C", "explanation": "A common language is one of the attributes of a nation. A nation is a large body of people united by common descent, history, culture, or language, inhabiting a particular country or territory. Therefore, a common language is a characteristic of a nation, not a government, society, or state.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2009>10", "subject": "Government", "year": "2009", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The doctrine of the rule of law is credited to", "images": [], "options": {"A": "J.J Rousseau", "B": "John Locke", "C": "A.V Dicey", "D": "Thomas Hobbes"}, "answer": "C", "explanation": "Rule of law is associated with A.V Dicey. The rule of law is the legal principle that law should govern a nation, as opposed to being governed by arbitrary decisions of individual government officials.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>11", "subject": "Government", "year": "2009", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Equality before the law is a principle of", "images": [], "options": {"A": "separation of power", "B": "checks and balances", "C": "collective responsibility", "D": "rule of law"}, "answer": "D", "explanation": "Equality before the law is a principle of rule of law which implies that everyone is equal before the law.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>12", "subject": "Government", "year": "2009", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Which of the following is a limitation to the doctrine of rule of law?", "images": [], "options": {"A": "Diplomatic immunity", "B": "Private ownership of property", "C": "Right of enlightened citizens", "D": "Political authority of the executive"}, "answer": "A", "explanation": "Diplomatic immunity which gives privileges to political office holders is a limitation to the doctrine of rule of law.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2009>13", "subject": "Government", "year": "2009", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Which of the following principles is emphasized among the three organs of government in a presidential system?", "images": [], "options": {"A": "Separation of powers", "B": "Centralization", "C": "Delegated legislation", "D": "Political participation"}, "answer": "A", "explanation": "In a presidential system, the principle of 'Separation of powers' is emphasized. This principle ensures that the three organs of government (Executive, Legislature, and Judiciary) are independent of each other and have separate powers. This is to prevent the abuse of power and to ensure a balance in the system of governance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>14", "subject": "Government", "year": "2009", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The principle of checks and balances is aimed at", "images": [], "options": {"A": "allowing for a fusion of power among the organs of government", "B": "preventing any organs of government from performing its duties", "C": "allowing the total independence of the three organs of government", "D": "preventing any organ of government from becoming too powerful"}, "answer": "D", "explanation": "Checks and Balances is a principle aimed at preventing any organ of government from becoming too powerful.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>15", "subject": "Government", "year": "2009", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "A true representative government is one that", "images": [], "options": {"A": "resists freedom of movement", "B": "recognizes unlimited franchise", "C": "observes customs and traditions", "D": "allows devolution of governmental powers"}, "answer": "D", "explanation": "A true representative government is one that allows devolution of governmental powers. Devolution is the statutory delegation of powers from the central government of a sovereign state to govern at a subnational level, such as a regional or local level. It is a form of administrative decentralization. Devolved territories have the power to make legislation relevant to the area.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>16", "subject": "Government", "year": "2009", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "Which of the following is not a  main source of constitution?", "images": [], "options": {"A": "Judicial precedents", "B": "Legislative decisions", "C": "Previous constitutions", "D": "Public deliberations"}, "answer": "D", "explanation": "Public deliberations are not a main source of constitution. The main sources of constitution are judicial precedents, legislative decisions, and previous constitutions. Public deliberations can influence the constitution, but they are not a main source. A constitution is a set of fundamental principles or established precedents according to which a state or other organization is governed.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2009>17", "subject": "Government", "year": "2009", "type": "Objective", "topic": "CONSTITUTIONS : TYPES AND FEATURES", "question": "A constitution whose procedure  for amendment is same as  that of making an ordinary law is same as", "images": [], "options": {"A": "a unitary constitution", "B": "an unwritten constitution", "C": "a flexible constitution", "D": "a confederal constitution"}, "answer": "C", "explanation": "A flexible constitution is one whose procedures for amendment are the same as that of making an ordinary law. This means that it can be changed or modified without any special procedure. This is different from a rigid constitution which requires a special procedure for its amendment. A unitary constitution refers to a system where all powers are vested in a central government, an unwritten constitution is one that is not codified in a single document, and a confederal constitution is a union of states with a weak central authority.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>18", "subject": "Government", "year": "2009", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PRESIDENTIAL", "question": "A government system where the head of state is distinct from the head of government is called", "images": [], "options": {"A": "presidential", "B": "unitary", "C": "parliamentary", "D": "republican"}, "answer": "C", "explanation": "A parliamentary system of government is one where the head of state is distinct from the head of government. In such a system, the head of state is usually a monarch or a president with ceremonial powers, while the head of government is the prime minister who exercises executive powers. In a presidential system, the head of state is also the head of government. A unitary system is one where all powers are vested in a central government, and a republican system is one where the head of state is elected or appointed for a specific term.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2009>19", "subject": "Government", "year": "2009", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : REPUBLICAN", "question": "A system of government in which the head of state is elected for a fixed term of office is known as", "images": [], "options": {"A": "republican", "B": "monarchical", "C": "confederal", "D": "federal"}, "answer": "A", "explanation": "A republican system of government is one in which the head of state is elected for a fixed term of office. In this system, the head of state is usually a president. The other options do not fit the description given in the question. A monarchical system is one where the head of state is a king or queen, and their position is usually hereditary, not elected. A confederal system is a union of sovereign states, each of which retains its sovereignty. A federal system is a type of government where power is divided between a central government and individual states or provinces.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>20", "subject": "Government", "year": "2009", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : MONARCHICAL", "question": "The type of government that is headed by a king or a queen is called?", "images": [], "options": {"A": "monarchical", "B": "federal", "C": "presidential", "D": "republican"}, "answer": "A", "explanation": "A monarchical system of government is one that is headed by a king or a queen. The monarch's position is usually hereditary and not elected. The other options do not fit the description given in the question. A federal system is a type of government where power is divided between a central government and individual states or provinces. A presidential system is a democratic and republican system where a head of government leads an executive branch that is separate from the legislative branch. A republican system of government is one in which the head of state is elected for a fixed term of office.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2009>21", "subject": "Government", "year": "2009", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The principle which require members of the executive to resign when a governmental proposal is defeated in the parliament is known as", "images": [], "options": {"A": "delegated legislation", "B": "individual responsibility", "C": "devolutionary powers", "D": "collective responsibility"}, "answer": "D", "explanation": "The principle of collective responsibility is one that requires the executive to resign when a governmental proposal is defeated in a parliament.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>22", "subject": "Government", "year": "2009", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : REPUBLICAN", "question": "Which of the following systems of government is more responsive to the public opinion?", "images": [], "options": {"A": "Oligarchy", "B": "Republicanism", "C": "Plutocracy", "D": "Monarchy"}, "answer": "B", "explanation": "Republicanism is more responsive to public opinion. This is because in a republic, the government is considered a public matter and political power is supposed to remain with the people. The people elect representatives to exercise power for them. Therefore, the government is more likely to respond to public opinion in order to maintain the support of the people.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>23", "subject": "Government", "year": "2009", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "A federal system of government is adopted in a state with", "images": [], "options": {"A": "a single ethnic group", "B": "small population with large expense of land", "C": "weak economic base", "D": "marked inequalities among the component units"}, "answer": "D", "explanation": "Marked inequalities among the component units give rise to the adoption of a federal system of government in a state.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2009>24", "subject": "Government", "year": "2009", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : REPUBLICAN", "question": "A system of government in which government positions are acquired through popular elections is known as", "images": [], "options": {"A": "fascism", "B": "confederalism", "C": "monarchy", "D": "republicanism"}, "answer": "D", "explanation": "Republicanism is a system of government in which government positions are acquired through popular elections.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>25", "subject": "Government", "year": "2009", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : MONARCHICAL", "question": "A monarchy refers to", "images": [], "options": {"A": "getting political office by election", "B": "capturing political office by force", "C": "selection into office by a Council of State", "D": "hereditary right to a political office"}, "answer": "D", "explanation": "A monarchy refers to a form of government where a person, the monarch, is head of state for life or until abdication. The political legitimacy and authority of the monarch may vary from purely symbolic (crowned republic), to restricted (constitutional monarchy), to fully autocratic (absolute monarchy), and can expand across the domains of the executive, legislative and judicial. The option 4 'hereditary right to a political office' is correct because in a monarchy, the position is often inherited through a family line.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2009>26", "subject": "Government", "year": "2009", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "The head of judicial arm of government is known as", "images": [], "options": {"A": "Chief Justice", "B": "Attorney-General", "C": "a judge", "D": "an advocate"}, "answer": "A", "explanation": "The head of the judicial arm of government is known as the Chief Justice. The Chief Justice is the presiding member of a supreme court in any country with a justice system based on English common law, such as the Supreme Court of Bangladesh, the Supreme Court of Canada, the Supreme Court of Singapore, the Court of Final Appeal of Hong Kong, the Supreme Court of Japan, the Supreme Court of India, the Supreme Court of Pakistan, the Supreme Court of Nigeria, the Supreme Court of Nepal, the Constitutional Court of South Africa, the Supreme Court of Ireland, the Supreme Court of New Zealand, and the Supreme Court of the United States. In many other countries, the head of the judicial arm is known as the President of the Supreme Court, or similar title.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2009>27", "subject": "Government", "year": "2009", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS A PROCESS OR ART OR GOVERNING", "question": "The implementation of government polices is carried out by the", "images": [], "options": {"A": "Legislature", "B": "Judiciary", "C": "Ombudsman", "D": "Executive"}, "answer": "D", "explanation": "The implementation of government policies is carried out by the Executive branch of government. The Executive branch is responsible for implementing, enforcing, and administering laws and public policies enacted and established by the legislative branch. The Legislature makes the laws, the Judiciary interprets the laws, and the Ombudsman is an official appointed to investigate individuals' complaints against maladministration, especially that of public authorities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>28", "subject": "Government", "year": "2009", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY", "question": "A system where there is only one legislative chamber parliament is referred to as", "images": [], "options": {"A": "unicameral legislature", "B": "confederal legislature", "C": "monarchical legislature", "D": "bi-cameral legislature"}, "answer": "A", "explanation": "A system whereby there is only one legislative chamber parliament is called 'Unicameral legislature'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>29", "subject": "Government", "year": "2009", "type": "Objective", "topic": "CITIZENSHIP : MEANING AND MODE OF ACQUISITION", "question": "Citizenship can be acquired through", "images": [], "options": {"A": "renouncement", "B": "repudiation", "C": "birth", "D": "reference"}, "answer": "C", "explanation": "Citizenship can be acquired through birth. This is known as jus soli or right of soil, where a person is considered a citizen of a country if they are born within its territory, regardless of the nationality of their parents.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2009>30", "subject": "Government", "year": "2009", "type": "Objective", "topic": "CITIZENSHIP : MEANING AND MODE OF ACQUISITION", "question": "Residing in an area for a specified period of years is one of the basic conditions to acquire citizenship through", "images": [], "options": {"A": "marriage", "B": "honour", "C": "naturalization", "D": "birth"}, "answer": "C", "explanation": "Residing in an area for a specific period of years is one basic condition to acquire citizenship through naturalization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>31", "subject": "Government", "year": "2009", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "Civil rights in a country are enjoyed by", "images": [], "options": {"A": "citizens", "B": "aliens", "C": "prisoners", "D": "refugees"}, "answer": "A", "explanation": "Civil rights are the rights of citizens to political and social freedom and equality. They are enjoyed by citizens of a country, not aliens, prisoners, or refugees. Aliens, prisoners, and refugees have certain rights, but they do not enjoy the full civil rights that citizens do.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2009>32", "subject": "Government", "year": "2009", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Vibrant opposition parties in parliament help to", "images": [], "options": {"A": "threaten democracy", "B": "strengthen democracy", "C": "safeguard independence", "D": "protect sovereignty"}, "answer": "B", "explanation": "Vibrant opposition parties in parliament help to strengthen democracy. They do this by providing a check and balance to the ruling party, ensuring that power is not concentrated in one place, and that the interests of all citizens are represented. This strengthens the democratic process and ensures that it functions effectively.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>33", "subject": "Government", "year": "2009", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "The practice of voting in absentia through an authorized representative is", "images": [], "options": {"A": "Bye-election", "B": "delegated election", "C": "voting by proxy", "D": "quota voting"}, "answer": "C", "explanation": "Voting by proxy refers to the practice of voting in absentia through an authorized representative. This is when a person is unable to physically attend the voting process, they can delegate their voting power to another person to vote on their behalf.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>34", "subject": "Government", "year": "2009", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : ELECTORAL MANAGEMENT BODY", "question": "Which of the following is a function of an electoral commission?", "images": [], "options": {"A": "Educating the public on electoral policies", "B": "Registration of voters for election", "C": "Sharing of political powers among parties", "D": "Provision of essential services"}, "answer": "B", "explanation": "The function of an electoral commission includes the registration of voters for an election. This is a crucial part of the electoral process as it ensures that only eligible citizens are allowed to vote. The electoral commission is responsible for maintaining an updated and accurate voters' register.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>35", "subject": "Government", "year": "2009", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "A feature of pressure groups is that members", "images": [], "options": {"A": "oppose the government", "B": "are in the same labour union", "C": "do not believe in dialogue", "D": "have similar interests"}, "answer": "D", "explanation": "Pressure groups are organizations that try to influence public policy or legislation. They are characterized by the fact that their members have similar interests. They do not necessarily oppose the government or belong to the same labor union, and they often use dialogue as a means of achieving their goals.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2009>36", "subject": "Government", "year": "2009", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "Measuring public opinion becomes highly expensive when", "images": [], "options": {"A": "a referendum is held", "B": "public opinion poll is conducted", "C": "public debates are held", "D": "mass media reports are evaluated"}, "answer": "B", "explanation": "Public opinion polls are a method of measuring public opinion by asking a sample of the population specific questions. This process can be highly expensive due to the costs associated with survey design, data collection, and data analysis. While referendums, public debates, and mass media reports can also be used to gauge public opinion, they are not inherently expensive in the same way as conducting a public opinion poll.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>37", "subject": "Government", "year": "2009", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "The non-involvement of civil servants in partisan politics is related to", "images": [], "options": {"A": "anonymity", "B": "neutrality", "C": "permanence", "D": "impartiality"}, "answer": "B", "explanation": "The non-involvement of civil servants in partisan politics is related to neutrality. Neutrality in this context refers to the principle that civil servants, as employees of the state, should not engage in political activities or show political bias in their work. This is to ensure that the civil service remains impartial and serves all citizens equally, regardless of their political affiliations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>38", "subject": "Government", "year": "2009", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "A court can declare any action of a local government that is outside its area of jurisdiction as", "images": [], "options": {"A": "ultra vires", "B": "bill of rights", "C": "certiorari", "D": "habeas corpus"}, "answer": "A", "explanation": "Ultra vires is a situation whereby the court declares any action of a local government outside its jurisdiction.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2009>39", "subject": "Government", "year": "2009", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Law made by the legislative Council during the colonial period in British West African were called", "images": [], "options": {"A": "acts of parliament", "B": "delegated legislation", "C": "ordinances", "D": "bye-laws"}, "answer": "C", "explanation": "Ordinances are laws made by the legislative council during the colonial period in British West Africa.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>40", "subject": "Government", "year": "2009", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "The French Colonial policy of Assimilation was first applied in", "images": [], "options": {"A": "Conarky, Goree, Bamako, and St. Louis", "B": "Dakar, St.Louis, Goree, Conarki", "C": "Goree, Dakar, Bamako and Abidjan", "D": "St.Louis, Dakar, Goree, and Rufisque"}, "answer": "D", "explanation": "The French Colonial policy of Assimilation was first applied in St.Louis, Dakar, Goree, and Rufisque. The policy of Assimilation was a French colonial policy that aimed to transform colonial subjects into French citizens by teaching them the French language and French customs. This policy was first applied in the four communes of Senegal: St.Louis, Dakar, Goree, and Rufisque.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2009>41", "subject": "Government", "year": "2009", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "One of the criticisms against the policy of Assimilation was that it", "images": [], "options": {"A": "did not recognize African culture as good enough", "B": "granted French citizenship to all the people in Senegal", "C": "ignored the educated elite", "D": "recognized the traditional rulers"}, "answer": "A", "explanation": "The policy of Assimilation was a colonial policy adopted by the French, which aimed at turning the people in their colonies into Frenchmen by educating them in the French language and culture. One of the criticisms against this policy was that it did not recognize African culture as good enough. It was seen as a way of erasing African culture and imposing French culture on the people.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>42", "subject": "Government", "year": "2009", "type": "Objective", "topic": "NATIONALISM : NATIONALISM: MEANING, FACTORS AND EFFECTS.", "question": "Nationalism in British West Africa aimed at", "images": [], "options": {"A": "gaining independence", "B": "abolishing chieftaincy", "C": "collecting revenue", "D": "recognized the traditional rulers"}, "answer": "A", "explanation": "Nationalism in British West Africa was a political ideology that emerged in the late 19th and early 20th centuries among Africans. It was a movement aimed at gaining independence from colonial rule. The nationalists sought to free their countries from the control of the British and establish self-rule.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>43", "subject": "Government", "year": "2009", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "One of the demerits of pre-second world war constitutions of West African Colonies was the", "images": [], "options": {"A": "domination of the legislative council by official members", "B": "domination of the legislative council by un-official members", "C": "introduction of direct rules in the colonies", "D": "exclusion of traditional rulers from the government"}, "answer": "A", "explanation": "A demerit of the pre-second world war was the domination of the legislative council by official members.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>44", "subject": "Government", "year": "2009", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "The first military coup d'etat in West Africa was staged in", "images": [], "options": {"A": "The Gambia", "B": "Niger", "C": "Nigeria", "D": "Togo"}, "answer": "D", "explanation": "The first military coup d'etat in West Africa was staged in Togo in 1963. A coup d'etat is a sudden and decisive action in politics, especially one resulting in a change of government illegally or by force. In this case, Togo's President Sylvanus Olympio was assassinated and the military took control of the government.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2009>45", "subject": "Government", "year": "2009", "type": "Objective", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "Which of the following does not influence the foreign policy of a country?", "images": [], "options": {"A": "Historical and cultural matters", "B": "Ideological fathers", "C": "Economic factors", "D": "Intra-party conflicts"}, "answer": "D", "explanation": "Foreign policy of a country is influenced by a variety of factors including historical and cultural matters, ideological beliefs, and economic factors. However, intra-party conflicts within a country do not directly influence the foreign policy. Foreign policy is a national issue and is usually not affected by internal party politics.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>46", "subject": "Government", "year": "2009", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "The highest organ of the Economic Community of West African States (ECOWAS) is the", "images": [], "options": {"A": "Council of Ministers", "B": "Secretariat", "C": "Tribunal", "D": "Authority of Heads of States and Government"}, "answer": "D", "explanation": "The highest organ of the Economic Community of West African States (ECOWAS) is the Authority of Heads of States and Government. This body is responsible for the general direction and control of the Community and takes all decisions necessary to achieve the objectives of the Community. The Council of Ministers, Secretariat, and Tribunal are all important organs of ECOWAS, but they are not the highest organ.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>47", "subject": "Government", "year": "2009", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "Which of the following countries is a founding member of the Commonwealth?", "images": [], "options": {"A": "Zimbabwe", "B": "Gambia", "C": "India", "D": "South Africa"}, "answer": "C", "explanation": "India is a founding member of the Commonwealth. The Commonwealth is a political association of 54 member states, nearly all of which are former territories of the British Empire. The four countries that founded the Commonwealth are: United Kingdom, Canada, Australia, and India.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>48", "subject": "Government", "year": "2009", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "Which of the following African countries participated of the United Nations Organizations (UNO) charter in 1945?", "images": [], "options": {"A": "Ethiopia", "B": "Tunisia", "C": "Ghana", "D": "Nigeria"}, "answer": "A", "explanation": "Ethiopia was one of the 51 original members of the United Nations that signed the Charter in 1945. The United Nations (UN) is an international organization founded in 1945. It is composed of member states that are sovereign countries. The UN Charter is the treaty that established the United Nations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>49", "subject": "Government", "year": "2009", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The Economic and Social Council of the United Nations Organizations (UNO) is made up of", "images": [], "options": {"A": "25 members", "B": "26 members", "C": "27 members", "D": "28 members"}, "answer": "C", "explanation": "The Economic and Social Council (ECOSOC) of the United Nations (UN) is made up of 54 members. However, none of the options provided in the question matches this correct answer. Therefore, the closest option to the correct answer is 27 members. ECOSOC is one of the six main organs of the UN, responsible for coordinating the economic, social, and related work of 15 UN specialized agencies, their functional commissions and five regional commissions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2009>50", "subject": "Government", "year": "2009", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The United Nations Secretary-General is appointed for", "images": [], "options": {"A": "Five years term", "B": "four years term", "C": "three years term", "D": "single year term"}, "answer": "A", "explanation": "The United Nations Secretary-General is appointed for a five-year term. This is in accordance with the UN Charter, which allows the Secretary-General to be appointed for a term of five years, and can be reappointed. The Secretary-General's selection is made by the General Assembly, upon the recommendation of the Security Council. The Secretary-General is the chief administrative officer of the UN, and plays a crucial role in peacekeeping, conflict resolution, and administrative issues within the organization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>1", "subject": "Government", "year": "2010", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN ACADEMIC FIELD OF STUDY – REASONS FOR STUDYING GOVERNMENT.", "question": "Government as a subject refers to the study of", "images": [], "options": {"A": "territorial expansion", "B": "political leaders", "C": "the various nations of the world", "D": "the institution of the state"}, "answer": "D", "explanation": "Government as a subject refers to the study of the institution of the state. It involves understanding the structure, functions, and operations of the various arms of government and how they interact with each other and with the citizens. It does not primarily focus on territorial expansion, political leaders, or the various nations of the world.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2010>2", "subject": "Government", "year": "2010", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN INSTITUTION OF THE STATE:", "question": "Government is distinguished from the state because it", "images": [], "options": {"A": "can be changed periodically", "B": "does not operate in any defined territory", "C": "is a loosely organized structure", "D": "enforces its will on the people of the state"}, "answer": "A", "explanation": "Government is distinguished from the state because it can be changed periodically. The government refers to the group of people and institutions that make and enforce laws for a society or country at a particular time. It can be changed through elections, revolutions, or other means. The state, on the other hand, is a political entity with a high degree of sovereignty, consisting of institutions that govern the population residing within its borders. It remains constant over time, regardless of changes in government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>3", "subject": "Government", "year": "2010", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A government is legitimate if it", "images": [], "options": {"A": "comes to power through a coup d'etat", "B": "is not oppressive", "C": "provides social services for the people", "D": "has the mandate of the people to rule"}, "answer": "D", "explanation": "A government is considered legitimate if it has the mandate of the people to rule. This means that the government has been given the authority to govern by the people, usually through a democratic election process. While providing social services and not being oppressive are desirable qualities in a government, they do not necessarily make a government legitimate. A coup d'etat, on the other hand, is a forceful takeover of government, which is generally considered illegitimate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>4", "subject": "Government", "year": "2010", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A sovereign power over a number of people in a specific geographical area is called", "images": [], "options": {"A": "society", "B": "region", "C": "state", "D": "nation"}, "answer": "C", "explanation": "A sovereign power over a number of people in a specific geographical area is called a state. A state is a political entity that has a centralized government that maintains a monopoly on the legitimate use of force within a certain geographical territory. A society is a group of individuals involved in persistent social interaction, or a large social group sharing the same spatial or social territory. A region is a specific area within a country or city, while a nation refers to a large body of people united by common descent, history, culture, or language, inhabiting a particular country or territory.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2010>5", "subject": "Government", "year": "2010", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Absence of government in a state is referred to as", "images": [], "options": {"A": "anarchy", "B": "confusion", "C": "coup d'etat", "D": "instability"}, "answer": "A", "explanation": "The absence of government in a state is referred to as anarchy. Anarchy is a state of society without government or law. It is a situation where there is no public authority and everyone does as they please. This is different from confusion, coup d'etat, and instability which are states of disorder, a sudden decisive exercise of force in politics; especially the violent overthrow or alteration of an existing government by a small group, and lack of steadiness or consistency respectively.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2010>6", "subject": "Government", "year": "2010", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A situation where all the citizens meet in an open place to govern the state is called", "images": [], "options": {"A": "direct democracy", "B": "electoral college", "C": "representative democracy", "D": "guided democracy"}, "answer": "A", "explanation": "A situation where all the citizens meet in an open place to govern the state is called direct democracy. Direct democracy is a form of democracy in which people decide on policy initiatives directly. This is different from electoral college, representative democracy, and guided democracy which are a body of people representing the states of the US, who formally cast votes for the election of the president and vice president, a type of democracy founded on the principle of elected officials representing a group of people, and a form of democracy which functions in accordance with the principles of democracy but is subject to the guidance of an individual or group respectively.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2010>7", "subject": "Government", "year": "2010", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A system of government in which the political power is vested in the elected representative is known as", "images": [], "options": {"A": "oligarchy", "B": "democracy", "C": "feudalism", "D": "fascism"}, "answer": "B", "explanation": "Democracy is a system of government in which the political power is vested in the elected representatives.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>8", "subject": "Government", "year": "2010", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Sovereignty implies all the following except", "images": [], "options": {"A": "the highest authority in a state", "B": "a state of political independence", "C": "unlimited powers of a state to make and enforce laws", "D": "the supremacy of political powers"}, "answer": "D", "explanation": "Sovereignty implies the highest authority in a state, a state of political independence, and unlimited powers of a state to make and enforce laws. However, it does not imply the supremacy of political powers. Sovereignty is the full right and power of a governing body over itself, without any interference from outside sources or bodies. In political theory, sovereignty is a substantive term designating supreme legitimate authority over some polity. The concept of sovereignty has been discussed throughout history, and is still actively debated. Its definition, concept, and application has changed throughout, especially during the Age of Enlightenment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>9", "subject": "Government", "year": "2010", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Popular sovereignty is located in the", "images": [], "options": {"A": "military", "B": "police", "C": "electorate", "D": "opinion leader"}, "answer": "C", "explanation": "Popular sovereignty is the principle that the authority of a state and its government are created and sustained by the consent of its people, through their elected representatives. In this case, the 'people' are represented by the 'electorate', who are the individuals eligible to vote. Therefore, popular sovereignty is located in the electorate.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2010>10", "subject": "Government", "year": "2010", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A system of government in which the leader exercises absolute power and allows no opposition is called", "images": [], "options": {"A": "totalitarianism", "B": "capitalism", "C": "communism", "D": "socialism"}, "answer": "A", "explanation": "Totalitarianism is a system of government in which the leader exercises absolute power and allows no opposition.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2010>11", "subject": "Government", "year": "2010", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following is a basic component of political culture?", "images": [], "options": {"A": "Cultural development", "B": "Cultural design", "C": "Cultural display", "D": "Cognitive orientation"}, "answer": "D", "explanation": "Political culture refers to the attitudes, beliefs, values, and symbols that influence the behavior of the political system. One of the basic components of political culture is cognitive orientation. Cognitive orientation refers to the knowledge and beliefs about the political system. It includes the understanding of the roles of the government, the rights and responsibilities of the citizens, and the operation of the political system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>12", "subject": "Government", "year": "2010", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Communism as propounded by Karl Max was later interpreted by", "images": [], "options": {"A": "Locke", "B": "Dicey", "C": "C.Bentham", "D": "Lennin"}, "answer": "D", "explanation": "Communism as propounded by Karl Marx was later interpreted by Vladimir Lenin. Lenin was a Russian revolutionary and political theorist who served as the head of government of Soviet Russia from 1917 to 1924 and of the Soviet Union from 1922 to 1924. He developed a variant of it known as Leninism. The other options, Locke, Dicey, and C.Bentham, are not associated with the interpretation of Marx's communism.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2010>13", "subject": "Government", "year": "2010", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "According to Karl Marx. Those who own and control the means of production in a capitalist society are the", "images": [], "options": {"A": "colonialists", "B": "workers", "C": "bourgeoisies", "D": "peasants"}, "answer": "C", "explanation": "According to Karl Marx, those who own and control the means of production in a capitalist society are the 'bourgeoisie'. The bourgeoisie is a social class in capitalism, characterized by ownership of capital and control over the means of production. The workers, who do not own any means of production, are referred to as the proletariat.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2010>14", "subject": "Government", "year": "2010", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The rule of law is limited by", "images": [], "options": {"A": "free press", "B": "diplomatic immunity", "C": "constitutionalism", "D": "separation of powers"}, "answer": "B", "explanation": "The rule of law is limited by diplomatic immunity. Diplomatic immunity is a form of legal immunity that ensures diplomats are given safe passage and are considered not susceptible to lawsuit or prosecution under the host country's laws. This can limit the application of the rule of law as it provides exceptions for certain individuals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>15", "subject": "Government", "year": "2010", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "Which of the following is not a fundamental human right?", "images": [], "options": {"A": "Right to life", "B": "Right to vote", "C": "Freedom of movement", "D": "Freedom of religion"}, "answer": "B", "explanation": "The right to vote is not considered a fundamental human right. Fundamental human rights are basic rights and freedoms to which all individuals are entitled, regardless of nationality, sex, national or ethnic origin, race, religion, language, or other status. These include the right to life, freedom of speech, freedom of religion, freedom of movement, and others. The right to vote, however, is a political right associated with democracies, but not universally recognized as a fundamental human right.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2010>16", "subject": "Government", "year": "2010", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN INSTITUTION OF THE STATE:", "question": "The institution created for checking abuses by government department is known as the", "images": [], "options": {"A": "secret service", "B": "judicial commission", "C": "ombudsman", "D": "corp marshal"}, "answer": "C", "explanation": "The institution created for checking abuses by government departments is known as the ombudsman. An ombudsman is an official, usually appointed by the government, who investigates complaints (usually lodged by private citizens) against businesses, financial institutions, universities, government departments and other public entities, and attempts to resolve the conflicts or concerns raised, either through mediation, recommendations, or rulings. They are essentially an intermediary between the public and powerful institutions, which can act independently and impartially.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>17", "subject": "Government", "year": "2010", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : MONARCHICAL", "question": "A good example of an absolute Monarch is", "images": [], "options": {"A": "Adolf Hitler of Germany", "B": "Benito Mussolini of Italy", "C": "Halie Salessie of Ethiopia", "D": "Magaret Thatcher of Britain"}, "answer": "C", "explanation": "An absolute monarchy is a form of government where the monarch has absolute power among his or her people. An absolute monarch wields unrestricted political power over the sovereign state and its people. Halie Salessie of Ethiopia was an example of an absolute monarch. He was the Emperor of Ethiopia from 1930 to 1974 and he had absolute power over the state and its people.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>18", "subject": "Government", "year": "2010", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "The system of government in which powers are shared between the centre and the component units is called", "images": [], "options": {"A": "totalitarianism", "B": "federalism", "C": "unitary", "D": "oligarchy"}, "answer": "B", "explanation": "Federalism is a system of government in which powers are divided between a central authority and constituent political units, like states or provinces. In a federal system, the central government and the states or provinces share powers, with the central government having powers over national affairs and the states or provinces having powers over local or regional affairs. This is in contrast to a unitary system, where the central government has all the power, or an oligarchy, where power is held by a small group of people.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2010>19", "subject": "Government", "year": "2010", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY", "question": "The power of the central government to dissolve subordinate units at will is a feature of", "images": [], "options": {"A": "confederal system of government", "B": "unitary system of government", "C": "parliamentary system of government", "D": "federal system of government"}, "answer": "B", "explanation": "In a unitary system of government, the central government holds supreme power and can dissolve subordinate units at will. This is different from a confederal system where the power is held by individual states, or a federal system where power is shared between the central government and the states.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>20", "subject": "Government", "year": "2010", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "Which of the following is a feature of federalism?", "images": [], "options": {"A": "Unwritten constitution", "B": "Flexible constitution", "C": "Unitary constitution", "D": "Written constitution"}, "answer": "D", "explanation": "A feature of federalism is a written constitution. This is because a federal system of government is based on a constitution that outlines the division of powers between the central government and the states or provinces. An unwritten, flexible, or unitary constitution does not provide this clear division of powers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2010>21", "subject": "Government", "year": "2010", "type": "Objective", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : FEATURES AND PROBLEMS", "question": "The exclusive list in federalism includes all the following except", "images": [], "options": {"A": "defence", "B": "foreign relation", "C": "currency", "D": "transportation"}, "answer": "D", "explanation": "In a federal system of government, the exclusive list refers to the powers that are exclusively reserved for the central or federal government. These powers typically include defence, foreign relations, and currency. Transportation, however, is not exclusively reserved for the federal government. It is usually a concurrent power, meaning both the federal and state governments can legislate on it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>22", "subject": "Government", "year": "2010", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "The order of mandamus is a", "images": [], "options": {"A": "form of order by a superior body to perform a function", "B": "mandate from the executive to the public cooperations", "C": "plea for man of alibi in court", "D": "writ to produce a detained person for trial"}, "answer": "D", "explanation": "The order of Mandamus is a writ to produce a detained person for trial.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2010>23", "subject": "Government", "year": "2010", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "In the legislature, a filibuster is one who", "images": [], "options": {"A": "is in charge of party discipline", "B": "presents party manifesto during parliamentary sessions", "C": "does not take part in law making", "D": "prevents the passage of a bill by making long speeches"}, "answer": "D", "explanation": "A filibuster is a legislative tactic where a long speech is made to delay or prevent a decision being made on the proposed bill.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>24", "subject": "Government", "year": "2010", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "Which of the following measures will ensure the independence of the judiciary Judge?", "images": [], "options": {"A": "salaries must be handled by foreign banks", "B": "salaries must be fixed and subject to arbitrary review", "C": "must not be separated from the executives", "D": "must be controlled by the president"}, "answer": "B", "explanation": "Independence of judicial judges will be maintained if fixed salaries are subject to arbitrary review.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2010>25", "subject": "Government", "year": "2010", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "The most important function of the Upper House in a federation is to", "images": [], "options": {"A": "serve as the highest court of the land", "B": "ensure equal representation of the component units", "C": "provide a place for retired politicians in the legislature", "D": "invite politicians for questioning"}, "answer": "B", "explanation": "The most important function of the upper house is to ensure equal representation of component units.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>26", "subject": "Government", "year": "2010", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "Bi-cameral legislature is the same as", "images": [], "options": {"A": "legislature with two chambers", "B": "one chamber legislature", "C": "the Upper House in any legislature", "D": "the Lower House in any legislature"}, "answer": "A", "explanation": "Bi-cameral legislature refers to a legislature with two chambers or houses. It is a system of government where the legislature is divided into two separate assemblies, chambers, or houses, known as the 'Upper House' and the 'Lower House'. It is not a term for one chamber legislature, the Upper House, or the Lower House.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2010>27", "subject": "Government", "year": "2010", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "A short break in parliamentary session is referred to as", "images": [], "options": {"A": "suspension", "B": "recess", "C": "dissolution", "D": "termination"}, "answer": "B", "explanation": "A short break in a parliamentary session is referred to as a recess. This is a period of time when the parliament is not sitting but has not been formally closed. It's a break in the parliamentary business, not a termination, dissolution or suspension of it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>28", "subject": "Government", "year": "2010", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "The term guillotine in the legislature is referred to as", "images": [], "options": {"A": "allocation of time to a bill", "B": "passing a bill into law", "C": "voting a bill into law", "D": "passing an appropriation bill"}, "answer": "A", "explanation": "Guillotine refers to the allocation of time to a bill. It is a procedure used to prevent delay in the discussion of a legislative bill by fixing times at which various parts of it must be voted on.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>29", "subject": "Government", "year": "2010", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "The rights of individuals are usually enshrined in the", "images": [], "options": {"A": "law books", "B": "courts", "C": "constitutions", "D": "journals"}, "answer": "C", "explanation": "The rights of individuals are usually enshrined in the constitution of a country. A constitution is a set of fundamental principles or established precedents according to which a state or other organization is governed. These rules together make up, i.e. constitute, what the entity is. It is the constitution that defines the rights and freedoms of the citizens in a democratic society.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2010>30", "subject": "Government", "year": "2010", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "A citizen's freedom of movement may be restrained if he", "images": [], "options": {"A": "has refused to salute the Head of State", "B": "has been convicted by the courts", "C": "refuses to vote at elections", "D": "criticizes the government"}, "answer": "B", "explanation": "A citizen's freedom of movement may be restrained if he has been convicted by the courts. This is because the court has the power to restrict the movement of an individual as a form of punishment for a crime committed. This can be in the form of imprisonment, house arrest, or probation. The other options do not legally warrant a restriction on a citizen's freedom of movement.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>31", "subject": "Government", "year": "2010", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "A major advantage of one party system is that it", "images": [], "options": {"A": "prevents dictatorship", "B": "promotes unity", "C": "allows opposition", "D": "promotes freedom and liberty"}, "answer": "B", "explanation": "A one-party system is a type of state in which one political party has the right to form the government, usually based on the existing constitution. All other parties are either outlawed or allowed to take only a limited and controlled participation in elections. Thus, a major advantage of a one-party system is that it promotes unity because there is no opposition to create division.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>32", "subject": "Government", "year": "2010", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Which of the following best describes the concept of enfranchisement rights?", "images": [], "options": {"A": "to campaign for candidates during elections", "B": "to sue and be sued", "C": "given to people to vote and be voted for", "D": "to free expression on political issues"}, "answer": "C", "explanation": "Enfranchisement rights refer to the rights given to citizens to participate in the political process, which includes the right to vote (suffrage) and the right to be voted for (stand for public office). Therefore, the option 'given to people to vote and be voted for' best describes the concept of enfranchisement rights.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>33", "subject": "Government", "year": "2010", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "The arrangement by which a country is divided into parts for election purpose is called", "images": [], "options": {"A": "enfranchisement", "B": "gerrymandering", "C": "delimitation", "D": "democratization"}, "answer": "C", "explanation": "The arrangement by which a country is divided into parts for election purpose is called delimitation. Delimitation is the process of fixing limits or boundaries of territorial constituencies in a country or a province having a legislative body.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>34", "subject": "Government", "year": "2010", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "The process by which voters may remove a public officer before the end of his term of office is called", "images": [], "options": {"A": "gerrymandering", "B": "recall", "C": "bye-election", "D": "referendum"}, "answer": "B", "explanation": "\" Recall \" is the process by which voters may remove a public officer before the end of his term of office.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>35", "subject": "Government", "year": "2010", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "A yes or no vote cast by the electorate to decide an important issue in an area is known as", "images": [], "options": {"A": "franchise", "B": "plebiscite", "C": "electoral college", "D": "public opinion"}, "answer": "B", "explanation": "A yes or no vote cast by the electorate to decide an important issue in an area is known as a plebiscite. A plebiscite is a direct vote by eligible voters to resolve an important public issue. It is a form of direct democracy where the citizens are given the power to decide on a specific issue.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>36", "subject": "Government", "year": "2010", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "The term winner-takes-all can also be associated with", "images": [], "options": {"A": "second ballot system", "B": "representative government", "C": "first-past-the post system", "D": "proportional representation"}, "answer": "C", "explanation": "\"First-past-the-post\" (FPTP) principle, meaning that the candidate with the plurality of votes is the winner of the congressional seat or positions. The losing party or parties win no representation or positions at all.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>37", "subject": "Government", "year": "2010", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "Anonymity of the civil service means that they", "images": [], "options": {"A": "are free from the political heads", "B": "are to be seen but not to be heard", "C": "cannot vote for any political party", "D": "are to execute government policies"}, "answer": "B", "explanation": "Anonymity of the civil service means that civil servants are to be seen but not to be heard. This means that they are expected to carry out their duties without seeking public attention or recognition. They work behind the scenes to implement government policies and are not allowed to publicly express their personal political views or affiliations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>38", "subject": "Government", "year": "2010", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "The Loi-cadre Reforms of 1956 in the French West Africa were as a result of", "images": [], "options": {"A": "pressure from the French territories", "B": "change in French Policy of Association", "C": "opposition to Bamako conference", "D": "British colonial policy of granting internal self-government"}, "answer": "B", "explanation": "The Lois - Cadre reforms of 1956 in the French West Africa were as a result of change in French Policy of Association.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2010>39", "subject": "Government", "year": "2010", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Which of the following best describes the status of Governor-General in British West African Countries at independence? They", "images": [], "options": {"A": "were representing the Queen of England", "B": "were above the law", "C": "maintained friendly relations with France", "D": "were the heads of government"}, "answer": "A", "explanation": "The status of Governor-General in British West African countries can best be seen as \"they were representing the Queen of England\".", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2010>40", "subject": "Government", "year": "2010", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Before the Second World War, the British Colonial Executive Council consisted of", "images": [], "options": {"A": "only elected Africans", "B": "only White officials", "C": "unofficial members", "D": "official and unofficial members"}, "answer": "B", "explanation": "Before the second World war, the British colonial Executive consisted of only White officials.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>41", "subject": "Government", "year": "2010", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "The National Congress of British West Africa (NCBWA) was found in 1919 in", "images": [], "options": {"A": "Lagos", "B": "Monrovia", "C": "Accra", "D": "Bathurst"}, "answer": "C", "explanation": "The National Congress of British West Africa (NCBWA) was founded in 1919 in Accra, Ghana. The NCBWA was a political pressure group that demanded constitutional and administrative reforms and sought to unify the peoples of British West Africa.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>42", "subject": "Government", "year": "2010", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "The West African Students' Union worked towards", "images": [], "options": {"A": "the end of colonial rule", "B": "the end of indirect rule", "C": "getting accommodation for West African Students", "D": "the end of the policy of direct rule"}, "answer": "A", "explanation": "The West African Students' Union (WASU) was an organization that worked towards the end of colonial rule. It was a platform for political activism and played a significant role in the decolonization process in West Africa. The union provided a forum for the discussion of political ideas, and its members became some of the leading figures in the nationalist movements of their respective countries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>43", "subject": "Government", "year": "2010", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "The policy of Assimilation was abandoned because", "images": [], "options": {"A": "it was too expensive to maintain", "B": "the French were fed up", "C": "the Africans liked it", "D": "it was less expensive"}, "answer": "A", "explanation": "The policy of Assimilation was abandoned primarily because it was too expensive to maintain. The policy of Assimilation was a French colonial policy which aimed to fully integrate the colonies into the French state by extending French citizenship to the colonized people. However, this policy was expensive as it required significant resources to educate and transform the colonized people to become 'French'. Therefore, the French government found it unsustainable and abandoned it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>44", "subject": "Government", "year": "2010", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : POST- INDEPENDENCE CONSTITUTIONS", "question": "The constitutional reforms in West Africa after the second World War were geared towards", "images": [], "options": {"A": "the assimilation of the people", "B": "the evaluation of colonialism", "C": "making the colonies independent states", "D": "making the people support their economic interest"}, "answer": "C", "explanation": "Constitutional reforms after the World War II was geared towards making the colonies independent states.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2010>45", "subject": "Government", "year": "2010", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "One of the reasons for Military take-over in West Africa is", "images": [], "options": {"A": "smooth administration", "B": "political stability", "C": "corruption among political leaders", "D": "making the people support the economic interest"}, "answer": "C", "explanation": "One of the reasons for military takeovers in West Africa is corruption among political leaders. This is because the military often intervenes in politics when they perceive that the civilian government is corrupt and not serving the interests of the people. This has been a common reason for military coups in many West African countries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>46", "subject": "Government", "year": "2010", "type": "Objective", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "Which of the following best describes the foreign policy of West African countries during the Cold War?", "images": [], "options": {"A": "Support for the western bloc", "B": "Support for the eastern bloc", "C": "Non-alignment with any power bloc", "D": "Allegiance to Nazi government"}, "answer": "C", "explanation": "During the Cold War, many West African countries adopted a policy of non-alignment. This means they did not formally align themselves with or against any major power blocs. The Non-Aligned Movement was a group of states which were not formally aligned with or against any major power bloc. It was founded in 1961 in Belgrade, and was largely conceived by India's first prime minister, Jawaharlal Nehru; Indonesia's first president, Sukarno; Egypt's second president, Gamal Abdel Nasser; Ghana's first president Kwame Nkrumah; and Yugoslavia's president, Josip Broz Tito.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>47", "subject": "Government", "year": "2010", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "The Administration Headquaters of the Economic Community of West African States (ECOWAS) is in", "images": [], "options": {"A": "Freetown", "B": "Lome", "C": "Banjul", "D": "Abuja"}, "answer": "D", "explanation": "The Economic Community of West African States (ECOWAS) is a regional political and economic union of fifteen countries located in West Africa. Its administrative headquarters is located in Abuja, Nigeria. Therefore, the correct answer is Abuja.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2010>48", "subject": "Government", "year": "2010", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "The head of the Commonwealth of Nations is the", "images": [], "options": {"A": "Colonial Secretary", "B": "Australian foreign Secretary", "C": "British Monarch", "D": "New Zealand Foreign Minister"}, "answer": "C", "explanation": "The Commonwealth of Nations, generally known simply as the Commonwealth, is a political association of 54 member states, nearly all of which are former territories of the British Empire. The head of the Commonwealth is the British Monarch, currently Queen Elizabeth II. Therefore, the correct answer is British Monarch.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>49", "subject": "Government", "year": "2010", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "A representative of one country in another within the Commonwealth of Nation is called", "images": [], "options": {"A": "High Commissioner", "B": "Attache", "C": "Foreign Minister", "D": "Consul"}, "answer": "A", "explanation": "The high commissioner is a representative of one country in another within the Commonwealth of Nations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2010>50", "subject": "Government", "year": "2010", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The use of Veto power in the United Nations Organization (UNO) is only exercised by the", "images": [], "options": {"A": "Economic and Social Council", "B": "International Court of Justice", "C": "Trusteeship Council", "D": "Security Council"}, "answer": "D", "explanation": "Then use of veto power in the UNO is only exercised by the Security council. The United Nations Security Council \"power of veto\" refers to the veto power wielded solely by the five permanent members of the United Nations Security Council (China, France, Russia, United Kingdom, and United States), enabling them to prevent the adoption of any \"substantive\" resolution.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2011>1", "subject": "Government", "year": "2011", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN INSTITUTION OF THE STATE:", "question": "Government as an institution of the state is defined as a body which", "images": [], "options": {"A": "Conducts election for the country", "B": "Makes, enforces and interprets laws for the state", "C": "Hires and trains political leaders", "D": "Makes and interprets laws"}, "answer": "B", "explanation": "Government as an institution of the state is defined as a body which makes, enforces and interprets laws for the state .", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2011>2", "subject": "Government", "year": "2011", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN ACADEMIC FIELD OF STUDY – REASONS FOR STUDYING GOVERNMENT.", "question": "The study of government in school is important because the students can", "images": [], "options": {"A": "be assisted by political leaders", "B": "learn about their rights", "C": "qualify for elections", "D": "be nominated for a trip abroad"}, "answer": "B", "explanation": "The study of government in school is important because it helps students learn about their rights. Understanding the government and its functions helps students to understand their rights and responsibilities as citizens. It also helps them to understand how they can participate in the democratic process and influence government decisions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2011>3", "subject": "Government", "year": "2011", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "The primary function of government in a state is to", "images": [], "options": {"A": "Maintain law and order", "B": "Provide transport services", "C": "Engage in campaigns and rallies", "D": "Imprison criminals"}, "answer": "A", "explanation": "The primary assignment of government in a state is to maintain law and order. This is done by the three organs of government - Legislature, Executive and Judiciary.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2011>4", "subject": "Government", "year": "2011", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS A PROCESS OR ART OR GOVERNING", "question": "The functions of the state are achieved through", "images": [], "options": {"A": "Political socialisation", "B": "Separation of powers", "C": "Organs of government", "D": "Diplomatic means"}, "answer": "C", "explanation": "The organs of government are used by the government to achieve its functions - Legislature makes the law, Executive enforces law, Judiciary interprets law.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>5", "subject": "Government", "year": "2011", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A unique feature of a state", "images": [], "options": {"A": "Information", "B": "Anarchy", "C": "Organised law", "D": "Direct democracy"}, "answer": "C", "explanation": "A unique feature of a state is 'Organised law'. A state is a political entity that is represented by one centralized government that has sovereignty over a geographic area. One of the key features of a state is the presence of a structured and organized system of law that governs the conduct of the people within the state. This system of law is enforced by the government of the state.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>6", "subject": "Government", "year": "2011", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Ability to enforce obedience is known as", "images": [], "options": {"A": "Legitimacy", "B": "Power", "C": "Influence", "D": "Fame"}, "answer": "B", "explanation": "The ability to enforce obedience is known as 'Power'. In the context of government and politics, power refers to the ability of an entity (such as a government) to compel or influence individuals to behave in certain ways. This can be achieved through the use of force, the imposition of laws, or the threat of punishment. Power is a fundamental concept in the study of political science and is central to understanding the dynamics of governance and authority.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2011>7", "subject": "Government", "year": "2011", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A major source of political power is", "images": [], "options": {"A": "Election", "B": "Force", "C": "Influence", "D": "Ombudsman"}, "answer": "A", "explanation": "Power has different types such as political physical, economic etc. The political power is derived from election.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>8", "subject": "Government", "year": "2011", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Power is transferred into authority through", "images": [], "options": {"A": "Force", "B": "Legitimacy", "C": "Judiciary", "D": "Sovereignty"}, "answer": "B", "explanation": "Power can be transferred into authority through legitimacy. Legitimacy is the acceptance and recognition by citizens of the right of their leaders to govern them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>9", "subject": "Government", "year": "2011", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Political authority is the", "images": [], "options": {"A": "Legitimate right to exercise political power", "B": "Right to control political behaviour", "C": "Right to participate in political campaigns", "D": "Right to form political parties"}, "answer": "A", "explanation": "The legitimate right to exercise political power is political authority. This is because when citizens vote a citizen into a political office, that elected citizen automatically gets the acceptability of the citizens. By so doing, he exercises political power by the virtue of holding such power.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2011>10", "subject": "Government", "year": "2011", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The extent to which the citizens accept the institutions' officials and activities of government is known as", "images": [], "options": {"A": "Authority", "B": "Permission", "C": "Legitimacy", "D": "Power"}, "answer": "C", "explanation": "The extent to which the citizens accept the institutions' officials and activities of government is known as legitimacy. Legitimacy in government is the recognition and acceptance of the authority of a governing regime by its population. It is the consent of the citizens that their government has the right to rule and the belief that the government's actions are appropriate and justified.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2011>11", "subject": "Government", "year": "2011", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The concept of sovereignty was propounded by", "images": [], "options": {"A": "Adam Smith", "B": "Jeremy Bentham", "C": "Karl Marx", "D": "Jean Bodin"}, "answer": "D", "explanation": "Jean Bodin, a jurist and political thinker propounded the theory of sovereignty between (1530 - 1556). For him, sovereignty is the supreme absolute power of a state to make and enforce law.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>12", "subject": "Government", "year": "2011", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Popular sovereignty belongs to the", "images": [], "options": {"A": "Immigrants", "B": "Electorate", "C": "Cabinet", "D": "Legislature"}, "answer": "B", "explanation": "Among the types of sovereignty, popular sovereignty belongs to the electorate. This is because, their views are highly important and make a government popular or determine the popularity of a government through elections.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>13", "subject": "Government", "year": "2011", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following factors places limitation to the application of sovereignty in a state?", "images": [], "options": {"A": "Civil Service", "B": "International Laws", "C": "Political Culture", "D": "Political parties"}, "answer": "B", "explanation": "Although, sovereignty is said to be the absolute power of a country/ state to enforce law over its territory without external aggression. However, international laws can limit the absoluteness of sovereignty of a state that belongs to it, for instance, the charter of the UNO or ICJ International Court of Justice can limit the sovereignty of a state.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2011>14", "subject": "Government", "year": "2011", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Democracy originated from", "images": [], "options": {"A": "Greece", "B": "Britain", "C": "USA", "D": "Germany"}, "answer": "A", "explanation": "The idea of democracy originated from Greece. This is because, it was in the city of Athens that democracy began and the type of democracy practised then is called \"Direct Democracy\".", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2011>15", "subject": "Government", "year": "2011", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Which of the following is a basic principle of democracy? Rule by", "images": [], "options": {"A": "the majority, and the protection of the minority", "B": "wealthy few", "C": "the minority at the expense of the majority", "D": "two political parties"}, "answer": "A", "explanation": "Democracy is known to be the rule of the majority. Although the majority does not neglect the minority as it also seeks to protect it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>16", "subject": "Government", "year": "2011", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The concept of political culture was introduced by", "images": [], "options": {"A": "Fredrich Engels", "B": "Abraham Lincoln", "C": "Harold Laski", "D": "Gabriel Almond"}, "answer": "D", "explanation": "Political culture was introduced by Gabriel Almond and his friend Sidney Verbal and they wrote a book \"The Civic Culture\".", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>17", "subject": "Government", "year": "2011", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following is a component of political culture?", "images": [], "options": {"A": "Injunction", "B": "Cognitive orientation", "C": "Mandamus", "D": "Harbeas Corpus"}, "answer": "B", "explanation": "Political culture aims at educating citizens about issues of politics. Among the various orientation through which political culture achieves that is \"cognitive orientation\" which is designed to keep citizens informed about the programmes and conduct of politics.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>18", "subject": "Government", "year": "2011", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The teaching and learning of political culture is known as political", "images": [], "options": {"A": "Participation", "B": "Socialization", "C": "Administration", "D": "Development"}, "answer": "B", "explanation": "The teaching and learning of political culture is known as political socialization. It is the process by which individuals learn and frequently internalize a political lens framing their perceptions of how power is arranged and how the world around them is (and should be) organized. Political participation, administration, and development are not processes related to the teaching and learning of political culture.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>19", "subject": "Government", "year": "2011", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following can contribute to political socialisation?", "images": [], "options": {"A": "Gerrymandering", "B": "Tourism", "C": "Diplomatic immunity", "D": "Terrorism"}, "answer": "B", "explanation": "Tourism is one of the avenues through which political culture can be imbibed. Tourism is the act of visiting places for both pleasure and socialization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>20", "subject": "Government", "year": "2011", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following political concepts promotes sharing and co-operation in a society?", "images": [], "options": {"A": "Aristocracy", "B": "Capitalism", "C": "Communalism", "D": "Oligarchy"}, "answer": "C", "explanation": "Communalism is a political concept that promotes the distribution of resources and cooperation in a society. This is because it is communal based.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>21", "subject": "Government", "year": "2011", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following is true about a capitalist state?", "images": [], "options": {"A": "Private individuals control the economy", "B": "The workers are not exploited", "C": "Government controls the means of production", "D": "There is no class struggle"}, "answer": "A", "explanation": "Capitalism is an economic concept that is based on the fact that the production and distribution should be controlled by private individuals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>22", "subject": "Government", "year": "2011", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The highest stage of socialism is", "images": [], "options": {"A": "Oligarchy", "B": "Capitalism", "C": "Totalitarianism", "D": "Communism"}, "answer": "D", "explanation": "The highest stage of socialism is communism. In a communist society, all property is publicly owned and each person works and is paid according to their abilities and needs. The other options are incorrect because they are not stages of socialism.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2011>23", "subject": "Government", "year": "2011", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "Foreign domination by a group of people for social and economic benefits is known as", "images": [], "options": {"A": "Nationalism", "B": "Colonialism", "C": "Feudalism", "D": "Constitutionalism"}, "answer": "B", "explanation": "Colonialism is the belief that a foreign power is superior to the local one and by that token, should dominate the local one e.g Britain.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>24", "subject": "Government", "year": "2011", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A communist system recognizes", "images": [], "options": {"A": "class division", "B": "the need of individual", "C": "human capital", "D": "division of labour"}, "answer": "B", "explanation": "A Communist state recognizes the individual's need. The government provides for the needs of citizens but usually according to their contributions.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2011>25", "subject": "Government", "year": "2011", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following is the lowest in the hierarchy of a feudal system?", "images": [], "options": {"A": "Lords", "B": "Serfs", "C": "Knights", "D": "Nobles"}, "answer": "B", "explanation": "Feudalism is a system of land ownership. In feudalism, there are classes which have rank e.g Lords → Nobles → Knights → Serfs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>26", "subject": "Government", "year": "2011", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A common feature of feudalism is", "images": [], "options": {"A": "hierarchical land ownership between the lords and the serfs", "B": "private ownership of the means of production and distribution", "C": "separation of powers", "D": "fusion of powers"}, "answer": "A", "explanation": "Feudalism is characterized by a hierarchical system of land use and patronage, known as fiefdom. The lords owned the land and the serfs worked on it. The lords provided protection and in return, the serfs provided their labor. This is what is referred to as hierarchical land ownership between the lords and the serfs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>27", "subject": "Government", "year": "2011", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "An open market economy is a unique feature of", "images": [], "options": {"A": "Welfarism", "B": "Socialism", "C": "Feudalism", "D": "Capitalism"}, "answer": "D", "explanation": "Communism discourages socialism because it is a community system which is based on classless society.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>28", "subject": "Government", "year": "2011", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following political systems discourages socialism?", "images": [], "options": {"A": "Fascism", "B": "Feudalism", "C": "Communalism", "D": "Welfarism"}, "answer": "A", "explanation": "It is Fascism. While socialism strives for communal control of means of production, fascism agitates for total governmental control, and hence dictatorial tendencies.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2011>29", "subject": "Government", "year": "2011", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The mano is a unique feature of", "images": [], "options": {"A": "Feudalism", "B": "Monarchy", "C": "Totalitarianism", "D": "Communism"}, "answer": "A", "explanation": "The Manorial system, or 'mano' as it is referred to in the question, is a unique feature of Feudalism. Feudalism was a socio-economic system that existed in Europe during the Middle Ages. In this system, the 'mano' or manor was the basic unit. It was a piece of land, essentially a self-sufficient estate, given by a lord to a vassal in exchange for loyalty and service.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2011>30", "subject": "Government", "year": "2011", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The principle of rule of law was popularized by", "images": [], "options": {"A": "Gabriel Almond", "B": "Charles Montesquieu", "C": "Jean Bodin", "D": "A.V Dicey"}, "answer": "D", "explanation": "The principle of Rule of Law was popularized by A.V Dicey who wrote a book in 1885 titled \"The Law of Constitution\".", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>31", "subject": "Government", "year": "2011", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "The body charged with the responsibility of preparing a new constitution in a country is the", "images": [], "options": {"A": "Electoral Commission", "B": "Constituent Assembly", "C": "Judicial Service Commission", "D": "Electoral College"}, "answer": "B", "explanation": "The constituent assembly is a body that is charged with the responsibility of preparing a new constitution in a country.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>32", "subject": "Government", "year": "2011", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "The institution connected with law adjudication is the", "images": [], "options": {"A": "Judiciary", "B": "Police", "C": "Government", "D": "Executive"}, "answer": "A", "explanation": "The institution connected with law adjudication is the Judiciary. The Judiciary is the system of courts that interprets and applies the law in the name of the state. The judiciary can also be thought of as the mechanism for the resolution of disputes. Under the doctrine of the separation of powers, the judiciary generally does not make statutory law (which is the responsibility of the legislature) or enforce law (which is the responsibility of the executive), but rather interprets law and applies it to the facts of each case.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2011>33", "subject": "Government", "year": "2011", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : CONFEDERAL", "question": "Which of the following is not a characteristic of a confederation", "images": [], "options": {"A": "The right to secede is allowed", "B": "Sovereignty resides in the centre", "C": "The centre and the units agree before taking decisions", "D": "Autonomous units are more powerful than the centre"}, "answer": "B", "explanation": "Confederal system is a loose political arrangement in which sovereign states come together and the component states have a weak central government. In a confederal state, the right to secede (break-apart) is a common feature since they come together in a mutual agreement.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2011>34", "subject": "Government", "year": "2011", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "Which of the following is a function of a head of state", "images": [], "options": {"A": "Settles cases", "B": "Arbitrates electoral petitions", "C": "Creates new constitutions", "D": "Receives foreign dignitaries"}, "answer": "D", "explanation": "The head of state in many countries has the function of receiving foreign dignitaries. This is part of the ceremonial duties of the head of state. Settling cases, arbitrating electoral petitions, and creating new constitutions are not typical functions of a head of state.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>35", "subject": "Government", "year": "2011", "type": "Objective", "topic": "CITIZENSHIP : MEANING AND MODE OF ACQUISITION", "question": "Citizenship can be changed through", "images": [], "options": {"A": "Proclamation", "B": "Residence", "C": "Renunciation", "D": "Announcement"}, "answer": "C", "explanation": "Citizenship is the state of becoming a legal member of a society. One's citizenship can be changed through \"renunciation\".", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>36", "subject": "Government", "year": "2011", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "On which of the following platforms do political parties mainly present their manifestoes to the electorate?", "images": [], "options": {"A": "Campaign rallies", "B": "Assemblies", "C": "Town halls", "D": "Media"}, "answer": "A", "explanation": "It is mostly through campaign rallies. Other means are also applicable, but campaign rallies are the most common due to massive turn out of the electorate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>37", "subject": "Government", "year": "2011", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS", "question": "In a two-party system, only two political parties", "images": [], "options": {"A": "Exist in the country", "B": "Dominate the political scene", "C": "Register their members", "D": "Undertake political education"}, "answer": "B", "explanation": "In a two-party system, only two parties are dominant in the country. This means, there could be more than two parties but the dominant ones are two.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>38", "subject": "Government", "year": "2011", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : TYPES, MERITS AND DEMERITS", "question": "Which of the following is not a form of proportional representation?", "images": [], "options": {"A": "Alternative vote", "B": "Second ballot", "C": "List system", "D": "Plurality system"}, "answer": "D", "explanation": "The Plurality system is not a form of proportional representation. Proportional representation is a type of electoral system that divides seats according to the proportion of votes each party receives. In contrast, the Plurality system (also known as 'first past the post') awards the seat to the candidate with the most votes, regardless of whether they have a majority. This means that a party can win a majority of seats without winning a majority of the vote.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2011>39", "subject": "Government", "year": "2011", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "The efficiency of public corporations can be enhanced through", "images": [], "options": {"A": "Increased production of goods", "B": "Appointment of staff based on patronage", "C": "Frequent redeployment of staff", "D": "Less government interference"}, "answer": "D", "explanation": "It'll be most likely less government interference. This will lead to less bureaucracy in decision making.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>40", "subject": "Government", "year": "2011", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI~~PRE-COLONIAL POLITICAL SYSTEM : IGBO~~PRE-COLONIAL POLITICAL SYSTEM : YORUBA", "question": "A chief could be deposed in the pre-colonial era if he", "images": [], "options": {"A": "Violated the written constitution", "B": "Persistently neglected the advice of his elders", "C": "Refused to collect taxes for the British governor", "D": "Married too many wives"}, "answer": "C", "explanation": "Under the Indirect rule system, a chief could be deposed if he refused to collect taxes for the British Governor.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2011>41", "subject": "Government", "year": "2011", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI~~PRE-COLONIAL POLITICAL SYSTEM : IGBO~~PRE-COLONIAL POLITICAL SYSTEM : YORUBA", "question": "A common feature in a pre-colonial centralised state was", "images": [], "options": {"A": "Loyalty to one political superior", "B": "Absence of single superior political authority", "C": "The existence of autocratic rule", "D": "Existence of separation of powers"}, "answer": "A", "explanation": "In a pre-colonial centralized state, there was usually one political superior to whom loyalty was given. This is because in a centralized state, power and authority are concentrated in a single central government, and all other political subdivisions are subordinate to it. This is different from a decentralized state where power is distributed among various political subdivisions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>42", "subject": "Government", "year": "2011", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Under the British Crown Colony system of administration, the head of the executive council was the", "images": [], "options": {"A": "Governor-General", "B": "Head of government business", "C": "Speaker", "D": "Prime Minister"}, "answer": "A", "explanation": "Under the British Crown Colony system of administration, the head of the executive council was the Governor General.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2011>43", "subject": "Government", "year": "2011", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "Taxation as a feature of indirect rule served as a", "images": [], "options": {"A": "Source of revenue for colonial administration", "B": "System of modernising chieftaincy", "C": "Policy of making the local people poor", "D": "Means to ridicule the chiefs"}, "answer": "A", "explanation": "Taxation as a feature of Indirect Rule served as a source of revenue for colonial administration because British government was short of funds..", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>44", "subject": "Government", "year": "2011", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "One effect of the French policy of assimilation was that it", "images": [], "options": {"A": "Made all French West Africans, French citizens", "B": "Increased nationalist activities in French West Africa", "C": "Delayed nationalism in French West Africa", "D": "Expanded education into the interior of French West Africa"}, "answer": "C", "explanation": "One of the effects of French policy of administration was that it delayed nationalism in French West Africa. This was because such activities were proscribed (banned).", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2011>45", "subject": "Government", "year": "2011", "type": "Objective", "topic": "NATIONALISM : NATIONALISM: MEANING, FACTORS AND EFFECTS.", "question": "The late development of nationalism in French West Africa was due to", "images": [], "options": {"A": "Absorption of French Colonial ex-service men into the French Army", "B": "Migration of the citizenry to British West African Colonies", "C": "Establishment of the traditional council of chiefs", "D": "Oppressive French colonial policies"}, "answer": "D", "explanation": "The late development of nationalism in French West Africa was due to oppressive French colonial policies. The French colonial policy of assimilation meant that the colonies were considered part of France and were subject to French law. This policy was oppressive and did not allow for the development of nationalism.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2011>46", "subject": "Government", "year": "2011", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "Which of the following was the function of traditional rulers during the colonial era? They", "images": [], "options": {"A": "Settled all forms of disputes", "B": "Implemented government policies", "C": "Collected and spent taxes and rates", "D": "Were sources of consultation on customary affairs"}, "answer": "D", "explanation": "Traditional rulers during the colonial era, were sources of consultation on customary affairs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>47", "subject": "Government", "year": "2011", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "The first British West African country to practice the elective principle was", "images": [], "options": {"A": "Nigeria", "B": "The Gambia", "C": "Sierra Leone", "D": "Ghana"}, "answer": "A", "explanation": "Nigeria was the first British West country to practise the elective principle in 1923 as documented in the constitution of Hugh Clifford, 1922. The elective principle provided for four seats, three from Lagos and one from Calabar under Herbert Macaulay's party; Nigerian National Democratic Party (N.N.D.P).", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>48", "subject": "Government", "year": "2011", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "The first Pan- West African political organisation formed by the educated elite in the early twentieth century was the", "images": [], "options": {"A": "Aborigines' Rights Protection Society (ARPS)", "B": "National Congress of British West Africa (NCBWA)", "C": "West African Students' Union (WAYU)", "D": "West African Youth Leagus (WAYL)"}, "answer": "B", "explanation": "National Congress of British West Africa formed in 1919 in Accra, Ghana was the first Pan-African Political Organisation formed in the early 20th century.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2011>49", "subject": "Government", "year": "2011", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "Which of the following is a process in the transition from military to civilian rule?", "images": [], "options": {"A": "Appointment of an Attorney-General", "B": "Suspension of the constitution", "C": "Setting up of a constituent assembly", "D": "Non-implementation of development plans"}, "answer": "C", "explanation": "In the past, setting up of a constituent assembly usually preceded transition from a military to a civilian rule.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2011>50", "subject": "Government", "year": "2011", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "The objective of the Economic Community of West African States (ECOWAS) is to", "images": [], "options": {"A": "Promote economic development among member states", "B": "Achieve African Unity", "C": "Establish political unification of West Africa", "D": "Eradicate all forms of racism in West Africa"}, "answer": "A", "explanation": "The aims of the Community are to promote cooperation and integration, leading to the establishment of an economic union in West Africa in order to raise the living standards of its peoples, and to maintain and enhance economic stability, foster relations among member states.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2012>1", "subject": "Government", "year": "2012", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN ACADEMIC FIELD OF STUDY – REASONS FOR STUDYING GOVERNMENT.", "question": "The study of government is important because it", "images": [], "options": {"A": "Directs people's attention to development of non-state institutions", "B": "Enables citizens to understand the processes for managing state affairs", "C": "Encourages individuals to take decisions to satisfy their aspirations", "D": "Encourages the elite to remain in power"}, "answer": "B", "explanation": "The study of government is critical as it enables citizens to understand the process for managing state affairs. This is learned through the understanding of the three organs of government.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2012>2", "subject": "Government", "year": "2012", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : MONARCHICAL", "question": "A system of government where political powers are inherited is", "images": [], "options": {"A": "Monarchy", "B": "Diarchy", "C": "Democracy", "D": "Aristocracy"}, "answer": "A", "explanation": "Monarchy is a system of government where a King, Queen or other similar title holder rules. In such situation, the political power is usually hereditary or inherited.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>3", "subject": "Government", "year": "2012", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Democracy can be promoted through", "images": [], "options": {"A": "Gerrymandering", "B": "Slander", "C": "Accountability", "D": "Lobbying"}, "answer": "C", "explanation": "Democracy as the government of the majority can be promoted through accountability. This is because since it is a system of representative government, the leaders are expected to be accountable to the citizens.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>4", "subject": "Government", "year": "2012", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The ability to command obedience is called", "images": [], "options": {"A": "power", "B": "Influence", "C": "Legitimacy", "D": "Mobilisation"}, "answer": "A", "explanation": "The ability to command obedience is power while the (legal) right to enforce obedience is Authority.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>5", "subject": "Government", "year": "2012", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Legitimacy is determined mainly by", "images": [], "options": {"A": "Charisma", "B": "Influence", "C": "Acceptance", "D": "Desire"}, "answer": "C", "explanation": "Legitimacy in the context of governance refers to the acceptance and recognition of an authority, often a governing law or a regime. It is determined mainly by the acceptance of the people. If the people accept and recognize the authority, then it is considered legitimate. Therefore, the correct answer is 'Acceptance'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2012>6", "subject": "Government", "year": "2012", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following is a feature of democracy?", "images": [], "options": {"A": "Majority rule", "B": "Election by selected adults", "C": "Quick decision making", "D": "Rule by wealthy men"}, "answer": "A", "explanation": "Democracy is a system of government where the citizens exercise power by voting. One of the key features of democracy is the 'Majority rule'. In a democratic system, decisions are made based on the majority vote. This means that if more than half of the people vote for a particular decision, then that decision is made. Therefore, the correct answer is 'Majority rule'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2012>7", "subject": "Government", "year": "2012", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following is a source of political power?", "images": [], "options": {"A": "Gerrymandering", "B": "Election", "C": "Filibuster", "D": "Immunity"}, "answer": "B", "explanation": "The source of political power is election. This is because political leaders get or derive their power through election.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>8", "subject": "Government", "year": "2012", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Laws made by non-legislative bodies are called", "images": [], "options": {"A": "Judicial review", "B": "Delegated legislation", "C": "Criminal laws", "D": "Case law"}, "answer": "B", "explanation": "Delegated legislation is an act of transferring some legislative powers to other organs of government to make bye-laws. That is, any law which is not made by the legislature but by other organs of government is technically referred to as delegated legislation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>9", "subject": "Government", "year": "2012", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Delegated legislation is unpopular because it", "images": [], "options": {"A": "Quickens the law making process", "B": "Receives wide publicity", "C": "Is not made by the legislature", "D": "Caters for emergency situations"}, "answer": "C", "explanation": "Any law that is not made by the legislature is often unpopular because it does not get general recognition.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2012>10", "subject": "Government", "year": "2012", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Political socialization begins from", "images": [], "options": {"A": "Adulthood", "B": "Childhood", "C": "Old age", "D": "Manhood"}, "answer": "B", "explanation": "Political socialization begins from home or childhood. This is because a child begins from home to learn about politics through the parents' political orientation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2012>11", "subject": "Government", "year": "2012", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "A.V Dicey popularized the principle of", "images": [], "options": {"A": "Rule of law", "B": "Democracy", "C": "Political culture", "D": "Separation of powers"}, "answer": "A", "explanation": "A.V Dicey is a British jurist and constitutional theorist who is best known for popularizing the principle of 'Rule of Law'. The rule of law is a legal principle that law should govern a nation, and that all are subject to it, including those who govern. It primarily refers to the influence and authority of law within society, particularly as a constraint upon behavior, including behavior of government officials.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>12", "subject": "Government", "year": "2012", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following is the lowest in the hierarchy of feudal system?", "images": [], "options": {"A": "Knights", "B": "Serfs", "C": "Nobles", "D": "Lords"}, "answer": "B", "explanation": "It is the Serfs. Feudalism was an European political system in which a lord owned all the land while vassals and serfs farmed on it.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2012>13", "subject": "Government", "year": "2012", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The ratification of major executive decisions by the legislature is in line with the application of", "images": [], "options": {"A": "Separation of powers", "B": "Rule of law", "C": "Checks and balances", "D": "Fusion of powers"}, "answer": "C", "explanation": "Checks and balances is a political concept that emphasizes the need for the three organs of government to check the action of one another.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>14", "subject": "Government", "year": "2012", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "In which of the following political systems is the rule of law most enhanced", "images": [], "options": {"A": "Cabinet System", "B": "Feudal System", "C": "Fascist system", "D": "Communist System"}, "answer": "A", "explanation": "One of the cardinal features of cabinet system of government is the application of rule of law. This is because the constitution often contains it.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2012>15", "subject": "Government", "year": "2012", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "A constitution is the", "images": [], "options": {"A": "Written document of traditional practices", "B": "Functional aspect of government activities", "C": "General advise to the people", "D": "Format to carry out social services"}, "answer": "B", "explanation": "A constitution is a set of fundamental principles or established precedents according to which a state or other organization is governed. These rules together make up, i.e. constitute, what the entity is. It is the functional aspect of government activities, providing a framework for the operation of a government. It is not merely a written document of traditional practices, a general advice to the people, or a format to carry out social services.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2012>16", "subject": "Government", "year": "2012", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "A constitution is important because it", "images": [], "options": {"A": "Teaches moral values of the society", "B": "Prescribes rules for those who govern", "C": "Serves as a source of conflict in the society", "D": "Describes the laws and admonishes obedience"}, "answer": "B", "explanation": "A constitution is important because it prescribes rules for those who govern. It sets out how the government is structured, what powers it has, and how those powers can be exercised. It also sets out the rights of individuals, and how those rights can be protected. It does not primarily teach moral values of the society, serve as a source of conflict in the society, or describe the laws and admonish obedience.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2012>17", "subject": "Government", "year": "2012", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "Which of the following cannot be found in a constitution?", "images": [], "options": {"A": "Fundamental human rights", "B": "Manifestoes of political parties", "C": "Organs of government", "D": "Duties and obligations of citizens"}, "answer": "B", "explanation": "A constitution contains the Fundamental Human Rights, organs of government and the relationship among them, duties and obligations of citizens but political manifestoes are not found in any constitution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>18", "subject": "Government", "year": "2012", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNITMENT : FEDERAL", "question": "A rigid constitution is a feature of", "images": [], "options": {"A": "Unitary system", "B": "Monarchical system", "C": "Federal System", "D": "Confederal System"}, "answer": "C", "explanation": "There are two methods of amending constitution - rigid and flexible. A rigid constitution is the type that requires a complex process for its amendment while a flexible constitution is one that can be amended through a simple procedure. Usually, a rigid constitution is federal while a flexible constitution is Unitary.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>19", "subject": "Government", "year": "2012", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET", "question": "In a parliamentary system, the executive is weak because it is", "images": [], "options": {"A": "Accountable to parliament", "B": "Responsible for its own actions", "C": "Headed by a Prime Minister", "D": "the head of state that controls the government"}, "answer": "A", "explanation": "In parliamentary system, the executive is often weak because it is accountable to the legislature (the head of government for instance, using Nigerian situation between 1960 - 1966 (January)). Nnamdi Azikiwe was the head of Executive (Head of State) weak while Tafawa Balewa was the head of the Legislature (Head of Government) powerful.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>20", "subject": "Government", "year": "2012", "type": "Objective", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : FEATURES AND PROBLEMS", "question": "In a federal system of government, the powers of the state government are subordinate to", "images": [], "options": {"A": "The regional constitutions", "B": "The supreme body of state laws", "C": "Acts of parliament at the centre", "D": "Provincial laws"}, "answer": "C", "explanation": "In a federal system of government, the powers of the state government are not subordinate to the regional constitutions, the supreme body of state laws, or provincial laws. Instead, they are subordinate to the acts of parliament at the centre. This is because in a federal system, the constitution divides powers between the central government and the state governments, and the central government has the power to make laws that apply to the entire country.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2012>21", "subject": "Government", "year": "2012", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : CONFEDERAL", "question": "An advantage of a confederation over a federation is that the component units", "images": [], "options": {"A": "have the right to secede", "B": "hare resources equally", "C": "are politically stable", "D": "co-operate fully with the centre"}, "answer": "A", "explanation": "One of the benefits of Confederal system over federal is that the component states have the right to secede (break away). They can go apart if the association is no longer beneficial to them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>22", "subject": "Government", "year": "2012", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : CONFEDERAL", "question": "Confederation was once practiced in", "images": [], "options": {"A": "Nigeria and Ghana", "B": "Senegal and the Gambia", "C": "Mali and Cote d'ivoire", "D": "Ghana and Benin"}, "answer": "B", "explanation": "Senegal and the Gambia once formed a confederation known as Senegambia. The other options listed did not practice confederation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>23", "subject": "Government", "year": "2012", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "Which of the following acts as a check on the Executive in the control of finances of a state?", "images": [], "options": {"A": "Judiciary", "B": "Civil Service", "C": "Press", "D": "Legislature"}, "answer": "D", "explanation": "The Legislature acts as a check on the Executive in the control of finances of a state. This is because the Executive cannot spend money that has not been approved by the Legislature. This is a way of ensuring that the Executive does not misuse or misappropriate state funds.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2012>24", "subject": "Government", "year": "2012", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "In a legislature, cross-carpeting means", "images": [], "options": {"A": "Crossing over the carpet", "B": "Decamping to another party", "C": "Legislative dismissal", "D": "Legislative instrument"}, "answer": "B", "explanation": "In a legislature, cross-carpeting means decamping to another party. This is a term used in politics to describe the act of moving from one political party to another. It is often done by politicians who are dissatisfied with their current party or who believe that they have a better chance of winning an election with a different party.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>25", "subject": "Government", "year": "2012", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "The responsibility of the Judiciary is to", "images": [], "options": {"A": "Make rules", "B": "Formulate decisions", "C": "Arrest offenders", "D": "Adjudicate cases"}, "answer": "D", "explanation": "The Judiciary's primary responsibility is to adjudicate cases. This means they interpret the law and apply it to individual cases, resolving disputes and ensuring justice is served.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2012>26", "subject": "Government", "year": "2012", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "One of the limitations on freedom of speech is", "images": [], "options": {"A": "Libel", "B": "Trespassing", "C": "Bye-laws", "D": "Unlawful detention"}, "answer": "A", "explanation": "One of the fundamental human rights is freedom of speech. However, this can be limited if one writes an untrue account of someone (l  Libel) or says what is not true (Slander).", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2012>27", "subject": "Government", "year": "2012", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "A citizen's duties do not include", "images": [], "options": {"A": "Defending the nation", "B": "Obeying the law", "C": "Paying taxes", "D": "Respecting others"}, "answer": "A", "explanation": "Defending the nation is a duty of a citizen. In many countries, this is often fulfilled through mandatory military service or voluntary enlistment in the military. Therefore, this option is incorrect.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2012>28", "subject": "Government", "year": "2012", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "One-party system leads to", "images": [], "options": {"A": "Dictatorship", "B": "Democracy", "C": "Diarchy", "D": "Theocracy"}, "answer": "A", "explanation": "One party system is one whereby only one party is constitutionally allowed to take part in an election. Such often leads to dictatorship as the leader may declare himself president for life.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>29", "subject": "Government", "year": "2012", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS", "question": "In a democratic state, the party system that usually operates is", "images": [], "options": {"A": "Mass party", "B": "Multi-Party", "C": "One-party", "D": "Elite party"}, "answer": "B", "explanation": "In a democratic state, the party system that usually operates is the Multi-Party system. This is because democracy is about representation and the freedom to choose. A multi-party system allows for a variety of parties to represent different views and interests. It also provides voters with a range of options to choose from, thereby promoting political competition and preventing the concentration of power in a single party.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>30", "subject": "Government", "year": "2012", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "The coming together of two or more political parties to form a government is", "images": [], "options": {"A": "Coalition", "B": "Merger", "C": "Unification", "D": "Co-operation"}, "answer": "A", "explanation": "The coming together of two or more political parties to form a government is known as a Coalition. This usually happens when no single party has an absolute majority in the parliament. In such a case, parties with similar ideologies or interests come together to form a government. This is different from a Merger, where two or more parties join to become a single party; Unification, which is the process of making or becoming a single unit; and Co-operation, which is a general term for parties working together but not necessarily forming a government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>31", "subject": "Government", "year": "2012", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Universal Adult Suffrage is associated with a", "images": [], "options": {"A": "Democratic government", "B": "Military government", "C": "Gerontocratic government", "D": "Fascist government"}, "answer": "A", "explanation": "Universal adult suffrage permits all qualified adult citizens to cast their votes and be voted for. While restricted franchise places a number of conditions which deny many citizens of exercising their political right.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>32", "subject": "Government", "year": "2012", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Restricted franchise violates the idea of", "images": [], "options": {"A": "Political equality", "B": "Political culture", "C": "Public accountability", "D": "Political socialisation"}, "answer": "A", "explanation": "Restricted franchise, which limits the right to vote to certain groups or individuals, violates the idea of Political equality. Political equality is a principle that all citizens are equal in the eyes of the law and have equal access to legislative processes. This principle is undermined when the franchise is restricted.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>33", "subject": "Government", "year": "2012", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "A major advantage of the Secret Ballot System of voting is that", "images": [], "options": {"A": "It is faster than other systems", "B": "It ensures the anonymity of the voter", "C": "It extends the franchise to all adults", "D": "Nobody can be prevented from voting"}, "answer": "B", "explanation": "Secret ballot system of voting is when voting is done privately in order to give voters opportunity from intimidation. Voting of this kind does not reveal the identity of voters thereby giving them free choices to make.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>34", "subject": "Government", "year": "2012", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "The 'first-past-the-post' system of voting is also called", "images": [], "options": {"A": "Second ballot system", "B": "Proportional representation", "C": "Second majority system", "D": "Alternative vote system"}, "answer": "A", "explanation": "The 'first-past-the-post' system of voting is also known as the 'simple majority' or 'plurality' system. It is a system in which the candidate with the most votes wins, even if they do not have more than half the votes. It is not the same as the 'second ballot system', 'proportional representation', or 'alternative vote system'. Therefore, 'Second ballot system' is the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>35", "subject": "Government", "year": "2012", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Proportional representation is more appropriate in a", "images": [], "options": {"A": "Multi-party system", "B": "Plurality system", "C": "Unitary system", "D": "Monarchical system"}, "answer": "A", "explanation": "Proportional representation is a type of voting system that is designed to create a representative body that reflects the overall proportion of public support for each political party. It is more appropriate in a multi-party system because it allows for a more equitable representation of multiple parties in the legislature. In a plurality system, a unitary system, or a monarchical system, the representation may not be as diverse or equitable.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>36", "subject": "Government", "year": "2012", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "Which of the following can aid in the formation of public opinion?", "images": [], "options": {"A": "Order-in-council", "B": "Free press", "C": "Existence of one party system", "D": "Existence of press censorship"}, "answer": "B", "explanation": "Public opinion is a view generally help by people on a giving public issue. In order for such views to be properly expressed, the press plays a dominant role in disseminating it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>37", "subject": "Government", "year": "2012", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "The Civil Service is an institution for", "images": [], "options": {"A": "Carrying out private organisational goals", "B": "Effecting civil society policies", "C": "Formulating and executing public policies", "D": "Initiating bureaucratic private agenda"}, "answer": "C", "explanation": "The Civil Service is an institution for formulating and executing public policies. The Civil Service is a sector of government composed mainly of career bureaucrats hired on professional merit rather than appointed or elected, whose institutional tenure typically survives transitions of political leadership. They are responsible for implementing the decisions of the government and formulating policies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>38", "subject": "Government", "year": "2012", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC/CIVIL SERVICE COMMISSION –MEANING AND FUNCTIONS.", "question": "The recruitment of personnel into the Civil Service by the Public Civil Service Commission prevents", "images": [], "options": {"A": "Political patronage", "B": "Bribery and corruption", "C": "Over staffing", "D": "Bureaucracy"}, "answer": "A", "explanation": "Civil Service Commission is responsible for the recruitment of personnel. This is to prevent political interference.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2012>39", "subject": "Government", "year": "2012", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "Which of the following manages a public corporation", "images": [], "options": {"A": "Chambers of Commerce", "B": "Board of directors", "C": "An Accountant- Genera", "D": "An Auditor- General"}, "answer": "B", "explanation": "A public corporation is managed by the Board of Directors while Civic service is managed by the Minister.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>40", "subject": "Government", "year": "2012", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "Local governments are essential because they", "images": [], "options": {"A": "Encourage division in a country", "B": "Implement government policies at national levels", "C": "Make laws for a nation", "D": "Train local people in the art of governing"}, "answer": "D", "explanation": "Local government is a government at the grass root level. It is essential for the training of people at the local level.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2012>41", "subject": "Government", "year": "2012", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "Which of the following delayed Nationalist movements in French West Africa?", "images": [], "options": {"A": "Presence of educated elite", "B": "The policy of assimilation", "C": "The use of local chiefs", "D": "Granting of freedom of Africans"}, "answer": "B", "explanation": "Assimilation was a \"harsh and unfair\" colonial policy adopted by the French colonial administration in Africa. It prevented all forms of political activities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>42", "subject": "Government", "year": "2012", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "The National Congress of British West Africa(NCBWA) was founded in", "images": [], "options": {"A": "Sierra Leone", "B": "Liberia", "C": "Ghana", "D": "Nigeria"}, "answer": "C", "explanation": "National Council of British West Africa (NCBWA) was formed in Ghana in 1919 by Joseph Caseley Hayford.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>43", "subject": "Government", "year": "2012", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "The West African Studenst Union (WASU) was formed by", "images": [], "options": {"A": "Siaka Stevens", "B": "K.A Gbedemah", "C": "E.F Small", "D": "Oladipo Solanke"}, "answer": "D", "explanation": "The West African Students Union (WASU) was formed by Oladipo Solanke. WASU was a student organization that was founded in London in 1925 by Nigerian student Ladipo Solanke and Sierra Leonean student Herbert Bankole-Bright. The organization was created to serve as a platform for students from British West Africa to challenge the racial prejudice they faced in Britain and to fight for the independence of African countries from colonial rule.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>44", "subject": "Government", "year": "2012", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "Military governments usually rule through", "images": [], "options": {"A": "Bye-laws", "B": "Decrees", "C": "Parliament", "D": "Statutes"}, "answer": "B", "explanation": "Military governments usually rule through decrees. A decree is a rule of law usually issued by a head of state (such as the president of a republic or a monarch), according to certain procedures. It has the force of law. In a military government, the military leader, who is the head of state, often rules by issuing decrees.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2012>45", "subject": "Government", "year": "2012", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "A military coup d'etat is followed by", "images": [], "options": {"A": "Enforcement of fundamental human rights", "B": "Suspension of the Constitution", "C": "Breaking of diplomatic relations with foreign countries", "D": "Mass importation of fire arms"}, "answer": "B", "explanation": "A military coup d'etat is usually followed by the suspension of the constitution. This is because a coup d'etat is a sudden and decisive action in politics, especially one resulting in a change of government illegally or by force. The military takes over the government and imposes its own rules, which often involves suspending the existing constitution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>46", "subject": "Government", "year": "2012", "type": "Objective", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "Which of the following factors influences a country's foreign policies?", "images": [], "options": {"A": "Size of the country's civil service", "B": "Overall national interest of the country", "C": "Capacity of the police force", "D": "Type of traditional rulers in the country"}, "answer": "B", "explanation": "The overall national interest of a country is a major factor that influences its foreign policies. Foreign policies are strategies that a country uses to safeguard its national interests and to achieve its goals in international relations. These policies are designed to help protect the country's national interests, and the overall national interest is the primary consideration in formulating these policies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>47", "subject": "Government", "year": "2012", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "The Organisation of African Unity (OAU)  was set up in", "images": [], "options": {"A": "Accra", "B": "Harare", "C": "Cairo", "D": "Addis Ababa"}, "answer": "D", "explanation": "The OAU (Organisation of African Unity) and now African Union (AU) was set up in Addis Ababa, Ethiopia in 1963.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2012>48", "subject": "Government", "year": "2012", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "The organ of the Organisation of African Unity (OAU) established for peaceful settlement of disputes is the", "images": [], "options": {"A": "Commission of Mediation, Conciliation and Arbitration", "B": "Council of Ministers", "C": "Secretariat", "D": "Assembly of heads of state and government"}, "answer": "A", "explanation": "Commission of Mediation, Counciliation and Arbitration is the organ of AU that is charged with peaceful settlement of dispute.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2012>49", "subject": "Government", "year": "2012", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "The head of Commonwealth of Nations is the", "images": [], "options": {"A": "Prime Ministers", "B": "High Commissioner", "C": "British Foreign Secretary", "D": "British Monarch"}, "answer": "D", "explanation": "Commonwealth of nations is an organisation that comprises all countries that were formally colonies of the British colonial administration. The organisation has the British Monarch as its head.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2012>50", "subject": "Government", "year": "2012", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "Which of the following organs of the United Nations has outlived its usefulness? The", "images": [], "options": {"A": "General Assembly", "B": "Trusteeship Council", "C": "International Court of Justice", "D": "Economic and Social Council"}, "answer": "B", "explanation": "The Trusteeship Council suspended its operations on 1 November 1994, a month after the independence of Palau, the last remaining United Nations trust territory.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2013>1", "subject": "Government", "year": "2013", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "Government can be defined as the study of", "images": [], "options": {"A": "Constitutions", "B": "Cabinet system of government only", "C": "How people rule themselves", "D": "Presidential system of government only"}, "answer": "C", "explanation": "Government is a system or group of people governing an organized community, often a state. In the case of its broad associative definition, government normally consists of legislature, executive, and judiciary. It is the means by which state policy is enforced, as well as the mechanism for determining the policy of the state. Therefore, the study of government is the study of how people rule themselves, not just the study of constitutions or specific systems of government.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2013>2", "subject": "Government", "year": "2013", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN INSTITUTION OF THE STATE:", "question": "Which of the following is not an acceptable function of the government?", "images": [], "options": {"A": "Defence", "B": "Subversion", "C": "Embarking on public enlightenment", "D": "Providing social amenities"}, "answer": "B", "explanation": "Subversion is not an acceptable function of the government. Subversion refers to an attempt to transform the established social order and its structures of power, authority, and hierarchy. This is contrary to the role of government, which is to maintain order, provide public services, ensure national security, and support the economic system. The other options listed, such as defense, public enlightenment, and providing social amenities, are all legitimate functions of government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2013>3", "subject": "Government", "year": "2013", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following is a feature of a state?", "images": [], "options": {"A": "Pursuance of sectional interest", "B": "Colonial experience", "C": "Territorial boundary", "D": "Temporary existence"}, "answer": "C", "explanation": "A state is a geographical organised people who have a defined territory with an organised legitimate government possessing the supreme power and authority. The features of a state are: Territory, government, sovereignty and population.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2013>4", "subject": "Government", "year": "2013", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "As a political ideology, communism seeks to", "images": [], "options": {"A": "Accumulate capital in the hands of a few", "B": "Accomodate division of citizens into classes", "C": "Eliminate all forms of socio-economic inequalities", "D": "Create economic opportunities for profit making"}, "answer": "C", "explanation": "Communism as a political ideology aims to establish a classless society where all property is publicly owned and each person works and is paid according to their abilities and needs. This means that communism seeks to eliminate all forms of socio-economic inequalities. Therefore, 'Eliminate all forms of socio-economic inequalities' is the correct answer.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2013>5", "subject": "Government", "year": "2013", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Totalitarianism means a government headed by", "images": [], "options": {"A": "A dictator", "B": "Wealthy people", "C": "Educated elite", "D": "The Masses"}, "answer": "A", "explanation": "Totalitarianism is a form of government which does not tolerate opposition. It is often always dictatorial in nature. It originated from Germany under Adolf Hitler.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2013>6", "subject": "Government", "year": "2013", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : MONARCHICAL", "question": "Monarch means government", "images": [], "options": {"A": "Headed by a king", "B": "By the people", "C": "Of the majority", "D": "Run by the elite"}, "answer": "A", "explanation": "Monarchy is a system of government headed by a royal title holder. The person exercising the power is the Monarch.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2013>7", "subject": "Government", "year": "2013", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The rule of law is observed when", "images": [], "options": {"A": "Democracy is practised", "B": "Laws are kept secret", "C": "Revolution is encouraged", "D": "Only the elite can govern"}, "answer": "A", "explanation": "Rule of law is the supremacy of law or constitution that stresses over all other considerations. This is commonly observed as one of the features of democracy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2013>8", "subject": "Government", "year": "2013", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Delegated legislation is necessary because it", "images": [], "options": {"A": "Helps to promote dictatorship", "B": "Prevents even development", "C": "Is useful in times of emergency", "D": "Gives a lot of power to the president"}, "answer": "C", "explanation": "Delegated Legislation is the act of transferring some of the legislature powers to other organs of government. One of the reasons for this is to meet up with emergency.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2013>9", "subject": "Government", "year": "2013", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "One of the criticisms against delegated legislation is that it", "images": [], "options": {"A": "Promotes separation of powers", "B": "Is not practised in advanced countries", "C": "Encroaches on parliamentary power", "D": "Gives too much power to the Judiciary"}, "answer": "C", "explanation": "Delegated Legislation gives access to other organs of government to encroach on the parliamentary power.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2013>10", "subject": "Government", "year": "2013", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Fundamental Human Rights seek to", "images": [], "options": {"A": "Promote dignity of man", "B": "Train political activists", "C": "Encourage economic activities", "D": "Enthrone mob rule"}, "answer": "A", "explanation": "Fundamental Human Rights seek to promote the dignity of man by making life and situation bearable to him.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2013>11", "subject": "Government", "year": "2013", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Constitutionalism implies that", "images": [], "options": {"A": "Citizens should read the constitution always", "B": "Leaders should ignore the dictates of the constitution", "C": "Citizens should challenge the provisions of the constitution", "D": "Leaders should act according to the stipulations of the constitution"}, "answer": "D", "explanation": "Constitutionalism is the idea, often associated with the political theories of John Locke and the 'founders' of the American republic, that government can and should be legally limited in its powers, and that its authority or legitimacy depends on its observing these limitations. Therefore, it implies that leaders should act according to the stipulations of the constitution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2013>12", "subject": "Government", "year": "2013", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "Which of the following is not a source of a country's constitution?", "images": [], "options": {"A": "Legislative decisions", "B": "Past constitutions", "C": "Writ of mandamus", "D": "Judicial precedents"}, "answer": "C", "explanation": "A country's constitution is derived from several sources including legislative decisions, past constitutions, and judicial precedents. However, a writ of mandamus, which is a court order compelling someone to execute a duty that they are legally obligated to complete, is not a source of a country's constitution. It is a form of legal remedy, not a source of constitutional law.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2013>13", "subject": "Government", "year": "2013", "type": "Objective", "topic": "CONSTITUTIONS : FUNCTIONS", "question": "Which of the following is not within the scope of a constitution?", "images": [], "options": {"A": "Fundamental human rights", "B": "Organs of government", "C": "Coup d'etat", "D": "Preamble"}, "answer": "C", "explanation": "A constitution is a set of fundamental principles or established precedents according to which a state or other organization is governed. These rules together make up, i.e. constitute, what the entity is. It includes fundamental human rights, organs of government, and preamble. However, a coup d'etat, which is a sudden and decisive action in politics, especially one resulting in a change of government illegally or by force, is not within the scope of a constitution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2013>14", "subject": "Government", "year": "2013", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY", "question": "Centralisation of power is a feature of a", "images": [], "options": {"A": "Federal system", "B": "Confederal system", "C": "Presidential system", "D": "Unitary system"}, "answer": "D", "explanation": "Unitary system of government is where all governmental powers are centred at the centre. This is centralisation of power.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2013>15", "subject": "Government", "year": "2013", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY", "question": "In a unitary system, governmental powers are concentrated at the", "images": [], "options": {"A": "Component units", "B": "Local level", "C": "Centre", "D": "Regions"}, "answer": "C", "explanation": "Unitary system of government is where all governmental powers are centred at the centre. This is centralisation of power.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2013>16", "subject": "Government", "year": "2013", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET", "question": "Which of the following is true of a parliamentary system of government?", "images": [], "options": {"A": "There is an Executive President", "B": "Fusion of powers is discouraged", "C": "Collective responsibility is emphasised", "D": "The Prime Minister is the head of the Judiciary"}, "answer": "C", "explanation": "In a parliamentary system of government, the principle of collective responsibility is highly emphasized. This means that all members of the government must publicly support all governmental decisions made in Cabinet, even if they do not privately agree with them. If a member of the government cannot support a policy of the government they are expected to resign. Therefore, the statement 'Collective responsibility is emphasised' is true of a parliamentary system of government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2013>17", "subject": "Government", "year": "2013", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PRESIDENTIAL", "question": "The system of government in which the President acts as the head of state, and the head of government is", "images": [], "options": {"A": "Diarchy", "B": "Presidential", "C": "Unitary", "D": "Parliamentary"}, "answer": "B", "explanation": "In a Presidential system of government, the President acts as both the head of state and the head of government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2013>18", "subject": "Government", "year": "2013", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : CONFEDERAL", "question": "Which of the following is true of a confederation?", "images": [], "options": {"A": "It has a rigid constitution", "B": "The central government is stronger than the component units", "C": "There is a legal right of secession", "D": "There is no provision for a state constitution"}, "answer": "C", "explanation": "A confederation is a union of sovereign states, united for purposes of common action. In a confederation, the central government is usually weaker than the component units and there is a legal right of secession. This means that the individual states or provinces have the right to leave the union if they choose to do so. This is different from a federation, where the central government is stronger and there is no legal right of secession.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2013>19", "subject": "Government", "year": "2013", "type": "Objective", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : ORIGINS, FACTORS AND STRUCTURE", "question": "Which of the following is a factor in the formation of a federation?", "images": [], "options": {"A": "Desire for a union", "B": "Absence of a common enemy", "C": "Small population", "D": "Geographical in contiguity"}, "answer": "A", "explanation": "A federation is a political entity characterized by a union of partially self-governing provinces, states, or other regions under a central federal government. The desire for a union is a key factor in the formation of a federation as it involves the coming together of different states or provinces to form a central government while still maintaining their individual autonomy.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2013>20", "subject": "Government", "year": "2013", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : EXECUTIVE", "question": "The formation and implementation of policies are the major duties of the", "images": [], "options": {"A": "Police", "B": "Judiciary", "C": "Executive", "D": "Legislature"}, "answer": "C", "explanation": "The executive organ of government is responsible for the formulation and implementation of government policies.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2013>21", "subject": "Government", "year": "2013", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "Bicameralism is adopted because it", "images": [], "options": {"A": "Guards against intra-party clashes", "B": "Prevents arbitrary law making", "C": "Projects party manifestoes", "D": "Is the only system available"}, "answer": "B", "explanation": "Bicameralism is two chambers of legislature operating in a country. The importance of it is to prevent arbitrary law making.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2013>22", "subject": "Government", "year": "2013", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "Parliamentary filibuster refers to a", "images": [], "options": {"A": "A procedure of impeaching the president", "B": "Delay method of prolonging debates in parliament", "C": "Process of passing bills into laws", "D": "A special way of initiating money bills"}, "answer": "B", "explanation": "Parliamentary filibuster refers to a delay method of prolonging debates in parliament. It is a tactic used in legislative bodies whereby debate over a proposed piece of legislation is extended, obstructing progress in a legislative assembly, which in turn can delay or entirely prevent a vote on the proposal. It is often used to delay or block the passage of legislation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2013>23", "subject": "Government", "year": "2013", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : EXECUTIVE", "question": "Which of the following functions is performed by the executive?", "images": [], "options": {"A": "Recruitment of judges", "B": "Passing of bills to laws", "C": "Adjudication of cases", "D": "Implementation of policies"}, "answer": "D", "explanation": "The executive branch of government is responsible for implementing, enforcing, and administering laws or policies. This means they put into action the laws that the legislative branch makes. Therefore, the correct answer is 'Implementation of policies'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2013>24", "subject": "Government", "year": "2013", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "When a court of law declares an action of the executive ultra-vires, it implies that", "images": [], "options": {"A": "The action is illegal, and above the power given", "B": "The executive has to implement the action", "C": "Such an action should be passed into law", "D": "Only the legislature can deal with such an action"}, "answer": "A", "explanation": "Ultra-vires means null and void. When a court declares the actions of the legislature or executive ultra-vires, it means the action is illegal and above the power given.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2013>25", "subject": "Government", "year": "2013", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "Which of the following is a duty of a good citizen?", "images": [], "options": {"A": "Paying tax regularly", "B": "Must assist the poor", "C": "Should challenge the law of the land", "D": "Must join the law enforcement agents"}, "answer": "A", "explanation": "A good citizen is expected to fulfill certain responsibilities and duties, one of which is paying taxes regularly. Taxes are a major source of government revenue, which is used to provide public goods and services. Therefore, paying taxes regularly is a duty of a good citizen. The other options do not necessarily represent duties of a good citizen. Assisting the poor, while commendable, is not a legal obligation. Challenging the law of the land can lead to legal consequences unless it's done through proper channels. Joining law enforcement is a career choice, not a civic duty.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2013>26", "subject": "Government", "year": "2013", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "Citizens can be deprived of their rights during", "images": [], "options": {"A": "Democratic regime", "B": "Parliamentary debate", "C": "Emergency periods", "D": "Political campaigns"}, "answer": "C", "explanation": "Fundamental human rights are in alienable rights. However, rights can be denied in some situations. For instance, the right to freedom of movement can be denied in emergency period.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2013>27", "subject": "Government", "year": "2013", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "Which of the following is an obligation of a citizen?", "images": [], "options": {"A": "Arresting offenders", "B": "Voting at elections", "C": "Prosecuting offenders", "D": "Adjudicating cases"}, "answer": "B", "explanation": "A citizen's obligation refers to the duties and responsibilities that a citizen is expected to fulfill. Voting at elections is one of the key obligations of a citizen. It is a way of participating in the democratic process and choosing leaders. Arresting offenders, prosecuting offenders, and adjudicating cases are typically the responsibilities of law enforcement agencies and the judiciary, not ordinary citizens.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2013>28", "subject": "Government", "year": "2013", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS", "question": "A multi-party system often leads to the formation of a", "images": [], "options": {"A": "Coalition government", "B": "Very strong executive", "C": "Dictatorial government", "D": "Confederal government"}, "answer": "A", "explanation": "A multi-party system often leads to the formation of a coalition government. This is because in a multi-party system, it is often difficult for a single party to gain an absolute majority. As a result, parties may need to form alliances or coalitions with other parties to form a government. A very strong executive, a dictatorial government, and a confederal government are not direct outcomes of a multi-party system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2013>29", "subject": "Government", "year": "2013", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Which of the following is not a function of a political party?", "images": [], "options": {"A": "Educating the government", "B": "Interest articulation", "C": "Aggregation of opinions", "D": "Selection of persons for government"}, "answer": "A", "explanation": "Political parties do not educate the government. Their functions include interest articulation, aggregation of opinions, and selection of persons for government. Interest articulation is the expression of political, economic, and social wants and needs of different interest groups in a society. Aggregation of opinions is the process of forming a common or collective opinion from individual opinions. Selection of persons for government is the process of choosing individuals to hold public offices.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2013>30", "subject": "Government", "year": "2013", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Franchise means the right of all qualified citizens to", "images": [], "options": {"A": "Manipulate election results", "B": "Conduct elections", "C": "Enforce electoral laws", "D": "Vote and be voted for"}, "answer": "D", "explanation": "Franchise refers to the right of all qualified citizens to vote and be voted for. It does not involve manipulating election results, conducting elections, or enforcing electoral laws. It is a fundamental democratic right that allows citizens to participate in the political process.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2013>31", "subject": "Government", "year": "2013", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "The geographical units into which a country is divided for the purpose of election are called", "images": [], "options": {"A": "States", "B": "Constituencies", "C": "Polling areas", "D": "County Councils"}, "answer": "B", "explanation": "The geographical units into which a country is divided for the purpose of election are called constituencies. A constituency is a geographical area that an elected official represents. It is the basic unit in electoral systems. The voters in a constituency choose their representative in an election.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2013>32", "subject": "Government", "year": "2013", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : ELECTORAL MANAGEMENT BODY", "question": "One way to ensure a free and fair election is to", "images": [], "options": {"A": "Operate a one-party system", "B": "Allow parties to campaign on election day", "C": "Guarantee the security of electoral officers and materials", "D": "Appoint a politician as the chairman of the electoral commission"}, "answer": "C", "explanation": "One way to ensure a free and fair election is to guarantee the security of electoral officers and materials. This is because the safety of the electoral officers and the integrity of the electoral materials are crucial for a free and fair election. If the officers are threatened or the materials are tampered with, it could lead to manipulation of the election results.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2013>33", "subject": "Government", "year": "2013", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "An election which involves the use of an electoral college is", "images": [], "options": {"A": "Run-off election", "B": "A general election", "C": "An open balloting", "D": "An indirect election"}, "answer": "D", "explanation": "An election which involves the use of an electoral college is an indirect election. An electoral college is a group of people appointed by each state who formally elect the President and Vice-President of the United States. This system is a process, not a place. The founding fathers established it in the Constitution, in part, as a compromise between the election of the President by a vote in Congress and election of the President by a popular vote of qualified citizens.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2013>34", "subject": "Government", "year": "2013", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : ELECTORAL MANAGEMENT BODY", "question": "Which of the following functions is performed by the electoral commission?", "images": [], "options": {"A": "Distribution of party membership cards", "B": "Presenting parties manifestoes", "C": "Delimiting the country into constituencies", "D": "Conducting oath of office for elected president"}, "answer": "C", "explanation": "One of the functions of the electoral commission is delimiting the country into constituencies. This means that the electoral commission is responsible for determining the boundaries of areas from which public representatives are to be elected. This is done to ensure that each representative represents approximately the same number of constituents. The other options are not primary functions of the electoral commission.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2013>35", "subject": "Government", "year": "2013", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Which of the following statements distinguishes political parties from pressure groups?", "images": [], "options": {"A": "Political parties only lobby government to change certain policies", "B": "Pressure groups select candidates for political offices", "C": "Political parties influence government policies", "D": "Pressure groups influence government policies to member's interest"}, "answer": "C", "explanation": "Political parties are different from pressure groups in that they seek to gain control of government to implement their policies, while pressure groups aim to influence those policies. Therefore, the statement 'Political parties influence government policies' distinguishes political parties from pressure groups.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2013>36", "subject": "Government", "year": "2013", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "Public opinion enables a government to", "images": [], "options": {"A": "Influence the public", "B": "Suppress its opponents", "C": "Cut down the cost of governing", "D": "Know the feeling of the masses"}, "answer": "D", "explanation": "Public opinion is a collective expression of the general population's thoughts on a particular issue. It enables a government to understand the feelings, thoughts, and attitudes of the masses towards its policies and actions. Therefore, 'Know the feeling of the masses' is the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2013>37", "subject": "Government", "year": "2013", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "The anonymity in the Civil Service means that a civil servant", "images": [], "options": {"A": "Is above the law of the land", "B": "Receives neither praise nor blame", "C": "Should take part in partisan politics", "D": "Should not be disciplined for any misconduct"}, "answer": "B", "explanation": "The anonymity in the Civil Service means that a civil servant receives neither praise nor blame. This is because civil servants are expected to provide impartial advice and implement government policies without seeking personal recognition or gain. They work behind the scenes and it is the elected officials who take the credit or blame for their actions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2013>38", "subject": "Government", "year": "2013", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "Which of the following is a problem of the Civil Service?", "images": [], "options": {"A": "Red-tapism", "B": "Offering professional advice to political leaders", "C": "Continuous keeping of records", "D": "Changing of government through election"}, "answer": "A", "explanation": "Red-tapism is synonymous protocol. Following due process. This actually slower down the decision and it is therefore, a problem of civil service.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2013>39", "subject": "Government", "year": "2013", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "Public corporations are set up by", "images": [], "options": {"A": "A Minister", "B": "A Director", "C": "A Permanent Secretary", "D": "An Act of parliament"}, "answer": "D", "explanation": "Public corporations are established by an Act of Parliament. This is because they are government-owned entities created to provide a specific service to the public. The Act of Parliament outlines the purpose, function, and powers of the corporation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2013>40", "subject": "Government", "year": "2013", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "Which of the following is true of a public corporation. It is", "images": [], "options": {"A": "Established by a bye-law", "B": "Owned by the Minister of Finance", "C": "Set up to make profit for share holders", "D": "Set up to provide essential services"}, "answer": "D", "explanation": "Public corporations are set up to provide essential services. They are not established to make profit for shareholders, but to provide services that are essential to the public, such as water, electricity, and transportation. They are owned by the government, not by the Minister of Finance or established by a bye-law.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2013>41", "subject": "Government", "year": "2013", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "All the following are problems facing local governments in West Africa except", "images": [], "options": {"A": "Shortage of trained personnel", "B": "Obtaining loans from banks", "C": "Nepotism", "D": "Corruption"}, "answer": "B", "explanation": "Local governments in West Africa face several challenges, including shortage of trained personnel, nepotism, and corruption. However, obtaining loans from banks is not a problem exclusive to local governments. It's a general problem that can affect any individual or organization, not just local governments. Therefore, it's not a correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2013>42", "subject": "Government", "year": "2013", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "Local authorities are established to", "images": [], "options": {"A": "Bring government nearer to the people", "B": "Give more powers to traditional rulers", "C": "Make people less loyal to the central government", "D": "Make central government interfere in local affairs"}, "answer": "A", "explanation": "Local authorities are established primarily to bring government nearer to the people. This is done by decentralizing the functions of the central government to the local level, thereby making governance more accessible and responsive to the needs of the people at the grassroots level. The other options do not accurately describe the purpose of local authorities.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2013>43", "subject": "Government", "year": "2013", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "A British Colony means", "images": [], "options": {"A": "A territory endowed with arable farm land", "B": "An area for colonial plantation", "C": "An area directly under the control of the traditional rulers and chiefs", "D": "A territory acquired by colonialist through settlement or conquest"}, "answer": "D", "explanation": "Colonial Masters got their colonies through conquest or negotiation. A British colony therefore means a territory acquired by the colonialist.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2013>44", "subject": "Government", "year": "2013", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Which of the following was not a reason for the adoption of the Indirect Rule in British West African Territories", "images": [], "options": {"A": "The chiefs approved of it", "B": "Administrative officers were in short supply", "C": "There was insufficient funding", "D": "The traditional rulers commanded respect among their subjects"}, "answer": "A", "explanation": "The adoption of Indirect Rule in British West African Territories was not because the chiefs approved of it. Indirect Rule was a system of governance used by the British to control their colonies. It was adopted due to reasons such as shortage of administrative officers, insufficient funding, and the respect commanded by traditional rulers among their subjects. The chiefs' approval was not a primary reason for its adoption.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2013>45", "subject": "Government", "year": "2013", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "A major disadvantage of the Indirect Rule system was that the", "images": [], "options": {"A": "Economy was over industrialised", "B": "Appointments were based on qualification", "C": "British failed to give qualitative education to Africans", "D": "Central administration was dominated by Africans"}, "answer": "C", "explanation": "One of the demerit of indirect rule system was that the British failed to provide qualitative education.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2013>46", "subject": "Government", "year": "2013", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The organ of the United Nations Organisation that co-ordinates the activities of its specialised agencies is the", "images": [], "options": {"A": "General Assembly", "B": "International Court of Justice", "C": "Economic and Social Council", "D": "Trusteeship Council"}, "answer": "C", "explanation": "Economic and social council (ECOSOC) is charged with the activities of special agencies of the United Nations Organisation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2013>47", "subject": "Government", "year": "2013", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The primary objective of the United Nations Organisation (UNO) is to", "images": [], "options": {"A": "Stop aggression", "B": "Help poor countries", "C": "Fight against injustice", "D": "Maintain world peace"}, "answer": "D", "explanation": "The primary objective of the United Nations Organisation (UNO) is to maintain world peace. The UNO was established after World War II with the aim of preventing future wars, promoting human rights, fostering social and economic development, protecting the environment, and providing aid in the event of natural disasters, armed conflict, and humanitarian crises.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2013>48", "subject": "Government", "year": "2013", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "Which of the following international organizations do all West African countries belong to", "images": [], "options": {"A": "Organisation of Petroleum Exporting Countries", "B": "North Atlantic Treaty Organisation", "C": "European Union", "D": "Organisation of African Unity"}, "answer": "D", "explanation": "All African States belong to African Union or Organisation African Unity is the only regional organisation that all African State belong.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2013>49", "subject": "Government", "year": "2013", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "Which of the following is not an organ of the Organisation of African Unity (OAU). The", "images": [], "options": {"A": "Assembly of Heads of State and Government", "B": "Tribunal of the Community", "C": "Council of Ministers", "D": "Secretariat"}, "answer": "B", "explanation": "The main organs of the Organisation of African Unity (OAU) include the Assembly of Heads of State and Government, the Council of Ministers, and the Secretariat. The 'Tribunal of the Community' is not an organ of the OAU.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2013>50", "subject": "Government", "year": "2013", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "The headquarter of the Economic Community of West African States (ECOWAS) Fund for Cooperation, Compensation and Development is located in", "images": [], "options": {"A": "Lome", "B": "Lagos", "C": "Accra", "D": "Dakar"}, "answer": "A", "explanation": "The Treaty establishing The Economic Community of West African States (ECOWAS) also instituted the ECOWAS Fund for Co­operation, Compensation and Development (ECOWAS Fund) as the Community's financial institution. It became operational in 1979.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2014>1", "subject": "Government", "year": "2014", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "Government protects the lives and property of the citizens of the state through the", "images": [], "options": {"A": "Courts and the police", "B": "Legislature and prisons", "C": "Ministers and the police", "D": "Customs and the police"}, "answer": "A", "explanation": "The protection of lives and property of citizen is done by the government through the courts and the police.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2014>2", "subject": "Government", "year": "2014", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Political power could be acquired through", "images": [], "options": {"A": "Persuasion", "B": "Election", "C": "Sanction", "D": "Nomination"}, "answer": "B", "explanation": "Political power can be acquired through election. In democratic societies, citizens elect their leaders through a process of voting. This is the most common and accepted means of acquiring political power. Persuasion, sanction, and nomination can play a role in the political process, but they do not directly lead to the acquisition of political power.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>3", "subject": "Government", "year": "2014", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following countries in Africa practiced socialism?", "images": [], "options": {"A": "Nigeria", "B": "Togo", "C": "Tanzania", "D": "Kenya"}, "answer": "C", "explanation": "Tanzania practiced socialism under the leadership of Julius Nyerere. He introduced a form of African socialism known as Ujamaa, which was characterized by the nationalization of banks and industries, collective farming, and villagization. None of the other countries listed practiced socialism.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2014>4", "subject": "Government", "year": "2014", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Nazism was introduced by", "images": [], "options": {"A": "Adolf Hitler", "B": "Tsar Nicholas II", "C": "Karl Marx", "D": "Mao Tse Tung"}, "answer": "A", "explanation": "Nazism, also known as National Socialism, was introduced by Adolf Hitler in Germany. It was a far-right political ideology that was characterized by extreme nationalism, racism, and totalitarianism. Tsar Nicholas II was a Russian monarch, Karl Marx was a philosopher who developed the theory of communism, and Mao Tse Tung was a Chinese communist leader. None of them introduced Nazism.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2014>5", "subject": "Government", "year": "2014", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The following are merits of separation of powers except", "images": [], "options": {"A": "Abuse of power", "B": "Freedom and Liberty", "C": "Stable political system", "D": "Absence of dominance"}, "answer": "A", "explanation": "Separation of Powers as a concept emphasizes that the three organs of government should act separately. It also gives rise to checks and balances. It prevents the encroachment of power or right as it guarantees the freedom of citizens.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>6", "subject": "Government", "year": "2014", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Which of the following is not a merit of checks and balances?", "images": [], "options": {"A": "Prevents excessive use of power", "B": "Has respect for human rights", "C": "Encourages the use of veto power", "D": "Prevents dictatorship"}, "answer": "C", "explanation": "Separation of Powers as a concept emphasizes that the three organs of government should act separately. It also gives rise to checks and balances. It prevents the encroachment of power or right as it guarantees the freedom of citizens.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>7", "subject": "Government", "year": "2014", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Representative government is alternatively called", "images": [], "options": {"A": "Rule of law", "B": "Indirect democracy", "C": "Separation of powers", "D": "Classical democracy"}, "answer": "B", "explanation": "Democracy is a system of representation, but direct democracy was not based on representative as all citizens directly took part in politics indirect democracy is a representational.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>8", "subject": "Government", "year": "2014", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "A constitution is a", "images": [], "options": {"A": "Set of regulations and customs", "B": "Body of doctrine and principles", "C": "Set of principles and customs", "D": "Body of rules, regulations and customs"}, "answer": "D", "explanation": "A constitution is a body of rules, regulations, and customs. It is a document that outlines the fundamental principles and established precedents according to which a state or other organization is governed. These rules together make up, i.e. constitute, what the entity is.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>9", "subject": "Government", "year": "2014", "type": "Objective", "topic": "CONSTITUTIONS : TYPES AND FEATURES", "question": "A feature of rigid constitution is that it requires", "images": [], "options": {"A": "Amendment by the Judiciary", "B": "One-third majority for its amendment", "C": "Special amendment procedures", "D": "The votes of the electorate for its amendment"}, "answer": "C", "explanation": "A rigid constitution is one that requires special procedures to be amended. This is to ensure that changes are not made lightly or without due consideration. The special procedures often involve more than a simple majority vote, and may require a supermajority or a referendum. Therefore, the correct answer is 'Special amendment procedures'.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2014>10", "subject": "Government", "year": "2014", "type": "Objective", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : FEATURES AND PROBLEMS", "question": "A characteristic of a federal system of government is that power is", "images": [], "options": {"A": "Shared between the central and unit governments", "B": "Shared between the component units of government", "C": "Held by the national government", "D": "Held by the state government"}, "answer": "A", "explanation": "Federal system of government exists where the powers of government are shared between the federal and other component unit(s).", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>11", "subject": "Government", "year": "2014", "type": "Objective", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : FEATURES AND PROBLEMS", "question": "In a federal system of government, education and health are examples of", "images": [], "options": {"A": "Separation of powers", "B": "Reserved powers", "C": "Concurrent powers", "D": "Exclusive powers"}, "answer": "C", "explanation": "Concurrent legislative powers are functions, exercised by both the federal and the state governments, and some of the items are health and education.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>12", "subject": "Government", "year": "2014", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "Which of the following is not a function of the Judiciary", "images": [], "options": {"A": "Settlement of disputes", "B": "Maintenance of law and order", "C": "Interpretation of law", "D": "Protection of rights"}, "answer": "B", "explanation": "The function of the Judiciary does not include the maintenance of law and order. This is primarily the responsibility of the executive branch of government, which includes law enforcement agencies. The Judiciary's main functions include the interpretation of laws, settlement of disputes, and protection of rights. The Judiciary ensures that laws are applied correctly and fairly, and it resolves disputes that arise under the law. It also protects individuals' rights by ensuring that laws and government actions do not violate these rights.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>13", "subject": "Government", "year": "2014", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "Statutes are", "images": [], "options": {"A": "Bills passed by the local government", "B": "Laws passed by the Judiciary", "C": "Bills passed by the executive", "D": "Laws passed by the parliament"}, "answer": "D", "explanation": "Statutes are laws that are passed by the parliament. A statute is a formal written enactment of a legislative authority that governs a state, city, or county. They are typically established by the legislative branch of government and are made in response to a perceived need to create laws or to clarify existing laws.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>14", "subject": "Government", "year": "2014", "type": "Objective", "topic": "CITIZENSHIP : MEANS OF SAFEGUARDING RIGHTS OF CITIZENS.", "question": "Slander limits a person's freedom of", "images": [], "options": {"A": "Expression", "B": "Movement", "C": "Association", "D": "Religion"}, "answer": "A", "explanation": "Slander limits a person's freedom of expression. Slander is a type of defamation which is a false statement, usually spoken or oral, that injures a person's reputation. This can limit a person's freedom of expression as they may be afraid to speak out due to fear of legal repercussions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>15", "subject": "Government", "year": "2014", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "Which of the following bodies has the right to change the laws of the country. The", "images": [], "options": {"A": "Judiciary", "B": "Ombudsman", "C": "Legislature", "D": "Executive"}, "answer": "C", "explanation": "The body that has the right to change the laws of a country is the Legislature. The Legislature is the law-making body of a political entity, usually a national government, that has power to amend, pass, and repeal laws. The Judiciary interprets the law, the Ombudsman investigates complaints against public entities, and the Executive is responsible for implementing and enforcing laws.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>16", "subject": "Government", "year": "2014", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "All the following are sources of revenue of a political party except", "images": [], "options": {"A": "Payment of dues", "B": "Donations", "C": "Custom duties", "D": "Fund raising"}, "answer": "C", "explanation": "Custom duties are not a source of revenue for a political party. Custom duties are taxes on imports and exports and they go to the government, not political parties. Payment of dues, donations, and fund raising are all common ways that political parties raise money.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>17", "subject": "Government", "year": "2014", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Part manifesto is important in the following ways except to", "images": [], "options": {"A": "Evaluate the party", "B": "Limit choice", "C": "Attract people", "D": "Guide the party"}, "answer": "B", "explanation": "Party Manifesto is a programme or plan of action which a political party intends to carry out if voted into power.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>18", "subject": "Government", "year": "2014", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS", "question": "Coalition can be defined as parties coming together", "images": [], "options": {"A": "To appoint a leader", "B": "To form a government", "C": "With a common manifesto", "D": "To oppose the government"}, "answer": "B", "explanation": "Coalition government is a situation whereby more than a political party come together to form government e.g APC of Nigeria during the 2015 elections.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2014>19", "subject": "Government", "year": "2014", "type": "Objective", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : FEATURES AND PROBLEMS", "question": "Which of the following West African countries practised a one-party system?", "images": [], "options": {"A": "Benin", "B": "Nigeria", "C": "Ghana", "D": "Liberia"}, "answer": "C", "explanation": "Ghana practised a one-party system under the leadership of Kwame Nkrumah. A one-party system is a type of state in which one political party has the right to form the government, usually based on the existing constitution. All other parties are either outlawed or allowed to take only a limited and controlled participation in elections.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2014>20", "subject": "Government", "year": "2014", "type": "Objective", "topic": "CITIZENSHIP : MEANING AND MODE OF ACQUISITION", "question": "In limited franchise, restriction on voting can be based on", "images": [], "options": {"A": "Height", "B": "Property", "C": "Strength", "D": "Exposure"}, "answer": "B", "explanation": "In limited or restricted franchise, restriction on voting can be based on colour, gender or property.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2014>21", "subject": "Government", "year": "2014", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Which of the following is a limitation of Universal Adult Suffrage?", "images": [], "options": {"A": "Wealth", "B": "Age", "C": "Race", "D": "Sex"}, "answer": "B", "explanation": "Universal adult suffrage is based on \"age\" as a requirement to vote. For instance, in a country like Nigeria any citizen who is under the age of 18 is not permitted to vote.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>22", "subject": "Government", "year": "2014", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Which of the following is an example of a general election?", "images": [], "options": {"A": "Bye election", "B": "Presidential Election", "C": "Local election", "D": "Student Union Election"}, "answer": "B", "explanation": "General election is that election that is conducted in the whole country at the same time under the same condition. Example is Presidential election.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>23", "subject": "Government", "year": "2014", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "The purpose of an election is to", "images": [], "options": {"A": "Allow people to participate in choosing their leaders", "B": "Provide social amenities for the electorate", "C": "Give political education to the rich", "D": "Allow the counting of votes in public"}, "answer": "A", "explanation": "The purpose of an election is to allow people to participate in choosing their leaders. This is a fundamental aspect of democratic governance where citizens have the right to choose who will represent them in government. The other options do not accurately represent the primary purpose of an election.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>24", "subject": "Government", "year": "2014", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Universal Adult Suffrage is popular because it", "images": [], "options": {"A": "Allows for equal political representation", "B": "Allows for greater political participation", "C": "Encourages a multi-party system", "D": "Ensures equal performance of all political system"}, "answer": "B", "explanation": "Universal Adult Suffrage is popular because it allows for greater political participation. Universal suffrage refers to the right of almost all adults to vote in political elections. It is a key aspect of democratic societies and is popular because it allows all citizens, regardless of their social or economic status, to have a say in who governs them. The other options, while they may be effects or characteristics of universal suffrage, do not capture the primary reason for its popularity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>25", "subject": "Government", "year": "2014", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Which of the following is not a factor that promotes democratic electoral system?", "images": [], "options": {"A": "Political consciousness", "B": "Periodic election", "C": "Up-to-date electoral register", "D": "Popularity of the governor"}, "answer": "D", "explanation": "The popularity of the governor is not a factor that promotes a democratic electoral system. A democratic electoral system is promoted by factors such as political consciousness, periodic elections, and an up-to-date electoral register. These factors ensure that citizens are aware of their political rights, elections are held regularly to allow citizens to choose their leaders, and that all eligible voters are accounted for. The popularity of a governor, however, does not necessarily promote a democratic electoral system as it is subjective and can be influenced by factors outside of the democratic process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>26", "subject": "Government", "year": "2014", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "A factor that could make elections free and fair is the", "images": [], "options": {"A": "Existence of dependent electoral commission", "B": "Adoption of a flexible constitution", "C": "Opportunity for people to vote twice", "D": "Registration of eligible voters"}, "answer": "D", "explanation": "The registration of eligible voters is a factor that could make elections free and fair. This is because it ensures that all citizens who are eligible to vote are given the opportunity to do so. This promotes equality and fairness in the electoral process. The existence of a dependent electoral commission, on the other hand, could potentially compromise the fairness of elections as it may be influenced by external factors. Similarly, the adoption of a flexible constitution and the opportunity for people to vote twice could also compromise the integrity of the electoral process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>27", "subject": "Government", "year": "2014", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : ELECTORAL MANAGEMENT BODY", "question": "The body responsible for conducting and supervising elections in West African countries is called", "images": [], "options": {"A": "Ombudsman", "B": "Electoral Commission", "C": "Election observers", "D": "Constituent assembly"}, "answer": "B", "explanation": "The body responsible for conducting and supervising elections in West African countries is called the Electoral Commission. This body is responsible for ensuring that elections are conducted in a free and fair manner. It is also responsible for the registration of voters, the conduct of elections, and the declaration of results.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>28", "subject": "Government", "year": "2014", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Which of the following is not a problem of an electoral commission in West Africa?", "images": [], "options": {"A": "Electoral malpractice", "B": "Inadequate personnel", "C": "Inadequate funds", "D": "Registration of voters"}, "answer": "D", "explanation": "Registration of voters is not a problem of an electoral commission in West Africa, rather it is one of the responsibilities of the electoral commission. The electoral commission is responsible for registering eligible voters, conducting elections, and declaring results. Problems that the electoral commission might face include electoral malpractice, inadequate personnel, and inadequate funds.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>29", "subject": "Government", "year": "2014", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "Which of the following is not an aim of pressure groups?", "images": [], "options": {"A": "Contesting election", "B": "Agitating for interests", "C": "Influencing government decisions", "D": "Education for their members"}, "answer": "A", "explanation": "Pressure groups are organizations that attempt to influence government policies but do not seek to gain control of government through election. Therefore, contesting election is not an aim of pressure groups.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2014>30", "subject": "Government", "year": "2014", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "A pressure group formed only by teachers is", "images": [], "options": {"A": "A promotional group", "B": "An occupational group", "C": "A religious group", "D": "An economic group"}, "answer": "B", "explanation": "A pressure group formed only by teachers is an occupational group. Occupational groups are pressure groups that represent the interests of their members who share the same job or profession.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2014>31", "subject": "Government", "year": "2014", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "Neutrality in the Civil Service means that", "images": [], "options": {"A": "The government can seek or replace top civil servants", "B": "Officials can only be removed from office due to ill health", "C": "Civil servant should be loyal to the government and non-partisan", "D": "Officials need to defend the budget in parliament"}, "answer": "C", "explanation": "Neutrality in the Civil Service means that civil servants should be loyal to the government and non-partisan. This means they should not show favoritism or bias towards any political party or group. They should serve the government of the day and implement its policies without any prejudice.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>32", "subject": "Government", "year": "2014", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "Red-tapism in the Civil Service is a product of", "images": [], "options": {"A": "Democracy", "B": "Autocracy", "C": "Bureaucracy", "D": "Theocracy"}, "answer": "C", "explanation": "Another name for Red-tapism is Bureaucracy. It is the practice of requiring excessive paperwork and tedious procedures before official action can be considered or completed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>33", "subject": "Government", "year": "2014", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "An advantage of public corporations in West Africa is", "images": [], "options": {"A": "Creation of exposure", "B": "Political interference", "C": "Provision of employment", "D": "Provision of all the services needed"}, "answer": "D", "explanation": "Providing for all the services needed by citizens is an advantage of public corporations in West Africa.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>34", "subject": "Government", "year": "2014", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "The central government can reduce annual subventions to public corporations through", "images": [], "options": {"A": "Parliamentary control", "B": "Ministerial control", "C": "Judicial control", "D": "Public control"}, "answer": "A", "explanation": "Parliamentary control  an come in form of calling for the corporations to carry out audit so as to know more about the financial life of corporations.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2014>35", "subject": "Government", "year": "2014", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "Collection of rates is a source of revenue to", "images": [], "options": {"A": "Civil servants", "B": "Ministerial control", "C": "Local authorities", "D": "Central government"}, "answer": "C", "explanation": "Collection of rates is a source of revenue to local authorities. Rates are a type of tax that property owners pay to local authorities, not to civil servants, ministerial control, or the central government. The revenue collected from rates is used to fund local services such as waste collection, road maintenance, and public parks.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2014>36", "subject": "Government", "year": "2014", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "The money given by the central government to local authorities is known as", "images": [], "options": {"A": "Block grants", "B": "Capital expenditure", "C": "Loans", "D": "Royalties"}, "answer": "A", "explanation": "The money given by the central government to local authorities is known as block grants. Block grants are a form of financial aid that the central government gives to local authorities to fund various programs and services. They are not considered capital expenditure, loans, or royalties. Capital expenditure refers to funds used by a company to acquire or upgrade physical assets such as property, industrial buildings or equipment. Loans are borrowed money that needs to be repaid with interest. Royalties are payments made to an individual or company for the use of its property, such as patents, copyrighted works, or natural resources.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>37", "subject": "Government", "year": "2014", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI", "question": "The laws of the pre-colonial African political systems were", "images": [], "options": {"A": "Written", "B": "Codified", "C": "Unwritten", "D": "Rigid"}, "answer": "C", "explanation": "The laws of the pre-colonial African political systems were unwritten. This means that they were not formally inscribed in any document, but were instead passed down orally from generation to generation. This is a common characteristic of many traditional societies, where the law is embedded in the customs and practices of the people.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>38", "subject": "Government", "year": "2014", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "Auditing the accounts of public corporations amounts to", "images": [], "options": {"A": "Media control", "B": "Judicial control", "C": "Public control", "D": "Financial control"}, "answer": "D", "explanation": "Auditing the accounts of public corporations amounts to financial control. Auditing is a process of examining the financial records of an organization to ensure that they are accurate and in accordance with any applicable rules (including statutory regulations), internal controls, and industry standards. Therefore, it is a form of financial control as it is a way of checking that the financial affairs of public corporations are being conducted properly.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2014>39", "subject": "Government", "year": "2014", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "The following were features of the French policy of Assimilation except", "images": [], "options": {"A": "Centralised administration", "B": "Recognition of chieftaincy institution", "C": "Limited education", "D": "Indigent policy"}, "answer": "B", "explanation": "The French policy of Assimilation was a colonial policy where the French tried to assimilate the colonized people into French culture and society. This policy did not recognize the chieftaincy institution as it was seen as a form of traditional governance that was not in line with French governance. Therefore, the recognition of chieftaincy institution was not a feature of the French policy of Assimilation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2014>40", "subject": "Government", "year": "2014", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "The recurrent coups in West African countries resulted in", "images": [], "options": {"A": "Dictatorship", "B": "Political instability", "C": "Nepotism", "D": "Poor conditions in the army"}, "answer": "B", "explanation": "The recurrent coups in West African countries often resulted in political instability. A coup d'etat is a sudden and decisive action in politics, especially one resulting in a change of government illegally or by force. This often leads to a period of instability as the new government tries to establish itself and gain control. Therefore, political instability is a common result of recurrent coups.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2014>41", "subject": "Government", "year": "2014", "type": "Objective", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "Foreign policy refers to the", "images": [], "options": {"A": "Policy made by a foreign country", "B": "Policy made by a country for foreigners", "C": "Principles that govern a country when it is at war", "D": "Principles that govern a state's international behaviour"}, "answer": "D", "explanation": "Foreign policy refers to the principles that govern a state's international behaviour. It is a strategy or approach chosen by national governments to achieve diplomatic goals. It is not a policy made by a foreign country or for foreigners, and it is not only applicable when a country is at war.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2014>42", "subject": "Government", "year": "2014", "type": "Objective", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : FEATURES AND PROBLEMS", "question": "Which of the following is a factor for the adoption of a unitary system of government in some West African Countries?", "images": [], "options": {"A": "Vast territories", "B": "Small territories", "C": "Abundant resources", "D": "Heterogenous culture"}, "answer": "B", "explanation": "One of the basic condition for the adoption of the Unitary system of government is small size of the country (The country has to be small).", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>43", "subject": "Government", "year": "2014", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "Which of the following is a permanent member of the Security Council of the United Nations Organisation (UNO)?", "images": [], "options": {"A": "Germany", "B": "Japan", "C": "Canada", "D": "Russia"}, "answer": "D", "explanation": "The United Nations Security Council (UNSC) is one of the six main organs of the United Nations, charged with ensuring international peace and security, accepting new members to the United Nations and approving any changes to its charter. Its powers include the establishment of peacekeeping operations, the establishment of international sanctions, and the authorization of military action. The UNSC comprises of 15 members, out of which 5 are permanent members. The five permanent members are China, France, Russia, the United Kingdom, and the United States.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2014>44", "subject": "Government", "year": "2014", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "The Commonwealth is", "images": [], "options": {"A": "An economic organisation for the Caribbeans", "B": "A political organisation formed during the first world war", "C": "Made up of all independent ex-colonies of Britain", "D": "Made up of independent European countries"}, "answer": "C", "explanation": "The Commonwealth is a political association of 54 member states, nearly all of which are former territories of the British Empire. The chief institutions of the organisation are the Commonwealth Secretariat, which focuses on intergovernmental aspects, and the Commonwealth Foundation, which focuses on non-governmental relations amongst member states. The Commonwealth dates back to the first half of the 20th century with the decolonisation of the British Empire through increased self-governance of its territories. It was formally constituted by the London Declaration in 1949, which established the member states as 'free and equal'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2014>45", "subject": "Government", "year": "2014", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The United Natios Organisation(UNO) came into existence in", "images": [], "options": {"A": "1945", "B": "1948", "C": "1950", "D": "1953"}, "answer": "A", "explanation": "The United Nations Organization (UNO) was established on October 24, 1945, after World War II, with the aim of preventing future wars. The UN Charter, which is the foundational treaty of the United Nations, was ratified on this date by the majority of its signatories, including the five permanent members of the Security Council.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2014>46", "subject": "Government", "year": "2014", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "The head of the Commonwealth of Nations is", "images": [], "options": {"A": "German Chancellor", "B": "President of America", "C": "Queen of England", "D": "British Prime Minister"}, "answer": "C", "explanation": "The head of the Commonwealth of Nations is the Queen of England. The Commonwealth of Nations, generally known simply as the Commonwealth, is a political association of 54 member states, nearly all of which are former territories of the British Empire. The head of the Commonwealth is Queen Elizabeth II.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2014>47", "subject": "Government", "year": "2014", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "A Commonwealth member that has no colonial link with the United Kingdom is", "images": [], "options": {"A": "Nigeria", "B": "Kenya", "C": "Ghana", "D": "Mozambique"}, "answer": "D", "explanation": "Mozambique is a member of the Commonwealth of Nations but it was never a colony of the United Kingdom. It was a Portuguese colony. The Commonwealth of Nations is a political association of 54 member states, nearly all of which are former territories of the British Empire.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>48", "subject": "Government", "year": "2014", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "The meetings of the Commonwealth of Nations are held once every", "images": [], "options": {"A": "Six years", "B": "Five years", "C": "Three years", "D": "Two years"}, "answer": "D", "explanation": "They are held once every two years, although this pattern has twice been interrupted. They are held around the Commonwealth, rotating by invitation amongst its members.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2014>49", "subject": "Government", "year": "2014", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "The ECOWAS Fund for Co-operation,Compensation and Development is located in", "images": [], "options": {"A": "Togo", "B": "Nigeria", "C": "The Gambia", "D": "Sierra Leone"}, "answer": "B", "explanation": "The ECOWAS Fund for Co-operation, Compensation and Development is located in Nigeria. The ECOWAS Fund for Co-operation, Compensation and Development was established to provide financial support for the development projects within the ECOWAS region. The fund is managed by the ECOWAS Bank for Investment and Development (EBID), which is headquartered in Nigeria.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2014>50", "subject": "Government", "year": "2014", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The organ responsible for investigating internal disputes in the United Nations Organisation (UNO) is the", "images": [], "options": {"A": "General Assembly", "B": "Security Council", "C": "Secretariat", "D": "Economic and Social Council"}, "answer": "B", "explanation": "Under the Charter, the Security Council has primary responsibility for the maintenance of international peace and security.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2015>1", "subject": "Government", "year": "2015", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN INSTITUTION OF THE STATE:", "question": "Which of the following best defines government as an institution of the state?", "images": [], "options": {"A": "An institution established for class struggle", "B": "Machinery established for exercising political power", "C": "A process of organizing societal values", "D": "The art through which political parties are managed"}, "answer": "B", "explanation": "It is the political direction and control exercised over the actions of the members, citizens, or inhabitants of communities, societies, and states; direction of the affairs of a state, community, etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>2", "subject": "Government", "year": "2015", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN ACADEMIC FIELD OF STUDY – REASONS FOR STUDYING GOVERNMENT.", "question": "Which of the following is a reason for studying government?", "images": [], "options": {"A": "Knowledge of the rights of the individual", "B": "Acquisition of skills to work in a state-owned industry", "C": "Helps the individual to form a pressure group", "D": "Enables citizens to vote during elections"}, "answer": "A", "explanation": "Studying government is important for the knowledge of the rights of the individual. This is because understanding how government works helps citizens learn how to influence government and what role they play in it. This knowledge includes understanding the rights and responsibilities of citizens, how government decisions are made, and the processes by which citizens can participate in their government.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2015>3", "subject": "Government", "year": "2015", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "The most visible feature of a state is", "images": [], "options": {"A": "Compulsory membership", "B": "Defined geographical territory", "C": "Written constitution", "D": "Sovereign power"}, "answer": "B", "explanation": "The most visible feature of a state is its defined geographical territory. This is because a state is a politically organized body of people usually occupying a definite territory. Hence, the territory is the physical area within which the state exercises its sovereignty.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>4", "subject": "Government", "year": "2015", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Representative democracy is characterised by", "images": [], "options": {"A": "Free election and proper register of voters", "B": "A politically educated elite", "C": "Representation of the poor only", "D": "Rule of the interest groups"}, "answer": "A", "explanation": "Representative democracy is characterized by free election and proper register of voters. In a representative democracy, citizens elect representatives to make decisions and pass laws on behalf of all the people instead of the people voting directly on laws. Free and fair elections and proper register of voters ensure that the elected representatives truly represent the will of the people.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2015>5", "subject": "Government", "year": "2015", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The set of attitudes and beliefs that determine that behaviour of citizens in a political system is called", "images": [], "options": {"A": "Socialisation", "B": "Political culture", "C": "Representation government", "D": "Devolution"}, "answer": "B", "explanation": "Political culture refers to the set of attitudes, beliefs, and sentiments which give order and meaning to a political process and which provide the underlying assumptions and rules that govern behavior in the political system. It encompasses both the political ideals and operating norms of a polity.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2015>6", "subject": "Government", "year": "2015", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Fundamental human rights are entrenched in constitutions purposely to", "images": [], "options": {"A": "Ensure freedom of speech", "B": "Guarantee the liberty of citizens", "C": "Promote good governance", "D": "Promote trade"}, "answer": "B", "explanation": "Fundamental human rights are entrenched in constitutions to guarantee the liberty of citizens. These rights are basic and are meant to protect individuals from any form of abuse or violation from the government, organizations, or other individuals. They include rights such as the right to life, freedom of speech, freedom of assembly, and the right to a fair trial among others.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>7", "subject": "Government", "year": "2015", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Diplomatic and parliamentary put limitations on", "images": [], "options": {"A": "The rule of law", "B": "Separation of powers", "C": "Checks and balances", "D": "Foreign policies"}, "answer": "C", "explanation": "Diplomatic and parliamentary immunity put limitations on the concept of checks and balances. Checks and balances is a system where each branch of government can amend or veto acts of another branch so as to prevent any one branch from exerting too much power. Diplomatic and parliamentary immunity can limit this system as it provides certain privileges and protections to diplomats and parliamentarians, which can prevent them from being held accountable in the same way as other branches of government.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2015>8", "subject": "Government", "year": "2015", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Montesquieu's political theory of separation of powers was meant to", "images": [], "options": {"A": "Promote unity in government", "B": "Prevent dictatorial rule", "C": "Ensure social justice", "D": "Enhance state security"}, "answer": "B", "explanation": "Montesquieu's political theory of separation of powers was meant to prevent dictatorial rule. The separation of powers is a model for the governance of a state where the state is divided into branches, each with separate and independent powers and areas of responsibility so that the powers of one branch are not in conflict with the powers associated with the other branches. This system is designed to prevent the concentration of power and provide for checks and balances.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>9", "subject": "Government", "year": "2015", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY", "question": "Which of the following countries practised a centralised system of government?", "images": [], "options": {"A": "Nigeria", "B": "Ghana", "C": "USA", "D": "India"}, "answer": "A", "explanation": "A centralized system of government is one in which power or legal authority is exerted or coordinated by a de facto political executive to which federal states, local authorities, and smaller units are considered subject. In this system, the central government makes all decisions about the policy, laws, and public welfare. Nigeria is a good example of a country that practices a centralized system of government.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2015>10", "subject": "Government", "year": "2015", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "Which of the following countries operates an unwritten constitution?", "images": [], "options": {"A": "Britain", "B": "USA", "C": "Japan", "D": "Canada"}, "answer": "A", "explanation": "An unwritten constitution is a type of constitution where the fundamental rules often take the form of customs, usage, precedent and a variety of statutes and legal instruments. An example of an unwritten constitution is the Constitution of the United Kingdom. This is because, unlike in other countries like the USA and Canada, the UK does not have a single, written document that forms the constitution. Instead, it is made up of statutes (laws), conventions, judicial decisions, treaties, and works of authority.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2015>11", "subject": "Government", "year": "2015", "type": "Objective", "topic": "CONSTITUTIONS : TYPES AND FEATURES", "question": "A constitution that can be amended through ordinary law making process is said to be", "images": [], "options": {"A": "Written", "B": "Unwritten", "C": "Rigid", "D": "Flexible"}, "answer": "D", "explanation": "A flexible constitution is one that can be amended through ordinary law making process. This is because a flexible constitution does not have a special procedure for amendment, unlike a rigid constitution which requires a special procedure that is different from the ordinary law making process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>12", "subject": "Government", "year": "2015", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Which of the following systems of governments operates on the principles of checks and balances?", "images": [], "options": {"A": "Theocracy", "B": "Presidential", "C": "Parliamentary", "D": "Monarchical"}, "answer": "B", "explanation": "Presidential system of government operates on the platform of checks and balances as a result of separation of powers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>13", "subject": "Government", "year": "2015", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : CONFEDERAL", "question": "Confederal system of government means", "images": [], "options": {"A": "Powerful centre and weak component units", "B": "Weak centre and powerful component units", "C": "Powerful centre and powerful component units", "D": "Weak component units and weak centre"}, "answer": "B", "explanation": "A confederal system of government is a system where the component units (states or regions) have more power than the central government. This means that the central government is weak and the component units are powerful. This system allows for a high degree of regional or local autonomy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>14", "subject": "Government", "year": "2015", "type": "Objective", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : FEATURES AND PROBLEMS", "question": "In a federal system of government, the power shared between the central and state government is known as", "images": [], "options": {"A": "Legislative power", "B": "Exclusive power", "C": "Concurrent power", "D": "Judicial power"}, "answer": "C", "explanation": "In a federal system of government, the power that is shared between the central and state government is known as concurrent power. Concurrent powers are powers that are shared by both the state and the federal government. These powers may be exercised simultaneously within the same territory and in relation to the same body of citizens. These powers are contrasted with exclusive powers, which only the federal or state government can exercise, and with reserved powers, which are only granted to the state governments.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>15", "subject": "Government", "year": "2015", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : EXECUTIVE", "question": "The prerogative power resides with the", "images": [], "options": {"A": "Ombudsman", "B": "Executive", "C": "National assembly", "D": "Civil organisation"}, "answer": "B", "explanation": "Prorogation of Mercy is the power vested on the head of executive to grand pardon to a condemned citizen/ criminal.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2015>16", "subject": "Government", "year": "2015", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : REPUBLICAN", "question": "Quick decision making is an advantage of", "images": [], "options": {"A": "Unicameralism", "B": "Constitutionalism", "C": "Federalism", "D": "Republicanism"}, "answer": "A", "explanation": "Unicameralism one chamber of legislature. It enables quick decision making as there is no need for long processes or consultations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>17", "subject": "Government", "year": "2015", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : EXECUTIVE", "question": "The organ of government responsible for the implementation of policies in a state is the", "images": [], "options": {"A": "Legislature", "B": "Judiciary", "C": "Executive", "D": "Public Bureau"}, "answer": "C", "explanation": "The executive branch of government is responsible for the implementation of policies in a state. The executive branch includes the president, vice president, the Cabinet, executive departments, independent agencies, and other boards, commissions, and committees. Their responsibility is to enforce laws and implement policies passed by the legislative branch.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2015>18", "subject": "Government", "year": "2015", "type": "Objective", "topic": "CITIZENSHIP : MEANING AND MODE OF ACQUISITION", "question": "A citizen is an individual who", "images": [], "options": {"A": "Has the legal and political rights in a country", "B": "Has lived in a country for sometime", "C": "Enjoys only economic rights", "D": "Enjoys immunity in the country"}, "answer": "A", "explanation": "A citizen is an individual who has the legal and political rights in a country. This includes the right to live and work in that country, to vote in elections, to receive government protection, and to benefit from the country's laws. Citizenship is usually gained by birth within a certain territory, descent from a citizen parent, marriage to a citizen, and naturalization.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2015>19", "subject": "Government", "year": "2015", "type": "Objective", "topic": "CITIZENSHIP : MEANING AND MODE OF ACQUISITION", "question": "Which of the following is a condition for granting citizenship to a foreigner?", "images": [], "options": {"A": "Swearing an oath of allegiance", "B": "Possession of a university degree", "C": "A registered member of a political party", "D": "Possession of an international passport"}, "answer": "A", "explanation": "A foreigner can be granted citizenship in a country by swearing an oath of allegiance to that country. This is a common practice in many countries where the foreigner pledges loyalty to the country and its laws. The other options do not necessarily qualify a foreigner for citizenship. Possession of a university degree or an international passport, or being a registered member of a political party, are not universal conditions for granting citizenship.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>20", "subject": "Government", "year": "2015", "type": "Objective", "topic": "CITIZENSHIP : MEANING AND MODE OF ACQUISITION", "question": "Citizenship can be acquired through all of the following methods except", "images": [], "options": {"A": "Birth", "B": "Nationalization", "C": "Naturalisation", "D": "Marriage"}, "answer": "B", "explanation": "Citizenship can be acquired through birth, naturalisation, and marriage. However, nationalization is not a method of acquiring citizenship. Nationalization refers to the process by which a state takes control of a private industry or assets, not the process of granting citizenship to individuals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>21", "subject": "Government", "year": "2015", "type": "Objective", "topic": "CITIZENSHIP : MEANING AND MODE OF ACQUISITION", "question": "The conferment of citizenship on a distinguished personality of another country is called", "images": [], "options": {"A": "Citizenship by birth", "B": "Honorary citizenship", "C": "Adoption", "D": "Citizenship by registration"}, "answer": "B", "explanation": "Honorary citizens is when a person is conferred with the citizenship of another country or a country on the basis of his/her contribution to the development of the country.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2015>22", "subject": "Government", "year": "2015", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "The primary aim of any political party is to", "images": [], "options": {"A": "Pressurize the government", "B": "Remain in the opposition", "C": "Control the government", "D": "Ensure fair play in business"}, "answer": "C", "explanation": "The primary aim of any political party is to Control the government. Political parties are organized groups of people with similar ideas about the way a country or region should be governed. They aim to be elected into power so they can implement their policies and ideas. Pressurizing the government, remaining in the opposition, and ensuring fair play in business can be activities of a political party, but they are not the primary aim.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>23", "subject": "Government", "year": "2015", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "A manifesto can be defined as the", "images": [], "options": {"A": "Opportunity to form a political party", "B": "Proposed programmes of a political party", "C": "Policy of a political party in power", "D": "Power to rule the masses"}, "answer": "B", "explanation": "A manifesto is a public declaration of policies and aims, especially one issued before an election by a political party or candidate. Therefore, it is the proposed programmes of a political party. It is not the opportunity to form a political party, the policy of a political party in power, or the power to rule the masses.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>24", "subject": "Government", "year": "2015", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS", "question": "Which of the following exists in a one-party state?", "images": [], "options": {"A": "Only the workers' party is allowed to exist", "B": "Only the students' party is allowed to exist", "C": "Elections to the legislature are held at the party's conference", "D": "The ruling party is the only legal party"}, "answer": "D", "explanation": "In a one-party state, only one political party is allowed to govern or exist. This means that the ruling party is the only legal party. It is not that only the workers' party or the students' party is allowed to exist, or that elections to the legislature are held at the party's conference.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2015>25", "subject": "Government", "year": "2015", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS", "question": "Which of the following party systems best represents all shades of opinions?", "images": [], "options": {"A": "Multi-party", "B": "Two-party", "C": "One-party", "D": "Elite party"}, "answer": "A", "explanation": "Multi-party system is believed to represent all shades of opinion as it makes available diverse programmes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>26", "subject": "Government", "year": "2015", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "The practice of multi-party system in West Africa tends to promote", "images": [], "options": {"A": "Sectionalism and factionalism", "B": "National integration", "C": "Social discrimination", "D": "Economic integration"}, "answer": "A", "explanation": "The practice of multi-party system in West Africa tends to promote sectionalism and factionalism. This is because in a multi-party system, each party tends to represent a particular section or faction of the society, often based on ethnic, religious or regional lines. This can lead to division and conflict, rather than promoting national or economic integration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>27", "subject": "Government", "year": "2015", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Franchise is the right to", "images": [], "options": {"A": "Express political views", "B": "Control the government", "C": "Vote and be voted for", "D": "Ensure good governance"}, "answer": "C", "explanation": "Franchise refers to the right granted to citizens to participate in the political process through voting in elections. It is the right to vote and be voted for. It does not directly relate to expressing political views, controlling the government, or ensuring good governance, although these can be indirect outcomes of exercising franchise.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2015>28", "subject": "Government", "year": "2015", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "The following are the aims of an election except that", "images": [], "options": {"A": "A group sticks on to power", "B": "There is accountability of the leaders", "C": "There is a smooth change of government", "D": "The people determine who rules"}, "answer": "A", "explanation": "The aims of an election include accountability of leaders, smooth change of government, and allowing the people to determine who rules. However, an election is not aimed at ensuring that a particular group sticks on to power. In fact, the democratic process of election is designed to prevent such a scenario by providing a platform for change and choice.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>29", "subject": "Government", "year": "2015", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS A PROCESS OR ART OR GOVERNING", "question": "Politics is practically demonstrated during", "images": [], "options": {"A": "Electioneering campaigns", "B": "Parliamentary debates", "C": "Formation of political parties", "D": "Inter-party consultative meetings"}, "answer": "A", "explanation": "Politics has been defined as \"who\" gets \"what\" and \"how\" politicians display their skill, determination to winning elections during electioneering campaign. This makes them do different things for this purpose.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>30", "subject": "Government", "year": "2015", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "An election held to fill a vacant post in the legislature due to the death or resignation of a member is called", "images": [], "options": {"A": "Run-off election", "B": "Electoral college", "C": "Bye-election", "D": "Primary election"}, "answer": "C", "explanation": "A bye-election is an election held to fill a vacant post in the legislature due to the death or resignation of a member. This is different from a run-off election, which is a second election held to determine a winner when no candidate achieves the necessary majority in the first election. An electoral college is a body of electors chosen by the voters who formally elect the President and Vice President in the United States. A primary election is a preliminary election to appoint delegates to a party conference or to select the candidates for a principal, especially presidential, election.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>31", "subject": "Government", "year": "2015", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "Which of the following is a function of pressure groups?", "images": [], "options": {"A": "Represent and protect the rich", "B": "Protect the interest of the government", "C": "Serve as avenue for political victimisation", "D": "Provide forum for the ventilation of grievances"}, "answer": "D", "explanation": "Pressure groups are organizations that attempt to influence government policies. They provide a forum for the ventilation of grievances, which means they allow people to express their complaints or concerns. This is different from representing or protecting the rich, protecting the interest of the government, or serving as an avenue for political victimisation, which are not primary functions of pressure groups.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2015>32", "subject": "Government", "year": "2015", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "Public opinion is defined as the", "images": [], "options": {"A": "Aggregate views of the people", "B": "Sentiments of opposition parties", "C": "Consensus of the mass media", "D": "Reaction of pressure groups"}, "answer": "A", "explanation": "Public opinion is defined as the aggregate views of the people. It is the collective opinion of many people on some issue, problem, etc., and is a significant force in politics and public policy. It is not merely the sentiments of opposition parties, the consensus of the mass media, or the reaction of pressure groups.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2015>33", "subject": "Government", "year": "2015", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "Public opinion on the performance of the government is best measured by", "images": [], "options": {"A": "Military strength", "B": "General elections", "C": "The mass media", "D": "Parliamentary debates"}, "answer": "B", "explanation": "General election is the best way of measuring the performance of the government and the popularity of it.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>34", "subject": "Government", "year": "2015", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "The method in which a group of people are interviewed on a specific political issue is called", "images": [], "options": {"A": "Referendum", "B": "Individual speech", "C": "Individual writing", "D": "Opinion sampling"}, "answer": "D", "explanation": "The method in which a group of people are interviewed on a specific political issue is called opinion sampling. This is a research method used to gather data from a specific group of people about their opinions, thoughts, or attitudes towards a particular subject or concept. It involves asking people questions and collecting their responses.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>35", "subject": "Government", "year": "2015", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "The Civil Service is an administrative institution of", "images": [], "options": {"A": "The executive arm of government", "B": "Public corporations", "C": "Para-military organisation", "D": "A business enterprise"}, "answer": "A", "explanation": "The Civil Service is an administrative institution of the executive arm of government. It is a part of the public administration that implements the laws and policies made by the government. It does not belong to public corporations, para-military organizations, or business enterprises.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>36", "subject": "Government", "year": "2015", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "Which of the following is a feature of the Civil Service?", "images": [], "options": {"A": "Disloyalty", "B": "Impartiality", "C": "Political activism", "D": "Temporary tenure"}, "answer": "B", "explanation": "Impartiality is a key feature of the Civil Service. Civil servants are expected to be neutral and non-partisan in their work, providing the same level of service to all citizens regardless of their political affiliations. They are not supposed to be involved in political activism, and they do not have a temporary tenure - they are typically career employees of the government. Disloyalty is not a feature of the Civil Service.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2015>37", "subject": "Government", "year": "2015", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "The major source of local government revenue is", "images": [], "options": {"A": "Donations", "B": "Income from investments", "C": "Loans from finance institutions", "D": "Grants from the central authority"}, "answer": "D", "explanation": "The major source of local government revenue is the grants from the central authority. This is because local governments are administrative divisions of the central government, and they receive a significant portion of their funding from the central government. This funding is often allocated based on population size and need.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>38", "subject": "Government", "year": "2015", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI~~PRE-COLONIAL POLITICAL SYSTEM : IGBO~~PRE-COLONIAL POLITICAL SYSTEM : YORUBA", "question": "In the pre-colonial African political system, the function of the king makers were performed by", "images": [], "options": {"A": "Age grades", "B": "Women", "C": "Council of elders", "D": "Special people"}, "answer": "C", "explanation": "The function of kingmakers was perform by the council of elder during the pre-colonial period. Example is the Oyomesi of the Oyo-kingdom.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>39", "subject": "Government", "year": "2015", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "Colonialism is defined as the", "images": [], "options": {"A": "Struggle against foreign domination", "B": "Political struggle for independence", "C": "Economic dependence on developed nations", "D": "Imposition of foreign rule on a territory"}, "answer": "D", "explanation": "Colonialism is simply the imposition of foreign rule on a country. Examples are Indirect rule of Britain in Nigeria, Assimilation of France in Senegal, Apartheid of Britain in South Africa etc.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2015>40", "subject": "Government", "year": "2015", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "'Casting vote' was one of the ways the Governor in British West Africa controlled the", "images": [], "options": {"A": "Colonial treasure", "B": "Colonial secretary", "C": "Native authority", "D": "Legislative council"}, "answer": "D", "explanation": "The colonial Governor of British West Africa controlled the legislative council through \"Casting Vote\".", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2015>41", "subject": "Government", "year": "2015", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "The French policy of assimilation was based on the assumption that African culture was", "images": [], "options": {"A": "Expensive", "B": "Inferior", "C": "Unpopular", "D": "Superior"}, "answer": "B", "explanation": "The French policy of assimilation was based on the assumption that African culture was inferior. This policy was a colonial strategy that aimed to transform colonial subjects into French citizens by educating them in the French language and culture. The underlying assumption was that French culture was superior to African culture, hence the need for assimilation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>42", "subject": "Government", "year": "2015", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "The administrative structure adopted in the French colonial territories was", "images": [], "options": {"A": "more of a centralised administration", "B": "focused mainly on traditional rulers", "C": "favourable to the African age grades", "D": "for the development of African culture"}, "answer": "A", "explanation": "A more centralized administrative structure was adopted in the French colonial territory with the headquarters in France.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>43", "subject": "Government", "year": "2015", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "The Pan-African Movements emerged as a result of", "images": [], "options": {"A": "African cultural heritage", "B": "European racial domination", "C": "The formation of the African Union", "D": "The growth of socialism in Europe"}, "answer": "B", "explanation": "The Pan-African Movements emerged primarily as a response to European racial domination. The movement aimed to unify African nations and people globally to collectively resist and end colonialism and racism. It was not directly related to African cultural heritage, the formation of the African Union, or the growth of socialism in Europe.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2015>44", "subject": "Government", "year": "2015", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : MASS MEDIA", "question": "Which of the following was the first print media used by nationalists to oppose colonialism in the British West Africa?", "images": [], "options": {"A": "Daily News", "B": "Daily Times", "C": "West African Pilot", "D": "Guardian Newspaper"}, "answer": "C", "explanation": "The first print media used by nationalist to oppose (the) colonialism in British West Africa was the West African Pilot.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>45", "subject": "Government", "year": "2015", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "One of the prominent West African nationalist leaders was", "images": [], "options": {"A": "Kwame Nkrumah", "B": "Jomo Kenyatta", "C": "S.L. Akintola", "D": "Sekou Toure"}, "answer": "A", "explanation": "Kwame Nkrumah was a prominent West African nationalist leader. He was the first Prime Minister and President of Ghana, having led the Gold Coast to independence from Britain in 1957. An influential advocate of Pan-Africanism, Nkrumah was a founding member of the Organization of African Unity and winner of the Lenin Peace Prize in 1962.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2015>46", "subject": "Government", "year": "2015", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "Which of the following cannot be altered by a military coup d'etat? The", "images": [], "options": {"A": "Constitution", "B": "Legal System", "C": "Legislature", "D": "State"}, "answer": "D", "explanation": "A military coup d'etat can alter the constitution, legal system, and legislature of a country. However, it cannot alter the state itself. The state refers to the political entity in a defined geographic territory. The state remains, even if the government changes due to a coup d'etat. The state is the political entity that remains constant regardless of the changes in government, leadership, or political system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>47", "subject": "Government", "year": "2015", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "Laws promulgated by a military government are called", "images": [], "options": {"A": "Bills", "B": "Acts", "C": "Decrees", "D": "Proclamations"}, "answer": "C", "explanation": "Laws promulgated by a military government are called Decrees. A decree is a rule of law usually issued by a head of state (such as the president of a republic or a monarch), according to certain procedures. It has the force of law. The particular term used for this concept may vary from country to country. The executive orders made by the President of the United States, for example, are decrees.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>48", "subject": "Government", "year": "2015", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "The origin of the Commonwealth of Nations can be traced to", "images": [], "options": {"A": "Colonial ties", "B": "World economic order", "C": "Equality of states", "D": "Sovereignty of states"}, "answer": "A", "explanation": "The origin of the Commonwealth of Nations can be traced to Colonial ties. The Commonwealth of Nations, generally known simply as the Commonwealth, is a political association of 54 member states, nearly all of which are former territories of the British Empire. The chief institutions of the organisation are the Commonwealth Secretariat, which focuses on intergovernmental aspects, and the Commonwealth Foundation, which focuses on non-governmental relations amongst member states.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2015>49", "subject": "Government", "year": "2015", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The first black African to hold the position of UN Secretary-General was", "images": [], "options": {"A": "Salim Ahmed Salim", "B": "Kofi Annan", "C": "Emeka Anyaoku", "D": "Nelson Mandela"}, "answer": "B", "explanation": "The first black African to hold the position of UN Secretary-General was Kofi Annan. He served as the Secretary-General from January 1997 to December 2006. He was a Ghanaian diplomat who served as the seventh Secretary-General of the United Nations. The other options are incorrect as Salim Ahmed Salim is a Tanzanian politician who served as the Secretary-General of the Organisation of African Unity (OAU), Emeka Anyaoku is a Nigerian diplomat who was the third Commonwealth Secretary-General, and Nelson Mandela was a South African anti-apartheid revolutionary and political leader who served as President of South Africa.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2015>50", "subject": "Government", "year": "2015", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The Secretary-General of the United Nations Organisation (UNO) is appointed for a period of", "images": [], "options": {"A": "Three years", "B": "Five years", "C": "Seven years", "D": "Nine years"}, "answer": "B", "explanation": "The Secretary-General of the United Nations Organisation (UNO) is appointed for a period of five years. According to the UN Charter, the Secretary-General is appointed by the General Assembly upon the recommendation of the Security Council. The Secretary-General's selection is therefore subject to the veto of any of the five permanent members of the Security Council. The other options are incorrect as the term of office for the UN Secretary-General is not three, seven, or nine years.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2016>1", "subject": "Government", "year": "2016", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN ACADEMIC FIELD OF STUDY – REASONS FOR STUDYING GOVERNMENT.", "question": "Government refers to all the following except", "images": [], "options": {"A": "an academic field of study", "B": "a process of making and enforcing laws", "C": "an institution made up of people with common interest", "D": "an organised group of people"}, "answer": "C", "explanation": "Government as a subject matter is defined in three aspects; Government as an institution of  the state, Government as a process or the art of governing and then Government as an academic field of study.    Government as an institution of the state is defined as the machinery that is setup by the state to administer it's functions and duties. It can be seen as a 'machinery' set up by the state, to keep the state organised, run its affairs and administer its various functions and duties.    Government As A Process Or The Art Of Governing. Government is referred to as an art of governing because it is a body vested with the supreme power of the affairs of a state. A government is vested with the power of maintaining peace and security by putting in place machinery for that purpose.    Government as an academic field of study refers to the study of political institutions, processes and theories taught in schools, colleges and higher institution of learning. It is called Political Science in higher institution.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2016>2", "subject": "Government", "year": "2016", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "All the following are experienced by the community without government except", "images": [], "options": {"A": "insecurity", "B": "planned development", "C": "lawlessness", "D": "political anarchy"}, "answer": "B", "explanation": "Functions of government are defence, law making, promotion of economy, provision of social amenities, administration of justice and protection and lives and property. A state lacking all this will experience insecurity, lawlessness and political anarchy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2016>3", "subject": "Government", "year": "2016", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN ACADEMIC FIELD OF STUDY – REASONS FOR STUDYING GOVERNMENT.", "question": "As an academic field, the study of government does not include", "images": [], "options": {"A": "Political economy", "B": "Comparative polities", "C": "Public administration", "D": "Ecological interaction"}, "answer": "D", "explanation": "Government as an academic field studies political institutions, public administration, international relations, political thoughts/theories, political economy and comparative politics.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2016>4", "subject": "Government", "year": "2016", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following systems of government is authoritarian in the nature?", "images": [], "options": {"A": "Capitalist system", "B": "Fascism", "C": "Republicanism", "D": "Constitutional monarchy"}, "answer": "B", "explanation": "Fascism is an ideology which is authoritarian in nature. The ruler of Fascist government (usually male) makes the command without regards to fundamental human rights. Fascism involves an extreme sense of nationalism where the members feel the need to be violent towards who they consider as threats or enemies of the nation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2016>5", "subject": "Government", "year": "2016", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The system that allows the opposition to participate in governance is", "images": [], "options": {"A": "dictatorial", "B": "collectivism", "C": "aristocratic", "D": "democratic"}, "answer": "D", "explanation": "A democratic government coms into power with the consent of the people through voting in elections. This form of government abides by the constitution and there is a place and voice for opposition.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2016>6", "subject": "Government", "year": "2016", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Which of the following hinders the establishment of a representative government in a stage?", "images": [], "options": {"A": "Mass illiteracy", "B": "Existence of pressure groups", "C": "Vibrant political culture", "D": "Independent electoral commission"}, "answer": "A", "explanation": "In the process of choosing a representative government through elections, the illiteracy of the electorate may hinder them from identifying party names, logo or even the names of their candidate of their choice.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2016>7", "subject": "Government", "year": "2016", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following is not an attribute of a state?", "images": [], "options": {"A": "Definite Territory", "B": "Population", "C": "Government", "D": "Common Language"}, "answer": "D", "explanation": "Features of a state are sovereignty, territory government and population. Common language is peculiar to a nation and not a state.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2016>8", "subject": "Government", "year": "2016", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "In democracy, sovereignty is vested in the", "images": [], "options": {"A": "judge", "B": "people", "C": "legislature", "D": "executive"}, "answer": "B", "explanation": "In a democracy, the masses have the ultimate power to man their affairs. This sovereignty is in turn vested in their leaders of choice when government officials are elected through elections.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2016>9", "subject": "Government", "year": "2016", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "According to Charles Montesquieu, the theory of separation of powers is to prevent", "images": [], "options": {"A": "influence", "B": "authority", "C": "power", "D": "arbitrariness"}, "answer": "D", "explanation": "Arbitrariness means unrestrained and autocratic in the use of the authority. When there is no separation of power, there will be too much power concentrated.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2016>10", "subject": "Government", "year": "2016", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "Decentralization is a common feature of", "images": [], "options": {"A": "totalitarian system of government", "B": "federal system of government", "C": "unitary system of government", "D": "fascist system of government"}, "answer": "B", "explanation": "Decentralization occurs  when power is shared between the central government and other constituent units ( state or local government). This is only applicable in a federal system of government where constituent units are recognized.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2016>11", "subject": "Government", "year": "2016", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Bye-laws are made through", "images": [], "options": {"A": "delegated legislation", "B": "executive instrument", "C": "presidential order", "D": "emergency border"}, "answer": "A", "explanation": "Bye-laws are laws made by local government, public corporations or ministries when powers and functions are transferred to them through the Acts of  Parliament. This is referred to as delegated legislation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2016>12", "subject": "Government", "year": "2016", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Power is transferred into legal authority through", "images": [], "options": {"A": "force", "B": "prayers", "C": "influence", "D": "legitimacy"}, "answer": "D", "explanation": "Power is transferred into legal authority through legitimacy. Legitimacy in government is the recognition and acceptance of the authority of a governing regime by the population. When power is legitimized, it is transformed into legal authority that is recognized by the citizens.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2016>13", "subject": "Government", "year": "2016", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "Conventions are mostly used by states that have", "images": [], "options": {"A": "a large number of illiterates", "B": "A lot of people not interested in political activities", "C": "unwritten constitution", "D": "rigid constitution"}, "answer": "C", "explanation": "Conventions are mostly used by states that have an unwritten constitution. A convention is a way in which something is usually done, especially within a particular area or activity. In the context of governance, conventions are unwritten rules that are observed by the state. They are often used in countries with an unwritten constitution, such as the United Kingdom, where they provide guidance on how certain aspects of the country's political life should be conducted.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2016>14", "subject": "Government", "year": "2016", "type": "Objective", "topic": "CONSTITUTIONS : TYPES AND FEATURES", "question": "One advantage of a flexible constitution is that it", "images": [], "options": {"A": "can lead to dictatorship", "B": "can easily be manipulated", "C": "is best suited for a federation", "D": "can be amended by a simple majority"}, "answer": "D", "explanation": "Flexible constitution is easy to amend and can easily adapt to the dynamic nature of a state. However it does not suit a federal state, it is easy to manipulate and in turn cause infringement of the citizens rights.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2016>15", "subject": "Government", "year": "2016", "type": "Objective", "topic": "CONSTITUTIONS : TYPES AND FEATURES", "question": "A constitution that requires complicated procedures for its amendment is", "images": [], "options": {"A": "rigid", "B": "flexible", "C": "written", "D": "unwritten"}, "answer": "A", "explanation": "A rigid constitution like that of the USA, Nigeria and Ghana usually require a long and complicated process to b amended. Most written constitution are written.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2016>16", "subject": "Government", "year": "2016", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "The official who enforces discipline among members of his party in parliament is the", "images": [], "options": {"A": "majority leader", "B": "minority leader", "C": "clerk of the house", "D": "chief whip"}, "answer": "D", "explanation": "The chief is a political office in the legislature whose task is to administer the  whipping system that tries to ensure that members of the party attend and vote as the party leadership desires.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2016>17", "subject": "Government", "year": "2016", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "When an action of the executives is declared ultra-vires, it is a control exercised  by the", "images": [], "options": {"A": "public", "B": "minister", "C": "judiciary", "D": "parliament"}, "answer": "C", "explanation": "The term 'ultra vires' is a Latin phrase meaning 'beyond the powers'. It is used in legal context to refer to actions taken by an individual or body that exceed the powers granted to them by law. When an action of the executives is declared ultra-vires, it is a control exercised by the judiciary. The judiciary has the power to review the actions of the executive and legislative branches of government and declare them unconstitutional or ultra vires if they exceed the powers granted to them by the constitution or law.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2016>18", "subject": "Government", "year": "2016", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PRESIDENTIAL", "question": "In a presidential system of government, the president can can constitutionally be removed from the office through", "images": [], "options": {"A": "persuasion", "B": "impeachment", "C": "coup'd etat", "D": "vote-of -no- confidence"}, "answer": "B", "explanation": "President or Governors of states in a presidential system of government can be removed through impeachment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2016>19", "subject": "Government", "year": "2016", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY", "question": "Which of the following is an important feature of a unitary constitution?", "images": [], "options": {"A": "Centralization of power", "B": "Decentralization of power", "C": "Deconcentration of power", "D": "Power shared by the constitution"}, "answer": "A", "explanation": "In a unitary system of government, the constitution vests all powers of the governance in s a single central government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2016>20", "subject": "Government", "year": "2016", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : MONARCHICAL", "question": "One of the feature of an absolute monach is the the ruler", "images": [], "options": {"A": "is elected by the electorate", "B": "has a definite tenure of office", "C": "is elected by the representative of the people", "D": "wields the supreme power in a state"}, "answer": "D", "explanation": "An absolute monarch exercises supreme power and he/she can't be constitutionally controlled. This title is is hereditary and doesn't have a definite tenure of office.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2016>21", "subject": "Government", "year": "2016", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET", "question": "A notable feature of cabinet system of government is", "images": [], "options": {"A": "collective responsibility", "B": "the separation of powers", "C": "violation of human rights", "D": "impeachment of the executives"}, "answer": "A", "explanation": "In a cabinet or parliamentary system of government, the members of executive are collectively responsible for their actions. The ministers are collectively responsible to the prime minister.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2016>22", "subject": "Government", "year": "2016", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "All the following are the conditions for the adoption of federalism except", "images": [], "options": {"A": "size", "B": "defence", "C": "population", "D": "homogeneity"}, "answer": "D", "explanation": "When a country is composed of a group of people of the same culture, background and tradition, federalism necessarily shouldn't be adopted.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2016>23", "subject": "Government", "year": "2016", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "The priviledge citizens  enjoyed in a country irrespective of sex, tribe or creed is", "images": [], "options": {"A": "right", "B": "constitution", "C": "manifesto", "D": "franchise"}, "answer": "A", "explanation": "Fundamental human rights are privileges enjoyed by the citizens of a state. This rights are not to be violated. Such rights are rights to life, right to freedom and from discrimination e.t.c", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2016>24", "subject": "Government", "year": "2016", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The judicial order requiring a detained person to be brought before a judge is the writ of", "images": [], "options": {"A": "Habeas corpus", "B": "Mandamus", "C": "Prohibition", "D": "Certiorari"}, "answer": "A", "explanation": "A writ of mandamus is a judicial order requiring an inferior public authority to do some specific act it is obliged under the law to do. It is also a writ of prohibition directs a subordinate court to stop doing doing something the law prohibits or writ of certiorari is a writ seeking judicial review.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2016>25", "subject": "Government", "year": "2016", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "A political party can contest and win a widely accepted election if it has", "images": [], "options": {"A": "the ability to rig election", "B": "intolerant attitude to opposition", "C": "a broad-based membership", "D": "thee support of very wealthy politicians"}, "answer": "C", "explanation": "A widely accepted election has enjoyed recognition and acceptance from the people and this can only be achieved when there is no rigging, intolerant attitude to opposing parties or the support of only a few people(wealthy or not)", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2016>26", "subject": "Government", "year": "2016", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Political parties aim at all the following except", "images": [], "options": {"A": "contesting elections", "B": "forming a government", "C": "organizing general election", "D": "educating the electorate politically"}, "answer": "C", "explanation": "Political parties are not responsible for the conduct of elections.An electoral body is set up for that. Independent National Electoral Commission (INEC) is the electoral body of Nigeria in the 4th republic.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2016>27", "subject": "Government", "year": "2016", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Which of the following is not a means through which political parties reach the populace?", "images": [], "options": {"A": "posters", "B": "newspapers", "C": "schools", "D": "The internet"}, "answer": "C", "explanation": "Posters, Newspapers, the internet and other media are agents of political socialisation aimed at educating the people politically.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2016>28", "subject": "Government", "year": "2016", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "An association whose ultimate aim is to influence government policies is known as", "images": [], "options": {"A": "civil service", "B": "pressure group", "C": "political party", "D": "public corporation"}, "answer": "B", "explanation": "Pressure groups usually influence government policies in order to meet the needs of their members. Civil service is a part of the executive arm of government i.e they implement government policies. Political parties aim to gain power in government through the winning elections.  Public corporations are establishments set up by the government to provide basic amenities.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2016>29", "subject": "Government", "year": "2016", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "Membership of pressure groups is usually limited because they", "images": [], "options": {"A": "pursue specific and narrow objectives", "B": "promote other peoples interest", "C": "do not have dynamic interest", "D": "promote the interest of the government"}, "answer": "A", "explanation": "The desires of a particular pressure group are peculiar to only its members. For example a professional pressure group like the Nigerian Bar Association(NBA) is concerned with the Nigerian Legal Practitioners while the Nigerian Labour Congress(NLC) mans the affairs of workers.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2016>30", "subject": "Government", "year": "2016", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Elections are conducted to", "images": [], "options": {"A": "provide permanent employment for the people", "B": "make the people choose their leader", "C": "know the number of people in a country", "D": "Know the social amenities in the country"}, "answer": "B", "explanation": "In an election, there may be two candidates (in a two party system) or lots of candidates (multi party system) contesting for a position. The electorates are then given a chance to peacefully and willingly choose their preferred candidates as leaders", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2016>31", "subject": "Government", "year": "2016", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Suffrage is also known as", "images": [], "options": {"A": "franchise", "B": "plebiscite", "C": "public opinion", "D": "electoral college"}, "answer": "A", "explanation": "Suffrage or political franchise or simply franchise is the right to vote in the public, political election ( although the term is sometimes used for any right to vote).", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2016>32", "subject": "Government", "year": "2016", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : ELECTORAL MANAGEMENT BODY", "question": "For an election to be fair and free, the Electoral commission must be", "images": [], "options": {"A": "ready to manipulate", "B": "For ready to reject criticisms", "C": "headed by a minister in the executive", "D": "independent of other institutions of government"}, "answer": "D", "explanation": "Other factors responsible for a free and fair election include preparation of voters register, political education of the electorate, supervised  counting of votes, opportunity to campaign and training of officials", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2016>33", "subject": "Government", "year": "2016", "type": "Objective", "topic": "CITIZENSHIP : MEANING AND MODE OF ACQUISITION", "question": "Which of the following category of people can vote in periodic elections?", "images": [], "options": {"A": "Minors", "B": "Aliens", "C": "Lunatics", "D": "Citizens"}, "answer": "D", "explanation": "Though citizens enjoy rights to vote and be voted for, there are limitations to this right. People who are considered underage ( for example 0 -17 in Nigeria), lunatics and aliens are not allowed to vote in elections.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2016>34", "subject": "Government", "year": "2016", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "The Anonymity of a civil servant means that he", "images": [], "options": {"A": "is above the law of the land", "B": "should take part in partisan politics", "C": "receives neither praise nor blame publicly", "D": "should be prosecuted for professional misconduct"}, "answer": "C", "explanation": "Civil servants work in ministries headed by ministers, so, success or failure of any civil servant is directed to ministers. This is known as anonymity", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2016>35", "subject": "Government", "year": "2016", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "Which of the following functions is performed by the civil service?", "images": [], "options": {"A": "Enactment of laws", "B": "Settlement of disputes", "C": "Appointment of ministers", "D": "Implementation of policies"}, "answer": "D", "explanation": "The Civil service is body of the executive arm of government, i.e, it is also responsible for making and implementing government policies. The legislature is responsible for enactment laws of the judiciary settle disputes. In a presidential system of government, the president appoints ministers in a cabinet system of government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2016>36", "subject": "Government", "year": "2016", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "Public corporations are established to", "images": [], "options": {"A": "make maximum profits", "B": "help businessmen", "C": "provide employment for defeated politicians", "D": "provide utility services to the public at minimal cost"}, "answer": "D", "explanation": "Public corporations are established by the government to provide basic amenities like water, electricity, railway etc. Some are NEPA, Water Corporation, Nigeria Port Authority etc", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2016>37", "subject": "Government", "year": "2016", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "A minister controls public corporation by", "images": [], "options": {"A": "providing the corporation's finances", "B": "auditing the accounts of the corporation personally", "C": "criticizing the corporation through the mass media", "D": "ensuring the effective administration of th corporation"}, "answer": "D", "explanation": "A minister is the political head head of a corporation who gives policy guidelines to the Board of the Corporation. Other principal officers of a public corporation are the chairman the Board of directors, managing director and key senior officials.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2016>38", "subject": "Government", "year": "2016", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "An institution of government that makes bye-laws is the", "images": [], "options": {"A": "judiciary", "B": "executive", "C": "legislature", "D": "local authorities"}, "answer": "D", "explanation": "Bye-laws are made by local government and public corporations through powers vested in them through the Acts of Parliament.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2016>39", "subject": "Government", "year": "2016", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "Local government are  created to", "images": [], "options": {"A": "give more powers to the traditional rulers", "B": "bring the government closer to the people", "C": "make the people obey more of the local laws", "D": "take over the functions of the central government"}, "answer": "B", "explanation": "With th creation of local government, people at the grassroots will be able to participate in the affairs of the country.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2016>40", "subject": "Government", "year": "2016", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI~~PRE-COLONIAL POLITICAL SYSTEM : IGBO~~PRE-COLONIAL POLITICAL SYSTEM : YORUBA", "question": "Some pre-colonial West African government were democratic because of the existence of", "images": [], "options": {"A": "powerful traditional rulers", "B": "age grades", "C": "religious institutions", "D": "checks and balances"}, "answer": "D", "explanation": "The pre-colonial Oyo Empire employed the principle of checks and balances. The powers of Alaafin were limited through activities of the Oyomesi when an Alaafin dies.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2016>41", "subject": "Government", "year": "2016", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "One of the measures introduced by indirect rule was", "images": [], "options": {"A": "collection and keeping of taxes by the chiefs only", "B": "not recognizing traditional institutions", "C": "fixing and collection of taxes by British officials themselves", "D": "exclusion of the educated elite from the colonial administration"}, "answer": "A", "explanation": "Indirect rule was a system of governance used by the British to control parts of their colonial empire, particularly in Africa and Asia, through pre-existing local power structures. These dependencies were overseen by a small number of European officials. One of the measures introduced by indirect rule was the collection and keeping of taxes by the chiefs only. The British used local chiefs and rulers to collect taxes and maintain law and order in their areas, while the British officials supervised their activities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2016>42", "subject": "Government", "year": "2016", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "Which of the following policies was replaced by the french policy of association?", "images": [], "options": {"A": "Apartheid", "B": "Assimilation", "C": "Indirect rule", "D": "Frenchification"}, "answer": "B", "explanation": "The french Colonial Administration adopted the policy of assimilation initially and they  tried to eradicate the cultures of their colonies so as to replace them with the french way of life which they believe to be the best in the world. This policy failed and they changed to the policy association.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2016>43", "subject": "Government", "year": "2016", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : POST- INDEPENDENCE CONSTITUTIONS", "question": "The appointment and deposition of chiefs by their people was a demand of the", "images": [], "options": {"A": "Pan African Movement", "B": "National Congress of British West Africa", "C": "West Africa Student's Union", "D": "West African Youth League"}, "answer": "B", "explanation": "The National Congress of British West Africa (NCBWA) was a political pressure group that demanded constitutional reforms and more representation for Africans in the legislative councils. One of their demands was the appointment and deposition of chiefs by their people. The NCBWA believed that this would give the people more control over their local governance.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2016>44", "subject": "Government", "year": "2016", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "The desire for constitutional development in British West African Colonies was as a result of the", "images": [], "options": {"A": "rigidity of the constitution", "B": "desire of the British to review the constitution", "C": "power of traditional rulers", "D": "growing agitation of the people for political independence"}, "answer": "D", "explanation": "West African countries colonised by the British were unhappy with most pre-independence. Constitution because it was western and the people were excluded from running the affairs of their countries.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2016>45", "subject": "Government", "year": "2016", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "The following are features of a military regimes except", "images": [], "options": {"A": "respect for human right", "B": "suspension of the constitution", "C": "rules by decrees or edicts", "D": "curtailment of human rights"}, "answer": "A", "explanation": "Military regimes are violent systems of government thus, there is use of force to make every citizen submit. A military government suspends the constitution silences the press and violates human rights. Laws a federal military government makes are called decrees while those made by a state military government are known as edicts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2016>46", "subject": "Government", "year": "2016", "type": "Objective", "topic": "MILITARY RULE : VARIOUS MILITARY REGIMES", "question": "Military regimes in West Africa have often made use of civilians because", "images": [], "options": {"A": "only civilians can make decrees", "B": "the soldiers are dramatic", "C": "civilians are part of the armed forces", "D": "they need the experience of civilians in the armed forces"}, "answer": "D", "explanation": "Military government are most times not informed and knowledgeable about running the affairs of the country, so they employ the use of civilians.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2016>47", "subject": "Government", "year": "2016", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "One criticism leveled as against the pre-independence political parties in West Africa was that some of them", "images": [], "options": {"A": "did not possess credible programmes", "B": "did not contribute to political development", "C": "were not national in outlook", "D": "were instruments of the colonial administration"}, "answer": "C", "explanation": "Pre-independence political parties possesses credible programmes which moved the country forward and they weren't controlled by colonial government.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2016>48", "subject": "Government", "year": "2016", "type": "Objective", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "Foreign policy is the", "images": [], "options": {"A": "general principles that guide foreigners in a country", "B": "policy made by a country during war", "C": "policy made by a country in peace time", "D": "general principles of a country in the conduct of international relations"}, "answer": "D", "explanation": "The foreign policy of a country are self - interest strategies adopted by a country to safeguard its national interests and to achieve goals in the international community.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2016>49", "subject": "Government", "year": "2016", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "The Commonwealth of Nations was originally made up of", "images": [], "options": {"A": "former Portuguese Colonies in Africa", "B": "former Spanish colonies in Africa", "C": "independent nations formerly under British Empire", "D": "France and her former colonies in West Africa"}, "answer": "C", "explanation": "Commonwealth of Nations was formerly known as Commonwealth. Then, it was an association of countries that gained independence after being colonised by Britain. Presently, Commonwealth of Nations is a system of partnership involving sovereign states that are of equal basis.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2016>50", "subject": "Government", "year": "2016", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "Which of th following countries was not instrumental to the formation of the United Nations Organisations(UNO)?", "images": [], "options": {"A": "United States Of America", "B": "Britain", "C": "Germany", "D": "USSR"}, "answer": "C", "explanation": "The United Nations (UN) was established after World War II with the aim of preventing future wars. The UN was established on 24 October 1945 after World War II with the aim of preventing another such conflict. At its founding, the UN had 51 member states; there are now 193. The headquarters of the United Nations is in Manhattan, New York City, and is subject to extraterritoriality. The five countries instrumental to the formation of the UN were the United States, the United Kingdom, the Soviet Union, China, and France. Germany was not instrumental to the formation of the United Nations as it was one of the defeated powers in World War II.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>1", "subject": "Government", "year": "2017", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "Government is defined as an agency established to manage the affairs of", "images": [], "options": {"A": "rulers", "B": "foreigners", "C": "the state", "D": "all workers"}, "answer": "C", "explanation": "Government is defined as an institution or agency that is established to manage the affairs of the state. It is responsible for the administration of the state, making and enforcing laws, and maintaining order. The state refers to a political entity that is composed of a government and the people who live within its jurisdiction.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2017>2", "subject": "Government", "year": "2017", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN INSTITUTION OF THE STATE:", "question": "Function of government is", "images": [], "options": {"A": "controlling electoral commission", "B": "organization pressure group", "C": "making of laws", "D": "forming political parties"}, "answer": "C", "explanation": "One of the primary functions of the government is the making of laws. Laws are rules and guidelines created by the government to regulate the behavior of its citizens. The government, through its legislative arm, is responsible for creating these laws. The other options listed are not primary functions of the government. Controlling the electoral commission is a function of the government, but it is not the primary function. Organizing pressure groups and forming political parties are not functions of the government, but rather activities that occur within a political system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>3", "subject": "Government", "year": "2017", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : EXECUTIVE", "question": "Government maintains law and order through the following except", "images": [], "options": {"A": "police", "B": "immigration", "C": "the legislature", "D": "prison service"}, "answer": "C", "explanation": "The executive is charged with the responsibility of maintaining law and order through the armed fores, the police etc but not through the legislature", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>4", "subject": "Government", "year": "2017", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "According to Karl Max, socialism developed as a consequence of the evils of", "images": [], "options": {"A": "monarchy", "B": "communalism", "C": "feudalism", "D": "capitalism"}, "answer": "D", "explanation": "Karl Max stated that the evils of capitalist which stressed private ownership of the means of production and distribution were consequential to the development of socialism", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2017>5", "subject": "Government", "year": "2017", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A system of government which is based on public ownership of means of production and distribution is called", "images": [], "options": {"A": "socialism", "B": "capitalism", "C": "feudalism", "D": "oligarchy"}, "answer": "A", "explanation": "Socialism is a political, social, and economic philosophy encompassing a range of economic and social systems characterised by social ownership of the means of production and workers' self-management of enterprises. It includes the political theories and movements associated with such systems. Social ownership can be public, collective, cooperative, or of equity.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2017>6", "subject": "Government", "year": "2017", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following is not a feature of a state?", "images": [], "options": {"A": "Sovereignty", "B": "Government", "C": "Mass Media", "D": "Territory"}, "answer": "C", "explanation": "A state is a polity under a system of governance with a monopoly on force. There is no universal agreement on the definition of a state, but it generally includes a set of institutions that possess the authority to make the rules that govern the people of a society in a given geographical area. The four key features of a state are population, territory, sovereignty, and government. Mass media is not a feature of a state.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2017>7", "subject": "Government", "year": "2017", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Acceptability of the government in power by the governed is known as", "images": [], "options": {"A": "legitimacy", "B": "sovereignty", "C": "democracy", "D": "authority"}, "answer": "A", "explanation": "Legitimacy refers to the acceptance and recognition of an authority, usually a governing law or a regime. It is the belief that a rule, institution, or leader has the right to govern. It is a complex notion that includes aspects of legality, morality, and consent. In the context of the question, the acceptability of the government in power by the governed is referred to as legitimacy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>8", "subject": "Government", "year": "2017", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "For democracy to be sustained in a country it needs a", "images": [], "options": {"A": "rich political leader", "B": "well-informed electorate", "C": "partial electoral commission", "D": "large police force"}, "answer": "B", "explanation": "Democracy needs a well-informed electorate to thrive in a country as having an ignorant electorate may result in political apathy", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>9", "subject": "Government", "year": "2017", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following agents can be considered as the most effective agent of political socialization? The", "images": [], "options": {"A": "family", "B": "peer group", "C": "school", "D": "mass media"}, "answer": "A", "explanation": "Since the family is the breeding ground of individuals, it has much ability to socialize an individual politically", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2017>10", "subject": "Government", "year": "2017", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The guiding principle of communism is \"from each according to his/her.", "images": [], "options": {"A": "ability and to each according to his/her need", "B": "qualification and to each according to his/her need", "C": "race and to each according to his/her ability", "D": "age and to each according to his/her status"}, "answer": "A", "explanation": "Since communism stresses public distribution of property, it is thus a guiding principle that from each according to his ability and to each according to his/her need.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2017>11", "subject": "Government", "year": "2017", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following countries practised totalitarianism?", "images": [], "options": {"A": "Germany, Russia and Japan", "B": "Italy, Russia and Germany", "C": "Italy, Germany and Japan", "D": "Russia, Italy and England"}, "answer": "B", "explanation": "Totalitarianism is a political system where the state holds total authority over the society and seeks to control all aspects of public and private life wherever possible. In the 20th century, Germany under Adolf Hitler, Russia under Joseph Stalin, and Italy under Benito Mussolini practiced totalitarianism. Therefore, the correct answer is 'Italy, Russia and Germany'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>12", "subject": "Government", "year": "2017", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The theory of separation of powers was produced by", "images": [], "options": {"A": "Dicey", "B": "Max Weber", "C": "Charles Montesquieu", "D": "Gabriel Almond"}, "answer": "C", "explanation": "The theory of separation of power was propounded by a French scholar, Baron de Charles Montesquieu in his book titled, \"Espirit des Louis' (The Spirit of The Law) which was published in 1747.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>13", "subject": "Government", "year": "2017", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The principle of check and balances is important because it", "images": [], "options": {"A": "prevents each organ of government from being doctorial", "B": "frees other organs from judical control", "C": "makes the organs confront themselves", "D": "makes the government to perform it civic responsibilities"}, "answer": "A", "explanation": "When each organ can be checked by other organs, then the organs would be prevented from being dictatorial", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>14", "subject": "Government", "year": "2017", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "An agreed set of regulations, conventions and customs by which a country or an organization is governed is the", "images": [], "options": {"A": "constitution", "B": "sovereignty", "C": "suffrage", "D": "culture"}, "answer": "A", "explanation": "The term for an agreed set of regulations, conventions, and customs by which a country or an organization is governed is a 'constitution'. A constitution is a set of fundamental principles or established precedents according to which a state or other organization is governed. These rules together make up, i.e. constitute, what the entity is. Therefore, the correct answer is option 1: 'constitution'.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2017>15", "subject": "Government", "year": "2017", "type": "Objective", "topic": "CONSTITUTIONS : TYPES AND FEATURES", "question": "A constitution is considered to be flexible if it", "images": [], "options": {"A": "can be amended by a simple majority", "B": "can be altered through special procedure", "C": "requires two-third majority", "D": "is difficult to amend"}, "answer": "A", "explanation": "A flexible constitution is one that can be easily amended or changed. This usually requires a simple majority vote in the legislature, rather than a special procedure or a two-thirds majority. This makes the constitution adaptable to changing circumstances.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>16", "subject": "Government", "year": "2017", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : EXECUTIVE", "question": "The body responsible for the implementation of law is the", "images": [], "options": {"A": "judiciary", "B": "legislature", "C": "executive", "D": "court"}, "answer": "C", "explanation": "The organ of government charged with the responsibility of policy execution or implementation is the executive.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2017>17", "subject": "Government", "year": "2017", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "Bicameralism is necessary in a federal state to demonstrate that", "images": [], "options": {"A": "the executive is adequately represented", "B": "localized interests receive adequate representation", "C": "representation in the upper house is based on population", "D": "representation of the rich in society is taken care of"}, "answer": "B", "explanation": "When there are two houses in the central legislative body in a federal state, the interest of the locals are adequately represented", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>18", "subject": "Government", "year": "2017", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "Which of the following strengthens the power of the Supreme Court against the executive and the legislature?", "images": [], "options": {"A": "Judicial precedent", "B": "Judicial review", "C": "Court injunction", "D": "Oath swearing"}, "answer": "B", "explanation": "Judiciary review could be check on the legislature; to accept its compliance with the law/constitution or on the executive; to check its decisions and be invalidated if not in compliance with the constitution of the state.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>19", "subject": "Government", "year": "2017", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : MONARCHICAL", "question": "In the United States of America, the king or queen is referred to as", "images": [], "options": {"A": "ceremonial head", "B": "political head", "C": "constitutional head", "D": "democratic leader"}, "answer": "A", "explanation": "The congress is the USA's way of addressing its legislature.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2017>20", "subject": "Government", "year": "2017", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : MONARCHICAL", "question": "In a constitutional monarchy, the king or queen is referred to as", "images": [], "options": {"A": "ceremonial head", "B": "political head", "C": "constitutional head", "D": "democratic leader"}, "answer": "A", "explanation": "Since the king or queen in a constitutional monarchy is the Head of state, they are therefore vested with ceremonial duties, for example, the queen of England", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2017>21", "subject": "Government", "year": "2017", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "A corrupt judicial system erodes the observance of", "images": [], "options": {"A": "national peace and stability", "B": "the rule of law", "C": "international laws and conventions", "D": "democratic values of the executive"}, "answer": "B", "explanation": "When the judiciary which should be the last hope of the common man becomes corrupt, judges begin to live above the law and preferential treatment will be given to the guilty privileged, thus eroding the rule of law", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>22", "subject": "Government", "year": "2017", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PRESIDENTIAL", "question": "Which system of government has fusion of ceremonial and executive functions as a feature?", "images": [], "options": {"A": "Presidential", "B": "Cabinet", "C": "Confederal", "D": "Republican"}, "answer": "A", "explanation": "In a presidential system of government, the executive president is both the head of state and head of government", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2017>23", "subject": "Government", "year": "2017", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "One duty of a good citizen is", "images": [], "options": {"A": "building schools and hospitals", "B": "respect of the dignity and rights of others", "C": "loyalty to other nations", "D": "defending a suspect"}, "answer": "B", "explanation": "A good citizen is expected to respect the dignity and rights of others. This is a fundamental duty of every citizen in a society. It involves treating others with fairness, equality and respecting their freedoms and rights as provided by the law.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2017>24", "subject": "Government", "year": "2017", "type": "Objective", "topic": "CITIZENSHIP : MEANS OF SAFEGUARDING RIGHTS OF CITIZENS.", "question": "The rights of citizens to benefit from public utility is classified as", "images": [], "options": {"A": "social rights", "B": "natural rights", "C": "religious rights", "D": "political rights"}, "answer": "A", "explanation": "Since the public utility provides items necessary for good social living, the citizen's right to enjoy its services is social", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>25", "subject": "Government", "year": "2017", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Which of the following is a fundamental right? Right to", "images": [], "options": {"A": "life", "B": "education", "C": "criticize government", "D": "public office"}, "answer": "A", "explanation": "Life is the most important thing to human, without life other rights are useless; so right to life is fundamental", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2017>26", "subject": "Government", "year": "2017", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "The political party whose membership comprises people of high social status is called", "images": [], "options": {"A": "religious party", "B": "broker party", "C": "elite party", "D": "settles disputes"}, "answer": "C", "explanation": "An elite party is a political party whose membership comprises people of high social status. This type of party is often characterized by its small size and the high social status of its members, such as wealth, education, or professional standing. The term 'elite' refers to a small group of powerful people who hold a disproportionate amount of wealth, privilege, political power, or skill in a society.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>27", "subject": "Government", "year": "2017", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "The political party is significant because it", "images": [], "options": {"A": "stimulates political rancour", "B": "encourages electoral mal-practices", "C": "seek political power", "D": "settle disputes"}, "answer": "C", "explanation": "Political parties are significant because they seek political power. They do this by participating in elections, promoting their policies and ideologies, and trying to win the support of the electorate. Once they gain power, they can implement their policies and make decisions that affect the country. Therefore, the correct answer is 'seek political power'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>28", "subject": "Government", "year": "2017", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS", "question": "A political system in which there is only one legalized political party is called a", "images": [], "options": {"A": "de jure one party system", "B": "de facto one-party system", "C": "totalitarian single party system", "D": "mass party system"}, "answer": "A", "explanation": "Dejure party system is one in which there is only one legalized political party. Defacto party system is one in which there is only one dominant political party, though it may give room for the multi-party system, the dominant party always keeps winning election and never lose to the opposition.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2017>29", "subject": "Government", "year": "2017", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Provision of political education through rallies and newspapers is a function of a", "images": [], "options": {"A": "political parties", "B": "pressure groups", "C": "educated elite", "D": "the clergy"}, "answer": "A", "explanation": "Political parties are responsible for providing political education to the public. They do this through various means such as rallies and newspapers. During these rallies, they educate the public on their policies, government operations, and other political issues. This is not typically a function of pressure groups, the educated elite, or the clergy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>30", "subject": "Government", "year": "2017", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "Which of the following is not a method used by pressure groups to achieve their objectives?", "images": [], "options": {"A": "Employing lobbyists", "B": "Embarking on demonstrations", "C": "Embarking on strikes and boycotts", "D": "Contesting for political positions"}, "answer": "D", "explanation": "While other options are correct, \" Contesting for political position \" is not as pressure groups do not contest for political power, rather they influence politics.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>31", "subject": "Government", "year": "2017", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "An effective way of strengthening societal institutions is through the expression of", "images": [], "options": {"A": "personal opinion", "B": "group opinion", "C": "elite opinion", "D": "public opinion"}, "answer": "D", "explanation": "When public opinion is expressed, societal institution realize their fault and correct them, thereby strengthening them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>32", "subject": "Government", "year": "2017", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "A \"Yes\" or \"No\" vote on a specific political issue in a country", "images": [], "options": {"A": "referendum", "B": "public opinion", "C": "gerrymandering", "D": "suffrage"}, "answer": "A", "explanation": "Referendum is a vote which is observed in a country to finalized the decision to whether or not a political issue should be approved. It is known as a \"Yes\" or \"No\" vote.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>33", "subject": "Government", "year": "2017", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : TYPES, MERITS AND DEMERITS", "question": "The electorial system in which the winner should have more than all the votes of all other contestants put together is called", "images": [], "options": {"A": "simple majority system", "B": "referendum", "C": "second ballot system", "D": "absolute majority system"}, "answer": "D", "explanation": "Te absolute majority is an electoral system in which the winner must have a higher number of votes than the other political parties combined.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2017>34", "subject": "Government", "year": "2017", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "Which of the following is a civil/public servant?", "images": [], "options": {"A": "House majority leader", "B": "Clerk of the house", "C": "party whip", "D": "Minister of education"}, "answer": "B", "explanation": "A civil/public servant is a person employed in the public sector for a government department or agency. The Clerk of the House is a civil servant because they work for the government department that manages the operations of the House. The other options are political positions, not civil service positions. The House Majority Leader and the Party Whip are elected legislative roles, and the Minister of Education is a political appointment.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>35", "subject": "Government", "year": "2017", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "Which of the following statements about public corporation is not true?", "images": [], "options": {"A": "It is managed by a board of directors", "B": "It is established by an act of parliament", "C": "A huge capital is needed for its establishment", "D": "It is financed mainly by private individual"}, "answer": "D", "explanation": "Public corporations are funded by stakes, sale of goods and services etc. nd not by private individuals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>36", "subject": "Government", "year": "2017", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "Local governments are vital in modern in modern politics as they", "images": [], "options": {"A": "encourage dictatorship", "B": "train the local people in the art of governance", "C": "make laws for the the whole country", "D": "execute government policies at all level"}, "answer": "B", "explanation": "Local governments play a crucial role in modern politics as they are closer to the people and can understand their needs better. They do not encourage dictatorship or make laws for the whole country. However, they do train local people in the art of governance and execute government policies at the local level. Therefore, option 2 is the correct answer.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>37", "subject": "Government", "year": "2017", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI~~PRE-COLONIAL POLITICAL SYSTEM : IGBO~~PRE-COLONIAL POLITICAL SYSTEM : YORUBA", "question": "In the pre-colonial era, the breaking of an oath by a chief could", "images": [], "options": {"A": "lead to a war with his neighbours", "B": "lead to cleansing", "C": "make his state come under a curse", "D": "lead to his destoolment"}, "answer": "D", "explanation": "In the pre-colonial era, chiefs were seen as custodians of the land and were expected to uphold the customs and traditions of their people. Breaking an oath was seen as a serious offense that could lead to the chief being destooled or removed from his position.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2017>38", "subject": "Government", "year": "2017", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "One feature of pre-independence constitutions in West Africa is the", "images": [], "options": {"A": "judicial and executive councils", "B": "executive and legislative councils", "C": "judicial and legislative councils", "D": "consultative and judicial councils"}, "answer": "B", "explanation": "The legislative and executive councils were exclusive features of pre-independence West Africa, for examples the legislative and executive councils which were features of Nigeria's Clifford constitution of 1922.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>39", "subject": "Government", "year": "2017", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI~~PRE-COLONIAL POLITICAL SYSTEM : IGBO~~PRE-COLONIAL POLITICAL SYSTEM : YORUBA", "question": "The excessive power of the traditional rulers in the pre-colonial era could be checked by", "images": [], "options": {"A": "the hunters", "B": "the priests", "C": "children of the chiefs", "D": "the farmers"}, "answer": "B", "explanation": "The power of traditional rulers, for example the Alaafin of Oyo i pre-colonial Yoruba era could be checked by the priest, the Oluwo", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2017>40", "subject": "Government", "year": "2017", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "The secretary of State for the colonies was responsible for", "images": [], "options": {"A": "democratization of local governments", "B": "initiating colonial policies", "C": "fighting for the interest of the people", "D": "working with traditional leaders"}, "answer": "B", "explanation": "The secretary of state for the colonies who was next to the crown and who resided in England. He coordinated the colonies' governments except the Queen and he was responsible for initiating colonial policies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>41", "subject": "Government", "year": "2017", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "The crown colonies in the British West Africa were administered through", "images": [], "options": {"A": "assimilation", "B": "decentralization", "C": "association", "D": "direct rule"}, "answer": "D", "explanation": "The crown colonies in the British West Africa were administered through direct rule. Direct rule is a system of government in which a province is controlled by a central government. In the context of colonialism, it means that the colonies were governed by the British officials appointed by the crown.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>42", "subject": "Government", "year": "2017", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "Colonial administration in West Africa was as a result of", "images": [], "options": {"A": "a need for a new environment", "B": "the desire to underdevelop West Africa", "C": "a need for raw materials and markets", "D": "the urge to introduce western education"}, "answer": "C", "explanation": "Colonial administration in West Africa was primarily a result of a need for raw materials and markets. The European powers, including Britain, were in the industrial revolution phase and they needed raw materials for their industries and markets to sell their finished products. This was one of the main reasons for their interest in colonizing regions like West Africa.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>43", "subject": "Government", "year": "2017", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "Policy of assimilation was successfully operated by the French in", "images": [], "options": {"A": "Lome", "B": "Goree", "C": "Bamako", "D": "Abidjan"}, "answer": "D", "explanation": "The policy of assimilation was a colonial policy adopted by the French, which aimed at transforming colonies into French provinces. This policy was successfully operated in Abidjan, Ivory Coast. The French believed that their colonies were part of France, and therefore, the people should become French and be treated as such.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>44", "subject": "Government", "year": "2017", "type": "Objective", "topic": "NATIONALISM : NATIONALISM: MEANING, FACTORS AND EFFECTS.", "question": "The post-second World war national in West Africa was characterized by", "images": [], "options": {"A": "disorganization", "B": "lukewarm demands", "C": "disorientation", "D": "increased agitation"}, "answer": "D", "explanation": "The second World War gave Africans the intuition that the whites were not as special and powerful as they thought as they fought with and for many of them. This increased their agitation for independence.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>45", "subject": "Government", "year": "2017", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "One of the effects associated with most pre-independence constitutions in British West Africa was", "images": [], "options": {"A": "veto power of the Governor", "B": "all inclusive franchise", "C": "African domination of the executive council", "D": "African domination of the legislative council"}, "answer": "A", "explanation": "The veto power of the Governor underlined the ability of the executive and legislative councils to function.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>46", "subject": "Government", "year": "2017", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "In  a military regime, the arms of government that are usually fused are", "images": [], "options": {"A": "executive and judiciary", "B": "legislature and local council", "C": "legislature and executive", "D": "judiciary and the press"}, "answer": "C", "explanation": "In a military regime, the arms of government that are usually fused are the legislature and the executive. This is because in a military regime, the military takes over the functions of both the executive and the legislature. The executive arm of government is responsible for implementing laws while the legislative arm is responsible for making laws. In a military regime, the military makes and implements the laws, hence, the fusion of the two arms of government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>47", "subject": "Government", "year": "2017", "type": "Objective", "topic": "MILITARY RULE : VARIOUS MILITARY REGIMES", "question": "A military intervention into the politics of a state involves", "images": [], "options": {"A": "an overthrow of a legitimate government by pressure groups", "B": "the seizure of power from a legitimate government by the armed forces", "C": "violent overthrow of a democratic government by the police", "D": "the legitimate seizure of power by the police and civilians"}, "answer": "B", "explanation": "A military intervention into political means forceful overthrow a legitimate government. This is also called a military coup.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2017>48", "subject": "Government", "year": "2017", "type": "Objective", "topic": "FOREIGN POLICIES : ADVANTAGES AND DISADVANTAGES", "question": "A major merit of a country's foreign policy is that it", "images": [], "options": {"A": "encourages infringement on the the territories of other states", "B": "promotes country's national interest", "C": "stimulates political activities in the state", "D": "promotes understanding between the leaders and the led"}, "answer": "B", "explanation": "Foreign policy is advantageous to a country because it helps if it achieve its interests at the national level.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2017>49", "subject": "Government", "year": "2017", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "One primary objective of the New Partnership for African Development (NEPAD) is to", "images": [], "options": {"A": "settle disputes among African nations", "B": "eradicate poverty", "C": "betray corrupt African leaders", "D": "protect African citizens"}, "answer": "B", "explanation": "The New Partnership for African Development (NEPAD) has an objective to increase the standard of living of Africans by eradicating poverty", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2017>50", "subject": "Government", "year": "2017", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "The Economic Community West Africa states (ECOWAS) was formally established in Lagos on", "images": [], "options": {"A": "December 20, 1945", "B": "June 20, 1963", "C": "March 15, 1971", "D": "May 28, 1975"}, "answer": "D", "explanation": "The Economic Community of West African States (ECOWAS) has its headquarters in Lagos and it was established in 28 may, 1975", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2018>1", "subject": "Government", "year": "2018", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "A government performs the following functions except", "images": [], "options": {"A": "safeguarding life and property", "B": "maintaining law and order", "C": "providing all the needs of its citizen", "D": "providing basic welfare needs"}, "answer": "C", "explanation": "Government do not perform the function of providing all the needs of its citizens but provide basic welfare needs.    A government's basic functions are providing leadership, maintaining order, providing public services, providing national security, providing economic security, and providing economic assistance not all the needs of its citizen", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2018>2", "subject": "Government", "year": "2018", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "The basic purpose of setting up a state is to", "images": [], "options": {"A": "maintain law and order", "B": "protect foreign interest", "C": "promote development", "D": "provide social facilities"}, "answer": "A", "explanation": "The basic purpose of setting up a state is to maintain law and order. This is because without law and order, a state cannot function effectively. The other options, while important, are not the basic purpose of a state. Protecting foreign interest is a part of foreign policy, promoting development and providing social facilities are part of the state's responsibilities but not the basic purpose of its establishment.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2018>3", "subject": "Government", "year": "2018", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A political system in which government controls every aspect of a citizen's life is", "images": [], "options": {"A": "feudalism", "B": "monarchy", "C": "democracy", "D": "totalitarianism"}, "answer": "D", "explanation": "Totalitarianism is a political system whereby government controls every aspect of the citizen's life.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2018>4", "subject": "Government", "year": "2018", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A political system in which the state owns and controls the major means of production is known as", "images": [], "options": {"A": "feudalism", "B": "socialism", "C": "fascism", "D": "capitalism"}, "answer": "B", "explanation": "socialism is a system of government whereby the means of production and distribution of resources is owned by state.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2018>5", "subject": "Government", "year": "2018", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Communist governments aim at distributing goods and services according to", "images": [], "options": {"A": "gender and class", "B": "loyalty to the party", "C": "need and ability", "D": "work and residence"}, "answer": "C", "explanation": "Communist governments aim at distributing goods and services according to need and ability. This is a fundamental principle of communism, where the goal is to eliminate class distinctions by distributing wealth equally among the population. The idea is that those who are able to work do so to the best of their ability, and those who are in need receive what they require. None of the other options accurately reflect the principles of communism.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2018>6", "subject": "Government", "year": "2018", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The theory of separation of powers is associated with", "images": [], "options": {"A": "Jean Bodin", "B": "Baron de Montesquieue", "C": "A. V. Dicey.", "D": "J. J. Rousseau"}, "answer": "B", "explanation": "The theory of separation of powers is associated with Baron de Montesquieu. This theory proposes that the political power of the state should be divided into branches, each with separate and independent powers and areas of responsibility so that the powers of one branch are not in conflict with the powers associated with the other branches. The other options, Jean Bodin, A. V. Dicey, and J. J. Rousseau, are associated with other political theories and concepts.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2018>7", "subject": "Government", "year": "2018", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The process of taking part in the selection of leaders in a country is political", "images": [], "options": {"A": "socialization", "B": "participation", "C": "interaction", "D": "culture"}, "answer": "B", "explanation": "Political participation is the process of taking part in the selection of government or leaders in a country by the citizens.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2018>8", "subject": "Government", "year": "2018", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "By comparison, a state is", "images": [], "options": {"A": "less permanent than a government", "B": "more permanent than a government", "C": "more changeable than a government", "D": "equally permanent with a government"}, "answer": "B", "explanation": "A state is more permanent than a government. A state refers to a political entity that is represented by one centralized government that has sovereignty over a geographic area. A government, on the other hand, is the system or group of people governing an organized community, often a state. Governments can change through elections, coups, etc., but the state remains.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2018>9", "subject": "Government", "year": "2018", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "In modern democracies, a government is", "images": [], "options": {"A": "a contract between the rulers and the ruled", "B": "a preserve of the political party in power", "C": "monopoly of the ethnic groups in the majority", "D": "alternation of power between the majority and minority tribes"}, "answer": "A", "explanation": "In modern democracies, a government is considered a contract between the rulers and the ruled. This is based on the social contract theory, which posits that individuals have consented, either explicitly or tacitly, to surrender some of their freedoms and submit to the authority of the ruler or magistrate (or to the decision of a majority), in exchange for protection of their remaining rights. The other options do not accurately describe the nature of government in modern democracies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2018>10", "subject": "Government", "year": "2018", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Rule of law can be limited by", "images": [], "options": {"A": "power", "B": "state of emergency", "C": "legitimacy", "D": "checks and balances"}, "answer": "B", "explanation": "The rule of law can be limited by a state of emergency. In a state of emergency, governments are allowed to take actions that would normally be prohibited by law. This is done to maintain order and security during crises. The other options do not directly limit the rule of law. Power is a broad term that doesn't necessarily limit the rule of law. Legitimacy is a concept that supports the rule of law, not limit it. Checks and balances is a system that ensures the rule of law is upheld, not limited.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2018>11", "subject": "Government", "year": "2018", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The principle of separation of powers becomes meaningful when it is linked with the concept of", "images": [], "options": {"A": "the certainty of the law", "B": "checks and balances", "C": "legality of the law", "D": "judicial independence"}, "answer": "B", "explanation": "The principle of separation of powers become meaningful and effective when it is linked with the concept of checks and balance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2018>12", "subject": "Government", "year": "2018", "type": "Objective", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : FEATURES AND PROBLEMS", "question": "Which of the following factors does not militate against representative government in West Africa?", "images": [], "options": {"A": "Electoral irregularities", "B": "coup d'etat", "C": "Gagged media", "D": "Universal adult suffrage"}, "answer": "D", "explanation": "Universal adult suffrage does not militate against representative government in West Africa. Universal adult suffrage means that the right to vote should be not restricted by race, sex, belief, wealth, or social status, but granted to all adults subject only to minor exceptions. This is a fundamental part of a representative government where all citizens have the right to participate in the political process. On the other hand, factors like electoral irregularities, coup d'etat, and gagged media are all factors that can undermine the functioning of a representative government.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2018>13", "subject": "Government", "year": "2018", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Those who believe in democracy and good governance are opposed to a single party system because it", "images": [], "options": {"A": "encourages weak leadership", "B": "does not ensure national unity", "C": "curtails personal liberty", "D": "encourages divisiveness"}, "answer": "C", "explanation": "The disadvantages of a one party system is that there is no check on the power of the party. This inevitably leads to corruption and abuses of power.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2018>14", "subject": "Government", "year": "2018", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "The fundamental law of a country refers to its", "images": [], "options": {"A": "acts of parliament", "B": "conventions", "C": "constitution", "D": "judicial precedence"}, "answer": "C", "explanation": "Constitution is the fundamental law of a country. It is a document where the rules and regulation of a country is stipulated.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2018>15", "subject": "Government", "year": "2018", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "A country's constitution could be derived from the following sources except", "images": [], "options": {"A": "judicial precedents", "B": "customary sources", "C": "statutory sources", "D": "party manifesto"}, "answer": "D", "explanation": "A country's constitution is a set of fundamental principles or established precedents according to which a state or other organization is governed. These rules together make up, i.e. constitute, what the entity is. It is derived from judicial precedents, customary sources, and statutory sources. However, a party manifesto is not a source of a country's constitution. A party manifesto is a public declaration of the policy and aims of a political party, usually promoted during an election campaign, and it does not form part of the constitution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2018>16", "subject": "Government", "year": "2018", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS A PROCESS OR ART OR GOVERNING", "question": "Planning and formulation of government policies are first initiated at", "images": [], "options": {"A": "cabinet meetings", "B": "media houses", "C": "political rallies", "D": "open forum"}, "answer": "A", "explanation": "The planning and formulation of government policies are first initiated at cabinet meetings. The cabinet is a body of high-ranking state officials, typically consisting of the top leaders of the executive branch. They are usually called ministers, but in some jurisdictions are sometimes called secretaries. The functions of a cabinet are varied: in some countries, it is a collegiate decision-making body with collective responsibility, while in others it may function either as a purely advisory body or an assisting institution to a decision making head of state or head of government. Cabinets are typically the body responsible for the day-to-day management of the government and response to sudden events, whereas the legislative and judicial branches work in a measured pace, in sessions according to lengthy procedures.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2018>17", "subject": "Government", "year": "2018", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "Which of the following is the primary function of parliament?", "images": [], "options": {"A": "Impeachment of the president", "B": "Making of laws", "C": "Ratifying international treaties", "D": "Acting as a electoral college"}, "answer": "B", "explanation": "The primary function of parliament is the making of laws. Parliament is the supreme legislative body in a country. It has the responsibility to make laws, amend them, and repeal them. While it does have other functions such as impeachment of the president, ratifying international treaties, and acting as an electoral college, these are not its primary function.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2018>18", "subject": "Government", "year": "2018", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Judicial review is a mechanism for checking", "images": [], "options": {"A": "arbitrary use of power", "B": "irresponsible journalism", "C": "electoral malpractices", "D": "military adventures"}, "answer": "A", "explanation": "Judicial review is a mechanism for checking the arbitrary use of power. It is a process by which the judiciary reviews the legality of actions taken by the legislative and executive branches of government. If the courts find that a law or an action is in violation of the constitution or the principles of justice, they can declare it invalid. This helps to prevent the misuse of power and protect the rights of citizens.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2018>19", "subject": "Government", "year": "2018", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET", "question": "In a parliamentary system of government, the legislature and executive are fused to ensure", "images": [], "options": {"A": "supremacy of the ruling party in administering the state", "B": "smoothness in the administration of the state", "C": "the constitution is read in parliament at all times", "D": "the judiciary consults parliament before ruling on cases"}, "answer": "B", "explanation": "The major reason for the coming together of legislature and executive is to ensure smooth running of the state or smooth administration of the state.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2018>20", "subject": "Government", "year": "2018", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY", "question": "A country with homogeneous societies and a small population is suitable for the establishment of", "images": [], "options": {"A": "a nation state", "B": "a unitary state", "C": "a federal state", "D": "an autonomous state"}, "answer": "B", "explanation": "A country with homogeneous societies and a small population is suitable for the establishment of a unitary state. A unitary state is a state governed as a single entity in which the central government is ultimately supreme. The central government may create (or abolish) administrative divisions. Such units exercise only powers that the central government chooses to delegate. This system is suitable for small and culturally homogeneous countries because it allows for easier administration and less conflict.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2018>21", "subject": "Government", "year": "2018", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : CONFEDERAL", "question": "Which of the following factors usually leads to the collapse of a confederal state?", "images": [], "options": {"A": "Weak central government", "B": "Absence of a confederal parliament", "C": "Ill-equipped armed forces", "D": "Absence of a ceremonial Head of State"}, "answer": "A", "explanation": "A confederal state is a union of states where each member state retains substantial independence. The members of a confederation often delegate only a few powers to the central authority. Therefore, a weak central government, which lacks the power to enforce laws or maintain order, can lead to the collapse of a confederal state.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2018>22", "subject": "Government", "year": "2018", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PRESIDENTIAL", "question": "In the presidential system of government, the chief executive is responsible to the", "images": [], "options": {"A": "judiciary", "B": "monach", "C": "electorate", "D": "senate"}, "answer": "C", "explanation": "In a presidential system of government, the chief executive (the president) is elected by the people and is responsible to the electorate. The electorate is the body of citizens eligible to vote. The president is not responsible to the judiciary, the monarch, or the senate, but to the people who elected him/her.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2018>23", "subject": "Government", "year": "2018", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "Which of the following alternatives is a feature of a federation?", "images": [], "options": {"A": "Unwritten constitution", "B": "Unicameral legislature", "C": "Supremacy of the constitution", "D": "Right to secede"}, "answer": "C", "explanation": "A federation is a political entity characterized by a union of partially self-governing provinces, states, or other regions under a central federal government. One of the key features of a federation is the supremacy of the constitution. This means that the constitution is the highest law of the land and all government actions must conform to it. Therefore, the correct answer is 'Supremacy of the constitution'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2018>24", "subject": "Government", "year": "2018", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "A federal government is a form of", "images": [], "options": {"A": "decentralization", "B": "centralization", "C": "confederation", "D": "revolution"}, "answer": "A", "explanation": "Federal government is a form of decentralization where by powers are shared between the central and regional government.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2018>25", "subject": "Government", "year": "2018", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "To preserve individual liberties, the judiciary should", "images": [], "options": {"A": "consist of honest and impartial judges", "B": "be appointed by the executive", "C": "be prosecuted for judgement against the executive", "D": "participate in partisan politics"}, "answer": "A", "explanation": "To preserve the right or liberties of an individual, the judiciary should consist of honest and impartial judges.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2018>26", "subject": "Government", "year": "2018", "type": "Objective", "topic": "CITIZENSHIP : MEANS OF SAFEGUARDING RIGHTS OF CITIZENS.", "question": "Citizen can seek redress against injustice from the state through the", "images": [], "options": {"A": "Ombudsman", "B": "Head of Civil Service", "C": "Civil Service Commission", "D": "Titular Executive"}, "answer": "A", "explanation": "Ombudsman is a way in which citizens of a country can seek redress against injustice from the state.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2018>27", "subject": "Government", "year": "2018", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "Which of these is not a source of revenue for political parties?", "images": [], "options": {"A": "Dues", "B": "Grants", "C": "Tolls", "D": "Donations"}, "answer": "C", "explanation": "Tolls is not a source of revenue for a political parties the following are sources of revenue for a political parties; Dues, grants, donations etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2018>28", "subject": "Government", "year": "2018", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Which of these functions is performed by both political parties and pressure groups?", "images": [], "options": {"A": "Interest aggregation and articulation", "B": "Source of mediation in a state", "C": "Provision of specialized information", "D": "Seeking to manage affairs of a state"}, "answer": "A", "explanation": "Interest aggregation and articulation is a function performed by both political parties and pressure groups.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2018>29", "subject": "Government", "year": "2018", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "Pressure groups seek to influence the politics of government", "images": [], "options": {"A": "to the advantage of their members", "B": "so that all citizens can benefit", "C": "to suit the manifestoes of political parties", "D": "to conform with electoral act"}, "answer": "A", "explanation": "Pressure groups seek to influence the policies of government to the advantage of their members. Pressure groups is a selfish interest group that influence the policies of government for members only.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2018>30", "subject": "Government", "year": "2018", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : MASS MEDIA", "question": "Which of the following agencies helps the most in shaping public opinion?", "images": [], "options": {"A": "Pressure groups", "B": "Mass media", "C": "Colleges and universities", "D": "Peer groups"}, "answer": "B", "explanation": "Mass media plays a significant role in shaping public opinion. It provides information and perspective on a wide range of issues, and it often influences how people perceive these issues. It can shape public opinion by deciding which stories to cover and how to present them. This is different from other options like pressure groups, colleges and universities, and peer groups, which have a more limited reach and influence.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2018>31", "subject": "Government", "year": "2018", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "Public opinion can be measured through all of the following except the", "images": [], "options": {"A": "imposition of laws made without any debates", "B": "conduct of opinion polls", "C": "general views expressed in the mass media", "D": "holding of referendum in a state"}, "answer": "A", "explanation": "Public opinion is the collective opinion of the people of a society or state on an issue or problem. This concept came about through the process of urbanization and other political and social forces. It is measured through opinion polls, views expressed in the mass media, and referendums. However, the imposition of laws made without any debates does not measure public opinion because it does not involve the input or views of the public.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2018>32", "subject": "Government", "year": "2018", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "On which of the following grounds can a citizen abstain from voting?", "images": [], "options": {"A": "Religion", "B": "Education", "C": "Wealth", "D": "Status"}, "answer": "A", "explanation": "In a democratic society, every citizen has the right to vote or abstain from voting. The reasons for abstaining from voting can be personal or political. However, among the options provided, religion can be a valid reason for a citizen to abstain from voting. For instance, some religious beliefs may prohibit participation in political activities such as voting. Education, wealth, and status are not valid reasons for abstaining from voting as they do not inherently conflict with the act of voting.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2018>33", "subject": "Government", "year": "2018", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "An electoral system which allows party members to elect candidates for electives office is called", "images": [], "options": {"A": "general election", "B": "by election", "C": "direct election", "D": "primary election"}, "answer": "D", "explanation": "Primary election is an electoral system which allows party members to elect candidates for elective office.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2018>34", "subject": "Government", "year": "2018", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Indirect election is best described as", "images": [], "options": {"A": "only women electing legislators", "B": "the citizenry electing legislators", "C": "electoral college electing legislators", "D": "only adults electing legislators"}, "answer": "C", "explanation": "Indirect election is best described as an electoral college electing legislators. In this system, citizens vote for an intermediary, who then votes on their behalf. The intermediary, often part of an electoral college, then elects the legislators. This is different from a direct election, where citizens vote directly for their preferred candidate.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2018>35", "subject": "Government", "year": "2018", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "The class that controls and supervises the activities of the executive class in the civil service is", "images": [], "options": {"A": "clerical class", "B": "manipulative class", "C": "professional class", "D": "administrative class"}, "answer": "D", "explanation": "Administrative class controls and supervises the activities of the executive class in the civil service.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2018>36", "subject": "Government", "year": "2018", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC/CIVIL SERVICE COMMISSION –MEANING AND FUNCTIONS.", "question": "The agency responsible for investigating allegations of maladministration and punishing offending carrier officers in the executive is the", "images": [], "options": {"A": "Federal Character Commission", "B": "Ethics Commission", "C": "Judicial Commission", "D": "Public/Civil Service Commission"}, "answer": "D", "explanation": "Public/Civil Service Commission is an agency responsible for Investigating allegations of maladministration and punishing offending carrier officers in the executive.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2018>37", "subject": "Government", "year": "2018", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "The anonymity of civil servants means that they should not be", "images": [], "options": {"A": "prosecuted for any professional", "B": "disciplined because of their expertise", "C": "above the law of the land", "D": "praised or blamed publicly"}, "answer": "D", "explanation": "The anonymity of civil servants means that they are not identified to the public or media as being responsible for individual decisions within the government. This is to protect them from being personally criticized or praised for decisions that are made. This does not mean they are above the law or cannot be prosecuted or disciplined for professional misconduct.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2018>38", "subject": "Government", "year": "2018", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "The following were limitations imposed on traditional rulers under colonial rule except they", "images": [], "options": {"A": "were not permitted to raise armed forces", "B": "had no power to impose taxes", "C": "had no power to install or depose a chief", "D": "were no longer spiritual heads of the people"}, "answer": "D", "explanation": "The limitations imposed on traditional rulers under colonial rule does not involve traditional ruler were no longer spiritual heads of the people.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2018>39", "subject": "Government", "year": "2018", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "A system of administration which allowed traditional rulers under colonial rule except they", "images": [], "options": {"A": "divide and rule", "B": "colonialism", "C": "indirect rule", "D": "assimilation"}, "answer": "C", "explanation": "Indirect rule is a system of administration which allowed traditional rulers to rule their people under the supervision of the british official in West Africa.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2018>40", "subject": "Government", "year": "2018", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "One reason for the adoption of indirect rule in British West Africa was", "images": [], "options": {"A": "availability of British officials", "B": "to ensure justice", "C": "inadequate finance", "D": "to assimilate the indigenes"}, "answer": "C", "explanation": "One reason for the adoption of indirect rule in British West Africa was inadequate finance. The British did not have enough resources to establish a full direct administration in their colonies. Therefore, they used the existing traditional structures to govern, which was less expensive as it required fewer British officials and resources.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2018>41", "subject": "Government", "year": "2018", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "Local government is established in order to", "images": [], "options": {"A": "bring government nearer to the people", "B": "build churches and mosques", "C": "curb corruption in the society", "D": "promote political apathy"}, "answer": "A", "explanation": "Local government is established in order to bring government chosen to the people at the grass root.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2018>42", "subject": "Government", "year": "2018", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "Which of the following policies replaced assimilation?", "images": [], "options": {"A": "Indignant", "B": "Loi Cadre", "C": "Association", "D": "Indirect rule"}, "answer": "C", "explanation": "The policy of assimilation was replaced by the policy of association. Assimilation was a policy used by the French during colonial times where they aimed to turn the colonies into French provinces and the inhabitants into Frenchmen. However, this policy was not successful and was replaced by the policy of association. The policy of association respected the cultures and traditions of the colonized people and allowed them to administer their local affairs. It was a more indirect form of rule.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2018>43", "subject": "Government", "year": "2018", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "Which of the following is a reason for the failure of the assimilation policy in French West Africa?", "images": [], "options": {"A": "The change in name of their culture", "B": "The refusal of the Africans to be culturally colonized", "C": "The democratic policy of the French", "D": "Bribery of the opinion leaders by the French"}, "answer": "B", "explanation": "The refusal of the Africans to be culturally colonized is one of the reason for the failure of the assimilation policy in french West Africa.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2018>44", "subject": "Government", "year": "2018", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "Nationalism prior to the Second World War was led by", "images": [], "options": {"A": "educated elite and chiefs", "B": "chiefs and the elders", "C": "aggrieved cocoa farmers", "D": "african merchants"}, "answer": "A", "explanation": "Nationalism before the Second World War was led by Educated elite and Chiefs such as Obafemi Awolowo, Nnamdi Azikwe etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2018>45", "subject": "Government", "year": "2018", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "Which of the following is not a factor leading to military intervention in West African states?", "images": [], "options": {"A": "Excessive control of public enterprises", "B": "Falsification of election results", "C": "Mismanagement of the country's economy", "D": "Corruption in high places"}, "answer": "A", "explanation": "Excessive control of public enterprises is not a factor leading to military intervention in West Africa States.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2018>46", "subject": "Government", "year": "2018", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "One of the problems of military administration in West Africa is that soldiers", "images": [], "options": {"A": "are representatives of the people", "B": "lack discipline", "C": "are not well organized", "D": "are not trained for governance."}, "answer": "D", "explanation": "One of the problems of military administration in West Africa is that soldiers are not trained for governance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2018>47", "subject": "Government", "year": "2018", "type": "Objective", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "Foreign policy of a country could be influenced by", "images": [], "options": {"A": "personality of political leader", "B": "number of schools in a country", "C": "number of ministers in a country", "D": "national election"}, "answer": "A", "explanation": "The foreign policy of a country is often influenced by the personality of its political leader. This is because the leader's beliefs, values, and perspectives can shape the country's approach to international relations. For example, a leader who values peace and diplomacy may pursue policies that promote international cooperation, while a leader who is more aggressive or nationalistic may pursue policies that prioritize the country's interests over international cooperation. The number of schools or ministers in a country or the national election do not directly influence a country's foreign policy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2018>48", "subject": "Government", "year": "2018", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "In order to promote democracy and good governance, the Commonwealth of Nations", "images": [], "options": {"A": "prosecutes leaders who commit atrocities at the International Criminal Court", "B": "organizes seminars and training programs on technical assistance to members", "C": "sanctions members who do not pay their dues", "D": "sponsors election observer teams to monitor the conduct of elections"}, "answer": "D", "explanation": "The commonwealth of Nations sponsors election observer teams to monitor the conduct of election in order to promote democracy and good governance.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2018>49", "subject": "Government", "year": "2018", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "Which of the following is not a problem faced by the Economic Community of West African States (ECOWAS)?", "images": [], "options": {"A": "Financial security", "B": "Political Instability", "C": "Larger Market", "D": "Colonial Heritage"}, "answer": "C", "explanation": "ECOWAS is a regional group of fifteen West African countries. It faces several challenges including financial security and political instability. However, having a larger market is not a problem but rather an advantage for ECOWAS as it promotes trade and economic growth among member countries.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2018>50", "subject": "Government", "year": "2018", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The United Nations Organization (UNO) is primarily regarded as successful because", "images": [], "options": {"A": "its membership continues to increase", "B": "of its control of outbreak of another World war", "C": "all member countries have veto power", "D": "more member countries acquire more nuclear power"}, "answer": "B", "explanation": "The United Nations Organisation (UNO) is primarily regarded as successful because of its control of outbreak of another world war.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2019>1", "subject": "Government", "year": "2019", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "The constitutional power given to the judiciary to interpret legislative acts, executive and administrative actions and to declare its constitutionality or otherwise is", "images": [], "options": {"A": "judicial power", "B": "separation of powers", "C": "judicial review", "D": "administrative processes"}, "answer": "C", "explanation": "Judicial review is the power of the courts of a country to examine the actions of the legislative, executive and administrative arms of the government and to determine wether such actions are consistent with the constitution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>2", "subject": "Government", "year": "2019", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "The ultimate duty of a citizen is to demonstrate his/her", "images": [], "options": {"A": "allegiance to the sovereign", "B": "loyalty to the state", "C": "respect for the national flag", "D": "contribution to government expenditure"}, "answer": "B", "explanation": "The ultimate or main duty of a citizen is to demonstrate his/her loyalty to the state. Something that a citizen is required to do by law.    What is the ultimate duty of a citizen?  Citizens must comply with certain mandatory obligations, including: Obeying the law. Every citizen must obey federal, state and local laws, and pay the penalties that can be incurred when a law is broken.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2019>3", "subject": "Government", "year": "2019", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "Conventions and usages are rules based on", "images": [], "options": {"A": "traditions and customs", "B": "previous constitutions", "C": "legal documents", "D": "decisions of commoners"}, "answer": "A", "explanation": "Convention is a set of agreed, stipulated or generally accepted standards, norms, social norms, or criteria, often taking the form of a custom. Conventions end usages are rules based on traditions and customs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>4", "subject": "Government", "year": "2019", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN INSTITUTION OF THE STATE:", "question": "The body responsible for the execution of the policies of government is the", "images": [], "options": {"A": "Pressure Group", "B": "Civil Service", "C": "Constitutional Conference", "D": "Electoral Commission"}, "answer": "B", "explanation": "The Civil Service is the body responsible for the execution of the policies of government. They are the administrative staff of the government and they implement the decisions of the government. The other options like Pressure Group, Constitutional Conference, and Electoral Commission do not execute government policies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>5", "subject": "Government", "year": "2019", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "The electorate is defined as", "images": [], "options": {"A": "intended candidates for voting.", "B": "elected party members", "C": "elected civil society group", "D": "citizens that are qualified to vote"}, "answer": "D", "explanation": "Electorate is a body of people allowed to vote in an election. It is citizens that are qualified to vote.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2019>6", "subject": "Government", "year": "2019", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The right to govern and administer the affairs of the people of a country is", "images": [], "options": {"A": "power.", "B": "diplomacy.", "C": "authority.", "D": "influence."}, "answer": "C", "explanation": "Authority is the right to govern and administer the affairs of the people of a country. It is the right to give orders, make decisions and enforce obedience.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>7", "subject": "Government", "year": "2019", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY", "question": "One of the following is a characteristic of a unitary government.", "images": [], "options": {"A": "Heterogeneous society", "B": "Homogeneous society", "C": "Communal society", "D": "Feudal society"}, "answer": "B", "explanation": "Homogeneous society is a characteristic of a unitary government. Unitary system of government is possible when the population is small, similar cultural practice and the same language.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>8", "subject": "Government", "year": "2019", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "The mass type of party is", "images": [], "options": {"A": "broad-based.", "B": "capitalist.", "C": "feudalist.", "D": "conservative."}, "answer": "A", "explanation": "Mass type of party is broad-based. It is practice where there is large population and different ethnic group.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>9", "subject": "Government", "year": "2019", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Who among the following provided the detailed work on sovereignty?", "images": [], "options": {"A": "Jean Bodin", "B": "Fredrick Engels", "C": "Bolaji Akinyemi", "D": "Thomas Hobbes"}, "answer": "A", "explanation": "The detailed work of sovereignty was provided by Jean bodin. It was popularised by Jean Bodin (1530 - 1596). Bodin conceived it as a supreme, perpetual and indivisible power, marked by the ability to make law without the consent of any other.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2019>10", "subject": "Government", "year": "2019", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The family and peer groups are important agents of", "images": [], "options": {"A": "political culture", "B": "political socialization", "C": "charismatic authority", "D": "traditional authority"}, "answer": "B", "explanation": "Family and peer groups are important agents of political socialization. The family is the first agent of political social and followed by the peer groups.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>11", "subject": "Government", "year": "2019", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : CONFEDERAL", "question": "The confederal system of government is unpopular because", "images": [], "options": {"A": "the government operates oligarchy system.", "B": "it does not follow due process.", "C": "it discourages rapid development.", "D": "all the component units are sovereign"}, "answer": "D", "explanation": "The confederal system of government is unpopular because all the component units are sovereign.  It has a weak central authority while the components units are strong.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>12", "subject": "Government", "year": "2019", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "Local Government is relevant because it provides political", "images": [], "options": {"A": "discussion among electorate", "B": "discipline among party members", "C": "representation in the judiciary", "D": "participation at the grassroots"}, "answer": "D", "explanation": "Local government is a system whereby the elect rates are govern at the grassroot. Local government is relevant because it provides political participation at th grass root.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2019>13", "subject": "Government", "year": "2019", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "Pressure groups provide", "images": [], "options": {"A": "manifestoes for political parties", "B": "sponsorship of candidates for political office", "C": "aims and objectives for a wider appeal to the electorate", "D": "means by which governments ascertain public reactions to their policies"}, "answer": "D", "explanation": "Pressure group can be described as an organised group that does not put up candidates for election but seeks to influence government policy or legislation. Pressure group provide means by which government ascertain public reactions to their policies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>14", "subject": "Government", "year": "2019", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : EXECUTIVE~~ORGANS OF GOVERNMENT : JUDICIARY~~ORGANS OF GOVERNMENT : LEGISLATURE", "question": "The authority of the state is collectively exercised by the", "images": [], "options": {"A": "executive, legislature and judiciary", "B": "president, governor and chairman", "C": "police, army and navy", "D": "government, people and the civil servants"}, "answer": "A", "explanation": "The authority of the state is collectively exercised by executive, legislature and judiciary. The three bodies collectively exercised by the authority of the state.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2019>15", "subject": "Government", "year": "2019", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PRESIDENTIAL", "question": "In a presidential system of government, legislative approval is not necessary for the", "images": [], "options": {"A": "appointment of Supreme Court judges.", "B": "ratification of treaties.", "C": "granting of pardons.", "D": "appointment of civil servants."}, "answer": "C", "explanation": "In presidential system of government, legislative approval is not necessary for the granting of pardons presidential pardon power explained .. says the president shall have power to grant reprieves and pardons for .. pardon power is a necessary check on criminal justice.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2019>16", "subject": "Government", "year": "2019", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "The following are the reasons widely espoused for military intervention and rule in West Africa except", "images": [], "options": {"A": "tribalism and nepotism.", "B": "inordinate ambition of soldiers.", "C": "mal-administration.", "D": "religion."}, "answer": "D", "explanation": "While tribalism, nepotism, inordinate ambition of soldiers, and mal-administration have often been cited as reasons for military intervention and rule in West Africa, religion is not typically cited as a reason. This is because religion is a personal belief and does not directly influence the governance or administrative structure of a state. Therefore, it is not a widely espoused reason for military intervention and rule.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>17", "subject": "Government", "year": "2019", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : TYPES, MERITS AND DEMERITS", "question": "Which of the following electoral systems is ideal for a heterogeneous society?", "images": [], "options": {"A": "Simple majority", "B": "Preferential ballot", "C": "Non-transferable vote", "D": "Proportional representation"}, "answer": "D", "explanation": "Proportional representation is the best electoral system for heterogenous society. People come together to choose those that will represent them in government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>18", "subject": "Government", "year": "2019", "type": "Objective", "topic": "CONSTITUTIONS : FUNCTIONS", "question": "A constitution performs the role of", "images": [], "options": {"A": "law making.", "B": "law enforcement.", "C": "communicating the ideals of leaders.", "D": "stating the functions and limitations of leaders."}, "answer": "D", "explanation": "Constitution performs the role of good government while same time placing limitations on the powers of government. It states the functions and limitation of leaders.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2019>19", "subject": "Government", "year": "2019", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PRESIDENTIAL", "question": "Impeachment process is a unique feature of the", "images": [], "options": {"A": "parliamentary system.", "B": "presidential system.", "C": "federal system.", "D": "unitary system."}, "answer": "B", "explanation": "Impeachment is a process that allows charges to be brought against a public official for crimes alleged to have been committed while in office. It is a unique feature of the presidential system. In a presidential system, the president is both the head of state and the head of government, and has powers separate from those of the legislature. To prevent misuse of these powers, the impeachment process is used as a check and balance mechanism.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>20", "subject": "Government", "year": "2019", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Which of the following is a function of the party whip?", "images": [], "options": {"A": "Flogging erring party members", "B": "Ensuring that the members tow the party position", "C": "Ensuring the safety of the speaker", "D": "Assessing the performance of the law makers"}, "answer": "B", "explanation": "The function of party whip is to ensure party discipline in a legislature. This usually means ensure party members of the party vote according to the party platform, rather than according to their own individual idealogy. It ensures members tow the party position.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>21", "subject": "Government", "year": "2019", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "Labour groups mostly come under the umbrella of the", "images": [], "options": {"A": "industrial workers' union", "B": "trades union congress", "C": "anomic group", "D": "civil defence"}, "answer": "B", "explanation": "Trade unions may be affiliated to umbrella organisation at industrial, national relations. Labour groups mostly come under the umbrella of the trade union congress.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>22", "subject": "Government", "year": "2019", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : ELECTORAL MANAGEMENT BODY", "question": "The major problem facing electoral management bodies in West Africa is", "images": [], "options": {"A": "lack of qualified personnel.", "B": "poor communication network.", "C": "foreign interference.", "D": "electoral malpractice."}, "answer": "D", "explanation": "The major problem facing electoral management bodies in West Africa is electoral malpractice. Irregularities in the process of conducting election is a major problem facing electoral management bodies in West Africa.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2019>23", "subject": "Government", "year": "2019", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "The features of a state include all the following except", "images": [], "options": {"A": "government.", "B": "territory.", "C": "society.", "D": "population."}, "answer": "C", "explanation": "The features of a state include all the following except society. Society is not part of feature of any given state.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2019>24", "subject": "Government", "year": "2019", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "To facilitate movement of people from one member state to another, the Economic Community of West African States (ECOWAS) has", "images": [], "options": {"A": "created several boarder posts within member states.", "B": "waived visa requirements for citizens of member countries.", "C": "created one currency for all member countries.", "D": "maintained regional peace and security through deployment of forces."}, "answer": "B", "explanation": "The Economic Community of West African States (ECOWAS) has waived visa requirements for citizens of member countries to facilitate the free movement of people, goods and services. This is part of the ECOWAS Protocol on Free Movement of Persons, Residence and Establishment. The other options are not entirely correct. ECOWAS has not created one currency for all member countries, although there are plans for a single currency. The creation of border posts and deployment of forces are more related to security and peacekeeping, not specifically to facilitate movement of people.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>25", "subject": "Government", "year": "2019", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "Publice corporations are referred to as statutory bodies because they are established by", "images": [], "options": {"A": "a legislative instrument", "B": "Acts of parliament", "C": "an executive instrument", "D": "Bye-laws"}, "answer": "B", "explanation": "Public corporations are referred to as statutory bodies because they are established by the Act of parliament.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>26", "subject": "Government", "year": "2019", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN INSTITUTION OF THE STATE:", "question": "Which state institution serves as a link between the government and the people?", "images": [], "options": {"A": "Office of the President", "B": "The Civil Service", "C": "The Judiciary", "D": "The Church"}, "answer": "B", "explanation": "The Civil Service serves as a link between the government and the people. The Civil Service is a part of the public sector tasked with implementing the policies of the government of the day. It provides services directly to the citizens, and it is through these services that the government interacts with its citizens. Therefore, the correct answer is 'The Civil Service'.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>27", "subject": "Government", "year": "2019", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : MASS MEDIA", "question": "The media play a vital role in the political environment in that, it", "images": [], "options": {"A": "articulates the views of individuals.", "B": "incites people to be lawless.", "C": "projects individuals above the state.", "D": "articulates the views of the ruling party."}, "answer": "A", "explanation": "The media play a vital role in the political environment in that it articulate the views of individuals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>28", "subject": "Government", "year": "2019", "type": "Objective", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "Military might is a major determinant of a country's", "images": [], "options": {"A": "independence.", "B": "democracy.", "C": "foreign policy.", "D": "wealth."}, "answer": "A", "explanation": "Military might is a major determinant of a country's independence.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2019>29", "subject": "Government", "year": "2019", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "The major role of minority parties in parliament is to", "images": [], "options": {"A": "criticize every government policy.", "B": "ensure democratic governance.", "C": "monitor the activities of the president.", "D": "supervise the passage of bills."}, "answer": "B", "explanation": "The major role of minority parties in parliament is to ensure democratic governance. They do this by providing checks and balances, scrutinizing government policies and actions, and representing diverse views. This ensures that the government is held accountable and that decisions are made in the best interest of the public.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>30", "subject": "Government", "year": "2019", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "The political parties established in West Africa in the 1950's were aimed at", "images": [], "options": {"A": "securing independence for their people.", "B": "participating in the colonial administration.", "C": "introducing guerilla warfare against Europeans.", "D": "representing their people in the British parliament."}, "answer": "A", "explanation": "The political parties established in West Africa in the 1950's were aimed at securing independence further people.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>31", "subject": "Government", "year": "2019", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "The Commonwealth Secretariat is located in", "images": [], "options": {"A": "Los Angeles.", "B": "Kuala-Lumpur", "C": "London", "D": "Glasgow"}, "answer": "C", "explanation": "French colonial administration in West Africa sought to integrate her colonies with their home country.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>32", "subject": "Government", "year": "2019", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION~~COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "Which colonial administration in West Africa sought to integrate her colonies with their home country?", "images": [], "options": {"A": "British", "B": "Dutch", "C": "French", "D": "Danes"}, "answer": "C", "explanation": "French colonial administration in West Africa sought to integrate her colonies with their home country.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2019>33", "subject": "Government", "year": "2019", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "The following are benefits member countries derive from the Economic Community of West African States (ECOWAS) except", "images": [], "options": {"A": "economic cooperation.", "B": "larger market.", "C": "military assistance.", "D": "free ports."}, "answer": "D", "explanation": "The Economic Community of West African States (ECOWAS) is a regional political and economic union of fifteen countries located in West Africa. Its main objectives are to promote economic integration across the region. However, 'free ports' is not a benefit derived from ECOWAS. Free ports are areas with relaxed jurisdiction with respect to customs and taxes, which is not a direct benefit provided by ECOWAS.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>34", "subject": "Government", "year": "2019", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "Which of the following is not an obligation of a citizen?", "images": [], "options": {"A": "Payment of taxes", "B": "Voting in an election", "C": "Protecting public property", "D": "Attending religious gathering"}, "answer": "D", "explanation": "Citizenship comes with certain responsibilities and obligations, such as paying taxes, voting in elections, and protecting public property. These are all obligations that contribute to the functioning and well-being of a society. However, attending religious gatherings is not an obligation of a citizen. It is a personal choice and falls under the freedom of religion, which is a fundamental human right.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2019>35", "subject": "Government", "year": "2019", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "The implementation of indirect rule was supervised by the", "images": [], "options": {"A": "Chiefs and Council of Elders.", "B": "British Officials.", "C": "Spiritual leaders of the land.", "D": "Educated elite."}, "answer": "B", "explanation": "The implementation of indirect rule was supervised by the British Officials. Indirect rule was a system of governance used by the British to control parts of their colonial empire, particularly in Africa and Asia, through pre-existing local power structures. These dependencies were overseen by a Governor or a Resident, who was a British official.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>36", "subject": "Government", "year": "2019", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : MASS MEDIA", "question": "The electronic and print media make their views heard on national issues through", "images": [], "options": {"A": "public notice.", "B": "advertisement.", "C": "documentary.", "D": "editorial commentary."}, "answer": "D", "explanation": "The electronic and print media make their views heard on national issues through editorial commentary.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>37", "subject": "Government", "year": "2019", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Any type of restricted franchise is a violation of the principle of", "images": [], "options": {"A": "constitutionalism.", "B": "sovereignty.", "C": "political equality.", "D": "popular election."}, "answer": "C", "explanation": "Any type of restricted franchise is a violation of the principle of political equality. Restriction of franchise is limitations of political equality.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>38", "subject": "Government", "year": "2019", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "Public corporations can operate in a more efficient manner if they are", "images": [], "options": {"A": "free from political interference.", "B": "controlled by the judicial service commission.", "C": "under the head of the civil service.", "D": "controlled by the military."}, "answer": "A", "explanation": "Public corporations can operate in a more efficient manner if they are free from political interference.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>39", "subject": "Government", "year": "2019", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN INSTITUTION OF THE STATE:", "question": "The agency responsible for fulfilling the purpose of the state is", "images": [], "options": {"A": "government.", "B": "pressure group.", "C": "public corporation.", "D": "media."}, "answer": "A", "explanation": "The agency responsible for fulfilling the purpose of the state is government. Government is an agency responsible for fulfilling the purpose of the state.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2019>40", "subject": "Government", "year": "2019", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The power of the electorate signifies", "images": [], "options": {"A": "political sovereignty.", "B": "legal sovereignty.", "C": "external sovereignty.", "D": "internal sovereignty."}, "answer": "A", "explanation": "The power of the electoral signifies political sovereignty. Political sovereignty rests in that class of people under whose influence the mass of the people is or the people are.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2019>41", "subject": "Government", "year": "2019", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "The removal of government direct control and monopoly in manufacturing and service sectors is called", "images": [], "options": {"A": "privatization.", "B": "specialization.", "C": "commercialization.", "D": "decentralization."}, "answer": "A", "explanation": "Privatization is the removal of government direct control and monopoly in manufacturing and service sectors. It is when private individual take charge of the control of a business where government participation is minimal.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>42", "subject": "Government", "year": "2019", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "ECOWAS Monitoring Group (ECOMOG) was establish to", "images": [], "options": {"A": "recruit able-bodies men to defend West Africa.", "B": "restore peace to war-torn West African countries.", "C": "change bad government in West Africa.", "D": "arrest and prosecute war leaders."}, "answer": "B", "explanation": "The ECOWAS Monitoring Group (ECOMOG) was a West African multilateral armed force established by the Economic Community of West African States (ECOWAS). ECOMOG was a formal arrangement for separate armies to work together. It was established to restore peace to war-torn West African countries. It was not established to recruit able-bodied men to defend West Africa, change bad government in West Africa, or arrest and prosecute war leaders.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2019>43", "subject": "Government", "year": "2019", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The major concern of the United Nations Organization (UNO) is world", "images": [], "options": {"A": "trade.", "B": "peace.", "C": "health.", "D": "cooperation."}, "answer": "B", "explanation": "The major concern of the United Nations Organisation (UNO) is world peace to promote peace among the member state.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2019>44", "subject": "Government", "year": "2019", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "Nationalist agitation in British West Africa after the World War II led to the", "images": [], "options": {"A": "disregard for traditional rulers who supported the British.", "B": "formation of political parties.", "C": "killing of British administrative officials.", "D": "cooperation of the ex-servicemen with the governor."}, "answer": "B", "explanation": "Nationalist agitation in British West Africa after the World War II led to the formation of political parties.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>45", "subject": "Government", "year": "2019", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "An African-American who contributed greatly to the growth of nationalism in West Africa was", "images": [], "options": {"A": "Martin Luther King.", "B": "Jesse Jackson.", "C": "Nelson Mandela.", "D": "William Du Bois."}, "answer": "A", "explanation": "An African-American who contributed greatly to the growth of nationalism in West Africa was Martin Luther King.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2019>46", "subject": "Government", "year": "2019", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which of the following is not a component of political culture?", "images": [], "options": {"A": "Norms", "B": "Age", "C": "Beliefs", "D": "Attitudes"}, "answer": "B", "explanation": "Age is not a component of political culture. The components of political culture include Norms Beliefs and Attitudes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>47", "subject": "Government", "year": "2019", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI", "question": "The following were checks on the powers of Chiefs during the pre-colonial era except the", "images": [], "options": {"A": "British Officials", "B": "Kingmakers", "C": "Council of Elders", "D": "Age grades"}, "answer": "A", "explanation": "The following were checks on the powers of chiefs during the pre-colonial era except the british official. Kingmakers, Council of elders and Age grades were checks on the powers of chiefs during the pre-colonial era.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2019>48", "subject": "Government", "year": "2019", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : PRE-INDEPENDENCE CONSTITUTIONS", "question": "A common feature of pre-independence constitutions of British West African Colonies was the", "images": [], "options": {"A": "existence of separation of powers.", "B": "governor's membership of both the Legislative and Executive Councils.", "C": "adoption of federalism.", "D": "establishment of Council of Elders."}, "answer": "B", "explanation": "Governor's membership of both the Legislative and Executive Councils is a common feature of pre-Independence constitution of British West African colonies.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2019>49", "subject": "Government", "year": "2019", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "Which of the following features of Indirect Rule contributed immensely to Nationalism in British West Africa?", "images": [], "options": {"A": "Establishment of native treasuries", "B": "The appointment of resident district commissioners", "C": "Establishment of the native courts", "D": "Exclusion of the educated elites"}, "answer": "D", "explanation": "Features of Indirect rule contributed immensely to nationalism. In British West Africa is exclusion of the educated elites.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2019>50", "subject": "Government", "year": "2019", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "The first inter-territorial association organized by some educated African elite in the Gold Coast was the", "images": [], "options": {"A": "Aborigines' Rights Protection Society (ARPS).", "B": "National Congress of British West Africa (NCBWA).", "C": "Movement of Educated Elites in West Africa (MEEWA).", "D": "West African Frontier Forces (WAFF)."}, "answer": "A", "explanation": "The first inter-territorial association organized by some educated African elite in the Gold Coast was the Aborigines' Rights Protection Society (ARPS). The ARPS was formed in 1897 to resist the Crown Lands Bill of 1896 and the Lands Bill of 1897 which sought to give the British Crown the right to all lands in the colony. The ARPS was successful in its resistance and this marked the beginning of organized nationalist activities in the Gold Coast.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2020>1", "subject": "Government", "year": "2020", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "In a modern democracy, a government is", "images": [], "options": {"A": "a contract between the rulers and the ruled", "B": "a perserve of the political party in power", "C": "monopoly of the major ethnic group", "D": "alteration of power between the majority and minority tribes"}, "answer": "A", "explanation": "Democracy is a system of government in which power is vested in the people and exercised by them directly or through freely elected.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>2", "subject": "Government", "year": "2020", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "The ability to make and enforce laws and administer justice constitute the major functions of a", "images": [], "options": {"A": "nation", "B": "society", "C": "government", "D": "pressure group"}, "answer": "C", "explanation": "Government is a political direction and control exercised over the actions of the members, citizens or inhabitants of communities,societies,and states;direction of the affairs of a state,community etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>3", "subject": "Government", "year": "2020", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : EXECUTIVE", "question": "Executive power in a cabinet system of government is vested in the", "images": [], "options": {"A": "legislature", "B": "judiciary", "C": "civil service", "D": "Council of Ministers"}, "answer": "D", "explanation": "There is no strict separation of powers between the executive and the legislature.In the cabinet/parliamentary system,the real executive powers are vested in the council of ministers known as the cabinet or executive,headed by the Prime minister and the legislature serves as the source of authority for the executive.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>4", "subject": "Government", "year": "2020", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : CONFEDERAL", "question": "A feature of confederal state is that", "images": [], "options": {"A": "it is a single sovereign state", "B": "its constitution is flexible", "C": "any unit can secede at will", "D": "its powers are distributed equally between the centre and units"}, "answer": "C", "explanation": "A confederal state is a union of states where each state retains its sovereignty and independence and has the power to govern itself. One of the key features of a confederal state is that any unit (state) can secede at will. This means that any state in the confederation can decide to withdraw from the union at any time.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2020>5", "subject": "Government", "year": "2020", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "One of the limitations to the principle of rule law is", "images": [], "options": {"A": "immunity", "B": "equality", "C": "liberty", "D": "impartiality"}, "answer": "A", "explanation": "The limitations of rule of law are: state of emergency, the type of government, partial judiciary, special or administration tribunals, poverty,illiteracy and ignorance, granting of discretional powers, diplomaticand parliamentary immunity, obnoxious laws, police brutality, intergrity of judges,delegated legislation etc", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2020>6", "subject": "Government", "year": "2020", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY", "question": "Countries adopted unitary system of government because it", "images": [], "options": {"A": "detests dictatorship", "B": "promotes national integration", "C": "concentrates power only at the centre", "D": "allows the component units to secede at will"}, "answer": "B", "explanation": "Countries adopt a unitary system of government because it promotes national integration. A unitary system of government is a system where the central government holds supreme power, and any administrative divisions (which may exist) exercise only powers that the central government chooses to delegate. This system helps to promote national integration as it ensures that all decisions and policies are made and implemented uniformly across the country, thus promoting unity and reducing regional disparities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>7", "subject": "Government", "year": "2020", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : EXECUTIVE", "question": "Which of the following is an advantage of monocephalous executive?", "images": [], "options": {"A": "Sharing of power", "B": "Quick decision making", "C": "Impartial dispensation of justice", "D": "Enjoyment of press freedom"}, "answer": "B", "explanation": "Monocephalous executive advantages are: separation of power, checks and balances, fixed tenure of office, prevents emergence of dictators, effective executive control etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>8", "subject": "Government", "year": "2020", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A major difference between power and authority is that, authority is", "images": [], "options": {"A": "scarcely exercised", "B": "more dependent on coercion", "C": "acquired popularly", "D": "exercised through force"}, "answer": "C", "explanation": "One of the difference between power and authority is that, power requires some elements of force and sanction while authority is exercised without the application of force.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2020>9", "subject": "Government", "year": "2020", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Political participation can take the form of", "images": [], "options": {"A": "belonging to a trade union", "B": "being a member of a pressure group", "C": "canvassing for votes", "D": "organizing festival for good harvest"}, "answer": "B", "explanation": "Political participation can take many forms, including being a member of a pressure group. A pressure group is an organized group that seeks to influence government (public) policy or protect or advance a particular cause or interest. Groups may promote a specific issue and raise it up the political agenda, represent a particular section in society or they may have more general political and ideological objectives in mind when they campaign.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2020>10", "subject": "Government", "year": "2020", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Which of the following is a disadvantages of proportional representation? It", "images": [], "options": {"A": "encourages rigging", "B": "promotes strong government", "C": "makes for easy decision making in parliament", "D": "is difficult and cumbersome to operate"}, "answer": "D", "explanation": "The disadvantages of proportional representation are:   - it is a complicated form of election of representative  - the system is very expensive to operate  - the system does not give room for political stability  - the system is not easy to run", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2020>11", "subject": "Government", "year": "2020", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The sum total of authority in a state unrestrained by law is", "images": [], "options": {"A": "monarchy", "B": "society", "C": "oligarchy", "D": "sovereignty"}, "answer": "D", "explanation": "Sovereignty is the full right and power of a governing body over itself,without any interference from outside source or bodies. In political theory,it is the ultimate overseer, or authority, in the decision-making process of the state and in the maintenance of order.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>12", "subject": "Government", "year": "2020", "type": "Objective", "topic": "CONSTITUTIONS : FUNCTIONS", "question": "The flexibility and rigidity of costitution refer to the", "images": [], "options": {"A": "sources of constitution", "B": "making of constitution", "C": "ease of amending constitution", "D": "coding of constitution"}, "answer": "C", "explanation": "The flexibility and rigidity of costitution refer to how easily a constitution can be amended and how easily the constitutional landscape and framework can change.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2020>13", "subject": "Government", "year": "2020", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The observance of Rule of Law in a state requires", "images": [], "options": {"A": "an independent judiciary", "B": "an ineffective police system", "C": "a flexible constitution", "D": "existence of two-party system"}, "answer": "A", "explanation": "An independent judiciary is the concept that the judiciary should be independent from the other branches of government or the politician in office.That is, courts should not be subjected to improper influence from the other branches of government or form private or partisan interests.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>14", "subject": "Government", "year": "2020", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "The principle of seperating the judiciary from the other organs of government and making it free from executive and legislature influence is termed", "images": [], "options": {"A": "judicial independence", "B": "judicial review", "C": "separation of powers", "D": "functions of powers"}, "answer": "A", "explanation": "Judicial independence is the concept that the judiciary should be independent from the other branches of government or the politician in office.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2020>15", "subject": "Government", "year": "2020", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "The right to respect the personality of the individual is a", "images": [], "options": {"A": "civil right", "B": "natural right", "C": "social right", "D": "economic right"}, "answer": "B", "explanation": "The right to respect the personality of the individual is a natural right. Natural rights are those that are not dependent on the laws, customs, or beliefs of any particular culture or government, and are therefore universal and inalienable (i.e., rights that cannot be repealed or restrained by human laws).", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2020>16", "subject": "Government", "year": "2020", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "Which of the following constitutional provisions gives a high degree of authority to component part of a military state?", "images": [], "options": {"A": "Devaluation", "B": "Delegation", "C": "Diversification", "D": "Declaration"}, "answer": "B", "explanation": "Delegation of powers is the act whereby a political authority invested with certain powers turns over the exercise of those powers, in full or in part, to another authority.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2020>17", "subject": "Government", "year": "2020", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "The following are redress available at the court for aggrieved people except", "images": [], "options": {"A": "injunction", "B": "mandamus", "C": "executions", "D": "prorogation"}, "answer": "D", "explanation": "Prorogation is the action of proroguing, or ending, an assembly, especially a parliament, or the discontinuance of meetings for a given period of time, without a dissolution of parliament.The term is also used for the period of such a discontinuance between two legislative sessions of a legislative body.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>18", "subject": "Government", "year": "2020", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "Which of the following usually leads to the curtailment of the rights of citizens?", "images": [], "options": {"A": "Transitional period", "B": "Granting of presidential pardon", "C": "Period of constitutional reforms", "D": "Violent socio-political unrest"}, "answer": "D", "explanation": "Political violence is violence perpetrated by people or governments to achieve political goals. Violent socio-political unrest happens as a result of collective dissatisfaction and manifests in unconventional and sometimes forms of behaviour that disrupts the typical social order of society.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>19", "subject": "Government", "year": "2020", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "The national secretariat of a political party is managed by the", "images": [], "options": {"A": "presidential candidate", "B": "founding members", "C": "national chairman and general secretary", "D": "national executive and youth organizer"}, "answer": "C", "explanation": "In a governmental system, a party leader acts as the official representative of their political party.The party leader is typically responsible for managing the party's relationship with the general public.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>20", "subject": "Government", "year": "2020", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "The type of election which allows party members to elect candidates for elective offices is", "images": [], "options": {"A": "general election", "B": "bye election", "C": "direct election", "D": "primary election"}, "answer": "D", "explanation": "Primary election are a process by which voters can indicate their preference for their party's candidate or a candidate in general , in an upcoming general election, local election or by-election.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2020>21", "subject": "Government", "year": "2020", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "An oppostion party which sees itself as \"government-in-waiting\" is called", "images": [], "options": {"A": "shadow government", "B": "caretaker government", "C": "national government", "D": "responsible government"}, "answer": "A", "explanation": "Shadow government is a government-in-waiting that is prepared to take control in responsible to certain events, especially one made up of the leadership of the largest opposition party in parliament, which would assume control should the ruling party be displaced in elections.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>22", "subject": "Government", "year": "2020", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "The document which sets out the programme of a political party and guides the electorate to vote for it is the", "images": [], "options": {"A": "constitution", "B": "electoral regular", "C": "manifesto", "D": "white paper"}, "answer": "C", "explanation": "Manifestos is a published declaration of the intentions, motives or views of the issuer, be it an individual, group, political party or government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>23", "subject": "Government", "year": "2020", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS", "question": "An advantage of two party system is that it", "images": [], "options": {"A": "simplifies the electoral process", "B": "ensures winner takes all", "C": "protect the electoral commission", "D": "protect the electorate from vote buying"}, "answer": "A", "explanation": "Advantages of two party system are:   - it is more democratic in nature  - provision of alternative party  - prevention of dictatorship  - provision of watchdog to the government  - it gurantees stable political system  - gurantees political association  - allows for smooth change of government  - wden political education and guarantees the expression  of public opinion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>24", "subject": "Government", "year": "2020", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "Which of the following is a non- partisan organization with the aim of influencing government policies?", "images": [], "options": {"A": "political party", "B": "pressure group", "C": "Humanitarian society", "D": "Rebel organization"}, "answer": "B", "explanation": "Pressure group is a group of people bound together by some common interests or profession who engage in some activities to influence government policies to their own advantage.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>25", "subject": "Government", "year": "2020", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "The collective views hold by majority of citizens of a country above a particular policy is", "images": [], "options": {"A": "national interest", "B": "public opinion", "C": "commentary", "D": "bulletin"}, "answer": "B", "explanation": "Public opinion refers to the exercised view of a cross-section of citizens on government policies and actions whether they are proposed, in progress or already carried out. when a majority of the citizens hold a common view on an issue,this is regarded as the public opinion on the issue.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>26", "subject": "Government", "year": "2020", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN INSTITUTION OF THE STATE:", "question": "An institution under the executive arm of government responsible for formulating and implementing government policies is the", "images": [], "options": {"A": "public service", "B": "public corporation", "C": "civil service", "D": "judicial service"}, "answer": "C", "explanation": "The 'civil service' is an institution under the executive arm of government responsible for formulating and implementing government policies. The civil service serves as the administrative machinery of government, and its role includes policy formulation, implementation, and service delivery.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>27", "subject": "Government", "year": "2020", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "The following are means of controlling public corporation except", "images": [], "options": {"A": "legislative control", "B": "judicial control", "C": "ministerial control", "D": "chief of staff control"}, "answer": "D", "explanation": "Control of public corporations are :  - parliamentary control  - financial control  - judicial control  - ministerial control  - public control", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>28", "subject": "Government", "year": "2020", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC/CIVIL SERVICE COMMISSION –MEANING AND FUNCTIONS.", "question": "The institution established by the constitution to be responsible for recruiting personnel into the Civil service is the", "images": [], "options": {"A": "Personnel Management Office", "B": "Office of the president", "C": "National Labour Commission", "D": "Public Services Commission"}, "answer": "D", "explanation": "The public(Civil) service Commission is an independent body set up by the government charged with the responsibility for employing, promoting,disciplining and dismissing civil servants.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>29", "subject": "Government", "year": "2020", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "If a winner emerges in an election as a result of his/her votes being more than the combined votes of the opposing contestants; what type of electoral system is being practised?", "images": [], "options": {"A": "Absolute majority", "B": "Plurality", "C": "Second ballot", "D": "Alternative vote"}, "answer": "A", "explanation": "Absolute majority system refers to the ability of the winning candidates to acquire more than half of the total votes i.e his votes is more than the addition of all other candidates' votes.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2020>30", "subject": "Government", "year": "2020", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : ELECTORAL MANAGEMENT BODY", "question": "Which of the following is a function of an Electoral Commission?", "images": [], "options": {"A": "Adjudicating electoral petition", "B": "Provision of electoral registers", "C": "Disciplining personnel in the Civil Service", "D": "Promotion of public servants"}, "answer": "B", "explanation": "The functions or roles of Electoral commission are:  - the commission delimits the country into constituencies for the purpose of electing representatives into the government  - the commission organises and conducts elections into the various levels of government throughout the country.  - the commission registers political parties wishing to contest elections  - the commission registers voters and provides a comprehensive voters registers for every election in the country  - the commission recruits,trains and deploys officials to the different parts of the country to assist in the conduct and supervision of elections.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>31", "subject": "Government", "year": "2020", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Which of the following is not an electoral malpractice?", "images": [], "options": {"A": "Impersonation", "B": "Threatening", "C": "Campaigning for a candidate", "D": "Gerrymandering"}, "answer": "C", "explanation": "Campaigning for a candidate is not an electoral malpractice. Electoral malpractices are actions that interfere with the free and fair conduct of an election. These include impersonation, threatening, and gerrymandering. However, campaigning for a candidate is a legitimate part of the electoral process where a person or group promotes a candidate to voters.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>32", "subject": "Government", "year": "2020", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "Local government sources of revenue can best be improved through", "images": [], "options": {"A": "schools", "B": "the collection of import duties", "C": "the provision of housing units", "D": "cottage industries"}, "answer": "D", "explanation": "Local government sources of revenue can best be improved through cottage industries. Cottage industries are small-scale industries that can be started with a small amount of capital and can generate income for the local government through taxes. Schools, the collection of import duties, and the provision of housing units are not direct sources of revenue for local governments.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>33", "subject": "Government", "year": "2020", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "Public opinion is important in that, it", "images": [], "options": {"A": "helps political parties to asses their policies", "B": "creates delays in the execution of policies", "C": "may be unreliable and misleading", "D": "can be manipulated by political opponents"}, "answer": "A", "explanation": "Public opinion is important because the needs of the people are made known to the government through public opinion, it helps the government know the opinion of the citizens on its programmes and to react appropriately in continuing, moderating or stoppage such programmes, it helps the voters to know which candidates are most accepted and so align with the majority, public opinion makes people more aware of the activities of their government and the advisability of such activities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>34", "subject": "Government", "year": "2020", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "One of the features of pressure groups is that all members", "images": [], "options": {"A": "are rich", "B": "think in the same way", "C": "have similar interests", "D": "oppose the government"}, "answer": "C", "explanation": "Pressure group exist to protect the common interest of members and not to take over the governance as political parties do.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2020>35", "subject": "Government", "year": "2020", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "Which of the following modes of operation of pressure group undermines economic, social and political stability of a state?", "images": [], "options": {"A": "Lobbying", "B": "Symposia", "C": "Strikes", "D": "Debates"}, "answer": "C", "explanation": "Strike and boycotts are employ to achieve their aims where other means fail.In trying to avoid the great loss that may arise from a long-term strike,the owner of an organisation may agree to what the pressure group demands.If the strike is directed at government may negotiate with the pressure group in order to ensure industrial peace and political stability.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2020>36", "subject": "Government", "year": "2020", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "The police perform all the following functions except", "images": [], "options": {"A": "public execution of law breakers", "B": "prosecuting law breakers", "C": "protection of life and property", "D": "enforcement of law and order"}, "answer": "A", "explanation": "The functions of the police are : enforcement of law and order, protection of life and property, prosecuting law breakers etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>37", "subject": "Government", "year": "2020", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "Which of the following is a reason for the failure of the assimilation policy in French West Africa?", "images": [], "options": {"A": "The change in name of their culture", "B": "The refusal of the African to be culturally colonized", "C": "The paternal policy of the French", "D": "Bribery of the opinion leaders by the French"}, "answer": "B", "explanation": "The preference of the African people for their culture and way of life made it impossible for them to drop their culture for that of the French, and likewise did they reject the whole policy of assimilation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2020>38", "subject": "Government", "year": "2020", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "The capital of the French Federation of West African States was located in", "images": [], "options": {"A": "Bamako, Mali", "B": "Dakar, Senegal", "C": "Conakry, Guinea", "D": "Niamey, Niger"}, "answer": "B", "explanation": "French established a loose federation of her colonies, with headquaters in Dakar,Senegal, and appointed a governor-general resident in Dakar to supervise the activities of the federation.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2020>39", "subject": "Government", "year": "2020", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Under the crown colony system of administration major policies were implemented in the colonies by the", "images": [], "options": {"A": "Chief and their elders", "B": "Secretary of states for the colonies", "C": "Chiefs and the British", "D": "Colonial Governor"}, "answer": "B", "explanation": "The Crown Colony system of administration was a form of colonial administration in the British Empire. Under this system, the major policies were implemented in the colonies by the Secretary of State for the Colonies. The Secretary of State for the Colonies was a British government official who was responsible for managing the various colonies of the British Empire.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>40", "subject": "Government", "year": "2020", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "One way of improving productivity in the Public Services is through", "images": [], "options": {"A": "promotion without examination", "B": "higher salaries and allowances", "C": "increase in working hours", "D": "open door policy"}, "answer": "D", "explanation": "Improving productivity in the Public Services can be achieved through an open door policy. An open door policy is a communication policy in which a manager, CEO, MD, president or supervisor leaves their office door 'open' in order to encourage openness and transparency with the employees of that place. This encourages communication, feedback, and discussion about any matter of importance to an employee.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>41", "subject": "Government", "year": "2020", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Which of the following made the colonial Governor a \"Virtual Dictator\"?", "images": [], "options": {"A": "legislative Council", "B": "Executive Council", "C": "Appointment of departmental heads", "D": "Reserved veto powers"}, "answer": "D", "explanation": "A dictatorship is a form of government characterized by a single leader or group of leaders and  little or no toleration for political pluralism or independent programs or media.The veto power or right is vested in one branch of a government to cancel or postpone the decisions,enactments et.c.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>42", "subject": "Government", "year": "2020", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "Which of the following is a feature of the French Policy of Association?", "images": [], "options": {"A": "Elevation of the position of the Chiefs", "B": "French citizenship to subjects", "C": "Scholarship to needy students", "D": "Introduction of indigent"}, "answer": "B", "explanation": "One of the Feature of the French Policy of Association is that the Africans, no longer regarded as French citizens, but as inferior people, were subjected to dehumanising experiences such as forced labour.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>43", "subject": "Government", "year": "2020", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "The African Union is most often", "images": [], "options": {"A": "financial weakness", "B": "absence of African High Command", "C": "difference in culture", "D": "language barrier and race"}, "answer": "A", "explanation": "One of the waekeness of the AU is that AU has not been able to respond to issues of high level poverty snd joblessness among a significant portion of youth also, AU relies on the support of external donors such as UN and world bank.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2020>44", "subject": "Government", "year": "2020", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "The formation of the African Union is aimed at achieving a wider goal of", "images": [], "options": {"A": "cultural integration", "B": "continental government", "C": "national solidarity", "D": "African identity"}, "answer": "D", "explanation": "The aim of African Union are: to achieve unity and solidarity between the Africa countries and the people of africa, to accelerate the poltical and social economic intergration of the continent, to defend the sovereignty, territorial intergrity and independence of its member states, to promote and defend Africa positions on issue of interest to the continent and its people etc.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2020>45", "subject": "Government", "year": "2020", "type": "Objective", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "A major advantage of a country's foreign policy is that, it", "images": [], "options": {"A": "encourages infringement on the territories of other states", "B": "promotes the country's national interest", "C": "stimulates political activities in the state", "D": "promotes understanding between the leaders and the led"}, "answer": "B", "explanation": "The advantages of foreign policy are: protection of national interest, safeguarding the interest of Nigeria citizens, equality of the countries, foreign aid to other countries, resolution of conflict, non- alignment etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>46", "subject": "Government", "year": "2020", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "The West African Students Union(WASU) was formed by", "images": [], "options": {"A": "Siaka Stevens", "B": "K. A Gbedemah", "C": "E.F.Small", "D": "Oladipo Solanke"}, "answer": "D", "explanation": "The West African Students Union(WASU) was formed by Ladipo Solanke and founded in London in 1925 and active into the 1960s.It was an association of students from various West African Countries who were studying in the United Kingdom.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>47", "subject": "Government", "year": "2020", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "A military coup d' etat is followed by", "images": [], "options": {"A": "enforcement of fundamental human rights", "B": "suspension of the constitution", "C": "breaking of diplomatic relations with foreign countries", "D": "mass importation of fire arms"}, "answer": "B", "explanation": "Coup d'etat is an illegal, unconstitutional seizure of power by a political faction, the military or a dictator.The suspension and modification of some sections of constitution to be in line with the military rule.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2020>48", "subject": "Government", "year": "2020", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY", "question": "Which of the following countries is a unitary state?", "images": [], "options": {"A": "Nigeria", "B": "Egypt", "C": "Ghana", "D": "Canada"}, "answer": "C", "explanation": "Ghana is a unitary state. A unitary state is a state governed as a single entity in which the central government is ultimately supreme. The central government may create (or abolish) administrative divisions (sub-national units). Such units exercise only the powers that the central government chooses to delegate. Nigeria and Canada are federal states, while Egypt is a semi-presidential republic.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>49", "subject": "Government", "year": "2020", "type": "Objective", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "Which of the following does not influence a country's foreign policy?", "images": [], "options": {"A": "Desire for foreign investments", "B": "International law, Coventions and Treaties", "C": "Religion and racial factors", "D": "Age of the leader"}, "answer": "D", "explanation": "The factors that influence a country's policy are: geographical factor, demographical factor, economic factor, internal political factor, internal political pressure, historical experience, government, the ideological orientation of the ruling, the continuing rivalry between the east and west, interest/pressure groups.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2020>50", "subject": "Government", "year": "2020", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "The National Congress Of the British West Africa(NCBWA) was formed in", "images": [], "options": {"A": "Sierra leone", "B": "Liberia", "C": "Ghana", "D": "Nigeria"}, "answer": "A", "explanation": "The National Congress of British West Africa (NCBWA) was formed in Sierra Leone in 1920. The NCBWA was a collaborative effort of various nationalists in British West Africa, aiming to advocate for the rights of Africans and to promote unity among the British West African colonies. The congress was not formed in Liberia, Ghana, or Nigeria.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>1", "subject": "Government", "year": "2021", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "An undesirable attribute of capitalism is mostly seen in", "images": [], "options": {"A": "freedom of choice", "B": "exploitation of labour", "C": "efficient production of goods and services", "D": "effective utilization of labour"}, "answer": "B", "explanation": "Capitalism gives room for the exploitation of many people by few individuals in the country. It also leads to man's inhumanity to man. Profits are made at all costs even at the expense of human life.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>2", "subject": "Government", "year": "2021", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "A constitution that requires an absolute majority of members of parliament to amend is a", "images": [], "options": {"A": "confederal constitution", "B": "federal constitution", "C": "flexible constitution", "D": "rigid constitution"}, "answer": "D", "explanation": "A rigid constitution cannot be amended or changed so easily because of its special stringent and cumbersome procedures of amendment. The procedures for the amendment of a rigid constitution are different from the processes of making ordinary laws.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2021>3", "subject": "Government", "year": "2021", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "What is the term given to the action of discontinuing a session of a parliament or other legislative assembly without dissolving?", "images": [], "options": {"A": "Adjournment", "B": "Postponement", "C": "Prorogation", "D": "Recess"}, "answer": "C", "explanation": "'Prorogation' in politics is the action of ending an assembly, especially a parliament, or the discontinuance of meetings for a given period of time, without dissolution of parliament.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>4", "subject": "Government", "year": "2021", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PRESIDENTIAL", "question": "In a monocephalous executive system of government, all executive powers are vested in", "images": [], "options": {"A": "Chief Justice", "B": "President", "C": "Prime Minister", "D": "Speaker"}, "answer": "B", "explanation": "Also known as presidential system of government. This means that th executive power rests with one person, the president, but not shared between him and another person acting as head of state.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2021>5", "subject": "Government", "year": "2021", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "The action programme of a political party intended to be carried out when political power is won is known as", "images": [], "options": {"A": "code of conduct", "B": "party constitution", "C": "party survey", "D": "manifesto"}, "answer": "D", "explanation": "Manifesto is a public declaration of policy and aims, especially one issued before an election by a political party or candidate.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2021>6", "subject": "Government", "year": "2021", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : MASS MEDIA", "question": "What does the mass media rely on to gain public opinion?", "images": [], "options": {"A": "influential citizens", "B": "Propaganda and interviews", "C": "Polls and surveys", "D": "Rumour and gossip"}, "answer": "C", "explanation": "The measurement or determination of public opinion are: opinion poll, election, referendum, through the mass media and public response.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>7", "subject": "Government", "year": "2021", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : MASS MEDIA", "question": "Which of the following options is the role of a newspaper in a state?", "images": [], "options": {"A": "Determines government appointments", "B": "Disseminates information", "C": "Ensures fairness in newspaper circulation", "D": "Ensures fair distribution of relief items"}, "answer": "B", "explanation": "Newspaper is a printed publication appearing daily. It contains news, advertisements and articles on various subjects. Newspapers play an important role in a democracy. They act as bridge between the government and the governed.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2021>8", "subject": "Government", "year": "2021", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "The Civil Service helps the government to", "images": [], "options": {"A": "recruit personnel for the army", "B": "develop and implement policies effectively", "C": "maintain instability in the state", "D": "stay in power for a long time"}, "answer": "B", "explanation": "The functions of the civil service are: policy formation, policy execution, advice to the government, contributions in law making process, legislature function, provision of social services etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>9", "subject": "Government", "year": "2021", "type": "Objective", "topic": "CITIZENSHIP : MEANS OF SAFEGUARDING RIGHTS OF CITIZENS.", "question": "A citizen is barred from active politics when employed as a", "images": [], "options": {"A": "university lecturer", "B": "priest", "C": "civil servant", "D": "journalist"}, "answer": "C", "explanation": "The civil service and its workers known as the civil servants perform purely administrative and executive functions which entail formulation and implementation of government policies.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>10", "subject": "Government", "year": "2021", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Citizen's political participation is best practiced under a", "images": [], "options": {"A": "militant pressure group", "B": "neighborhood vigilant group", "C": "cooperative society", "D": "political party"}, "answer": "D", "explanation": "Political party is an organized group of people who share similar political opinions, principles, interests and beliefs with the aim of gaining political power and governing of the country.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2021>11", "subject": "Government", "year": "2021", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "The most important function of government is to ensure the", "images": [], "options": {"A": "building of offices and houses", "B": "judiciary is well resourced", "C": "second arm of government is respected", "D": "security of the citizens"}, "answer": "D", "explanation": "A government, basically, has three branches - the Executive, the Legislative, and the Judicial. These branches help in the all-round functioning of a government. The main function of the federal government is creating and enforcing laws to ensure order and stability within society.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2021>12", "subject": "Government", "year": "2021", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "The right to an adequate standard of living falls under", "images": [], "options": {"A": "civil right", "B": "economic right", "C": "free market economy", "D": "right to life"}, "answer": "B", "explanation": "Economic Rights means, with respect to a security, the right to the full pecuniary interest in the security, including, without limitation, the right to receive dividends and distributions, proceeds upon liquidation and receive the proceeds of disposition or conversion (if applicable) of the security.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>13", "subject": "Government", "year": "2021", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "People's political values are continuously shaped by the following agents except", "images": [], "options": {"A": "education", "B": "family", "C": "media", "D": "ombudsman"}, "answer": "D", "explanation": "People's political values are shaped by various agents such as education, family, and media. These agents play a significant role in influencing and shaping an individual's political values and beliefs. However, the ombudsman does not shape people's political values. An ombudsman is an official, usually appointed by the government, who investigates complaints (usually lodged by private citizens) against businesses, financial institutions, or government departments or other public entities, and attempts to resolve the conflicts or concerns raised, ensuring justice, fairness, and the proper administration of laws. Therefore, the ombudsman is not involved in shaping people's political values.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>14", "subject": "Government", "year": "2021", "type": "Objective", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : FEATURES AND PROBLEMS", "question": "In which political system are there two levels of government with considerable devolution?", "images": [], "options": {"A": "Capitalism", "B": "Federalism", "C": "Fascism", "D": "Unitarism"}, "answer": "B", "explanation": "Federalism is a political system where there are two levels of government with considerable devolution. In a federal system, power is divided between a central government and individual states, provinces, or other territorial units. Each level of government has its own set of responsibilities and powers. This is different from other political systems like capitalism (an economic system), fascism (a form of far-right, authoritarian government), and unitarism (a system where all power is centralized). Therefore, the correct answer is Federalism.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2021>15", "subject": "Government", "year": "2021", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "A system of government in which people elect their lawmakers and make them accountable for their actions and inactions in government is", "images": [], "options": {"A": "a representative government", "B": "first-past-the-post government", "C": "an oligarchy government", "D": "checks and balances system of government"}, "answer": "A", "explanation": "Representative democracy, also known as indirect democracy, is a type of democracy founded on the principle of elected persons representing a group of people,", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2021>16", "subject": "Government", "year": "2021", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Which territories in British West Africa did the colonial government exercise limited jurisdiction?", "images": [], "options": {"A": "Conquered states", "B": "Mandated territories", "C": "Protectorates", "D": "Trust territories"}, "answer": "C", "explanation": "In British West Africa, the colonial government exercised limited jurisdiction over the protectorates. A protectorate is a state that is controlled and protected by another sovereign state. It is independent in its internal affairs but under the control of an external sovereign state in its foreign relations. The British colonial government had limited jurisdiction over these territories because they were not fully under British control.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>17", "subject": "Government", "year": "2021", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "One of the following French West African colonies was the first to gain independence", "images": [], "options": {"A": "Benin", "B": "Burkina Faso", "C": "Guinea", "D": "Togo"}, "answer": "D", "explanation": "Togo was the first French West African colony to gain independence on April 27, 1960. The other countries listed gained independence later: Benin (then Dahomey) in 1960, Burkina Faso (then Upper Volta) in 1960, and Guinea in 1958, but Guinea was not a French West African colony, it was a French colony in West Africa.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>18", "subject": "Government", "year": "2021", "type": "Objective", "topic": "NATIONALISM : NATIONALISM: MEANING, FACTORS AND EFFECTS.", "question": "The struggle by the chiefs and people of West Africa against political, social and economic dominance by European powers was referred to as", "images": [], "options": {"A": "imperialism", "B": "nationalism", "C": "neo-colonialism", "D": "liberation"}, "answer": "B", "explanation": "Nationalism is an idea and movement that holds that the nation should be congruent with the state. As a movement, nationalism tends to promote the interests of a particular nation, especially with the aim of gaining and maintaining the nation's sovereignty over its homeland.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>19", "subject": "Government", "year": "2021", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "The European imperialist penetration into West Africa was primarily motivated by the following consideration except", "images": [], "options": {"A": "compassion", "B": "economic", "C": "social", "D": "military"}, "answer": "A", "explanation": "The European imperialist penetration into West Africa was primarily motivated by the following: Economic, social and military.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2021>20", "subject": "Government", "year": "2021", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "Which policy made the colonized French West African partners with France in her colonial project?", "images": [], "options": {"A": "Assimilation policy", "B": "Association policy", "C": "Indirect policy", "D": "Loi Cadre"}, "answer": "A", "explanation": "Assimilation was a major ideological component of French colonialism during the 19th and 20th centuries. The French government promoted the concept of cultural assimilation to colonial subjects in the French colonial empire, claiming that by adopting French culture they would ostensibly be granted the full rights enjoyed by French citizens and be legally considered \"French\".", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>21", "subject": "Government", "year": "2021", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "The British colonial governor in West Africa wielded sweeping powers by virtue of", "images": [], "options": {"A": "the land tenure system", "B": "drafting laws", "C": "tax collection", "D": "power"}, "answer": "B", "explanation": "The British colonial governor in West Africa wielded sweeping powers by virtue of drafting laws. During the colonial era, the British colonial governor had the power to draft laws that governed the colonies. This power was not derived from the land tenure system, tax collection, or just 'power' itself. It was specifically through the ability to create and enforce laws that the governor could exercise such extensive control.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>22", "subject": "Government", "year": "2021", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "The action plan by African countries under the New Partnership for Africa's Development (NEPAD), aimed at tackling the following issues except", "images": [], "options": {"A": "economic", "B": "political", "C": "religious", "D": "social"}, "answer": "A", "explanation": "The New Partnership for Africa's Development (NEPAD) is an economic development program of the African Union. NEPAD was adopted at the 37th session of the Assembly of Heads of State and Government in July 2001 in Lusaka, Zambia. NEPAD aims to provide an overarching vision and policy framework for accelerating economic co-operation and integration among African countries   The action plan by African countries under the New Partnership for Africa's Development (NEPAD), aimed at tackling the following issues of political, social and religious", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2021>23", "subject": "Government", "year": "2021", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "What motivated the adoption of Indirect Rule system by the British in her West African colonies?", "images": [], "options": {"A": "Effective and efficient tax system was in place", "B": "Chiefs did not have the power to make laws", "C": "Educated elites were in bed with the British government", "D": "The land was fertile for cash crop farming"}, "answer": "A", "explanation": "The colonial officials stressed that indirect rule was adopted in order to preserve and protect the political system already in existence. It was also a way of preparing Nigeria and the entire black race for eventual self-government. Language problem was another important factor that led to the adoption of indirect rule", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2021>24", "subject": "Government", "year": "2021", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "The Economic Community for West African States (ECOWAS) was established primarily to", "images": [], "options": {"A": "create a common currency for members countries", "B": "prevent neo-colonialism", "C": "sideline French West African countries in economic activities", "D": "Promote economic growth and development among member states"}, "answer": "D", "explanation": "Established on May 28 1975 via the treaty of Lagos, ECOWAS is a 15-member regional group with a mandate of promoting economic integration in all fields of activity of the constituting countries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>25", "subject": "Government", "year": "2021", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : MASS MEDIA", "question": "The media can best contributes to the democratic process of a country by", "images": [], "options": {"A": "lobbying ministries to be in their good books", "B": "setting the agenda for good governance", "C": "inciting strikes and demonstrations", "D": "recounting the achievement of the government in power"}, "answer": "B", "explanation": "It's a forum for support and safety information during a crisis   It's a valuable aid for crime-solving.   It's a form of political influence. Social media has given a true voice to the people.   It's the best-yet way to connect across vast distances", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2021>26", "subject": "Government", "year": "2021", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "Public corporations can deliver on their mandate if", "images": [], "options": {"A": "incidence of corruption and mismanagement were dealt with", "B": "loans were secured to pay staff well", "C": "politicians were members of the board", "D": "religious institutions pray for their success"}, "answer": "A", "explanation": "Public Corporations are expected to make profit or to be self-sustaining. However, profit-making is not the main aim for setting them up. They are managed and supervised by a board of directors appointed by the government for a specific period of time. One of the major problem is corruption.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>27", "subject": "Government", "year": "2021", "type": "Objective", "topic": "CITIZENSHIP : MEANING AND MODE OF ACQUISITION", "question": "Citizenship of a state is based on the following requirements except", "images": [], "options": {"A": "birth", "B": "marriage", "C": "education", "D": "naturalization"}, "answer": "C", "explanation": "The ways or method of acquisition of citizenship are: by birth, naturalization/application, registration/marriage, honorary citizenship, citizenship by conquest.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2021>28", "subject": "Government", "year": "2021", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS", "question": "One-party system encourages and often ends up in", "images": [], "options": {"A": "democracy", "B": "dictatorship", "C": "fair electoral contest", "D": "freedom of expression"}, "answer": "B", "explanation": "The disadvantages of party system are:   - undemocratic   - leads to dictatorship   - abridge human rights   - encompasses oppression   - leads to coup etc", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2021>29", "subject": "Government", "year": "2021", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "Which of the following tools is not used by pressure groups to achieve their aim?", "images": [], "options": {"A": "Boycotts", "B": "Demonstrations", "C": "Elections", "D": "Strikes"}, "answer": "C", "explanation": "Methods employed by pressure groups are:   - lobbying   - ultimatum   - strikes and boycotts   - pressure on the executive   - demonstration   - consultation   - protest letter etc", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>30", "subject": "Government", "year": "2021", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "Frequent military coup d' etats which topple elected governments negatively affect and stall", "images": [], "options": {"A": "education", "B": "culture and religion", "C": "health", "D": "democratic gains"}, "answer": "D", "explanation": "military coup d' etats which topple elected governments negatively affect and stall democratic gains", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2021>31", "subject": "Government", "year": "2021", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "How beneficial is delegated legislation to the democratic process? It", "images": [], "options": {"A": "aids lawmakers to become experts in legislation", "B": "cannot be applied during period of crises", "C": "helps to discipline personnel in the civil service", "D": "permits handling of certain aspect of legislation by non-technocrats"}, "answer": "A", "explanation": "Delegated legislation is beneficial to the democratic process because it aids lawmakers to become experts in legislation. Delegated legislation refers to laws that are passed by individuals or bodies under powers given to them by an act of parliament. This allows for more detailed and technical matters to be addressed by those who have the expertise in that area, thus improving the quality and effectiveness of the legislation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>32", "subject": "Government", "year": "2021", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "Local government performs a number of functions on behalf of the central government in the form of", "images": [], "options": {"A": "employing police officers", "B": "ensuring people attend religious institutions for prayers", "C": "mobilizing of resources for development", "D": "punishing opposition or dissent"}, "answer": "C", "explanation": "Powers and functions of local government are:   - provision of maintenance of market   - collection of taxes and rates   - maintenance of law and order   - provision of school and libraries etc", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>33", "subject": "Government", "year": "2021", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : MASS MEDIA", "question": "In an environment of press freedom, the media play the role of", "images": [], "options": {"A": "articulating views of individuals", "B": "inciting people to be lawless", "C": "projecting individuals above the state", "D": "highlighting only the activities of government"}, "answer": "A", "explanation": "The media plays a major role in keeping the citizenry abreast of current events and raising awareness of various issues in any society. It also has an extremely significant impact on the public's views and way of thinking. The media is the primary means through which public opinion is shaped and at times manipulated.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>34", "subject": "Government", "year": "2021", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Chiefs under the Indirect Rule system were used to carry out unpopular tasks, one of which was", "images": [], "options": {"A": "enforcement of Western education", "B": "establishment of churches", "C": "military conscription", "D": "presiding over native courts"}, "answer": "C", "explanation": "Under the Indirect Rule system, local chiefs were used by the colonial government to carry out certain tasks that were unpopular among the local population. One of these tasks was military conscription. This involved forcing people to join the military, which was often met with resistance from the local population. The other options such as enforcement of Western education and establishment of churches were not necessarily unpopular tasks, and presiding over native courts was a traditional role of chiefs, not an unpopular task imposed by the colonial government.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2021>35", "subject": "Government", "year": "2021", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "In restoring peace and security to Liberia and Sierra Leone, the Economic Community of West African States (ECOWAS), deployed a military force known as", "images": [], "options": {"A": "Regional Armed Forces (RAF)", "B": "Peace keeping Force of West Africa(PKFWA)", "C": "ECOWAS Ceasefire Monitoring Group (ECOMOG)", "D": "ECOWAS Heads of State and Government"}, "answer": "C", "explanation": "The Economic Community of West African States Monitoring Group (ECOMOG) was a West African multilateral armed force established by the Economic Community of West African States (ECOWAS). ECOMOG was a formal arrangement for separate armies to work together. It was largely supported by personnel and resources of the Nigerian Armed Forces, with sub-battalion strength units contributed by other ECOWAS members", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2021>36", "subject": "Government", "year": "2021", "type": "Objective", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "The desire for foreign investments and overseas market had become the driving force behind many West African countries", "images": [], "options": {"A": "educational policy", "B": "foreign policy", "C": "campaign tool", "D": "dream ideology"}, "answer": "B", "explanation": "Foreign Policy is such wheel around that the huge machinery of international politics revolves and operates. It is a sovereign relation between/among sovereign states of the world, to protect their own interest as well as of other states.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>37", "subject": "Government", "year": "2021", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "Citizenship does not only go with rights but also the performance of", "images": [], "options": {"A": "compulsory military service", "B": "compulsory teaching", "C": "certain obligations and duties", "D": "certain religious rites"}, "answer": "C", "explanation": "Citizenship is not only about enjoying rights but also about performing certain obligations and duties. These obligations and duties vary from country to country but generally include obeying the law, paying taxes, serving in the military if required, and voting in elections.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2021>38", "subject": "Government", "year": "2021", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "Taking over power, military governments disregard democratic protocols and rule mainly the", "images": [], "options": {"A": "decrees", "B": "popular acclamation", "C": "jury", "D": "court martial"}, "answer": "A", "explanation": "A decree is a rule of law usually issued by a head of state, according to certain procedures. It has the force of law. Decree is the law made by the military government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>39", "subject": "Government", "year": "2021", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : TYPES, MERITS AND DEMERITS", "question": "Which electoral system best suit a heterogeneous political environment?", "images": [], "options": {"A": "Non- transferable votes", "B": "Preferential ballot", "C": "Proportional representation", "D": "Run-off election"}, "answer": "C", "explanation": "Proportional representation (PR) characterizes electoral systems in which divisions in an electorate are reflected proportionately in the elected body. The concept applies mainly to geographical and political divisions of the electorate.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2021>40", "subject": "Government", "year": "2021", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "Judicial review in a democratic environment is an aspect of", "images": [], "options": {"A": "checks and balances", "B": "a check on the legislature", "C": "a check on the executive and the media", "D": "ensuring the police assist the judiciary in its work"}, "answer": "A", "explanation": "Judicial review is a process under which executive or legislative actions are subject to review by the judiciary. A court with authority for judicial review may invalidate laws, acts and governmental actions that are incompatible with a higher authority", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>41", "subject": "Government", "year": "2021", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "One advantage of multi-party system is that, the", "images": [], "options": {"A": "electorate have wide range of choice", "B": "educated elite represents their people in parliament", "C": "executive is not restrained by law", "D": "party in power creates employment for all sympathizers"}, "answer": "A", "explanation": "Since Multi party system gives room for people to elect their leaders from any political party of their choice, it therefore encourages democracy and allows more shades of opinion: Multi party system allows for more shades of opinion in the parliament which augurs well for the country", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>42", "subject": "Government", "year": "2021", "type": "Objective", "topic": "DEVELOPMENT OF MAJOR POLITICAL PARTIES : FORMATION, OBJECTIVES AND SOURCES OF INCOME", "question": "The following factors motivated the formation and growth of political parties in British West African territories except", "images": [], "options": {"A": "external socio-political factors", "B": "improvement in communication network", "C": "membership of legislature council", "D": "the role of newspapers"}, "answer": "C", "explanation": "The formation and growth of political parties in British West African territories were motivated by several factors including external socio-political factors, improvement in communication network, and the role of newspapers. However, membership of legislature council was not a motivating factor.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>43", "subject": "Government", "year": "2021", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : ELECTORAL MANAGEMENT BODY", "question": "Undue political interference in the work of electoral management bodies in West Africa has the potential to", "images": [], "options": {"A": "ensure fairness and transparency in their operations", "B": "employ qualified returning officers", "C": "erode the independence of the institutions", "D": "make all parties accept election results"}, "answer": "C", "explanation": "Undue political interference in the work of electoral management bodies in West Africa has the potential to erode the independence of the institutions", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2021>44", "subject": "Government", "year": "2021", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "A person who is denied the right to vote is described as", "images": [], "options": {"A": "uncivilized", "B": "disenfranchised", "C": "civil servant", "D": "non-partisan"}, "answer": "B", "explanation": "Disfranchisement, also called disenfranchisement, or voter disqualification is the restriction of suffrage (the right to vote) of a person or group of people, or a practice that has the effect of preventing a person exercising the right to vote. Disfranchisement can also refer to the revocation of power or control of a particular individual, community or being to the natural amenity they have; that is to deprive of a franchise, of a legal right, of some privilege or inherent immunity", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2021>45", "subject": "Government", "year": "2021", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "Public corporation is a semi-independent statutory body established by", "images": [], "options": {"A": "an Act of Parliament", "B": "a civil service commission", "C": "a private sector initiative", "D": "free zones board"}, "answer": "A", "explanation": "Public Corporation is a body corporate created by an Act of Parliament or Legislature. Its name is notified in the official gazette of the Central or State Government. It is an artificial person with the flexibility of the private sector and the powers of the government.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>46", "subject": "Government", "year": "2021", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "One of the objectives of the United Nations Organization (UNO) is to", "images": [], "options": {"A": "establish a standing army", "B": "give loans to poor countries in the world", "C": "promote and encourage respect for human rights and freedoms", "D": "ensure African leaders are respected"}, "answer": "C", "explanation": "The United Nations Organization (UNO) is an inter-governmental organization whose stated aims include promoting and facilitating cooperation in international law, international security, economic development, social progress, human rights, civil rights, civil liberties, political freedom, democracy and the achievement of lasting world peace.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>47", "subject": "Government", "year": "2021", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "The West African Youth League (W.A.Y.L) was a nationalist movement founded by", "images": [], "options": {"A": "Bankole-Bright", "B": "I.T.A Wallace-Johnson", "C": "J.E. Casely Hayford", "D": "Samuel Akinsanya"}, "answer": "B", "explanation": "The West African Youth League (WAYL) was a political organization founded by I. T. A. Wallace-Johnson in June 1935. The group was a major political force against the colonial government in West Africa, especially in the Gold Coast and Sierra Leone.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2021>48", "subject": "Government", "year": "2021", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "Commonwealth member states derive the following benefits from the association except", "images": [], "options": {"A": "assistance to war-torn countries", "B": "promotion of education", "C": "political instability", "D": "promotion of sports"}, "answer": "C", "explanation": "Advantages or benefits of common wealth membership are: Trade, military aid, common language, monetary aid, technical assistance, uniform legal system, co-operation in the field of education, scientific co-operation, encouragement of writers, free movement, common wealth games, useful forum etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>49", "subject": "Government", "year": "2021", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "The Economic Community of West Africa States (ECOWAS) is saddled with many problems, one of which is", "images": [], "options": {"A": "colonial heritage", "B": "facilitation of movement of people", "C": "inter-state trading", "D": "sports and cultural exchange"}, "answer": "A", "explanation": "The disadvantages or problems of ECOWAS are: Problems posed by immigrants, financial problems, increase in social vices, problem of language, fear of domination and unequal development, political instability etc.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2021>50", "subject": "Government", "year": "2021", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : CONFEDERAL", "question": "In which system of government are component units sovereign?", "images": [], "options": {"A": "Confederal", "B": "Federal", "C": "Monarchical", "D": "Republican"}, "answer": "A", "explanation": "A confederation is a union of sovereign groups or states united for purposes of common action. Usually created by a treaty, confederations of states tend to be established for dealing with critical issues, such as defense, foreign relations, internal trade or currency, with the central government being required to provide support for all its members.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2022>1", "subject": "Government", "year": "2022", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which political system allows only one ideology for the state?", "images": [], "options": {"A": "Socialism", "B": "Aristocracy", "C": "Communalism", "D": "Capitalism"}, "answer": "A", "explanation": "Socialism is the only political system that allows only one ideology as the state controls all means of production and distribution as a whole. Aristocracy puts it in the hand of a few members; communalism based on different groups while capitalism enables economy to be controlled by different individuals.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>2", "subject": "Government", "year": "2022", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "In a representative government, citizens exercise their political power", "images": [], "options": {"A": "directly", "B": "indirectly", "C": "in reverence for the political system", "D": "under undue political process"}, "answer": "B", "explanation": "In representative government, citizens elect certain individuals to represent their political interests.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2022>3", "subject": "Government", "year": "2022", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The essence of the concept of devolution is to cater for the interest of the", "images": [], "options": {"A": "ruling government", "B": "majority", "C": "minority", "D": "rule of law"}, "answer": "C", "explanation": "Devolution is the transfer of some authority from the central government to smaller organizations in order to bring the government closer to the minority while the central government covers the vast majority.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>4", "subject": "Government", "year": "2022", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "A country's constitution may be derived from which one of the following sources?", "images": [], "options": {"A": "Educational elites", "B": "Civil society organizations", "C": "Civil disobedience", "D": "Customs and conventions"}, "answer": "D", "explanation": "Customs and conventions are the original ways of life of the people in a particular place. When drawing a new constitution, customs and conventions serves as precedence.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>5", "subject": "Government", "year": "2022", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET", "question": "One major problem associated with the cabinet system of government is the", "images": [], "options": {"A": "abuse of power", "B": "frequent change of government", "C": "large number of ministers", "D": "supremacy of the executive"}, "answer": "D", "explanation": "As all members of the executives are part of the legislature, the executive could be dictatorial and overly supreme.  Arms of government are supposed to act as oversight over one another in democratic systems. Because all members of the executive are part of the legislature, there is more tendency of a dictatorship than a change of government which is why it is a major problem.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2022>6", "subject": "Government", "year": "2022", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "Representative governments around the world pay attention to public opinion because of the following factors except", "images": [], "options": {"A": "Protection of the government from media scrutiny.", "B": "Indication of government in good standing with the people.", "C": "Provision of feedback on implementation of government policies.", "D": "National security concern."}, "answer": "A", "explanation": "There is nothing a government can do to protect itself from media scrutiny and thus, this is not a factor why representative governments pay attention to public opinion.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>7", "subject": "Government", "year": "2022", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : GOVERNMENT AS AN INSTITUTION OF THE STATE:", "question": "The determination and execution of government policies the core function of the", "images": [], "options": {"A": "Public complaint commission", "B": "Public service commission", "C": "Civil service", "D": "Judicial service"}, "answer": "C", "explanation": "The civil service is typically described as the core, permanent administrative arm of government, including permanent and pensionable officials working in government ministries, departments and agencies. It includes staff who advise on, develop, and implement government policies and programmes and manage day-to-day activities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>8", "subject": "Government", "year": "2022", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "Public corporation has a legal personality which means that", "images": [], "options": {"A": "No legal suit can be brought against it", "B": "It can sue and be sued", "C": "It has ultimate power to make its own laws", "D": "There is a legal department that represents it"}, "answer": "B", "explanation": "To have legal personality means to be capable of having legal rights and duties within a certain legal system, such as to enter into contracts, sue, and be sued. Legal personality is a prerequisite to legal capacity, the ability of any legal person to amend rights and obligations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>9", "subject": "Government", "year": "2022", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "Local Government authorities may not receive cooperation from the local people to the issue of", "images": [], "options": {"A": "top bottom approach to development", "B": "accessibility to internet facilities", "C": "lack of support for the ruling government", "D": "non-availability of spiritual centres"}, "answer": "A", "explanation": "The top-bottom approach to development is a model where decision-making and policy formulation are done by the top-level management or government. This approach often faces resistance from local people as they feel their needs and perspectives are not considered. Hence, local government authorities may not receive cooperation from the local people on this issue.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>10", "subject": "Government", "year": "2022", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "Delegated legislation can be controlled by", "images": [], "options": {"A": "Report writing", "B": "Press conferences", "C": "Parliamentary question times", "D": "Threats of secession"}, "answer": "C", "explanation": "Also known as parliamentary or legislative control. This is usually exercised by requirement of law that the proposed delegated legislation be laid before the parliament which may debate it, and nod its approval, reject amend, limit, expand, suspend its approval, or otherwise control or review the delegated power or delegated legislation. Where the donee of the power is a sole administrator, the legislature may enlarge it by setting up a council or board to exercise the power to make rules or to consider and take action. Delegated legislation may also be limited by Parliament prescribing rule making standards for the delegate of powers or by imposing Procedural standards on the administrative process, which a delegate of power or authority is obliged to observe.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2022>11", "subject": "Government", "year": "2022", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS", "question": "A one party system imposed by law with all other parties proscribed is", "images": [], "options": {"A": "a socialist party system", "B": "a de jure one-party system", "C": "a communist political system", "D": "an elitist party system"}, "answer": "B", "explanation": "Because the question stipulates party system. The de jure party system is the correct answer. Communism is a political system instead.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2022>12", "subject": "Government", "year": "2022", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS", "question": "Multi-party system is saddled with the problem o", "images": [], "options": {"A": "divisiveness", "B": "limited choice", "C": "weak opposition", "D": "political consciousness"}, "answer": "A", "explanation": "The definition of divisive is something that tends to cause arguments or hostility among people. To the extent where there are many choices, there is always a tendency of disunity. Limited choices and weak opposition are near impossible when there are multiple choices while political consciousness is an advantage of multi-party system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>13", "subject": "Government", "year": "2022", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "One of the importance of voting in a democracy is that, it", "images": [], "options": {"A": "is less expensive.", "B": "endures development for all voters.", "C": "commits citizen to a political system", "D": "ensures winner takes all policy"}, "answer": "C", "explanation": "Voting in a democracy ensures that citizens are involved in their political system and have a say in political decisions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>14", "subject": "Government", "year": "2022", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "An electoral system in which the electorate elects a small group of people who in turn elects political office holders is known as", "images": [], "options": {"A": "general elections", "B": "second ballot system", "C": "electoral college", "D": "local election"}, "answer": "C", "explanation": "The Electoral College is a system where citizens indirectly elect the president and vice president through a body of electors. Electors are people chosen by their state parties prior to the general election who cast their vote for president/vice president.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2022>15", "subject": "Government", "year": "2022", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "Most pressure groups especially in West Africa fail to achieve their goals as a result of", "images": [], "options": {"A": "good governance", "B": "charisma of the president", "C": "transparency of the legislature", "D": "corrupt leadership"}, "answer": "D", "explanation": "Few groups that constitute the leadership of the pressure groups could use the platform to pursue opportunistic interests there by misrepresenting the entire citizens by deliberately misinforming government.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2022>16", "subject": "Government", "year": "2022", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "A pressure group which resorts to violence as a means of pressing home its demands is described as", "images": [], "options": {"A": "anomic", "B": "associational", "C": "labour agitation", "D": "attitudinal"}, "answer": "A", "explanation": "Anomic pressure groups are interest groups that use violence, demonstrations, arson, assassination, strikes and the like in expressing their aims and objectives. They are mob groups, not well organised but may be interested in some common goals. Street demonstrators and student riot groups are examples.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>17", "subject": "Government", "year": "2022", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : MASS MEDIA", "question": "Press control is necessary for a state particularly in the area of", "images": [], "options": {"A": "the economy", "B": "auditor-general's report", "C": "state security and secrets", "D": "foreign trade"}, "answer": "C", "explanation": "State security and secrets are delicate, hence, it will be reckless to have uncontrolled press releases on them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>18", "subject": "Government", "year": "2022", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : MASS MEDIA", "question": "The media helps to enrich discourse on national issues through its", "images": [], "options": {"A": "marketing", "B": "editorial comments", "C": "sales and advertisement", "D": "correspondents"}, "answer": "B", "explanation": "The media helps to enrich discourse on national issues through its editorial comments. Editorial comments are sections in a publication that express the newspaper's opinion on an issue. They are often used to discuss and analyze current events and issues, providing readers with different perspectives and insights. This can help to stimulate public debate and enrich discourse on national issues.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>19", "subject": "Government", "year": "2022", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : MASS MEDIA", "question": "Information dissemination and communication in a political environment had been made faster and easier with the advent of", "images": [], "options": {"A": "educated practitioners", "B": "press censorship", "C": "government spokesmen", "D": "social media"}, "answer": "D", "explanation": "Social media is a computer-based technology that facilitates the sharing of ideas, thoughts, and information through the building of virtual networks.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2022>20", "subject": "Government", "year": "2022", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "The passing of law by an arm of government to regulate society is the function of the", "images": [], "options": {"A": "Judiciary", "B": "Executive", "C": "Legislature", "D": "Police"}, "answer": "C", "explanation": "The legislature formulates laws, the executive implements the law while the judiciary interprets the law.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2022>21", "subject": "Government", "year": "2022", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "Militant nationalism in British West Africa after World War II sought to", "images": [], "options": {"A": "kill British nationals", "B": "overthrow colonialism", "C": "stop the export of raw materials", "D": "stop the denigration of African culture"}, "answer": "B", "explanation": "The Second World War was a catalyst for African political freedom and independence. The war helped build strong African nationalism, which resulted in a common goal for all Africans to fight for their freedom.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2022>22", "subject": "Government", "year": "2022", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "Proto-nationalism was a movement limited to the demands for", "images": [], "options": {"A": "immediate end to colonialism", "B": "reforms for the political class and respect for African religion", "C": "western education", "D": "social amenities and political participation"}, "answer": "D", "explanation": "Proto-nationalism was the activities of the nationalist movements channeled towards reforms and inclusion of natives in the colonial administration of their states. They did not aim at immediate sel-government rather, it aimed at including Africans to participate in the colonial administration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>23", "subject": "Government", "year": "2022", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "The youth movements across British West African territories served as a spring board for the formation of", "images": [], "options": {"A": "militant groups to fight and kill British officials", "B": "political parties to champion the course of self-rule", "C": "committees to represent the people", "D": "associations in pursuit of justice for the people"}, "answer": "B", "explanation": "One of the achievements of the National Congress of British West Africa was that through its agitation, the elective principle was introduced into the body politic of the British West African colonies. This in turn, led to the formation of political parties.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>24", "subject": "Government", "year": "2022", "type": "Objective", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "A country's foreign policy is foremost driven by", "images": [], "options": {"A": "economy", "B": "location", "C": "national resources", "D": "national interest"}, "answer": "D", "explanation": "Foreign policies are general objectives that guide the activities and relationships of one state in its interactions with other states. The development of foreign policy is influenced by domestic considerations, the policies or behaviour of other states, or plans to advance specific geopolitical designs.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2022>25", "subject": "Government", "year": "2022", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "The first inter-territorial political movement organized in the 1920s which sought to bring all the British West African territories together to fight the colonial establishment was the", "images": [], "options": {"A": "Aborigines Right Protection Society", "B": "West African Youth League", "C": "National Congress of British West Africa", "D": "West African Students Union"}, "answer": "C", "explanation": "The NCBWA, unlike previous movements, envisaged a united British West Africa as a political objective to be attained, was organised on a scale that simultaneously embraced all four colonies of British West Africa, and was led almost exclusively by the educated elite of the area.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2022>26", "subject": "Government", "year": "2022", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "The African Union is unable to play its role on the global political scene very well due to the", "images": [], "options": {"A": "inadequate system of education bequeathed by the colonialist", "B": "low level of wages in the member countries", "C": "Divided loyalty among member states", "D": "outbreak of pandemic on the African continent"}, "answer": "C", "explanation": "The AU has singularly failed at promoting African unity, its prime goal. This was witnessed in the embarrassing incident in January 2020, when Kenya battled Djibouti for the non-permanent seat on the UNSecurity Council. Before, African nations unanimously backed an agreed candidate, but the AU failed to resolve the dispute between the two member states. It also failed to back one name for the position of director-general of the World Trade Organization. These incidents highlight the deep divisions in Africa", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2022>27", "subject": "Government", "year": "2022", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "Which of the following options does the Commonwealth of Nations commit resources to?", "images": [], "options": {"A": "Use of a common currency", "B": "Superiority of the British crown", "C": "British leadership on all matters of diplomacy", "D": "Promotion of representative democracy"}, "answer": "D", "explanation": "The Commonwealth Charter is a document of the values and aspirations which unite the Commonwealth. The Commonwealth Charter expresses the commitment of member states to the development of free and democratic societies and the promotion of peace and prosperity to improve the lives of all the people of the Commonwealth.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>28", "subject": "Government", "year": "2022", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "Which summit drew the road map for the implementation of the African Union?", "images": [], "options": {"A": "Sirte summit", "B": "Lusaka summit", "C": "Lome summit", "D": "Lagos summit"}, "answer": "A", "explanation": "The Sirte Summit, held in Sirte, Libya in 1999, drew the roadmap for the implementation of the African Union. The African Union (AU) is a continental union consisting of 55 member states located on the continent of Africa. The AU was announced in the Sirte Declaration in Sirte, Libya on 9 September 1999, calling for the establishment of the African Union. The bloc was founded on 26 May 2001 in Addis Ababa, Ethiopia and launched on 9 July 2002 in Durban, South Africa.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2022>29", "subject": "Government", "year": "2022", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "One of the benefits which the West African state derive from the United Nations is", "images": [], "options": {"A": "equal opportunities of appointment to its highest office", "B": "permanent membership of the Security Council", "C": "greater access to all the organs of the United Nation", "D": "total eradication of poverty from the African continent"}, "answer": "C", "explanation": "The United Nations provides equal access to all its organs for all member states, regardless of their geographical location or size. This means that West African states, like all other member states, have the opportunity to participate in and benefit from all the organs of the United Nations. This includes the General Assembly, the Security Council, the Economic and Social Council, the International Court of Justice, and the Secretariat. However, the options of equal opportunities of appointment to its highest office and permanent membership of the Security Council are not benefits that are specifically provided to West African states by the United Nations. The total eradication of poverty from the African continent is a goal of the United Nations, but it is not a benefit that has been achieved.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>30", "subject": "Government", "year": "2022", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The Atlantic Charter gave birth to the", "images": [], "options": {"A": "Commonwealth of nations", "B": "Allied powers", "C": "United Nations", "D": "North Atlantic Treaty Organization"}, "answer": "C", "explanation": "The origin of the Charter of the United Nations can be traced back to the Atlantic Charter, signed on 14 August 1941, by which Franklin D. Roosevelt, President of the United States of America, and Winston Churchill, Prime Minister of the United Kingdom, made known \"certain common principles in the national policies of their respective countries on which they base their hopes for a better future for the world\".", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>31", "subject": "Government", "year": "2022", "type": "Objective", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "Which of the following factors does not influence a country's foreign policy?", "images": [], "options": {"A": "Human resources", "B": "Geographical location", "C": "System of education and number of universities", "D": "International laws and conventions"}, "answer": "C", "explanation": "The development of foreign policy is influenced by domestic considerations, the policies or behaviour of other states, or plans to advance specific geopolitical designs.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>32", "subject": "Government", "year": "2022", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "In which political system does the government control every aspect of a citizen's life?", "images": [], "options": {"A": "Communism", "B": "Dictatorship", "C": "Totalitarianism", "D": "Aristocracy"}, "answer": "C", "explanation": "In totalitarian regimes, the leadership controls nearly all aspects of the state and all aspects of the country's citizen's private lives. The reach of the government is limitless.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2022>33", "subject": "Government", "year": "2022", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "The administrative head of the ministry is the", "images": [], "options": {"A": "official of the ruling government", "B": "general manager", "C": "permanent secretary", "D": "chief co-ordinating officer"}, "answer": "C", "explanation": "While the minister is the political head of the ministry, it is to the permanent secretary, the administrative head of the ministry, that the full responsibility of administering the ministry in line with the governance philosophy of a country devolves. The permanent secretary sits at the top of the public service on the boundary between political power and public administration. The \"permanent\" in the idea of the \"permanent secretary\" is owed to the British and their conception of the idea of the civil service as a permanent feature of government.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2022>34", "subject": "Government", "year": "2022", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The sovereignty of a state can be limited to a great extent by", "images": [], "options": {"A": "rule of law", "B": "separation of powers", "C": "international laws and conventions", "D": "legislative assembly"}, "answer": "C", "explanation": "Every state has to have relations with other states. These are regulated by a law known as International Law. Under normal circumstances every state is expected to obey international law. Non-observance of International Law would result in chaos and confusion in international field. So every state is compelled to observe International Law. In many states international law is regarded a part of the law of the land.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>35", "subject": "Government", "year": "2022", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS", "question": "A coalition government is a common feature of a", "images": [], "options": {"A": "two-party system", "B": "multi-party system", "C": "one-party system", "D": "non-party system"}, "answer": "B", "explanation": "A Coalition Government implies the co-existence of at least two or more political parties. It is temporary conjunction for a specific interest as coalition politics is a dynamic affair where the parties or groups can dissolve or form new ones. A common feature of a multi-party system is that government is formed by a coalition of political parties. When there are several political parties in a country, it then become difficult for one party to win a clear majority in parliament. The part that has won the scanty majority will be forced to form a coalition government with another part.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>36", "subject": "Government", "year": "2022", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "The appointment of judges is based on the recommendation of the", "images": [], "options": {"A": "Civil service commission", "B": "Public service commission", "C": "Eminent persons in the society", "D": "Judicial service"}, "answer": "D", "explanation": "Judges in the federal courts are appointed by the president on the recommendation of the National Judicial Council and approved by the Senate. Judges in the state high courts are appointed by the state governors, also on the recommendation of the National Judicial Council, and approved by the state assembly.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>37", "subject": "Government", "year": "2022", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "Which of the following option is not a function of political parties?", "images": [], "options": {"A": "Political implementation", "B": "Political socialization", "C": "Political education", "D": "Aggregation of interests"}, "answer": "A", "explanation": "Political parties are responsible for political socialization, aggregation of interest and political education. They only implement policies when they form a government", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2022>38", "subject": "Government", "year": "2022", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "In an election, secret ballot is described as the process where the voter", "images": [], "options": {"A": "is screened off to conceal the vote", "B": "cast the vote in a sealed box", "C": "is assisted to cast the vote", "D": "is searched before casting the vote"}, "answer": "B", "explanation": "Also known as the Australian ballot; voting by this system usually takes place in a prescribed manner. The voting boxes are required to be of certain dimensions and closed, the only aperture being a small slit at the top. These containers are examined before the poll begins and cannot be opened until the count begins. The voter marks a ballot, often while standing in a special booth, and (after the voter's right to vote has been verified) the vote is placed inside the container.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>39", "subject": "Government", "year": "2022", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET", "question": "In which system of government does the legislature pass a vote of no confidence in the government?", "images": [], "options": {"A": "Federal", "B": "Cabinet", "C": "De Jure", "D": "Monarchical"}, "answer": "B", "explanation": "A significant attribute of the parliamentary system that cabinet is collectively accountable to legislature. The activities of the cabinet can be questioned and checked by legislature through various constitutional means. Ministers remain in office as long as they enjoy confidence in legislature.  In a case of no confidence in a single minister, the whole cabinet must resign.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2022>40", "subject": "Government", "year": "2022", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The concept of social justice implies that the state must ensure", "images": [], "options": {"A": "sharing of political power with opponents", "B": "security for multinational businesses", "C": "equality of citizens", "D": "fairness to foreign nationals"}, "answer": "C", "explanation": "Social justice refers to a fair and equitable division of resources, opportunities, and privileges in society. Originally a religious concept, it has come to be conceptualized more loosely as the just organization of social institutions that deliver access to economic benefits. It is sometimes referred to as \"distributive justice.\"", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>41", "subject": "Government", "year": "2022", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The basic human rights of citizens in a state are", "images": [], "options": {"A": "Freedom of movement, free education and free health", "B": "Free social services, speech and religion", "C": "Right to life, liberty, and property", "D": "Right higher education, property and freedom of thought"}, "answer": "C", "explanation": "Although all options are fundamental human rights; the right to life, liberty and property(social security) are basic human rights.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>42", "subject": "Government", "year": "2022", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "A quasi-federal structure is so arranged in order for the", "images": [], "options": {"A": "center to coordinate national level programmes.", "B": "component units to breakaway at will", "C": "citizens to have dual allegiance and dual citizenship", "D": "President to amend the constitution at will"}, "answer": "A", "explanation": "The term quasi-federal means a federal set-up where despite having two clear sets of government – central and the states/regions, more powers are given to the Central Government.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2022>43", "subject": "Government", "year": "2022", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "When a superior court declares an action of the executive ultra-vires, it means that", "images": [], "options": {"A": "the executive should leave power", "B": "a vote of no confidence had been passed on the government", "C": "the judiciary is more powerful than the executive", "D": "the action is illegal and of no effect"}, "answer": "D", "explanation": "Ultra vires acts are any acts that lie beyond the authority of a corporation to perform. The roots of the term are from a Latin phrase that means beyond the power.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2022>44", "subject": "Government", "year": "2022", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "Which of the following potions does not constitute the main objectives of the United Nations?", "images": [], "options": {"A": "The maintenance of international peace and security", "B": "The promotion of the well-being of the people of the world", "C": "International cooperation", "D": "The use of force to comply with its provisions"}, "answer": "D", "explanation": "Although the UN may exert force at one point or the other(last resort), it is not a primary objective.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>45", "subject": "Government", "year": "2022", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "The Economic Community of West African States was established with the following aims excepts to", "images": [], "options": {"A": "Use force to depose unconstitutional regimes", "B": "Improve the living standards of its people", "C": "Contribute to the progress and development of the African continent", "D": "Foster relations among member states"}, "answer": "A", "explanation": "ECOWAS lacks the ability to force its decisions on members. It cannot sanction erring members too.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>46", "subject": "Government", "year": "2022", "type": "Objective", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "The process of international integration arising from the inter-change of world views, products, ideas and other aspects of culture is known as", "images": [], "options": {"A": "National interest", "B": "Globalization", "C": "Geopolitics", "D": "Interest aggregation"}, "answer": "B", "explanation": "Globalization is the process of international integration arising from the interchange of world views, products, ideas, and other aspects of culture. It approaches in transportation, telecommunication-internet, mobile phones which have been the key factor in globalization, producing further interconnection of economic and cultural activities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>47", "subject": "Government", "year": "2022", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "One negative effect of colonialism on the people of West Africa over the years is the", "images": [], "options": {"A": "introduction of modern ideas of governance", "B": "creation of large political units", "C": "change of socio-political system of living", "D": "development of political institutions"}, "answer": "C", "explanation": "Some traditional political institutions were destroyed and replaced with foreign ones. Foreign culture was imposed on Africans without regard for their own culture. This led to the loss of the African culture.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>48", "subject": "Government", "year": "2022", "type": "Objective", "topic": "PRE-COLONIAL POLITICAL SYSTEM : HAUSA/FULANI~~PRE-COLONIAL POLITICAL SYSTEM : IGBO~~PRE-COLONIAL POLITICAL SYSTEM : YORUBA", "question": "The Council of Elders in the pre-colonial political institutions of West Africa best served on the Council as", "images": [], "options": {"A": "warriors of the state", "B": "go-between the gods and the people", "C": "custodians of the wealth of the state", "D": "representative of the commoners"}, "answer": "B", "explanation": "In the pre-colonial era, the council of elders served as the mouthpiece of the people to the gods as well as the custodian of knowledge.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2022>49", "subject": "Government", "year": "2022", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "Public corporations are struggling in the West African State as a result of", "images": [], "options": {"A": "heavy social and political cost", "B": "private-public partnership", "C": "public scrutiny and accountability", "D": "direct foreign investment"}, "answer": "A", "explanation": "A public corporation could be difficult to manage, as several meetings might be required with several government officials. Therefore, while decisions can be made quickly, the decision-making processing can also become quite slow if several staff members need to be present for meetings during strict time schedules. Public corporations are expensive to maintain and operate. They also might engage in anti-social activities, such as charging too much money for goods or providing goods that aren't sufficient for consumers.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2022>50", "subject": "Government", "year": "2022", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The following options are today the biggest threat to the democracy of West African States except", "images": [], "options": {"A": "Election disputes and related violence", "B": "Military intervention in politics", "C": "Youth unemployment", "D": "Non-involvement of traditional rulers in politics"}, "answer": "D", "explanation": "Although this could be a threat; unemployment, electoral violence and military intervention are the biggest threat to democracy in West African states.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2023>1", "subject": "Government", "year": "2023", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The underlying principle of the concept of seperation of powers is mainly to", "images": [], "options": {"A": "educate people on their rights", "B": "ensure constitutional review", "C": "prevent arbitrariness", "D": "tame the executive"}, "answer": "C", "explanation": "The principle of separation of powers is primarily to prevent arbitrariness. This principle is a model for the governance of a state, where the state's government is divided into branches, each with separate and independent powers and areas of responsibility so that the powers of one branch are not in conflict with the powers associated with the other branches.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>2", "subject": "Government", "year": "2023", "type": "Objective", "topic": "MEANING AND SCOPE OF GOVERNMENT : DEFINITION OF STATE, FEATURES, STRUCTURE AND FUNCTIONS.", "question": "What is commonly referred to as the association of the government and the governed?", "images": [], "options": {"A": "Monarchy", "B": "State", "C": "Confederation", "D": "Federation"}, "answer": "B", "explanation": "The association of the government and the governed is commonly referred to as the State. A state is a political entity represented by its government and population.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2023>3", "subject": "Government", "year": "2023", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "The exercise of power can arise from any of the following sources except", "images": [], "options": {"A": "legitimate power", "B": "charismatic power", "C": "expert power", "D": "ideological power"}, "answer": "D", "explanation": "The exercise of power can arise from legitimate power, charismatic power, and expert power. However, ideological power is not a source of power. It is rather a tool or mechanism through which power can be exercised.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>4", "subject": "Government", "year": "2023", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "There are two types of committee system in the House of parliament as part of their operations and one of such is", "images": [], "options": {"A": "Expert Committee", "B": "Parliamentary Service Board", "C": "Committee of the Whole House", "D": "Leadership Committee"}, "answer": "C", "explanation": "There are two types of committee systems in the House of Parliament as part of their operations. One of such is the Committee of the Whole House. This is a committee that includes all members of the House and meets in the House chamber.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2023>5", "subject": "Government", "year": "2023", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : EXECUTIVE", "question": "Maintenance of law and order in a state is the function of the", "images": [], "options": {"A": "judicial service", "B": "legislative arm of government", "C": "citizens of the state", "D": "executive arm of government"}, "answer": "D", "explanation": "The maintenance of law and order in a state is the function of the executive arm of government. The executive branch is responsible for implementing and enforcing laws, maintaining peace and order, and protecting the citizens.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2023>6", "subject": "Government", "year": "2023", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : LOCAL GOVERNMENTS", "question": "The local government system assists best in mentoring and grooming people for", "images": [], "options": {"A": "citizenship and justice", "B": "military operations", "C": "leadership position", "D": "large scale farming"}, "answer": "C", "explanation": "The local government system is the closest level of government to the people. It is a training ground for politicians and individuals who aspire to hold leadership positions at higher levels of government. Therefore, it assists best in mentoring and grooming people for leadership positions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>7", "subject": "Government", "year": "2023", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "The Fundamental Human Rights and Liberties must be entrenched in a constitution to", "images": [], "options": {"A": "make it difficult to tamper with", "B": "show concern for the people", "C": "serve majority interest", "D": "espouse love for the country"}, "answer": "A", "explanation": "Fundamental Human Rights and Liberties are entrenched in a constitution to make it difficult to tamper with. This is because the constitution is the supreme law of the land and any changes to it require a rigorous process. This ensures that these rights and liberties are protected and not easily violated.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2023>8", "subject": "Government", "year": "2023", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PRESIDENTIAL", "question": "An executive president is one who wields the powers of a", "images": [], "options": {"A": "ceremonial president only", "B": "leader of government business only", "C": "despot and benevolent dictator", "D": "head of state and government"}, "answer": "D", "explanation": "An executive president is one who wields the powers of both the head of state and government. This means that the president has the highest executive authority and is responsible for the implementation and enforcement of all laws and the operation of all government services.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>9", "subject": "Government", "year": "2023", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "The official routine observed in carrying out functions in the civil service is commonly known as", "images": [], "options": {"A": "official order", "B": "standard order", "C": "bureaucracy", "D": "command"}, "answer": "C", "explanation": "The official routine observed in carrying out functions in the civil service is commonly known as bureaucracy. Bureaucracy refers to the administrative system governing any large institution, whether publicly owned or privately owned.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>10", "subject": "Government", "year": "2023", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC/CIVIL SERVICE COMMISSION –MEANING AND FUNCTIONS.", "question": "The public Service Commission performs the following functions except", "images": [], "options": {"A": "imposition of income tax", "B": "discipline of personnel", "C": "welfare of personnel", "D": "advisory body"}, "answer": "A", "explanation": "The Public Service Commission does not have the power to impose income tax. This function is typically performed by the revenue or tax collection agency of the government. The Public Service Commission is responsible for the discipline of personnel, welfare of personnel, and serves as an advisory body.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2023>11", "subject": "Government", "year": "2023", "type": "Objective", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "The issues that are at the core of a country's foreign policy are referred to as", "images": [], "options": {"A": "diplomacy", "B": "national interest", "C": "state area", "D": "globalization"}, "answer": "B", "explanation": "The issues that are at the core of a country's foreign policy are referred to as national interest. National interest is a country's goals and ambitions whether economic, military, or cultural. It is a key concept in international relations where it refers to a country's goals and ambitions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>12", "subject": "Government", "year": "2023", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "One of the major criticisms levelled against the United Nations (UN) is its inability to", "images": [], "options": {"A": "ensure universal access to education", "B": "adopt a universal language for its operations", "C": "ensure fair permanent representation", "D": "enforce affirmative action and equal wealth"}, "answer": "C", "explanation": "One of the major criticisms levelled against the United Nations (UN) is its inability to ensure fair permanent representation. The UN Security Council, for example, has five permanent members with veto power, which many countries argue is not representative of the international community.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2023>13", "subject": "Government", "year": "2023", "type": "Objective", "topic": "FOREIGN POLICIES : ADVANTAGES AND DISADVANTAGES", "question": "The function of the Diplomatic Missions include the following except", "images": [], "options": {"A": "gather intelligence information", "B": "project the culture of the people", "C": "woo investors", "D": "pay salaries of workers of the mission"}, "answer": "D", "explanation": "The function of the Diplomatic Missions include gathering intelligence information, projecting the culture of the people, and wooing investors. However, paying salaries of workers of the mission is an administrative function, not a diplomatic one.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>14", "subject": "Government", "year": "2023", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : ELECTORAL MANAGEMENT BODY", "question": "One of the function of the electoral management body is to", "images": [], "options": {"A": "interpret the electoral laws fairly", "B": "look for external sources besides the government to fund its operations", "C": "engage in business to increase its financial capacity", "D": "conduct training programmes for presidential candidates"}, "answer": "A", "explanation": "One of the functions of the electoral management body is to interpret the electoral laws fairly. This is to ensure that elections are conducted in a free, fair, and transparent manner. The electoral management body does not engage in business or look for external sources of funding.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2023>15", "subject": "Government", "year": "2023", "type": "Objective", "topic": "CONSTITUTIONS : DEFINITION AND SOURCES", "question": "The rigid nature of a constitution makes it", "images": [], "options": {"A": "easy for quick review", "B": "complicated for amendment", "C": "infallible and standard", "D": "accessible to all"}, "answer": "B", "explanation": "The rigid nature of a constitution makes it complicated for amendment. A rigid constitution is one that requires a special process for its amendment, usually involving a higher degree of difficulty than for ordinary laws.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>16", "subject": "Government", "year": "2023", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "Bicameral legislature contributes to the democratic process by", "images": [], "options": {"A": "recommending the use of force in policy implementation", "B": "imposing programmes and policies on the executive", "C": "widening the scope of political participation", "D": "suppressing minority rights"}, "answer": "C", "explanation": "A bicameral legislature, which is a legislature with two chambers, contributes to the democratic process by widening the scope of political participation. This is because it allows for more representation and more viewpoints to be considered in the legislative process. The other options do not accurately describe the role of a bicameral legislature in a democratic process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>17", "subject": "Government", "year": "2023", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "The judiciary occupies an important place in every state because it is", "images": [], "options": {"A": "protector of the rights of the people", "B": "a body of upright and just people in society", "C": "mandated to supervise the functions of the executive", "D": "a unique profession of intellectuals"}, "answer": "A", "explanation": "The judiciary is important in every state because it serves as the protector of the rights of the people. It interprets the law and ensures that everyone, including the government, adheres to it. The other options do not accurately describe the primary role of the judiciary.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>18", "subject": "Government", "year": "2023", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "The French Colonial policies in her West African colonies were different from the British in many ways except in", "images": [], "options": {"A": "cultural imposition", "B": "citizenship", "C": "discriminatory laws", "D": "imperialism"}, "answer": "D", "explanation": "The French and British colonial policies were different in many ways, but both were forms of imperialism, which is the policy or ideology of extending a nation's rule over foreign nations. The other options are areas where the French and British colonial policies differed.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2023>19", "subject": "Government", "year": "2023", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "The pattern of rule by the French in her West African colonies was highly", "images": [], "options": {"A": "centralized", "B": "decentralized", "C": "proportional", "D": "consultative"}, "answer": "A", "explanation": "The French colonial rule in West Africa was highly centralized. This means that the power and decision-making were concentrated in a central authority, often in the hands of the colonial governor. The other options do not accurately describe the pattern of French colonial rule.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>20", "subject": "Government", "year": "2023", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "One of the negative effects of colonial rule on West African states was the", "images": [], "options": {"A": "building of roads and rail network", "B": "dependency syndrome", "C": "western education", "D": "social interventions"}, "answer": "B", "explanation": "One of the negative effects of colonial rule on West African states was the dependency syndrome. This refers to the condition where the colonized states become heavily dependent on the colonial powers for economic, political, and social needs. The other options are generally considered as positive effects of colonial rule.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>21", "subject": "Government", "year": "2023", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : UNITARY", "question": "Unitary system of government is adopted by some states because", "images": [], "options": {"A": "it guarantees democracy", "B": "it builds the capacity of citizens in good time", "C": "of homogeneity", "D": "of rich mineral resources"}, "answer": "C", "explanation": "A unitary system of government is often adopted by states that are homogeneous. In a unitary system, the central government holds most of the power, and this system works best in nations where the population has a lot in common, such as shared culture, language, and values. The other options do not directly relate to the reasons for adopting a unitary system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>22", "subject": "Government", "year": "2023", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Apart from globalization, what other factor to a large extent affects the sovereignty of a state?", "images": [], "options": {"A": "Right of a franchise", "B": "Inalienability", "C": "System of governemt", "D": "International laws"}, "answer": "D", "explanation": "International laws can significantly affect the sovereignty of a state. Sovereignty refers to the full right and power of a governing body to govern itself without any interference from outside sources or bodies. However, international laws, which are designed to regulate relations between states, can limit this sovereignty to some extent. The other options do not have as large an impact on state sovereignty.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2023>23", "subject": "Government", "year": "2023", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PRESSURE GROUPS", "question": "The reason for which the government should take a key interest in the activities of pressure groups is that, they", "images": [], "options": {"A": "force coalition among political parties for election", "B": "blackmail political leaders", "C": "provide valuable feedback on government policies and programmes", "D": "dictate the path and direction for government programmes"}, "answer": "C", "explanation": "Pressure groups provide valuable feedback on government policies and programmes. They represent specific interests and try to influence public policy in their favor. By doing so, they provide a form of checks and balances on the government, ensuring that a wide range of interests are considered in policy-making. The other options do not accurately describe the role of pressure groups.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>24", "subject": "Government", "year": "2023", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Elections plays a major role in the democratic process because, it", "images": [], "options": {"A": "projects the class system", "B": "confers legitimacy", "C": "ensures only good people rule", "D": "manipulates the electoral process"}, "answer": "B", "explanation": "Elections play a major role in the democratic process because they confer legitimacy. By participating in elections, citizens give their consent to be governed by the elected officials, which is a key aspect of democratic legitimacy. The other options do not accurately describe the major role of elections in the democratic process.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2023>25", "subject": "Government", "year": "2023", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "Public opinion is formed through the following channels except", "images": [], "options": {"A": "mas media", "B": "elections", "C": "cabinet", "D": "political parties"}, "answer": "C", "explanation": "Public opinion is formed through various channels such as mass media, elections, and political parties. However, the cabinet, which is a body of high-ranking state officials, typically consisting of the top leaders of the executive branch, is not a channel through which public opinion is formed. Rather, it is a body that makes decisions based on public opinion and other factors.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>26", "subject": "Government", "year": "2023", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "The civil service is different from the public service in terms of", "images": [], "options": {"A": "conditions of service", "B": "educational qualification", "C": "personality and stature", "D": "political affiliation"}, "answer": "A", "explanation": "The civil service is different from the public service in terms of conditions of service. The civil service is a part of the public service, but it is distinguished by its different conditions of service, which include things like pay scales, working hours, and benefits.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>27", "subject": "Government", "year": "2023", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : MASS MEDIA", "question": "The media, commonly referred to as the  fourth estate of the realm , monitors the activities of government on behalf of the", "images": [], "options": {"A": "media organization", "B": "executive", "C": "civil society", "D": "people"}, "answer": "D", "explanation": "The media, commonly referred to as the fourth estate of the realm, monitors the activities of government on behalf of the people. This is because the media's role is to inform the public about what the government is doing, and to hold the government accountable to the people.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>28", "subject": "Government", "year": "2023", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "One of the high points of the activities of the National Congress of British West Africa (NCBWA) led to the", "images": [], "options": {"A": "introduction of the elective principles", "B": "proposal for African unity", "C": "creation of the African High Command", "D": "Africanization of the Executive Council"}, "answer": "A", "explanation": "One of the high points of the activities of the National Congress of British West Africa (NCBWA) led to the introduction of the elective principles. The NCBWA was a political organization that advocated for the rights of Africans in British West Africa, and one of its major achievements was the introduction of the elective principle, which allowed Africans to vote for their own representatives.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2023>29", "subject": "Government", "year": "2023", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "The biggest obstacle which also slowed down nationalist activities in French West African Colonies was the", "images": [], "options": {"A": "assasination of chiefs", "B": "deportation of Africans to France", "C": "assimilation policy", "D": "constitutional reforms and entrenchment of human rights"}, "answer": "C", "explanation": "The biggest obstacle which also slowed down nationalist activities in French West African Colonies was the assimilation policy. This policy aimed to make Africans in French colonies 'French' in culture and citizenship, which undermined local cultures and identities and hindered the development of nationalist movements.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2023>30", "subject": "Government", "year": "2023", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "The best way to keep the military at bay from interfering in politics is by ensuring", "images": [], "options": {"A": "effective control of their day to day operations", "B": "their inclusion in government", "C": "high pay rise every year", "D": "good governance"}, "answer": "D", "explanation": "The best way to keep the military at bay from interfering in politics is by ensuring good governance. Good governance, which includes things like transparency, accountability, and respect for the rule of law, can help to prevent the conditions that might lead to a military coup.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>31", "subject": "Government", "year": "2023", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : MEANING AND PROCESSES", "question": "Secret voting assists the voter in making a decision without", "images": [], "options": {"A": "coercion", "B": "national interest", "C": "public good", "D": "pondering over issues"}, "answer": "A", "explanation": "Secret voting is a method of voting that ensures the voter's privacy in the election process. The key idea is to ensure the voter's choice is confidential which helps to prevent attempts of influence, coercion, or retaliation.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2023>32", "subject": "Government", "year": "2023", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "Which system of government allows for and guarantes maximum competition?", "images": [], "options": {"A": "Social democracy", "B": "Capitalism", "C": "Communalism", "D": "Feudalism"}, "answer": "B", "explanation": "Capitalism is an economic system where private entities own the factors of production. It allows for maximum competition as businesses compete for the same resources and customers in a free market to achieve profit maximization.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>33", "subject": "Government", "year": "2023", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "One of the factors that influences decentralization of power in a state is", "images": [], "options": {"A": "weak central authority", "B": "maximum loyalty", "C": "widening political participation", "D": "maximum allegiance to the state"}, "answer": "C", "explanation": "Decentralization of power in a state is influenced by the need to widen political participation. This is because decentralization allows for the distribution of authority away from a central authority to regional or local authorities, thereby allowing more people to participate in governance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>34", "subject": "Government", "year": "2023", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PARLIAMENTARY OR CABINET", "question": "One of the low points in the cabinet system of government is that, the", "images": [], "options": {"A": "Prime Minister does not regard the Head of State", "B": "centre of power in the system is stable", "C": "divided loyalty of the cabinet ministers is strong", "D": "tenure of government is always not stable"}, "answer": "D", "explanation": "In a cabinet system of government, one of the low points is that the tenure of government is not always stable. This is because the government is dependent on the confidence of the parliament, and a vote of no confidence can lead to the dissolution of the government.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2023>35", "subject": "Government", "year": "2023", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "What type of right enables citizens to participate in state affairs?", "images": [], "options": {"A": "Habeas corpus", "B": "Political right", "C": "Judicial right", "D": "Social right"}, "answer": "B", "explanation": "Political rights are rights that allow citizens to participate in state affairs. These include the right to vote, the right to freedom of speech and assembly, and the right to hold public office.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>36", "subject": "Government", "year": "2023", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "The reluctance of military regimes to hand-over power to civiliam administration is because, they", "images": [], "options": {"A": "feel a sense of entitlement", "B": "perceive civilians and politicians as evil doers and backward", "C": "have the backing of traditional rulers, their subjects and the clergy", "D": "negotiate better loan terms for the country than the civilian government"}, "answer": "A", "explanation": "Military regimes often feel a sense of entitlement to power due to their control over the armed forces and the state's security apparatus. This sense of entitlement can make them reluctant to hand over power to civilian administrations. The other options do not accurately capture the primary reason for this reluctance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>37", "subject": "Government", "year": "2023", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The following issues are some of the challenges the United Nations (UN) addresses except", "images": [], "options": {"A": "human rights", "B": "oligarchical regimes", "C": "humanitarian aid", "D": "climate change"}, "answer": "B", "explanation": "The United Nations (UN) is an international organization that addresses a wide range of global issues, including human rights, humanitarian aid, and climate change. However, it does not specifically address oligarchical regimes. An oligarchy is a form of government in which power is held by a small group of people. While the UN promotes democratic governance, it does not directly intervene in the internal affairs of sovereign states unless there is a threat to international peace and security.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>38", "subject": "Government", "year": "2023", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "The African Union (AU) is saddled with one of these challenges and that is", "images": [], "options": {"A": "weak labour force", "B": "absence of rich natural resources", "C": "tenstions and political discord among member states", "D": "inter-ethnic extinction and poor social cohesion"}, "answer": "C", "explanation": "The African Union (AU) is an organization that promotes unity and cooperation among African countries. One of the challenges it faces is tensions and political discord among member states. This can hinder cooperation and the achievement of the AU's objectives. The other options do not accurately describe the challenges faced by the AU.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2023>39", "subject": "Government", "year": "2023", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "The Economic Community of West African State (ECOWAS) is now confronted with a new security threat which is", "images": [], "options": {"A": "smuggling of illegal goods across states", "B": "weak national armies", "C": "proportional representation", "D": "extremism"}, "answer": "D", "explanation": "The Economic Community of West African States (ECOWAS) is a regional group of fifteen West African countries. In recent years, it has been confronted with a new security threat: extremism. This includes terrorist activities and violent extremism, which pose a significant threat to peace and security in the region. The other options do not accurately describe the new security threats faced by ECOWAS.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2023>40", "subject": "Government", "year": "2023", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "The Commonwealth Nations is committed to one of the following principles", "images": [], "options": {"A": "human rights and democracy", "B": "supervise political activities of member states", "C": "draft constitution for member states", "D": "finance budget of member states"}, "answer": "A", "explanation": "The Commonwealth is an intergovernmental organization of 54 member states that are mostly former territories of the British Empire. It is committed to promoting human rights and democracy among its member states. The other options do not accurately describe the principles to which the Commonwealth is committed.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>41", "subject": "Government", "year": "2023", "type": "Objective", "topic": "FOREIGN POLICIES : DEFINITION, FACTORS AND OBJECTIVES", "question": "Which one among the following is a significant factor that influences the foreign policy of a country?", "images": [], "options": {"A": "Educational system", "B": "Political system", "C": "Gender of the political leader", "D": "Recruitment policy"}, "answer": "B", "explanation": "The foreign policy of a country is significantly influenced by its political system. The political system of a country determines its governance structure, ideologies, and international relations. It shapes the country's approach to international diplomacy, alliances, and conflicts. The other options like educational system, gender of the political leader, and recruitment policy do not have a direct and significant influence on a country's foreign policy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>42", "subject": "Government", "year": "2023", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION", "question": "The art of maintaining peaceful relationship betwen states, groups or individuals mostly come about as a result of the activities and functions of", "images": [], "options": {"A": "the media", "B": "the legislature", "C": "security agencies", "D": "diplomats"}, "answer": "D", "explanation": "Diplomats are primarily responsible for maintaining peaceful relationships between states, groups, or individuals. They represent their home country abroad and work on negotiations, peace treaties, trade agreements, and other forms of international cooperation. While the media, the legislature, and security agencies can contribute to peaceful relationships, it is the diplomats who are primarily involved in these activities.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>43", "subject": "Government", "year": "2023", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "One of the formidable challenges the New Partnership for Africa's Development (NEPAD) is confronted with is the", "images": [], "options": {"A": "absence of a common platform for debate", "B": "arms race among member states", "C": "over reliance on foreign aid", "D": "absence of technology transfer"}, "answer": "C", "explanation": "One of the major challenges faced by the New Partnership for Africa's Development (NEPAD) is the over-reliance on foreign aid. This dependence often comes with conditions that may not align with the development goals of the African countries. It also creates a dependency syndrome that hinders self-sustained growth and development. The other options like absence of a common platform for debate, arms race among member states, and absence of technology transfer, while they may be challenges, are not as formidable as the over-reliance on foreign aid.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2023>44", "subject": "Government", "year": "2023", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "The overriding consideration for the creation of the New Partnership for Africa's Development (NEPAD) was to place Africa on the path to", "images": [], "options": {"A": "military might", "B": "non-alignment", "C": "growth and development", "D": "capitalist governance"}, "answer": "C", "explanation": "The New Partnership for Africa's Development (NEPAD) was created with the primary aim of placing Africa on the path to growth and development. It seeks to address the challenges of poverty, underdevelopment, and the marginalization of Africa in the global economy. The other options like military might, non-alignment, and capitalist governance were not the overriding considerations for the creation of NEPAD.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2023>45", "subject": "Government", "year": "2023", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT", "question": "A democratic country is one in which the people have the right to", "images": [], "options": {"A": "participate in decision making", "B": "disregard laws they abhor", "C": "violently overthrow a government", "D": "punish government by not honouring tax obligation"}, "answer": "A", "explanation": "A democratic country is one in which the people have the right to participate in decision making. This is a fundamental principle of democracy, which is government of the people, by the people, and for the people. The other options like disregarding laws they abhor, violently overthrowing a government, and punishing government by not honouring tax obligation are not democratic rights and can lead to anarchy and instability.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2023>46", "subject": "Government", "year": "2023", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "A state that has two levels of government is commonly referred to as", "images": [], "options": {"A": "cooperative government", "B": "federal state", "C": "concurrent state", "D": "coalition government"}, "answer": "B", "explanation": "A state that has two levels of government is commonly referred to as a federal state. In a federal state, power is divided between a central government and individual states, provinces, or other territorial units. Each level of government has its own set of responsibilities and powers.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2023>47", "subject": "Government", "year": "2023", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : DEMOCRACY", "question": "The cornerstone of a functioning democracy is the", "images": [], "options": {"A": "expenditure pattern of the executive", "B": "appropriation bill", "C": "foreign policy and military alliances", "D": "free and fair elections"}, "answer": "D", "explanation": "The cornerstone of a functioning democracy is free and fair elections. This is because in a democracy, the power to govern comes from the people who are governed. They express their will through voting in elections. If the elections are not free and fair, then the government does not truly represent the people, and the system is not a true democracy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>48", "subject": "Government", "year": "2023", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : CABINET", "question": "Which of the following systems of government does not practice collective responsibility?", "images": [], "options": {"A": "Cabinet system", "B": "Executive system", "C": "Non-Centralized system", "D": "Communalism system"}, "answer": "C", "explanation": "Collective responsibility is a concept in which members of a group are considered responsible for the actions of the group as a whole. In the context of government, this often applies to cabinet systems where all members of the cabinet are collectively responsible for the decisions made. Non-Centralized system does not practice collective responsibility as power and decision-making are not concentrated in a central authority.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>49", "subject": "Government", "year": "2023", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : COMMUNALISM", "question": "A social, political and economic arrangement in which landed property and other natural resources are collectively owned is referred to as", "images": [], "options": {"A": "Communalism", "B": "Feudalism", "C": "Federalism", "D": "Liberalism"}, "answer": "A", "explanation": "Communalism refers to a social, political and economic arrangement in which landed property and other natural resources are collectively owned. It is a system that emphasizes the common good rather than individual profit.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2023>50", "subject": "Government", "year": "2023", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "A public declaration of policy and aims especially one issued before an election by a political party or candidate is commonly called", "images": [], "options": {"A": "policy paper", "B": "guide to government", "C": "manifesto", "D": "steps to govern"}, "answer": "C", "explanation": "A public declaration of policy and aims, especially one issued before an election by a political party or candidate, is commonly called a manifesto. A manifesto outlines the party's or candidate's proposed policies and goals for the government.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2024>1", "subject": "Government", "year": "2024", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES", "question": "The ultimate source of power and authority which set the state apart from other forms of political organization is referred to as", "images": [], "options": {"A": "constitutionalism", "B": "checks and balances", "C": "rule of law", "D": "sovereignty"}, "answer": "D", "explanation": "The ultimate source of power and authority which sets the state apart from other forms of political organization is referred to as sovereignty. Sovereignty is the supreme authority within a territory. It is the source from which all specific powers derive.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>2", "subject": "Government", "year": "2024", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : EXECUTIVE", "question": "The institution through which leaders exercise power to make and enforce laws is the", "images": [], "options": {"A": "government", "B": "judiciary", "C": "political party", "D": "security agency"}, "answer": "A", "explanation": "The institution through which leaders exercise power to make and enforce laws is the government. The government is responsible for the administration of public policies and laws in a state.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>3", "subject": "Government", "year": "2024", "type": "Objective", "topic": "CONSTITUTIONS : FUNCTIONS", "question": "The fundamental principles by which a state is ordered and governed is usually outlined in a", "images": [], "options": {"A": "bill", "B": "constitution", "C": "parliamentary proceedings", "D": "state manual"}, "answer": "B", "explanation": "The fundamental principles by which a state is ordered and governed are usually outlined in a constitution. A constitution serves as the supreme law of the land, providing the framework for government and defining the rights of citizens.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>4", "subject": "Government", "year": "2024", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES", "question": "Which one among the following factors greatly restrains the government in a democratic society?", "images": [], "options": {"A": "Consent of the governed", "B": "Consent of the civil society organizations", "C": "Ideology of the party", "D": "Parliamentary debates"}, "answer": "A", "explanation": "In a democratic society, the government operates based on the rule of law, consent of the governed, and accountability to the people and institutions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>5", "subject": "Government", "year": "2024", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES", "question": "The following factors are challenges faced by the judiciary under the doctrine of Separation of Powers except", "images": [], "options": {"A": "Appointment of judges", "B": "Financial autonomy", "C": "Removal of judges from office", "D": "Poor legal infrastructure"}, "answer": "D", "explanation": "Factors like appointment of judges, financial autonomy, and removal of judges from office are essential for maintaining the independence but they are being challenged by interference.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>6", "subject": "Government", "year": "2024", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES", "question": "Accountability in constitutional democracy is best enforced through a system of", "images": [], "options": {"A": "Checks and balances", "B": "Civil society organizations", "C": "Subversion of the law", "D": "Selection of the right leaders"}, "answer": "A", "explanation": "Accountability in constitutional democracy is best enforced through a system of checks and balances. This system ensures that each branch of government (executive, legislative, and judicial) has the ability to monitor and limit the powers of the other branches, thus preventing any one branch from becoming too powerful.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>7", "subject": "Government", "year": "2024", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES", "question": "The application of the common principles that are important to improve decision-making processes and ultimately strengthen democracy and improve social and economic development is best described as", "images": [], "options": {"A": "Fundamental right", "B": "Good governance", "C": "Separation of powers", "D": "Social democracy"}, "answer": "B", "explanation": "The application of common principles to improve decision-making processes and strengthen democracy is best described as good governance. Good governance encompasses transparency, accountability, rule of law, and effective participation, all of which are crucial for the functioning of a democratic system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>8", "subject": "Government", "year": "2024", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES", "question": "One of the reasons for having two legislative chambers in the governance structure of a country is to ensure the", "images": [], "options": {"A": "Executive is kept under check and control", "B": "Powers of the lower chamber is suppressed", "C": "Strict control of the affairs of the state", "D": "Through scrutiny of legislation"}, "answer": "A", "explanation": "One of the reasons for having two legislative chambers is to ensure that the executive is kept under check and control. The bicameral system provides an additional layer of scrutiny and oversight on the actions of the executive branch, promoting accountability and preventing abuse of power.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>9", "subject": "Government", "year": "2024", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY", "question": "Which one of the following factors have contributed largely to the weakened and poor performance of state institutions in many West African States?", "images": [], "options": {"A": "Corruption", "B": "Globalization", "C": "Low remuneration and wages", "D": "Weak institutional memory"}, "answer": "A", "explanation": "The factor in this context is the lack of capacity building, weak governance structures, and historical factors that have undermined institutional effectiveness.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>10", "subject": "Government", "year": "2024", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : DEMOCRACY", "question": "One of the paramount roles to play as a citizen in sustaining the democratic system of governance is to", "images": [], "options": {"A": "Avoid criticism of government", "B": "Play the partisan card", "C": "Pray for a good leader", "D": "Register and vote in elections"}, "answer": "D", "explanation": "One of the paramount roles to play as a citizen in sustaining the democratic system of governance is to register and vote in elections. Voting is a fundamental right and responsibility of citizens in a democracy, as it allows them to participate in the decision-making process and hold elected officials accountable.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>11", "subject": "Government", "year": "2024", "type": "Objective", "topic": "CITIZENSHIP : MEANS OF SAFEGUARDING RIGHTS OF CITIZENS.", "question": "The responsibility of citizens towards nation-building is to", "images": [], "options": {"A": "Encourage civil disobedience in the face of hardship", "B": "Participate and contribute to decision-making", "C": "Stampede government policies and programmes", "D": "Boycott and withdraw services to the state"}, "answer": "B", "explanation": "The responsibility of citizens towards nation-building is to participate and contribute to decision-making. This is essential for the development and progress of a nation as citizens have the right and duty to actively engage in the decision-making processes that affect them.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>12", "subject": "Government", "year": "2024", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : ELECTORAL MANAGEMENT BODY", "question": "By competing in general elections, political parties ultimately offer citizens", "images": [], "options": {"A": "A choice in governance", "B": "Automatic membership of a party", "C": "Opportunity to be extremely loyal to one party", "D": "Opportunity to vilify government"}, "answer": "A", "explanation": "By competing in general elections, political parties ultimately offer citizens a choice in governance. General elections provide citizens with the opportunity to choose their representatives and the direction of governance, thereby ensuring democratic principles are upheld.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>13", "subject": "Government", "year": "2024", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : MASS MEDIA", "question": "Public opinion is an essential element in a democracy because it can act as a", "images": [], "options": {"A": "Check on leadership and government activities", "B": "Mouthpiece for the opposition only", "C": "News outlet for the media and government only", "D": "Propaganda tool for the government at all material times"}, "answer": "A", "explanation": "Public opinion is an essential element in a democracy because it can act as a check on leadership and government activities. Public opinion serves as a mechanism to hold leaders accountable and ensure that government actions align with the will of the people.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>14", "subject": "Government", "year": "2024", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "The media serve as a useful purpose in a democracy by", "images": [], "options": {"A": "Connecting the government and the people", "B": "Ensuring government plays to their dictates", "C": "Assisting in the formation of political parties", "D": "Manipulating political leaders in government"}, "answer": "A", "explanation": "The media serve as a useful purpose in a democracy by connecting the government and the people. The media act as a bridge between the government and the citizens, providing information, facilitating dialogue, and promoting transparency in governance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>15", "subject": "Government", "year": "2024", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : MASS MEDIA", "question": "One of the pivotal roles played by pressure groups in a functioning democracy is the", "images": [], "options": {"A": "Implementation of public policy by them", "B": "Influence on the public policy decisions", "C": "Trumpeting of good deeds of a government always", "D": "Blackmailing of the government to act in their favour"}, "answer": "B", "explanation": "One of the pivotal roles played by pressure groups in a functioning democracy is the influence on public policy decisions. Pressure groups advocate for specific interests and exert influence on policymakers to shape public policies, ensuring diverse voices are considered in the decision-making process.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>16", "subject": "Government", "year": "2024", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT~~THE ELECTORAL SYSTEM : ELECTORAL MANAGEMENT BODY", "question": "Promoting electoral integrity is the crucial function of which institution of state? The", "images": [], "options": {"A": "Civil society organizations", "B": "Executive arm of government", "C": "Electoral management body", "D": "Security services"}, "answer": "C", "explanation": "Promoting electoral integrity is the crucial function of the Electoral management body. This institution is responsible for organizing and overseeing elections, ensuring they are free and fair. The other options do not have the primary role of ensuring electoral integrity.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>17", "subject": "Government", "year": "2024", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES", "question": "Those rights which are explicitly protected by the constitution are referred to as", "images": [], "options": {"A": "Checks and balances", "B": "Constitutional clauses", "C": "Entrenched clauses", "D": "Separation of powers"}, "answer": "C", "explanation": "Those rights which are explicitly protected by the constitution are referred to as Entrenched clauses. These clauses are safeguarded from easy amendment or repeal, providing a higher level of protection compared to other rights. The other options do not accurately describe rights protected by the constitution.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>18", "subject": "Government", "year": "2024", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : LEGISLATURE", "question": "Constitutionally, the local government administration is controlled by the state through", "images": [], "options": {"A": "Administrators", "B": "Legislation", "C": "Native laws", "D": "State bureau"}, "answer": "B", "explanation": "Constitutionally, the local government administration is controlled by the state through Legislation. Laws and regulations passed by the state legislature dictate the functioning and control of local government bodies. The other options do not accurately represent the control mechanism of local government administration.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>19", "subject": "Government", "year": "2024", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : POLITICAL PARTICIPATION", "question": "Which state institution is referred to as the bureaucratic wing responsible for the running of government offices, agencies and departments?", "images": [], "options": {"A": "Bureau of national affairs", "B": "Civil service", "C": "Controller of state services", "D": "Public services board"}, "answer": "B", "explanation": "The state institution referred to as the bureaucratic wing responsible for the running of government offices, agencies, and departments is the Civil service. The civil service is a key component of government administration, handling the day-to-day operations of various government entities. The other options do not align with the role of the civil service.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>20", "subject": "Government", "year": "2024", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : POLITICAL PARTICIPATION", "question": "The local government administration in many West African countries is faced with a myriad of problems one of which is", "images": [], "options": {"A": "Employee retention", "B": "Illiterate traditional authorities", "C": "Unavailability of land", "D": "Weak institutional laws"}, "answer": "D", "explanation": "The local government administration in many West African countries is faced with a myriad of problems, one of which is Weak institutional laws.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>21", "subject": "Government", "year": "2024", "type": "Objective", "topic": "ORGANS OF GOVERNMENT : JUDICIARY", "question": "One of the following options does not pass as a means of ensuring the independence of the judiciary which is", "images": [], "options": {"A": "Immunity from prosecution", "B": "Promotion on merit", "C": "Security of tenure", "D": "Salary determined by the executive"}, "answer": "D", "explanation": "The correct option is 'Salary determined by the executive'. This option does not ensure the independence of the judiciary as the judiciary should have financial independence to avoid being influenced by the executive branch. Immunity from prosecution, promotion on merit, and security of tenure are mechanisms that can help ensure judicial independence.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>22", "subject": "Government", "year": "2024", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC/CIVIL SERVICE COMMISSION –MEANING AND FUNCTIONS.", "question": "As part of its constitutional mandate, the Public Service Commission operates to", "images": [], "options": {"A": "Appoint the head of the commission", "B": "Carry out the order of the presidency only", "C": "Recruit high ranking personnel for the civil service", "D": "Review salaries and allowances of staff of the executive only"}, "answer": "C", "explanation": "The correct option is 'Recruit high ranking personnel for the civil service'. The Public Service Commission's role includes recruiting high-ranking personnel for the civil service to ensure that qualified individuals are appointed based on merit and competence. The other options do not fully capture the mandate of the Public Service Commission.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>23", "subject": "Government", "year": "2024", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : MEANING, STRUCTURE, CHARACTERISTICS AND FUNCTIONS.", "question": "The impartiality of the civil servant is important to the governance structure because they work for the interest of the", "images": [], "options": {"A": "Bureaucrat", "B": "Executive", "C": "Presidency", "D": "State"}, "answer": "D", "explanation": "The correct option is 'State'. Civil servants work for the interest of the state as a whole, not just for a specific branch of government like the Executive, Presidency, or Bureaucrat. Their impartiality is crucial to serving the broader interests of the state.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2024>24", "subject": "Government", "year": "2024", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "Which one of the following cannot be considered as a factor that influences the delimitation of a country into constituencies", "images": [], "options": {"A": "Administrative convenience", "B": "Geographical proximity", "C": "Historical experience", "D": "Political socialization"}, "answer": "B", "explanation": "Factors that typically influence constituency delimitation include population distribution, geographical features, community interests, and ensuring fair representation, among others.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>25", "subject": "Government", "year": "2024", "type": "Objective", "topic": "CONSTITUTIONS : TYPES AND FEATURES", "question": "A type of constitution suitable for the governance of federal state is a", "images": [], "options": {"A": "Flexible constitution", "B": "Rigid constitution", "C": "Republican constitution", "D": "Parliamentary constitution"}, "answer": "B", "explanation": "The correct option is 'Rigid constitution'. A rigid constitution, which is difficult to amend, is suitable for the governance of a federal state as it helps in maintaining the distribution of powers between the federal and state governments. A flexible constitution would not provide the necessary stability and clarity in power distribution in a federal system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>26", "subject": "Government", "year": "2024", "type": "Objective", "topic": "CONSTITUTIONS : FUNCTIONS", "question": "A set of principles enshrined in a constitution that guides the government in making laws and politics for the welfare of the people is referred to as", "images": [], "options": {"A": "Directive principles of state policy", "B": "Constitutional provisions", "C": "Human Rights and Administrative Justice", "D": "Edicts, customs and traditions"}, "answer": "B", "explanation": "A set of principles enshrined in a constitution that guides the government in making laws and politics for the welfare of the people is referred to as Constitutional provisions. The constitution serves as the supreme law of the land and provides the framework for governance and decision-making.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>27", "subject": "Government", "year": "2024", "type": "Objective", "topic": "MILITARY RULE : VARIOUS MILITARY REGIMES", "question": "Which situation in a democratic state can create an environment where military intervention is perceived as the only option to restore order, protect the population or address grievances?", "images": [], "options": {"A": "Boycott of elections", "B": "Economic crisis", "C": "Political crises", "D": "Youth unemployment"}, "answer": "C", "explanation": "In a democratic state, political crises can create an environment where military intervention is perceived as the only option to restore order, protect the population, or address grievances. Political instability and breakdown of law and order can lead to such situations.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>28", "subject": "Government", "year": "2024", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "Despite the many challenges bedevilling the Economic Community of West African State (ECOWAS), it has managed over the years in promoting", "images": [], "options": {"A": "Regime protection and economic stability in member countries", "B": "Trade tariffs and self-reliance", "C": "Regional integration and cooperation", "D": "Collective will against globalization"}, "answer": "C", "explanation": "Despite the challenges, the Economic Community of West African States (ECOWAS) has managed over the years in promoting regional integration and cooperation among member countries. ECOWAS aims to enhance economic cooperation and integration for the development of West Africa.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>29", "subject": "Government", "year": "2024", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "One of the reasons for which the United Nations (UN) is considered as the only influential world body is the fact that, it", "images": [], "options": {"A": "Plays a crucial role in international diplomacy", "B": "Supports the war mission of member countries", "C": "Influences regime change by supporting the opposition", "D": "Withholds humanitarian support to military regimes"}, "answer": "A", "explanation": "(UN) is considered as the only influential world body. The UN's influence stems from its role in promoting international peace, security, and cooperation among nations through various agencies and initiatives.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>30", "subject": "Government", "year": "2024", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "The African Union (AU) aims at ensuring the following developments in member countries except for", "images": [], "options": {"A": "Equal distribution of wealth", "B": "Governance and democracy", "C": "Peace and security", "D": "Social development"}, "answer": "A", "explanation": "The African Union (AU) aims at ensuring various developments in member countries, including governance and democracy, peace and security, and social development. However, the AU does not specifically aim at ensuring equal distribution of wealth among member countries.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>31", "subject": "Government", "year": "2024", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "The Commonwealth of Nations concerns itself with one of the following activities member countries which is", "images": [], "options": {"A": "Assisting in the overthrow of unpopular government", "B": "Conducting elections in member country", "C": "Operating the financial sector of poor countries", "D": "Promotion of peace and security"}, "answer": "D", "explanation": "The correct answer is 'Promotion of peace and security'. The Commonwealth of Nations primarily focuses on promoting peace and security among its member countries through diplomatic means and cooperation. This is a key objective of the organization, making it the most suitable option.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>32", "subject": "Government", "year": "2024", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "The African Union (AU) aims to promote gender equality and women's empowerment through the strategic framework organ of the", "images": [], "options": {"A": "Africans Peer Review Mechanism (APRM).", "B": "African Development Bank (ADB).", "C": "New Partnership for Africa's Development (NEPAD)", "D": "Specialized Commission of Women Empowerment (SCWE)"}, "answer": "D", "explanation": "The African Union (AU) aims to promote gender equality and women's empowerment through the African Union Commission under which is Specialized Commission of Women Empowerment (SCWE).", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>33", "subject": "Government", "year": "2024", "type": "Objective", "topic": "FOREIGN POLICIES : ADVANTAGES AND DISADVANTAGES", "question": "What encompasses a range of diplomatic, political, economic and security decisions and actions that a state embarks on to protect and promote sovereignty on the global stage?", "images": [], "options": {"A": "Alliances", "B": "Foreign policy", "C": "National interest", "D": "Constitutionalism"}, "answer": "B", "explanation": "The correct answer is 'Foreign policy'. Foreign policy encompasses a range of diplomatic, political, economic, and security decisions and actions that a state undertakes to protect and promote its sovereignty on the global stage. It involves interactions with other states and international organizations to safeguard national interests.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>34", "subject": "Government", "year": "2024", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "Which colonial policy worked against the sovereign power and authority of the traditional political authority and institutions?", "images": [], "options": {"A": "Crown Colony Edict", "B": "Expatriate Edict", "C": "Indirect Rule", "D": "Protectorate Colony Law"}, "answer": "C", "explanation": "The correct answer is 'Indirect Rule'. Indirect Rule was a colonial policy that worked against the sovereign power and authority of traditional political authorities and institutions by using local indigenous leaders as intermediaries in the administration of the colony. This system undermined the traditional structures of governance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>35", "subject": "Government", "year": "2024", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "The surge in nationalism and its related activities was fueled by oppressive colonial experience and", "images": [], "options": {"A": "Partition of West African territories", "B": "The strong desire for civilization", "C": "Ideology and activities of Pan-Africanism", "D": "Monopoly of mineral resources and land degradation"}, "answer": "C", "explanation": "The surge in nationalism and related activities was fueled by the oppressive colonial experience and the desire for self-determination and independence.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>36", "subject": "Government", "year": "2024", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : POLITICAL PARTICIPATION", "question": "Which institution of state enables different groups and interests to be represented as well as actively participate in the political space?", "images": [], "options": {"A": "Advocate Groups", "B": "Democracy", "C": "Judiciary", "D": "Political party"}, "answer": "B", "explanation": "The correct answer is Democracy. Democracy is the institution of state that enables different groups and interests to be represented as well as actively participate in the political space. It allows for the fair representation of diverse views and ensures participation in decision-making processes.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>37", "subject": "Government", "year": "2024", "type": "Objective", "topic": "NATIONALISM : NATIONALISM: MEANING, FACTORS AND EFFECTS.", "question": "Nationalism played a crucial role in the struggle for independence in West Africa by way of fostering a sense of unity among the people and", "images": [], "options": {"A": "Abhorrence of Western style of governance", "B": "Civil disobedience and killings of White officials", "C": "Dismantling of artificial borders", "D": "Political consciousness"}, "answer": "D", "explanation": "The correct answer is Political consciousness. Nationalism in West Africa fostered a sense of unity among the people and led to the development of political consciousness. This consciousness was crucial in the struggle for independence as it united the people towards a common goal of self-governance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>38", "subject": "Government", "year": "2024", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "The Crown Colony policy introduced some progressive institutions of governance in West Africa such as the", "images": [], "options": {"A": "Creation of the rigid class system", "B": "Education of the traditional rulers", "C": "Introduction of Western Legal system", "D": "Introduction of military academy"}, "answer": "C", "explanation": "The correct answer is Introduction of Western Legal system. The Crown Colony policy introduced progressive institutions of governance in West Africa, including the introduction of the Western Legal system. This legal system brought about changes in the judicial processes and administration of justice in the region.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>39", "subject": "Government", "year": "2024", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "The following influential nationalist leaders contributed significantly to shaping the political destiny and nation-states of West Africa except", "images": [], "options": {"A": "Dawda Kairaba Jawara", "B": "Kwame Nkrumah", "C": "Nnamdi Azikiwe", "D": "Oliver Tambo"}, "answer": "D", "explanation": "The correct answer is Oliver Tambo. Among the influential nationalist leaders mentioned, Oliver Tambo was not directly involved in shaping the political destiny and nation-states of West Africa. The other leaders mentioned - Dawda Kairaba Jawara, Kwame Nkrumah, and Nnamdi Azikiwe - played significant roles in the political development of West Africa.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>40", "subject": "Government", "year": "2024", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "Diplomacy plays a vital role in shaping the interactions between states and by extension maintaining", "images": [], "options": {"A": "Bipolar world", "B": "Global stability", "C": "Power blocks", "D": "Unipolar world"}, "answer": "B", "explanation": "The correct answer is Global stability. Diplomacy plays a vital role in shaping interactions between states and maintaining global stability. Through diplomatic efforts, states negotiate, resolve conflicts, and promote cooperation, which are essential for ensuring stability in the international system.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>41", "subject": "Government", "year": "2024", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : DEMOCRACY", "question": "Military rule does not only pose a threat to democracy but also to", "images": [], "options": {"A": "Fundamental human rights", "B": "National borders", "C": "Nationalism and patriotism", "D": "State sovereignty"}, "answer": "A", "explanation": "Military rule not only poses a threat to democracy but also to fundamental human rights. During military rule, there is often a suppression of civil liberties and human rights in order to maintain power and control.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>42", "subject": "Government", "year": "2024", "type": "Objective", "topic": "CONSTITUTIONAL DEVELOPMENT : POST- INDEPENDENCE CONSTITUTIONS", "question": "The following constitute the key features of most independent constitutions of West African States except", "images": [], "options": {"A": "Nationalist leaders became army commanders", "B": "Democratic principle of governance", "C": "National unity and diversity", "D": "Socio-economic rights and development"}, "answer": "A", "explanation": "The key features of most independent constitutions of West African States include nationalist leaders becoming army commanders, democratic principle of governance, and socio-economic rights and development. Nationalist leaders becoming army commanders is not a common feature of independent constitutions.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>43", "subject": "Government", "year": "2024", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "The grave effect of the French Colonial Policy of Assimilation in her West African Colonies was the", "images": [], "options": {"A": "Aggressive development of nationalism", "B": "Shortfall in the essential needs of the colonies", "C": "Slow pace in their political fortunes", "D": "Waging war on neighbouring colonial territories"}, "answer": "B", "explanation": "The grave effect of the French Colonial Policy of Assimilation in her West African Colonies was the shortfall in the essential needs of the colonies. This policy aimed at making the colonies adopt French culture and institutions, often neglecting the basic needs of the local population.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>44", "subject": "Government", "year": "2024", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "The British Colonial policy in her West African territories was marked by the following strategies and structures except", "images": [], "options": {"A": "Divide and rule", "B": "Economic exploitation", "C": "Indirect rule", "D": "Investments in the colonies"}, "answer": "D", "explanation": "The British Colonial policy in her West African territories was marked by investments in the colonies. While strategies like divide and rule, economic exploitation, and indirect rule were employed, investments in the colonies were also a significant aspect of British colonial policy.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>45", "subject": "Government", "year": "2024", "type": "Objective", "topic": "FEDERAL/UNITARY SYSTEMS OF GOVERNMENT IN WEST AFRICA : ORIGINS, FACTORS AND STRUCTURE", "question": "Globalization impacts the development and progress of West African States by war of", "images": [], "options": {"A": "Manipulation of economics of states", "B": "Propping of regimes", "C": "Protecting state sovereignty", "D": "Technology transfer"}, "answer": "C", "explanation": "Globalization impacts the development and progress of West African States through various means but one sole impact is protecting state sovereignty.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>46", "subject": "Government", "year": "2024", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY", "question": "Power, authority, legitimacy and sovereignty are described in the study of government as what?", "images": [], "options": {"A": "Basic concepts and Principles", "B": "Constitutionalism and meanings", "C": "Principles and Structures", "D": "Structure of Governance"}, "answer": "A", "explanation": "Power, authority, legitimacy, and sovereignty are fundamental concepts in the study of government, representing basic concepts and principles that form the foundation of governance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>47", "subject": "Government", "year": "2024", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION, COMMUNALISM, FEUDALISM AND OLIGARCHY, LIBERALISM, SOCIALISM, COMMUNISM, CAPITALISM, FASCISM, ARISTOCRACY, TOTALITARIANISM.", "question": "A government with corrupt rulers who are their power to exploit the people and natural resources of their own territory to extend their personal wealth and political power is described as", "images": [], "options": {"A": "Autocracy", "B": "Capitalism", "C": "Kleptocracy", "D": "Oligarchy"}, "answer": "C", "explanation": "A government with corrupt rulers who exploit resources for personal gain is described as a Kleptocracy, where leaders use power for personal wealth accumulation.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>48", "subject": "Government", "year": "2024", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "In what way can the local government system assist in national development? By", "images": [], "options": {"A": "Aligning local efforts with broader national goals", "B": "Depending on the central government for basic needs and development", "C": "Encouraging youth movement to the industrial centres", "D": "Ensuring only top-bottom policies of government are supported"}, "answer": "A", "explanation": "The local government system can assist in national development by aligning local efforts with broader national goals, ensuring coordinated development across different levels of governance.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2024>49", "subject": "Government", "year": "2024", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The perceived perennial problem of the United Nations (UN) since its inception is the", "images": [], "options": {"A": "Directive Principles of State Policy", "B": "Deep seated diversity among member states", "C": "Nature of political leaders", "D": "Poor constitutional provisions of member states"}, "answer": "B", "explanation": "The perennial problem of the United Nations (UN) is the deep-seated diversity among member states, which often leads to challenges in reaching consensus and unified action.", "marks": "1", "difficulty": "3"}, {"id": "objective>Government>2024>50", "subject": "Government", "year": "2024", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : DEMOCRACY", "question": "For the executive to enjoy the good will of the people in a democratic state, it must adhere to the tenets of", "images": [], "options": {"A": "The Council of State", "B": "Exercise of unrestrained power", "C": "Laissez-faire government", "D": "Political equality"}, "answer": "D", "explanation": "The tenets of political equality include accountability, transparency, responsiveness, and respect for the rule of law.", "marks": "1", "difficulty": "2"}, {"id": "objective>Government>2025>1", "subject": "Government", "year": "2025", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : DEMOCRACY", "question": "Which of the following indicators is considered the lifeblood of democracy?", "images": [], "options": {"A": "Public opinion polls only", "B": "Political party membership.", "C": "Voter turnout and civic engagement", "D": "Confidentiality and secrecy"}, "answer": "C", "explanation": "In a democracy, citizens' participation through voting and other forms of civic engagement (e.g. attending town halls, joining civil society organizations, engaging in public debates) is essential. High voter turnout means citizens are actively shaping the leadership and direction of their government, which is the core principle of democracy-rule by the people.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>2", "subject": "Government", "year": "2025", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY, POLITICAL CULTURE AND SOCIALIZATION", "question": "Identify the term that describes the various approaches and strategies used to exert authority and manage the affairs of a state.", "images": [], "options": {"A": "Governance", "B": "Public policy", "C": "Jurisdiction", "D": "Sovereignty"}, "answer": "A", "explanation": "Governance refers to the way in which power is exercised in the management of a country's economic, political, and administrative affairs. It includes mechanisms, processes, and institutions through which authority is exercised-both in formal and informal ways.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>3", "subject": "Government", "year": "2025", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : PRESIDENTIAL", "question": "What concept defines a state's right to govern itself and maintain its territorial integrity without external intervention?", "images": [], "options": {"A": "Alliance", "B": "Interventionism", "C": "Self-determination", "D": "Sovereignty"}, "answer": "D", "explanation": "Sovereignty is the principle that a state has the ultimate authority over its territory and internal affairs without interference from other states. It's a core principle of international law.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>4", "subject": "Government", "year": "2025", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY", "question": "In the context of governmental structures, what type of function does a House of Representatives stand for?", "images": [], "options": {"A": "Dispensation of justice", "B": "Legislation", "C": "Ideology", "D": "Authority"}, "answer": "B", "explanation": "The House of Representatives (or similar legislative bodies) is primarily responsible for making laws. It debates and passes bills, which then go to the upper house or the president for approval, depending on the system.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>5", "subject": "Government", "year": "2025", "type": "Objective", "topic": "CITIZENSHIP : MEANS OF SAFEGUARDING RIGHTS OF CITIZENS.", "question": "What is considered the paramount role of a constitution in ensuring the stability and functioning of a democracy?", "images": [], "options": {"A": "Protection of civil liberties", "B": "Establishes governmental powers only", "C": "Appointment of the electoral commissioner", "D": "Regulates economic policies onl"}, "answer": "A", "explanation": "A constitution lays out the fundamental rights of citizens, limits government power, and outlines how government functions. Its core democratic role is protecting civil liberties-like freedom of speech, assembly, and religion-which ensures fairness and checks on power.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>6", "subject": "Government", "year": "2025", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNITMENT : FEDERAL", "question": "In the context of national development, which of the following best describes the most significant role of citizens?", "images": [], "options": {"A": "Active participation in governance", "B": "Financial and spiritual support", "C": "Observe the political arena keenly", "D": "Demonstrations, strikes, and boycotts"}, "answer": "A", "explanation": "National development thrives when citizens engage in decision-making, demand accountability, vote, and contribute ideas and services. This active involvement helps build inclusive institutions and sustainable policies.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>7", "subject": "Government", "year": "2025", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : DEMOCRACY", "question": "How does the media influence governance in a democratic society?", "images": [], "options": {"A": "Performing the watchdog role that holds government accountable to the people", "B": "Issuing editorial threats to government on policies", "C": "Giving hope to the citizens in times of need", "D": "Advancing the political ideology of parties"}, "answer": "A", "explanation": "Explanation: In a democracy, the media is often referred to as the \"fourth estate.\" It acts as a watchdog by monitoring government actions and holding officials accountable to the public. The media exposes corruption, mismanagement, and other failures, ensuring transparency and trust in governance. It also provides a platform for public debate and discussion, which is essential for a healthy democracy.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>8", "subject": "Government", "year": "2025", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC PRINCIPLES – RULE OF LAW, FUNDAMENTAL HUMAN RIGHTS, SEPARATION OF POWERS/CHECKS AND BALANCES, CONSTITUTIONALISM, POLITICAL PARTICIPATION, REPRESENTATIVE GOVERNMENT, CENTRALIZATION AND DECENTRALIZATION – (DELEGATED LEGISLATION, DEVOLUTION AND DECENTRALIZATION).", "question": "In what way do pressure groups significantly contribute to the governance structure?", "images": [], "options": {"A": "Lobbying government to adopt policies that align with their specific interests", "B": "Organizing community events to bring down tensions in society", "C": "Uniting citizens to run for public office and replace bad leaders in society", "D": "Providing financial support to political parties to gain popularity"}, "answer": "A", "explanation": "Explanation: Pressure groups (also known as interest groups or advocacy groups) aim to influence government policy in ways that benefit their members or causes. They do this primarily through lobbying, where they seek to persuade lawmakers and government officials to adopt policies that align with their interests. They may also provide expertise or mobilize public support to push for changes.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>9", "subject": "Government", "year": "2025", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : DEMOCRACY", "question": "How does public opinion influence democratic governance?", "images": [], "options": {"A": "Has no real impact on the governance and direction of the state", "B": "Determines the legal framework and constitutional principles", "C": "Is the sole determinant of the outcomes of elections", "D": "Assists in shaping the decisions of elected officials and guides public policy"}, "answer": "D", "explanation": "Public opinion plays a vital role in shaping democratic governance. Elected officials are accountable to the public, and their policies and decisions are often influenced by public sentiment. Politicians are motivated to align with popular opinion to maintain support and win re-election. This democratic feedback loop helps shape public policy.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>10", "subject": "Government", "year": "2025", "type": "Objective", "topic": "CITIZENSHIP : MEANS OF SAFEGUARDING RIGHTS OF CITIZENS.", "question": "What does a state typically expect from its citizens in return for its responsibility towards them?", "images": [], "options": {"A": "Passive obedience to state laws", "B": "Side with elected leaders always", "C": "Active involvement in civic duties", "D": "Unconditional support for all governmental policies"}, "answer": "C", "explanation": "In a democracy, the state expects citizens to actively participate in the democratic process, such as voting, engaging in political discussions, paying taxes, and serving on juries. This active engagement helps maintain the legitimacy of the government and strengthens the democratic system. Passive obedience or unconditional support without participation is not a hallmark of a healthy democracy.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>11", "subject": "Government", "year": "2025", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "In the context of national cohesion, how does political culture play a critical role in shaping the collective identity of a nation?", "images": [], "options": {"A": "Encourages civil disobedience in the face of hardship", "B": "Focuses on political development and well-being of citizens only", "C": "Fosters shared values that create a sense of belonging", "D": "Dictates laws without influencing attitudes"}, "answer": "C", "explanation": "Political culture refers to the set of shared beliefs, values, and practices that define a nation's political life. It shapes the way citizens perceive their role in the political system and their relationship to one another and the state. A strong political culture promotes a sense of unity and national identity, helping to create social cohesion and a collective understanding of the nation's goals.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>12", "subject": "Government", "year": "2025", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : POLITICAL PARTICIPATION", "question": "How does political socialization influence state development?", "images": [], "options": {"A": "Shapes citizens' understanding of government and society", "B": "Increases political agitation for equality", "C": "Promotes acceptance of political inequality", "D": "Encourages political awareness for purposes of extremism"}, "answer": "A", "explanation": "Political socialization is the process by which individuals learn and internalize the values, norms, and practices of their political system. This process helps citizens understand their role in government, the importance of civic duties, and the workings of the state. Political socialization fosters political awareness, which is essential for the development of a well-informed and active citizenry, contributing to the stability and functioning of a democracy.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>13", "subject": "Government", "year": "2025", "type": "Objective", "topic": "TOTALITARIANISM", "question": "Which of the following is a major indicator of totalitarian tendencies in a democracy?", "images": [], "options": {"A": "Erosion of civil liberties", "B": "Low voter turnout", "C": "Active political participation", "D": "Series of boycotts and demonstrations"}, "answer": "A", "explanation": "Totalitarian regimes often limit or suppress civil liberties like freedom of speech, assembly, and the press. In a democratic society, these rights are protected to ensure individual freedoms and political participation. The erosion of these freedoms, such as through censorship or authoritarian control over the media, signals a shift toward totalitarian tendencies. This undermines democracy by concentrating power and limiting the voice of the people.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>14", "subject": "Government", "year": "2025", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY", "question": "Why is judicial independence key to the stability of democracy?", "images": [], "options": {"A": "Connect the government and the people", "B": "Make judges sacrosanct", "C": "Protect the political class and party functionaries", "D": "Avoid political pressure, influence, and manipulation"}, "answer": "D", "explanation": "Judicial independence is crucial for the fair and impartial administration of justice. In a democracy, the judiciary must be free from political pressures or interference from the executive or legislative branches. This ensures that legal decisions are made based on the rule of law, rather than political considerations. Judicial independence protects individual rights and upholds the principles of democracy by ensuring that laws are applied equally to all citizens.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>15", "subject": "Government", "year": "2025", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : ELECTORAL MANAGEMENT BODY", "question": "Identify one of the key challenges of the Electoral Management Bodies in West Africa:", "images": [], "options": {"A": "Voter education gap and funding", "B": "Government expenditure on political parties", "C": "Consistency in election results", "D": "Over-reliance on technology in its operations"}, "answer": "A", "explanation": "One of the main challenges for Electoral Management Bodies (EMBs) in West Africa is the voter education gap and inadequate funding. In many countries, citizens lack the knowledge and awareness of how to vote properly, what their rights are, and how the electoral process works. This gap can lead to low voter turnout, spoiled ballots, and general disillusionment with the political process. Moreover, EMBs often suffer from limited budgets, which impacts their ability to run free and fair elections.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>16", "subject": "Government", "year": "2025", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : DEMOCRACY", "question": "How do political parties contribute to the sustainability of democracy?", "images": [], "options": {"A": "Centralizing power", "B": "Providing voter choice", "C": "Suppressing dissent", "D": "Limiting competition"}, "answer": "B", "explanation": "Political parties contribute to the sustainability of democracy primarily by providing voter choice. In a democratic system, political parties offer voters distinct alternatives, allowing them to choose representatives and policies that best align with their preferences. This competitive environment ensures political accountability and fosters active participation. Without political parties, the democratic process would lack structure and fail to reflect the diversity of public opinion.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>17", "subject": "Government", "year": "2025", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "What is the best strategy to adopt in maximizing the potential of public corporations?", "images": [], "options": {"A": "Strict regulations and discipline", "B": "Innovation, research, and retooling", "C": "Direct control by government and job cuts", "D": "Immediate profits and market competition"}, "answer": "B", "explanation": "To maximize the potential of public corporations, innovation, research, and retooling are essential. Public corporations need to adapt to changing markets, technologies, and consumer needs. By fostering a culture of innovation and continuous improvement, they can become more efficient, competitive, and sustainable in the long term. Strict regulations and job cuts may stifle creativity and hinder growth, while focusing solely on immediate profits or market competition might not address long-term strategic needs.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>18", "subject": "Government", "year": "2025", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC/CIVIL SERVICE COMMISSION –MEANING AND FUNCTIONS.", "question": "The role of the civil service in the governance structure includes:", "images": [], "options": {"A": "Ruling on cases timely", "B": "Conducting free and fair elections", "C": "Making legislative decisions", "D": "Providing administrative support"}, "answer": "D", "explanation": "The civil service plays a critical role in providing administrative support to the government. Civil servants are responsible for the day-to-day management of public affairs, the implementation of government policies, and the functioning of various public services. They do not make laws or conduct elections, but they ensure the smooth running of governmental functions by providing administrative expertise and support.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>19", "subject": "Government", "year": "2025", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY", "question": "What is commonly perceived as hindering the advancement of local government administration?", "images": [], "options": {"A": "Denial of training programs", "B": "Lack of transparency in financial transactions", "C": "Bureaucratic inefficiencies", "D": "No administrative communication"}, "answer": "B", "explanation": "A significant barrier to the advancement of local government administration is the lack of transparency in financial transactions. This leads to corruption, mismanagement of resources, and erosion of public trust. Transparency is key to ensuring that local governments are accountable to the people they serve. When financial dealings are not open, it hampers progress and undermines the legitimacy of the local governance system.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>20", "subject": "Government", "year": "2025", "type": "Objective", "topic": "STATE STRUCTURE AND CHARACTERISTICS OF GOVERNMENT : FEDERAL", "question": "Which of the following serves as a pillar in the functioning of a federal system of government?", "images": [], "options": {"A": "Centralized authority", "B": "Division of power", "C": "Absolute power", "D": "Unitary authority"}, "answer": "B", "explanation": "In a federal system of government, the division of power between central and regional (or state) governments is a fundamental pillar. Federalism ensures that both levels of government share authority, which prevents any one branch or level from becoming too powerful. This division allows for more localized decision-making while still maintaining a strong national government.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>21", "subject": "Government", "year": "2025", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : DEMOCRACY", "question": "Why is delegated legislation a key component of a democratic system?", "images": [], "options": {"A": "Allows easy passage of law and unconditional political power", "B": "Enables detailed regulation by experts", "C": "Eliminates the stress level of elected officials", "D": "Ensures uniform application of laws and punitive punishment"}, "answer": "B", "explanation": "Delegated legislation allows elected representatives to delegate the power to create detailed rules and regulations to experts or regulatory bodies. This is important in a democratic system because it allows for more efficient and specialized lawmaking, especially in complex or technical areas. It does not concentrate power or eliminate elected officials' responsibilities but instead supports the legislative process by providing expertise where needed.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>22", "subject": "Government", "year": "2025", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : DEMOCRACY", "question": "How best can traditional authorities and their institutions contribute to democratic governance?", "images": [], "options": {"A": "Promoting cultural values to resist globalization", "B": "Enhancing trust in governance institutions", "C": "Promoting cultural distinction and excellence", "D": "Prioritizing tradition and the authority of traditional rulers"}, "answer": "B", "explanation": "Traditional authorities can play a role in enhancing trust in governance institutions by acting as intermediaries between the government and local communities. In many cultures, traditional leaders have the respect of the people, and when integrated into democratic governance structures, they can help bridge gaps, promote social cohesion, and increase citizens' trust in government processes. They should not solely prioritize tradition but work within the framework of democratic principles.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>23", "subject": "Government", "year": "2025", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY", "question": "Which of the following characteristics best describes a Protectorate in the Colonial administrative policy?", "images": [], "options": {"A": "Full sovereignty and independence of the Colony", "B": "Complete annexation and integration into the protecting power", "C": "Limited sovereignty with external control over foreign affairs and defenseTotal economic control and political independence by the Colony", "D": "Total economic control and political independence by the Colony"}, "answer": "C", "explanation": "A protectorate refers to a colonial administrative arrangement where the colony maintains limited sovereignty but is under the control of a foreign power in matters of foreign affairs, defense, and sometimes economic matters. The protecting power often controls these aspects while allowing the local government some degree of internal autonomy. This contrasts with complete annexation or total independence.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>24", "subject": "Government", "year": "2025", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY AND STRUCTURE OF THE BRITISH COLONIAL ADMINISTRATION", "question": "The nature of a British Colony:", "images": [], "options": {"A": "operated with complete local autonomy and self-governance", "B": "was directly governed by the British Crown with appointed officials", "C": "was purposely established for economic benefits and human labour", "D": "allowed local assemblies to have full legislative powers"}, "answer": "B", "explanation": "In British colonies, governance was usually controlled directly by the British Crown through appointed officials (like governors or colonial administrators). While there were some local councils, real political power lay with the British officials, and the colonies did not have full local autonomy or self-governance. The British Crown had the ultimate control, and it was largely a centralized administration.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>25", "subject": "Government", "year": "2025", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : THE POLICY OF FRENCH COLONIAL ADMINISTRATION", "question": "The primary aim of the French policy of assimilation:", "images": [], "options": {"A": "promote complete independence and self-governance from the colonizer", "B": "exploit natural resources without regard to the local people and their traditional authorities", "C": "encourage the adoption of French culture, values, and language by colonized people", "D": "establish separate and autonomous local governments for the local people and their authorities"}, "answer": "C", "explanation": "French colonial policy, particularly the policy of assimilation, aimed at \"transforming\" colonized people into French citizens, expecting them to adopt French language, culture, values, and institutions. This was a form of cultural integration rather than an effort to promote independence or separate governance. The French did not establish autonomous local governments and instead sought to impose French ways of life.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>26", "subject": "Government", "year": "2025", "type": "Objective", "topic": "NATIONALISM : NATIONALISM: MEANING, FACTORS AND EFFECTS.", "question": "A critical lesson drawn from the role of nationalism and nationalist activities in modern governance:", "images": [], "options": {"A": "stimulate economic growth only", "B": "unify but also exclude", "C": "disregard rights for loyalty and militancy", "D": "encourage disregard for values and principles"}, "answer": "B", "explanation": "Nationalism can unify a people under a shared identity or cause, but it can also be exclusionary. Nationalist movements sometimes define who belongs to the \"nation\" and who does not, leading to the marginalization or exclusion of certain groups. While nationalism can foster unity, it can also sow division if not handled inclusively.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>27", "subject": "Government", "year": "2025", "type": "Objective", "topic": "NATIONALISM : KEY NATIONALIST LEADERS/MOVEMENTS AND THEIR CONTRIBUTIONS.", "question": "Nationalist leaders in the West African Colonies after World War II were primarily associated with:", "images": [], "options": {"A": "promoting colonial rule due to education", "B": "advocating for political independence", "C": "maintaining the traditional political system", "D": "sustaining the interest of the colonizer in foreign affairs"}, "answer": "B", "explanation": "After World War II, many nationalist leaders in West Africa became increasingly vocal in advocating for independence from colonial powers. They were influenced by global anti-colonial movements and the desire to control their own political, economic, and social destinies. They fought against colonial rule, not to promote it, and were not interested in maintaining traditional political systems if those systems were dominated by colonial structures.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>28", "subject": "Government", "year": "2025", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "The political agitation by the West African Colonies in the post World War II era was mainly driven by:", "images": [], "options": {"A": "a desire to strengthen traditional political governance", "B": "an aspiration for self-determination and independence", "C": "a commitment to colonial policies and governance structure", "D": "an interest in increasing foreign investments and growth of cottage industries"}, "answer": "B", "explanation": "Post-WWII, many African colonies, including West Africa, were focused on gaining independence from colonial rule. Nationalist movements gained momentum as people sought self-determination and an end to foreign domination. The desire for political autonomy, economic control, and national identity was central to their demands.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>29", "subject": "Government", "year": "2025", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "Which of the following statements best identifies the negative impacts of Colonial administration on the political development of British West Africa?", "images": [], "options": {"A": "Disruption of traditional structures of authority", "B": "Fragmentation of governance and spiritual powers", "C": "Setting of citizens against traditional authority", "D": "Concentration of power in the hands of British administrators"}, "answer": "D", "explanation": "Under British colonial rule, political power was centralized in the hands of British administrators. Local leaders often had their powers stripped away, and traditional forms of authority were undermined. This led to a lack of political autonomy for indigenous peoples and long-term political instability after independence. The colonial government typically held all decision-making power, which limited local political development.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>30", "subject": "Government", "year": "2025", "type": "Objective", "topic": "COLONIAL ADMINISTRATION : IMPACT, ADVANTAGES AND DISADVANTAGES OF COLONIAL RULE", "question": "Identify a common practice in the governance structure of the pre-independence constitutions of the British West African Colonies:", "images": [], "options": {"A": "Full local government", "B": "Centralized power", "C": "Unlimited franchise", "D": "Social development"}, "answer": "B", "explanation": "In British West African colonies, the governance structure was highly centralized. The British Crown appointed governors who held significant power over the colonies. While some attempts at local governance existed, ultimate authority rested with the British administrators. Full local government or unlimited franchise (universal voting rights) were not fully implemented, and social development was not the primary focus of colonial rule.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>31", "subject": "Government", "year": "2025", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "What common factor normally finds expression as the reason for military intervention in the politics of West African States?", "images": [], "options": {"A": "Low foreign investment in the economy", "B": "Neglect of traditional authorities", "C": "Security and political instability", "D": "Lack of infrastructure for the army"}, "answer": "C", "explanation": "Military coups in West African states have often been triggered by political instability, insecurity, or dissatisfaction with the ruling government. When governments fail to address political or economic crises, or when they are seen as corrupt, military intervention can become a perceived solution to restore order. Neglect of traditional authorities or low foreign investment are not as directly linked to military intervention as instability and insecurity are.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>32", "subject": "Government", "year": "2025", "type": "Objective", "topic": "MILITARY RULE : CAUSES AND EFFECTS", "question": "Which area of democratic governance structure is mostly negatively affected by military interventions in West African States?", "images": [], "options": {"A": "Local Government", "B": "Civil Service", "C": "Legislature", "D": "Economy"}, "answer": "A", "explanation": "Military interventions often disrupt the democratic process by undermining local governance structures. Local governments are the most vulnerable because military regimes typically suspend local elections, dissolve local councils, and centralize control. This diminishes the participation of local communities in decision-making and governance, weakening democratic structures at the grassroots level.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>33", "subject": "Government", "year": "2025", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "West African States should take foreign policy determination seriously to", "images": [], "options": {"A": "Limit the influence of the public", "B": "Gauge operational plans", "C": "Encourage apathy for political dissent", "D": "Favour all parties"}, "answer": "C", "explanation": "Foreign policy decisions that are poorly thought out or made without proper consultation can lead to public dissatisfaction, which in turn might cause apathy and disillusionment with the political process. By taking foreign policy seriously, states can prevent political alienation and avoid creating a climate of apathy among their citizens regarding their country's political direction.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>34", "subject": "Government", "year": "2025", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : POLITICAL PARTICIPATION", "question": "How can governance be made effectively accessible to all, regardless of background and distance? By adopting", "images": [], "options": {"A": "E-Governance", "B": "Media outreach", "C": "Expansion of civil service", "D": "Town hall meetings"}, "answer": "A", "explanation": "E-Governance allows for a more inclusive and accessible form of governance by using digital platforms to deliver services and communicate with citizens. This approach ensures that people from all backgrounds, even those in remote areas, have equal access to government services, information, and participation in the democratic process.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>35", "subject": "Government", "year": "2025", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : POLITICAL PARTIES", "question": "What key role do party systems play in the stability and continuity of democratic governance?", "images": [], "options": {"A": "Filter voter interest and participation", "B": "Enhance regional cooperation", "C": "Reduce cultural diversity", "D": "Represent diverse interests"}, "answer": "D", "explanation": "Political parties serve as vehicles for the representation of diverse interests in a society. A well-functioning party system reflects the varied social, cultural, and economic needs of a population, which contributes to the stability and continuity of democratic governance by ensuring that no group feels excluded from the political process.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>36", "subject": "Government", "year": "2025", "type": "Objective", "topic": "THE ELECTORAL SYSTEM : ELECTORAL MANAGEMENT BODY", "question": "How best can the Electoral Management Body operate to clear doubt and suspicion among political actors?", "images": [], "options": {"A": "Limit the influence of the public", "B": "Gauge operational plans", "C": "Enhance transparency", "D": "Favour all parties"}, "answer": "C", "explanation": "The Electoral Management Body (EMB) should be transparent in its operations to gain the trust of all political actors. Transparency ensures that the electoral process is perceived as fair, free, and legitimate. It involves clear communication about the procedures, rules, and outcomes, which minimizes suspicion and fosters confidence in the electoral system.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>37", "subject": "Government", "year": "2025", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY", "question": "What is the paramount consideration for the determination of foreign policy of a state?", "images": [], "options": {"A": "Historical Tradition", "B": "Gauge operational plans", "C": "Cultural Exchange", "D": "National Security"}, "answer": "D", "explanation": "National security is the primary consideration when determining a state's foreign policy. Foreign policy decisions are often shaped by the need to protect the nation's sovereignty, territorial integrity, and citizens. A country's security interests influence its relationships with other states, including defense alliances, trade agreements, and diplomatic actions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>38", "subject": "Government", "year": "2025", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "What is the main aim for the formation of the international peace and security body within the United Nations particularly in the context of", "images": [], "options": {"A": "Facilitate global trade", "B": "Foster diplomatic relations", "C": "Encourage cultural exchange", "D": "Regulate international policies"}, "answer": "B", "explanation": "The main aim of the United Nations' international peace and security body is to promote global peace and stability by fostering diplomatic relations among nations. Through dialogue, negotiation, and conflict resolution mechanisms, the UN seeks to prevent war and encourage peaceful diplomatic solutions to global issues.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>39", "subject": "Government", "year": "2025", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "Identify one of the outstanding achievements of the United Nations that has proven to be remarkably resilient over time.", "images": [], "options": {"A": "Universal Declaration of Human Rights", "B": "Trade among nations of the world", "C": "Technological innovations and arms", "D": "Universal application of democracy"}, "answer": "A", "explanation": "The Universal Declaration of Human Rights (UDHR) has been one of the United Nations' most significant and enduring achievements. Adopted in 1948, it has provided a foundation for the development of international human rights law and continues to serve as a reference point for the protection of human rights worldwide.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>40", "subject": "Government", "year": "2025", "type": "Objective", "topic": "PRESSURE GROUPS, PUBLIC OPINION AND MASS MEDIA : PUBLIC OPINION", "question": "Which method is most effective for collecting public opinion that can be utilized in political decision-making?", "images": [], "options": {"A": "Online surveys and polls", "B": "Single target community polls", "C": "High profile interview polls", "D": "Skewed opinion sample polls"}, "answer": "A", "explanation": "Online surveys and polls are highly effective because they can gather responses from a broad demographic quickly and efficiently. This method allows for inclusivity, with people from different backgrounds and geographic locations able to participate. It also allows for easy data analysis and can be used to inform political decisions.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>41", "subject": "Government", "year": "2025", "type": "Objective", "topic": "CITIZENSHIP : RIGHTS, DUTIES AND OBLIGATIONS OF INDIVIDUALS IN A STATE", "question": "What is the paramount obligation of a citizen to the development and stability of the state? To", "images": [], "options": {"A": "Engage in partisan politics", "B": "Advocate for one's rights and needs", "C": "Participate in community service only", "D": "Pay taxes, obey laws, and protect state properties"}, "answer": "D", "explanation": "Citizens' primary obligations include paying taxes, obeying the law, and protecting state property. These are fundamental duties that ensure the state's financial health, maintain public order, and uphold national security. While engaging in political activities or advocating for rights can be important, the basic civic responsibilities are essential for a functioning state.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>42", "subject": "Government", "year": "2025", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY", "question": "Identify the outstanding function of the constitution in the context of predictability and stability of the state.", "images": [], "options": {"A": "Guides the judiciary to dispense with justice.", "B": "Protects the Executive powers.", "C": "Establishes rules for governance.", "D": "Encourages law reforms and leadership style."}, "answer": "C", "explanation": "The constitution provides the fundamental legal framework for governance, establishing clear rules and guidelines for the functioning of the state. This ensures predictability and stability by outlining how the government should operate, the distribution of power, and the rights and duties of citizens.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>43", "subject": "Government", "year": "2025", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : DEMOCRACY", "question": "Which strong indicators should be present and functioning effectively for there to be meaningful democratic governance?", "images": [], "options": {"A": "Strong army and effective police force.", "B": "Corrupt-free society and active citizens.", "C": "Good leader and patriotic citizens.", "D": "Rule of Law, free and fair elections."}, "answer": "D", "explanation": "For democracy to function effectively, two key indicators are essential: the rule of law (ensuring that laws are applied equally and fairly) and free and fair elections (allowing citizens to choose their leaders freely and without manipulation). These elements provide the foundation for legitimate governance and political stability.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>44", "subject": "Government", "year": "2025", "type": "Objective", "topic": "POLITICAL PARTIES AND PARTY SYSTEMS : PARTY SYSTEMS", "question": "Identify the primary advantage of a multi-party system over a single-party system of government.", "images": [], "options": {"A": "Political diversity.", "B": "Political polarization.", "C": "Unipolar political system", "D": "Presence of electoral commissioner"}, "answer": "A", "explanation": "A multi-party system fosters political diversity by allowing multiple political parties to exist, which means different viewpoints, ideologies, and interests can be represented. This enhances democratic participation and provides voters with more choices, as opposed to a single-party system that can lead to monopolized governance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>45", "subject": "Government", "year": "2025", "type": "Objective", "topic": "PUBLIC/CIVIL SERVICE ADMINISTRATION : PUBLIC CORPORATIONS", "question": "Which of the following reasons explains why some schools of thought advocate for the commercialization or privatization of public corporations?", "images": [], "options": {"A": "Government control", "B": "Increased efficiency", "C": "State sovereignty", "D": "Redundancy"}, "answer": "B", "explanation": "Advocates for the commercialization or privatization of public corporations argue that private sector management can bring increased efficiency, productivity, and innovation. Public corporations, often controlled by the government, may face inefficiencies, lack of competition, and financial mismanagement. Privatization is seen as a way to improve service delivery and financial performance.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>46", "subject": "Government", "year": "2025", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : ECOWAS", "question": "What serves as the strong cord that binds the membership of the Economic Community of West African States (ECOWAS)?", "images": [], "options": {"A": "Economic cooperation", "B": "Cultural diversity.", "C": "Geographical isolation.", "D": "Political rivalry"}, "answer": "A", "explanation": "The core purpose of ECOWAS is to promote regional economic integration and cooperation. It aims to create a common economic space among West African countries through trade agreements, infrastructure projects, and economic policies. This economic cooperation is the key factor that unites its member states.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>47", "subject": "Government", "year": "2025", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE UNITED NATIONS ORGANIZATIONS - UNO", "question": "The success of the United Nations as the premier global organization can be attributed to which of the following factors?", "images": [], "options": {"A": "Exclusive regional influence.", "B": "Focus on military power", "C": "Specialized membership criteria", "D": "Strong international cooperation"}, "answer": "D", "explanation": "The success of the United Nations (UN) is largely due to the cooperation among its member states, regardless of their political, economic, or cultural differences. The UN's role in promoting peace, security, development, and human rights is strengthened through collaborative efforts from its diverse membership.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>48", "subject": "Government", "year": "2025", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : THE COMMONWEALTH OF NATIONS", "question": "Identify one reason for which Nigeria remains a member of the Commonwealth.", "images": [], "options": {"A": "Cultural assimilation.", "B": "Mandatory military assistance", "C": "Economic collaboration.", "D": "Visa-free policy."}, "answer": "C", "explanation": "Nigeria remains a member of the Commonwealth largely because of the economic collaboration that benefits both Nigeria and other member states. The Commonwealth offers opportunities for trade, development assistance, and mutual economic cooperation among its diverse members, which is valuable for Nigeria.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>49", "subject": "Government", "year": "2025", "type": "Objective", "topic": "INTERNATIONAL ORGANIZATIONS : AFRICAN UNION", "question": "How significant is the African Union to its members within the framework of the international community? It", "images": [], "options": {"A": "Shields member countries from Globalization", "B": "Protects member countries from Neo-Colonialism", "C": "Fosters regional unity and cooperation", "D": "Obstructs diplomatic engagement with other continents"}, "answer": "C", "explanation": "The African Union (AU) plays a critical role in promoting regional unity and cooperation among African states. It addresses common issues such as conflict resolution, economic integration, and political stability. The AU's objective is to foster solidarity among African nations and strengthen the continent's influence on the global stage.", "marks": "1", "difficulty": "1"}, {"id": "objective>Government>2025>50", "subject": "Government", "year": "2025", "type": "Objective", "topic": "BASIC CONCEPTS AND PRINCIPLES OF GOVERNMENT : BASIC CONCEPTS – STATE, SOCIETY, NATION, POWER, AUTHORITY, LEGITIMACY, SOVEREIGNTY, DEMOCRACY", "question": "In what way do civil society organizations contribute to democratic governance? By", "images": [], "options": {"A": "Advancing sectoral interests only.", "B": "Encouraging civil disobedience.", "C": "Facilitating citizen engagement and activism.", "D": "Setting political agendas only"}, "answer": "C", "explanation": "Civil society organizations (CSOs) are crucial for promoting democracy by encouraging citizen engagement, activism, and participation in the political process. They help hold the government accountable, advocate for human rights, and ensure that the voices of marginalized or vulnerable groups are heard in the democratic process.", "marks": "1", "difficulty": "1"}];